function lazySectionElement(sectionName) {
    return document.querySelector(`[data-lazy-section="${sectionName}"]`);
}

function targetIdFromHash(hash = window.location.hash) {
    const rawTargetId = String(hash || "").replace(/^#/, "");

    if (!rawTargetId) {
        return "";
    }

    try {
        return decodeURIComponent(rawTargetId);
    } catch (error) {
        return rawTargetId;
    }
}

function lazySectionFromTargetId(targetId) {
    if (String(targetId || "").startsWith("pantryItem-")) {
        return "pantry";
    }

    const sectionsByTargetId = {
        adminSupportSection: "admin-support",
        aiPantryAddItems: "pantry",
        aiPantryCookWhatImFeeling: "pantry",
        aiPantryCookWithWhatIHave: "pantry",
        aiPantryInventory: "pantry",
        aiPantryLocations: "pantry",
        aiPantryMissingIngredients: "pantry",
        aiPantryUploadReceipt: "pantry",
        aiPantryUseSoon: "pantry",
        aiPantrySection: "pantry",
        currentRecipeUrlLogCard: "current-recipes",
        cookbooksCard: "cookbooks",
        rulesCard: "rules",
        rules: "rules",
        storeOptionsSection: "store-options",
        "store-options": "store-options",
        sharedRecipePdfsSection: "shared-recipe-pdfs",
        shoppingViewsSection: "recipe-view",
        sectionView: "recipe-view",
        storeView: "recipe-view",
        recipeView: "recipe-view",
    };

    return sectionsByTargetId[targetId] || "";
}

function accountPanelKeyFromHash(hash = window.location.hash) {
    const hashValue = String(hash || "");

    if (targetIdFromHash(hashValue).startsWith("pantryItem-")) {
        return "aiPantry";
    }

    return USER_ACCOUNT_PANEL_HASH_KEYS[hashValue] || "";
}

function scrollToLazySectionTarget(targetId, fallbackTarget = null, options = {}) {
    const target = targetId ? document.getElementById(targetId) : null;
    const scrollTarget = target || fallbackTarget;

    if (!scrollTarget || typeof scrollTarget.scrollIntoView !== "function") {
        return false;
    }

    if (
        target
        && target.matches
        && target.matches("[data-pantry-inventory-row]")
        && typeof setPantryInventoryDetailsCollapsed === "function"
    ) {
        setPantryInventoryDetailsCollapsed(target, false);
    }

    scrollTarget.scrollIntoView({
        behavior: options.behavior || "smooth",
        block: options.block || "start",
    });

    if (target && options.focusTarget !== false && typeof target.focus === "function") {
        target.focus({ preventScroll: true });
    }

    return Boolean(target);
}

function normalizeAppShellSearchText(value) {
    return String(value || "")
        .toLowerCase()
        .replace(/[^a-z0-9]+/g, " ")
        .trim();
}

function appShellNavTargetId(link) {
    if (!link) {
        return "";
    }

    const explicitTarget = String(link.dataset.appNavTarget || "").replace(/^#/, "");
    if (explicitTarget) {
        return explicitTarget;
    }

    const href = String(link.getAttribute("href") || "");
    return href.startsWith("#") ? href.slice(1) : "";
}

function appShellNavPageTargets(link) {
    if (!link) {
        return [];
    }

    const primaryTarget = String(link.dataset.appPageTarget || "").trim();
    const aliasTargets = String(link.dataset.appPageAliases || "")
        .split(/\s+/)
        .map(target => target.trim())
        .filter(Boolean);

    return [...new Set([primaryTarget, ...aliasTargets].filter(Boolean))];
}

function appShellPrimaryNavigationLinks() {
    return [...document.querySelectorAll([
        "[data-app-sidebar] [data-app-nav-link]",
        "[data-app-mobile-nav-drawer] [data-app-nav-link]",
        ".app-mobile-bottom-nav [data-app-nav-link]",
    ].join(", "))];
}

function appShellNavActiveKey(link) {
    if (!link) {
        return "";
    }

    const action = String(link.dataset.appNavAction || "");
    const targetId = appShellNavTargetId(link);

    if (action === "app-page" || action === "ai-pantry") {
        const pageId = String(link.dataset.appPageTarget || "")
            || appPageFromTargetId(targetId);
        return pageId ? `page:${pageId}` : `target:${targetId}`;
    }

    if (action === "settings-section") {
        const sectionKey = String(link.dataset.settingsSectionTarget || "")
            || settingsSectionFromTargetId(targetId);
        return sectionKey ? `settings:${sectionKey}` : `target:${targetId}`;
    }

    if (action === "home") {
        return "action:home";
    }

    return action
        ? `action:${action}:${targetId}`
        : `target:${targetId}`;
}

function appShellSetActiveLink(activeLink) {
    const activeKey = appShellNavActiveKey(activeLink);

    appShellPrimaryNavigationLinks().forEach(link => {
        const sameLinkKey = activeKey && appShellNavActiveKey(link) === activeKey;
        link.classList.toggle("is-active", Boolean(sameLinkKey));
        if (sameLinkKey) {
            link.setAttribute("aria-current", "page");
        } else {
            link.removeAttribute("aria-current");
        }
    });
}

function appShellSetActivePageLink(pageId) {
    const pageKey = String(pageId || "");
    const pageLink = appShellPrimaryNavigationLinks()
        .find(link => appShellNavPageTargets(link).includes(pageKey));

    appShellSetActiveLink(pageLink || null);
}

function appShellSetSearchStatus(message) {
    const status = document.querySelector("[data-app-global-search-status]");

    if (status) {
        status.textContent = message || "";
    }
}

function appShellUpdateHash(targetId) {
    if (!targetId || !window.history || !window.history.pushState) {
        return;
    }

    const nextHash = `#${targetId}`;
    if (window.location.hash !== nextHash) {
        window.history.pushState(null, "", nextHash);
    }
}

function appShellScrollToTarget(targetId, options = {}) {
    const target = targetId ? document.getElementById(targetId) : null;

    if (!target) {
        return false;
    }

    target.scrollIntoView({
        behavior: options.behavior || "smooth",
        block: options.block || "start",
    });

    if (options.focusTarget !== false && typeof target.focus === "function") {
        target.focus({ preventScroll: true });
    }

    return true;
}

function appPageFromTargetId(targetId) {
    return APP_PAGE_TARGETS[String(targetId || "")] || "";
}

function setHomeDashboardVisible(visible) {
    document.querySelectorAll("[data-app-home-dashboard]").forEach(section => {
        section.hidden = !visible;
    });
}

function setHomeHeaderVisible(visible) {
    document.querySelectorAll("[data-app-home-header]").forEach(header => {
        header.hidden = !visible;
    });
}

function setUserAccountWorkspaceVisible(visible) {
    const section = document.getElementById("userAccountSection");

    if (!section || document.body.classList.contains("account-action-token")) {
        return section;
    }

    section.hidden = !visible;
    return section;
}

function hideAppPageWorkspaces(exceptPage = null) {
    document.querySelectorAll("[data-app-page-workspace]").forEach(page => {
        if (page !== exceptPage) {
            page.hidden = true;
        }
    });
}

function openHomeWorkspace(options = {}) {
    hideAppPageWorkspaces();
    setSettingsWorkspaceVisible(false);
    setUserAccountWorkspaceVisible(false);
    setHomeHeaderVisible(true);
    setHomeDashboardVisible(true);

    if (options.updateHash !== false) {
        appShellUpdateHash("appPageHeader");
    }

    if (options.scroll !== false) {
        appShellScrollToTarget("appPageHeader", {
            focusTarget: false,
            behavior: options.behavior || "smooth",
        });
    }

    return false;
}

function openUserAccountWorkspace(options = {}) {
    hideAppPageWorkspaces();
    setSettingsWorkspaceVisible(false);
    setHomeHeaderVisible(false);
    setHomeDashboardVisible(false);
    const section = setUserAccountWorkspaceVisible(true);

    if (!section) {
        return false;
    }

    const targetId = options.targetId || "userAccountSection";
    const target = targetId ? document.getElementById(targetId) : null;
    const scrollTarget = target || section;

    if (options.updateHash !== false) {
        appShellUpdateHash(targetId || "userAccountSection");
    }

    if (options.scroll !== false && scrollTarget) {
        window.requestAnimationFrame(() => {
            appShellScrollToTarget(scrollTarget.id || "userAccountSection", {
                focusTarget: Boolean(target && targetId !== "userAccountSection"),
                behavior: options.behavior || "smooth",
            });
        });
    }

    return false;
}

async function openAppPage(pageId, options = {}) {
    const page = document.getElementById(pageId);

    if (!page) {
        return false;
    }

    setHomeDashboardVisible(false);
    setHomeHeaderVisible(false);
    setSettingsWorkspaceVisible(false);
    setUserAccountWorkspaceVisible(false);
    hideAppPageWorkspaces(page);
    page.hidden = false;
    initDeferredImages(page);
    appShellSetActivePageLink(pageId);

    const targetId = options.targetId || "";
    const panelId = WORKSPACE_PANEL_TARGETS[targetId] || "";
    if (panelId) {
        const panel = document.getElementById(panelId);
        if (panel) {
            panel.hidden = false;
        }
    }

    const lazySection = options.skipLazy
        ? ""
        : (options.lazySection || lazySectionFromTargetId(targetId) || APP_PAGE_LAZY_SECTIONS[pageId] || "");

    if (lazySection) {
        const placeholder = lazySectionElement(lazySection);
        if (placeholder) {
            placeholder.hidden = false;
        }
        await loadLazySection(lazySection, {
            focus: false,
            targetId,
            userInitiated: true,
        });
    }

    const target = targetId ? document.getElementById(targetId) : null;
    const scrollTarget = target || page;

    if (options.updateHash !== false) {
        appShellUpdateHash(targetId || pageId);
    }

    if (options.scroll !== false && scrollTarget) {
        window.requestAnimationFrame(() => {
            scrollToLazySectionTarget(targetId, page, {
                focusTarget: Boolean(targetId && target),
            }) || appShellScrollToTarget(scrollTarget.id || pageId, {
                focusTarget: Boolean(targetId && target),
                behavior: options.behavior || "smooth",
            });
        });
    }

    return false;
}

function settingsSectionFromTargetId(targetId) {
    return SETTINGS_SECTION_TARGETS[String(targetId || "")] || "";
}

function settingsSectionFromHash(hash = window.location.hash) {
    return settingsSectionFromTargetId(targetIdFromHash(hash));
}

function setSettingsWorkspaceVisible(visible) {
    const workspace = document.querySelector("[data-settings-workspace]");

    if (workspace) {
        workspace.hidden = !visible;
    }

    return workspace;
}

async function openSettingsSection(sectionKey = "profile", options = {}) {
    const workspace = setSettingsWorkspaceVisible(true);

    if (!workspace) {
        return false;
    }

    setHomeDashboardVisible(false);
    setHomeHeaderVisible(false);
    setUserAccountWorkspaceVisible(false);
    hideAppPageWorkspaces();

    const normalizedSection = String(sectionKey || "profile");
    let activePanel = [...workspace.querySelectorAll("[data-settings-panel]")]
        .find(panel => panel.dataset.settingsPanel === normalizedSection);
    const fallbackPanel = workspace.querySelector('[data-settings-panel="profile"]');
    const activeSection = activePanel ? normalizedSection : "profile";

    activePanel = activePanel || fallbackPanel;

    workspace.querySelectorAll("[data-settings-panel]").forEach(panel => {
        panel.hidden = panel !== activePanel;
    });

    workspace.querySelectorAll("[data-settings-nav-button]").forEach(button => {
        const isActive = button.dataset.settingsSection === activeSection;
        button.classList.toggle("is-active", isActive);
        if (isActive) {
            button.setAttribute("aria-current", "page");
        } else {
            button.removeAttribute("aria-current");
        }
    });

    const lazySection = SETTINGS_SECTION_LAZY_SECTIONS[activeSection] || "";
    if (lazySection) {
        const placeholder = lazySectionElement(lazySection);
        if (placeholder) {
            placeholder.hidden = false;
        }
        await loadLazySection(lazySection, {
            focus: false,
            targetId: options.targetId || "",
            userInitiated: true,
        });
    }

    restoreHomeAddressHistoryCollapseState();
    restoreStoreOptionsDisplaySettings();
    restoreActiveStoreIconMode();
    restoreStoreOptionsListSort();
    initStoreLocationMaps();

    const targetId = options.targetId || "";
    const target = targetId ? document.getElementById(targetId) : null;
    const scrollTarget = target || activePanel || workspace;

    if (options.updateHash !== false) {
        appShellUpdateHash(targetId || (activePanel ? activePanel.id : "settingsWorkspaceSection"));
    }

    if (options.scroll !== false && scrollTarget) {
        window.requestAnimationFrame(() => {
            scrollToLazySectionTarget(targetId, scrollTarget, {
                focusTarget: Boolean(targetId && target),
            }) || appShellScrollToTarget(scrollTarget.id || "settingsWorkspaceSection", {
                focusTarget: false,
            });
        });
    }

    return false;
}

function openWorkspacePanel(panelId, options = {}) {
    const pageId = appPageFromTargetId(panelId);
    if (pageId && options.fromAppPage !== true) {
        return openAppPage(pageId, {
            ...options,
            targetId: options.targetId || panelId,
        });
    }

    const panel = document.getElementById(panelId);

    if (!panel) {
        return false;
    }

    panel.hidden = false;

    const targetId = options.targetId || "";
    const target = targetId ? document.getElementById(targetId) : null;

    if (options.updateHash !== false) {
        appShellUpdateHash(targetId || panelId);
    }

    if (options.scroll === false) {
        return false;
    }

    window.requestAnimationFrame(() => {
        (target || panel).scrollIntoView({
            behavior: options.behavior || "smooth",
            block: "start",
        });

        const firstControl = (target && typeof target.focus === "function" ? target : null)
            || panel.querySelector("button, input, select, textarea, a[href]");
        if (firstControl && typeof firstControl.focus === "function") {
            firstControl.focus({ preventScroll: true });
        }
    });

    return false;
}

async function openHashTargetWorkspace(hash = window.location.hash, options = {}) {
    const targetId = targetIdFromHash(hash);

    if (!targetId) {
        return false;
    }

    const pageId = appPageFromTargetId(targetId);
    if (pageId) {
        if (pageId === "pantryPage" && targetId !== "pantryPage") {
            await openAiPantryPanel({
                targetId,
                updateHash: false,
                scroll: options.scroll !== false,
            });
        } else {
            await openAppPage(pageId, {
                targetId: targetId === pageId ? "" : targetId,
                updateHash: false,
                scroll: options.scroll !== false,
            });
        }
        return true;
    }

    const accountPanelKey = USER_ACCOUNT_PANEL_HASH_KEYS[`#${targetId}`] || "";
    if (targetId === "userAccountSection" || (accountPanelKey && accountPanelKey !== "feedbackSupport")) {
        openUserAccountWorkspace({
            targetId,
            updateHash: false,
            scroll: options.scroll !== false,
        });
        return true;
    }

    const settingsSection = settingsSectionFromTargetId(targetId);
    if (settingsSection) {
        await openSettingsSection(settingsSection, {
            targetId,
            updateHash: false,
            scroll: options.scroll !== false,
        });
        return true;
    }

    const workspacePanelId = WORKSPACE_PANEL_TARGETS[targetId] || "";
    if (workspacePanelId) {
        openWorkspacePanel(workspacePanelId, {
            targetId,
            updateHash: false,
            scroll: options.scroll !== false,
        });
        return true;
    }

    return false;
}

function initSettingsWorkspace(options = {}) {
    openHashTargetWorkspace(window.location.hash, {
        scroll: options.scroll !== false,
    });
}

function initAppShellInitialWorkspace() {
    if (targetIdFromHash(window.location.hash)) {
        return;
    }

    if (document.body.classList.contains("account-action-token")) {
        openUserAccountWorkspace({
            updateHash: false,
            scroll: false,
        });
        return;
    }

    openHomeWorkspace({
        updateHash: false,
        scroll: false,
    });
}

function consumePostAuthenticationHomeReset() {
    if (safeStorageGet(sessionStorage, POST_AUTH_HOME_RESET_KEY) !== "1") {
        return false;
    }

    safeStorageRemove(sessionStorage, POST_AUTH_HOME_RESET_KEY);
    if ("scrollRestoration" in window.history) {
        window.history.scrollRestoration = "manual";
    }
    window.history.replaceState({}, document.title, window.location.pathname || "/");
    openHomeWorkspace({ updateHash: false, scroll: false });

    const homeLink = appShellPrimaryNavigationLinks()
        .find(link => String(link.dataset.appNavAction || "") === "home");
    appShellSetActiveLink(homeLink || null);

    window.requestAnimationFrame(() => {
        window.scrollTo({ top: 0, left: 0, behavior: "auto" });
        const mainContent = appMainScrollRegion();
        if (mainContent && typeof mainContent.scrollTo === "function") {
            mainContent.scrollTo({ top: 0, left: 0, behavior: "auto" });
        }
    });

    return true;
}

async function activateAppShellNavLink(link, options = {}) {
    if (!link) {
        return false;
    }

    const action = String(link.dataset.appNavAction || "");
    const targetId = appShellNavTargetId(link);
    const lazySection = String(link.dataset.appNavLazySection || "");
    const href = String(link.getAttribute("href") || "");

    appShellSetActiveLink(link);
    appShellSetSearchStatus("");

    if (action === "home") {
        return openHomeWorkspace();
    }

    if (action === "app-page") {
        const pageId = String(link.dataset.appPageTarget || "")
            || appPageFromTargetId(targetId)
            || "";
        if (pageId) {
            appShellUpdateHash(targetId || pageId);
            await openAppPage(pageId, {
                targetId,
                lazySection,
                updateHash: false,
            });
            return false;
        }
    }

    if (action === "ai-pantry") {
        appShellUpdateHash(targetId || "aiPantrySection");
        if (typeof openAiPantryPanel === "function") {
            return openAiPantryPanel({
                targetId: targetId || "aiPantrySection",
                pageId: String(link.dataset.appPageTarget || "") || "pantryPage",
            });
        }
        return false;
    }

    if (action === "usage-dashboard" && typeof toggleUsageDashboardPanel === "function") {
        appShellUpdateHash(targetId || "accountUsageDashboardPanel");
        openUserAccountWorkspace({
            targetId: "userAccountSection",
            updateHash: false,
            scroll: false,
        });
        return toggleUsageDashboardPanel(true);
    }

    if (action === "account-workspace") {
        appShellUpdateHash(targetId || "userAccountSection");
        return openUserAccountWorkspace({
            targetId: targetId || "userAccountSection",
            updateHash: false,
        });
    }

    if (action === "settings-section") {
        const sectionKey = String(link.dataset.settingsSectionTarget || "")
            || settingsSectionFromTargetId(targetId)
            || "profile";
        appShellUpdateHash(targetId || "settingsWorkspaceSection");
        await openSettingsSection(sectionKey, {
            targetId: targetId || "settingsWorkspaceSection",
            updateHash: false,
        });
        return false;
    }

    if (action === "workspace-panel") {
        const panelId = String(link.dataset.workspacePanelTarget || "")
            || WORKSPACE_PANEL_TARGETS[targetId]
            || "";
        if (panelId) {
            appShellUpdateHash(targetId || panelId);
            return openWorkspacePanel(panelId, {
                targetId,
                updateHash: false,
            });
        }
    }

    if (action === "feedback-support" && typeof openFeedbackSupportSection === "function") {
        appShellUpdateHash(targetId || "feedbackSupportSection");
        return openFeedbackSupportSection();
    }

    if (action === "account-settings" && typeof toggleUserProfileEditor === "function") {
        appShellUpdateHash(targetId || "userAccountSection");
        const opened = toggleUserProfileEditor(true);
        if (opened === false && targetId) {
            appShellScrollToTarget(targetId);
        }
        return false;
    }

    if (lazySection && typeof loadLazySection === "function") {
        const pageId = appPageFromTargetId(targetId);
        if (pageId) {
            appShellUpdateHash(targetId || pageId);
            await openAppPage(pageId, {
                targetId,
                lazySection,
                updateHash: false,
            });
            return false;
        }
        appShellUpdateHash(targetId);
        await loadLazySection(lazySection, {
            focus: true,
            targetId,
            userInitiated: true,
        });
        return false;
    }

    if (targetId) {
        const pageId = appPageFromTargetId(targetId);
        if (pageId) {
            appShellUpdateHash(targetId || pageId);
            await openAppPage(pageId, {
                targetId: targetId === pageId ? "" : targetId,
                updateHash: false,
            });
            return false;
        }
        appShellUpdateHash(targetId);
        scrollToLazySectionTarget(targetId, null, {
            focusTarget: options.focusTarget === true,
        }) || appShellScrollToTarget(targetId, {
            focusTarget: options.focusTarget === true,
        });
        return false;
    }

    if (href && !href.startsWith("#")) {
        window.location.assign(href);
    }

    return false;
}

function initAppShellNavigation() {
    if (document.documentElement.dataset.appShellNavigationBound === "1") {
        return;
    }

    document.documentElement.dataset.appShellNavigationBound = "1";

    const sidebarCollapseButton = document.querySelector("[data-app-sidebar-collapse]");
    if (sidebarCollapseButton) {
        const storedCollapsed = localStorage.getItem(APP_SIDEBAR_COLLAPSED_KEY) === "1";
        setAppSidebarCollapsed(storedCollapsed, { persist: false });
        sidebarCollapseButton.addEventListener("click", () => {
            setAppSidebarCollapsed(!document.body.classList.contains("app-sidebar-collapsed"));
        });
    }

    document.addEventListener("click", event => {
        if (!event.target || !event.target.closest || !event.target.closest(".app-home-recipe-actions")) {
            closeHomeRecipeMenus();
        }

        const mobileNavigationToggle = event.target && event.target.closest
            ? event.target.closest("[data-app-mobile-nav-toggle]")
            : null;
        if (mobileNavigationToggle) {
            setAppMobileNavigationOpen(true);
            return;
        }

        const mobileNavigationClose = event.target && event.target.closest
            ? event.target.closest("[data-app-mobile-nav-close], [data-app-mobile-nav-backdrop]")
            : null;
        if (mobileNavigationClose) {
            setAppMobileNavigationOpen(false, { restoreFocus: true });
            return;
        }

        const mobileDrawerSelection = event.target && event.target.closest
            ? event.target.closest("[data-app-mobile-nav-drawer] a, [data-app-mobile-drawer-close]")
            : null;
        if (mobileDrawerSelection) {
            setAppMobileNavigationOpen(false);
        }

        const link = event.target && event.target.closest
            ? event.target.closest("[data-app-nav-link], [data-app-plan-link]")
            : null;

        if (!link) {
            return;
        }

        if (!link.dataset.appNavAction && !link.dataset.appNavTarget && !link.dataset.appNavLazySection) {
            return;
        }

        event.preventDefault();
        activateAppShellNavLink(link);
    });

    window.addEventListener("hashchange", () => {
        openHashTargetWorkspace(window.location.hash, { scroll: true });
    });

    document.addEventListener("keydown", event => {
        if (event && event.key === "Escape") {
            const mobileDrawer = document.querySelector("[data-app-mobile-nav-drawer]");
            if (mobileDrawer && !mobileDrawer.hidden) {
                setAppMobileNavigationOpen(false, { restoreFocus: true });
                return;
            }
            closeHomeRecipeMenus({ restoreFocus: true });
            return;
        }

        if (!event || event.defaultPrevented || event.altKey || event.shiftKey) {
            return;
        }

        const isSearchShortcut = (event.ctrlKey || event.metaKey)
            && String(event.key || "").toLowerCase() === "k";

        if (!isSearchShortcut) {
            return;
        }

        const input = document.querySelector("[data-app-global-search]");
        if (!input || typeof input.focus !== "function") {
            return;
        }

        event.preventDefault();
        input.focus();
        if (typeof input.select === "function") {
            input.select();
        }
    });
}

function homeRecipeMenuButtons() {
    return [...document.querySelectorAll(".app-home-recipe-menu-toggle")];
}

function closeHomeRecipeMenus(options = {}) {
    let focusTarget = null;
    homeRecipeMenuButtons().forEach(button => {
        const menu = button.parentElement
            ? button.parentElement.querySelector(".app-home-recipe-menu")
            : null;
        if (menu && !menu.hidden) {
            focusTarget = focusTarget || button;
            menu.hidden = true;
        }
        button.setAttribute("aria-expanded", "false");
    });
    if (options.restoreFocus && focusTarget) {
        focusTarget.focus();
    }
    return false;
}

function toggleHomeRecipeMenu(button, event = null) {
    if (event) {
        event.preventDefault();
        event.stopPropagation();
    }
    const menu = button && button.parentElement
        ? button.parentElement.querySelector(".app-home-recipe-menu")
        : null;
    if (!menu) {
        return false;
    }
    const willOpen = menu.hidden;
    closeHomeRecipeMenus();
    menu.hidden = !willOpen;
    button.setAttribute("aria-expanded", willOpen ? "true" : "false");
    if (willOpen) {
        const firstItem = menu.querySelector('[role="menuitem"]');
        if (firstItem) {
            firstItem.focus();
        }
    }
    return false;
}

function openHomeRecipeAction(button, action, event = null) {
    if (event) {
        event.preventDefault();
        event.stopPropagation();
    }
    closeHomeRecipeMenus();
    if (action === "edit") {
        const recipeUrl = button ? button.dataset.recipeUrl || "" : "";
        return openRecipeEditPageFallback(button, recipeUrl);
    }
    return jumpToRecipeViewRecipe(button, event);
}

function openHomeRecipeCardEditor(card, event = null) {
    if (!card || eventStartedInNestedInteractive(event, card)) {
        return true;
    }

    if (event) {
        event.preventDefault();
        event.stopPropagation();
    }

    const recipeUrl = card.dataset.recipeUrl || "";
    return openRecipeEditPageFallback(card, recipeUrl);
}

function setRecipeFavoriteButtonState(button, favorite) {
    if (!button) {
        return;
    }

    const isFavorite = Boolean(favorite);
    const recipeName = button.dataset.recipeName || "recipe";
    button.setAttribute("aria-pressed", isFavorite ? "true" : "false");
    button.setAttribute(
        "aria-label",
        `${isFavorite ? "Remove" : "Add"} ${recipeName} ${isFavorite ? "from" : "to"} favorites`
    );
    button.title = button.getAttribute("aria-label");
}

function setRecipeFavoriteStateForUrl(recipeUrl, favorite) {
    if (!recipeUrl) {
        return;
    }

    document
        .querySelectorAll(`[data-recipe-favorite][data-recipe-url="${cssEscape(recipeUrl)}"]`)
        .forEach(button => setRecipeFavoriteButtonState(button, favorite));
}

function recipeFavoriteSyncUrls(value) {
    const urls = Array.isArray(value) ? value : [value];
    return [...new Set(urls.map(url => String(url || "").trim()).filter(Boolean))];
}

function recipeFavoriteSyncScope() {
    return String(document.body?.dataset.userId || "guest").trim() || "guest";
}

function applyRecipeFavoriteSyncPayload(payload = {}) {
    if (!payload || typeof payload !== "object" || typeof payload.favorite !== "boolean") {
        return false;
    }
    if (payload.scope && payload.scope !== recipeFavoriteSyncScope()) {
        return false;
    }

    const urls = recipeFavoriteSyncUrls(payload.urls || payload.url);
    if (!urls.length) {
        return false;
    }

    urls.forEach(url => setRecipeFavoriteStateForUrl(url, payload.favorite));
    rememberRecipeFavoriteState(urls, payload.favorite);
    const updatedAt = Number(payload.updatedAt) || Date.now();
    urls.forEach(url => recipeFavoriteLastChangedAt.set(url, updatedAt));
    return true;
}

function publishRecipeFavoriteState(recipeUrls, favorite) {
    const urls = recipeFavoriteSyncUrls(recipeUrls);
    if (!urls.length) {
        return;
    }

    const payload = {
        urls,
        favorite: Boolean(favorite),
        scope: recipeFavoriteSyncScope(),
        updatedAt: Date.now(),
    };
    if (recipeFavoriteSyncChannel) {
        try {
            recipeFavoriteSyncChannel.postMessage(payload);
        } catch (error) {
            console.debug("Recipe favorite broadcast sync is unavailable.", error);
        }
    }
    try {
        localStorage.setItem(RECIPE_FAVORITE_SYNC_STORAGE_KEY, JSON.stringify(payload));
        localStorage.removeItem(RECIPE_FAVORITE_SYNC_STORAGE_KEY);
    } catch (error) {
        console.debug("Recipe favorite cross-page storage sync is unavailable.", error);
    }
}

function recipeFavoriteControlUrls() {
    return recipeFavoriteSyncUrls(
        [...document.querySelectorAll("[data-recipe-favorite][data-recipe-url]")]
            .map(button => button.dataset.recipeUrl)
    );
}

async function syncRecipeFavoriteStateFromServer(recipeUrl, options = {}) {
    const url = String(recipeUrl || "").trim();
    if (!url) {
        return false;
    }

    const now = Date.now();
    const requestedAt = now;
    const lastSyncedAt = recipeFavoriteLastSyncedAt.get(url) || 0;
    if (options.force !== true && now - lastSyncedAt < RECIPE_FAVORITE_SYNC_MIN_INTERVAL_MS) {
        return true;
    }
    if (recipeFavoriteSyncRequests.has(url)) {
        return recipeFavoriteSyncRequests.get(url);
    }

    const request = fetch(`/api/recipe_favorite?url=${encodeURIComponent(url)}`, {
        method: "GET",
        headers: { "X-Requested-With": "fetch" },
        cache: "no-store",
    }).then(async response => {
        const data = await response.json();
        if (!response.ok || !data.ok) {
            throw new Error((data && data.error) || "Unable to refresh favorite state.");
        }

        const savedUrl = String(data.url || url).trim();
        const urls = recipeFavoriteSyncUrls([url, savedUrl]);
        if (urls.some(candidate => (recipeFavoriteLastChangedAt.get(candidate) || 0) > requestedAt)) {
            return true;
        }
        applyRecipeFavoriteSyncPayload({
            urls,
            favorite: Boolean(data.favorite),
            scope: recipeFavoriteSyncScope(),
            updatedAt: Date.now(),
        });
        const syncedAt = Date.now();
        urls.forEach(candidate => recipeFavoriteLastSyncedAt.set(candidate, syncedAt));
        return true;
    }).catch(error => {
        console.debug("Unable to refresh recipe favorite state.", error);
        return false;
    }).finally(() => {
        recipeFavoriteSyncRequests.delete(url);
    });

    recipeFavoriteSyncRequests.set(url, request);
    return request;
}

function refreshRecipeFavoriteControls(options = {}) {
    return Promise.all(
        recipeFavoriteControlUrls().map(url => syncRecipeFavoriteStateFromServer(url, options))
    );
}

function initRecipeFavoriteSync() {
    if (!document.documentElement || document.documentElement.dataset.recipeFavoriteSyncBound === "1") {
        return;
    }
    document.documentElement.dataset.recipeFavoriteSyncBound = "1";

    if (typeof BroadcastChannel === "function") {
        try {
            recipeFavoriteSyncChannel = new BroadcastChannel(RECIPE_FAVORITE_SYNC_CHANNEL_NAME);
            recipeFavoriteSyncChannel.addEventListener("message", event => {
                applyRecipeFavoriteSyncPayload(event.data);
            });
        } catch (error) {
            recipeFavoriteSyncChannel = null;
            console.debug("Recipe favorite broadcast sync is unavailable.", error);
        }
    }
    window.addEventListener("storage", event => {
        if (event.key !== RECIPE_FAVORITE_SYNC_STORAGE_KEY || !event.newValue) {
            return;
        }
        try {
            applyRecipeFavoriteSyncPayload(JSON.parse(event.newValue));
        } catch (error) {
            console.debug("Unable to read synchronized recipe favorite state.", error);
        }
    });
    window.addEventListener("pageshow", () => {
        void refreshRecipeFavoriteControls({ force: true });
    });
    window.addEventListener("focus", () => {
        void refreshRecipeFavoriteControls();
    });
    document.addEventListener("visibilitychange", () => {
        if (document.visibilityState === "visible") {
            void refreshRecipeFavoriteControls();
        }
    });
}

function syncRecipeEditorFavoriteControl(recipe = {}, originalUrl = "") {
    const buttons = [...document.querySelectorAll("[data-recipe-edit-favorite]")];
    if (!buttons.length) return;
    const recipeUrl = String(
        originalUrl
        || recipe.url
        || recipe.original_url
        || recipe.source_url
        || ""
    ).trim();
    const recipeName = String(
        recipe.recipe_title
        || recipe.display_name
        || "recipe"
    ).trim() || "recipe";
    const hasFavoriteState = Object.prototype.hasOwnProperty.call(recipe, "favorite");
    buttons.forEach(button => {
        const previousUrl = String(button.dataset.recipeUrl || "").trim();
        const favorite = hasFavoriteState
            ? Boolean(recipe.favorite)
            : (previousUrl === recipeUrl && button.getAttribute("aria-pressed") === "true");
        button.dataset.recipeUrl = recipeUrl;
        button.dataset.recipeName = recipeName;
        button.hidden = !recipeUrl;
        setRecipeFavoriteButtonState(button, favorite);
    });
}

async function toggleRecipeFavorite(button, event = null) {
    if (event) {
        event.preventDefault();
        event.stopPropagation();
    }

    const recipeUrl = button ? button.dataset.recipeUrl || "" : "";
    if (!recipeUrl || !button) {
        return false;
    }

    const wasFavorite = button.getAttribute("aria-pressed") === "true";
    const nextFavorite = !wasFavorite;
    applyRecipeFavoriteSyncPayload({
        urls: [recipeUrl],
        favorite: nextFavorite,
        scope: recipeFavoriteSyncScope(),
        updatedAt: Date.now(),
    });
    button.disabled = true;

    try {
        const response = await fetch("/api/recipe_favorite", {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
                "X-Requested-With": "fetch",
            },
            body: JSON.stringify({
                url: recipeUrl,
                favorite: nextFavorite,
            }),
        });
        const data = await response.json();

        if (!response.ok || !data.ok) {
            throw new Error((data && data.error) || "Unable to update favorite.");
        }

        const savedFavorite = Boolean(data.favorite);
        const savedRecipeUrl = String(data.url || recipeUrl).trim();
        applyRecipeFavoriteSyncPayload({
            urls: [recipeUrl, savedRecipeUrl],
            favorite: savedFavorite,
            scope: recipeFavoriteSyncScope(),
            updatedAt: Date.now(),
        });
        publishRecipeFavoriteState([recipeUrl, savedRecipeUrl], savedFavorite);
    } catch (err) {
        console.warn("Unable to update recipe favorite.", err);
        applyRecipeFavoriteSyncPayload({
            urls: [recipeUrl],
            favorite: wasFavorite,
            scope: recipeFavoriteSyncScope(),
            updatedAt: Date.now(),
        });
        window.alert(err.message || "Unable to update favorite.");
    } finally {
        document
            .querySelectorAll(`[data-recipe-favorite][data-recipe-url="${cssEscape(recipeUrl)}"]`)
            .forEach(favoriteButton => {
                favoriteButton.disabled = false;
            });
    }

    return false;
}

function openHomeRecentImport(jobId = "") {
    const normalizedJobId = String(jobId || "").trim();
    if (normalizedJobId) {
        jobActivityExpandedRows.add(normalizedJobId);
    }
    openUserAccountWorkspace({
        targetId: "jobActivitySection",
        updateHash: true,
        scroll: false,
    });
    return openJobActivityPanel();
}

function setAppSidebarCollapsed(collapsed, options = {}) {
    const isCollapsed = Boolean(collapsed);
    document.body.classList.toggle("app-sidebar-collapsed", isCollapsed);
    const button = document.querySelector("[data-app-sidebar-collapse]");
    if (button) {
        button.setAttribute("aria-pressed", isCollapsed ? "true" : "false");
        button.setAttribute("aria-label", isCollapsed ? "Expand sidebar" : "Collapse sidebar");
        button.setAttribute("title", isCollapsed ? "Expand sidebar" : "Collapse sidebar");
        const glyph = button.querySelector("span");
        if (glyph) {
            glyph.textContent = isCollapsed ? ">" : "<";
        }
    }
    if (options.persist !== false) {
        localStorage.setItem(APP_SIDEBAR_COLLAPSED_KEY, isCollapsed ? "1" : "0");
    }
    return false;
}

function setAppMobileNavigationOpen(open, options = {}) {
    const shouldOpen = Boolean(open);
    const drawer = document.querySelector("[data-app-mobile-nav-drawer]");
    const backdrop = document.querySelector("[data-app-mobile-nav-backdrop]");
    const toggle = document.querySelector("[data-app-mobile-nav-toggle]");

    if (!drawer || !backdrop || !toggle) {
        return false;
    }

    drawer.hidden = !shouldOpen;
    backdrop.hidden = !shouldOpen;
    drawer.setAttribute("aria-hidden", shouldOpen ? "false" : "true");
    toggle.setAttribute("aria-expanded", shouldOpen ? "true" : "false");
    document.body.classList.toggle("app-mobile-navigation-open", shouldOpen);

    if (shouldOpen) {
        const firstLink = drawer.querySelector(".app-nav-link");
        if (firstLink && typeof firstLink.focus === "function") {
            firstLink.focus();
        }
    } else if (options.restoreFocus === true && typeof toggle.focus === "function") {
        toggle.focus();
    }

    return false;
}

function openMealPlannerPageAndDialog() {
    openAppPage("mealPlannerPage", { targetId: "mealPlannerPage" }).then(() => {
        openMealPlannerDialog();
    });
    return false;
}

function openHomeMealPlanSlot(slot, event = null) {
    if (eventStartedInNestedInteractive(event, slot)) {
        return true;
    }
    if (event) {
        event.preventDefault();
    }
    openAppPage("mealPlannerPage", { targetId: "mealPlannerPage" });
    return false;
}

function handleHomeMealPlanSlotKeydown(slot, event) {
    if (!event || !["Enter", " "].includes(event.key)) {
        return true;
    }
    if (eventStartedInNestedInteractive(event, slot)) {
        return true;
    }
    event.preventDefault();
    return openHomeMealPlanSlot(slot);
}

function handleHomeMealThumbnailKeydown(link, event) {
    if (!link || !event || event.key !== " ") {
        return true;
    }
    event.preventDefault();
    event.stopPropagation();
    link.click();
    return false;
}

function setMealPlannerStatus(message, isError = false, selector = "[data-meal-plan-status]") {
    const status = document.querySelector(selector);
    if (!status) {
        return;
    }
    status.textContent = message || "";
    status.classList.toggle("error", Boolean(isError));
}

function formatMealPlannerServingNumber(value) {
    const numeric = Number(value);
    if (!Number.isFinite(numeric)) {
        return "1";
    }
    if (Number.isInteger(numeric)) {
        return String(numeric);
    }
    return String(Number(numeric.toFixed(4)));
}

function updateMealPlannerServingControls() {
    const input = document.getElementById("mealPlannerPlannedServings");
    const decrease = document.querySelector("[data-meal-servings-decrease]");
    if (!input) {
        return false;
    }
    const minimum = Number.parseFloat(input.min || "1") || 1;
    const current = Number.parseFloat(input.value);
    if (decrease) {
        decrease.disabled = !Number.isFinite(current) || current <= minimum;
    }
    return false;
}

function syncMealPlannerServingsFromRecipe() {
    const recipeInput = document.getElementById("mealPlannerRecipe");
    const servingsInput = document.getElementById("mealPlannerPlannedServings");
    const helper = document.querySelector("[data-meal-servings-help]");
    if (!recipeInput || !servingsInput) {
        return false;
    }

    const option = recipeInput.selectedOptions && recipeInput.selectedOptions[0];
    const selectedRecipe = String(option?.value || "").trim();
    const parsedDefault = Number.parseFloat(option?.dataset.defaultServings || "1");
    const defaultServings = Number.isFinite(parsedDefault) && parsedDefault >= 1 ? parsedDefault : 1;
    const yieldLabel = String(option?.dataset.yieldLabel || "").trim().replace(/[.]+$/, "");

    servingsInput.value = formatMealPlannerServingNumber(defaultServings);
    servingsInput.dataset.defaultServings = servingsInput.value;
    if (helper) {
        helper.textContent = selectedRecipe
            ? (yieldLabel
                ? `Recipe yields ${yieldLabel}.`
                : "Recipe yield is unavailable. Planned servings default to 1.")
            : "Select a recipe to use its default yield.";
    }
    updateMealPlannerServingControls();
    return false;
}

function adjustMealPlannerServings(delta) {
    const input = document.getElementById("mealPlannerPlannedServings");
    if (!input) {
        return false;
    }

    const minimum = Number.parseFloat(input.min || "1") || 1;
    const step = Number.parseFloat(input.dataset.step || "0.5") || 0.5;
    const current = Number.parseFloat(input.value);
    const fallback = Number.parseFloat(input.dataset.defaultServings || String(minimum));
    const base = Number.isFinite(current) ? current : (Number.isFinite(fallback) ? fallback : minimum);
    const direction = Number(delta) < 0 ? -1 : 1;
    const next = Math.max(minimum, base + (direction * step));

    input.value = formatMealPlannerServingNumber(next);
    input.dispatchEvent(new Event("input", { bubbles: true }));
    input.dispatchEvent(new Event("change", { bubbles: true }));
    updateMealPlannerServingControls();
    return false;
}

function openMealPlannerDialog(dateValue = "", mealType = "") {
    const dialog = document.getElementById("mealPlannerDialog");
    if (!dialog || typeof dialog.showModal !== "function") {
        return false;
    }
    const dateInput = dialog.querySelector('[name="date"]');
    const typeInput = dialog.querySelector('[name="meal_type"]');
    if (dateInput && dateValue) {
        dateInput.value = dateValue;
    }
    if (typeInput && mealType) {
        typeInput.value = mealType;
    }
    setMealPlannerStatus("");
    syncMealPlannerServingsFromRecipe();
    dialog.showModal();
    const recipeInput = dialog.querySelector('[name="recipe_url"]');
    (recipeInput || dateInput)?.focus();
    return false;
}

function closeMealPlannerDialog() {
    const dialog = document.getElementById("mealPlannerDialog");
    if (dialog && dialog.open) {
        dialog.close();
    }
    return false;
}

async function submitMealPlannerForm(event) {
    event.preventDefault();
    const form = event.currentTarget;
    const submitButton = form.querySelector("[data-meal-plan-submit]");
    const formData = new FormData(form);
    const servingsInput = form.querySelector('[name="planned_servings"]');
    const plannedServings = Number.parseFloat(formData.get("planned_servings"));
    if (!Number.isFinite(plannedServings) || plannedServings < 1) {
        setMealPlannerStatus("Planned servings must be a number of 1 or more.", true);
        servingsInput?.focus();
        return false;
    }
    const originalLabel = submitButton ? submitButton.textContent : "Add Meal";
    if (submitButton) {
        submitButton.disabled = true;
        submitButton.textContent = "Adding...";
    }
    setMealPlannerStatus("Adding meal...");
    try {
        const response = await fetch("/api/meal-plan", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                date: formData.get("date"),
                meal_type: formData.get("meal_type"),
                recipe_url: formData.get("recipe_url"),
                planned_servings: plannedServings,
            }),
        });
        const payload = await response.json().catch(() => ({}));
        if (!response.ok || !payload.ok) {
            throw new Error(payload.error || "The meal could not be added.");
        }
        setMealPlannerStatus("Meal added.");
        const weekValue = formData.get("date");
        window.location.assign(`/?meal_week=${encodeURIComponent(weekValue)}#mealPlannerPage`);
    } catch (error) {
        setMealPlannerStatus(error.message || "The meal could not be added.", true);
        if (submitButton) {
            submitButton.disabled = false;
            submitButton.textContent = originalLabel;
        }
    }
    return false;
}

function openMealPlannerDeleteDialog(button) {
    const dialog = document.getElementById("mealPlannerDeleteDialog");
    if (!dialog || typeof dialog.showModal !== "function") {
        return false;
    }
    const mealId = String(button?.dataset.mealId || "");
    const mealName = String(button?.dataset.mealName || "this meal");
    const idInput = dialog.querySelector("[data-meal-delete-id]");
    const copy = dialog.querySelector("[data-meal-delete-copy]");
    if (idInput) {
        idInput.value = mealId;
    }
    if (copy) {
        copy.textContent = `Remove ${mealName} from this week? The recipe itself will not be deleted, and you can add the meal again later.`;
    }
    setMealPlannerStatus("", false, "[data-meal-delete-status]");
    dialog.showModal();
    dialog.querySelector("[data-meal-delete-submit]")?.focus();
    return false;
}

function closeMealPlannerDeleteDialog() {
    const dialog = document.getElementById("mealPlannerDeleteDialog");
    if (dialog && dialog.open) {
        dialog.close();
    }
    return false;
}

async function confirmMealPlannerDelete(event) {
    event.preventDefault();
    const form = event.currentTarget;
    const mealId = String(form.querySelector("[data-meal-delete-id]")?.value || "");
    const submitButton = form.querySelector("[data-meal-delete-submit]");
    const originalLabel = submitButton ? submitButton.textContent : "Remove Meal";
    if (!mealId) {
        setMealPlannerStatus("The planned meal could not be identified.", true, "[data-meal-delete-status]");
        return false;
    }
    if (submitButton) {
        submitButton.disabled = true;
        submitButton.textContent = "Removing...";
    }
    try {
        const response = await fetch(`/api/meal-plan/${encodeURIComponent(mealId)}`, { method: "DELETE" });
        const payload = await response.json().catch(() => ({}));
        if (!response.ok || !payload.ok) {
            throw new Error(payload.error || "The meal could not be removed.");
        }
        window.location.reload();
    } catch (error) {
        setMealPlannerStatus(error.message || "The meal could not be removed.", true, "[data-meal-delete-status]");
        if (submitButton) {
            submitButton.disabled = false;
            submitButton.textContent = originalLabel;
        }
    }
    return false;
}

const GLOBAL_APP_SEARCH_DEBOUNCE_MS = 250;
const GLOBAL_APP_SEARCH_MIN_QUERY_LENGTH = 2;
const GLOBAL_APP_SEARCH_RESULT_LIMIT = 8;
const GLOBAL_APP_SEARCH_OPTION_LIMIT = 12;
const GLOBAL_APP_SEARCH_RECENT_LIMIT = 4;
const GLOBAL_APP_SEARCH_QUICK_ACTION_LIMIT = 3;
const GLOBAL_APP_SEARCH_PAGE_LIMIT = 3;
const GLOBAL_APP_SEARCH_TYPED_PAGE_LIMIT = 2;

function globalAppSearchInput(form) {
    return form ? form.querySelector("[data-app-global-search]") : null;
}

function globalAppSearchDropdown(form) {
    return form ? form.querySelector("[data-global-search-dropdown]") : null;
}

function globalAppSearchContent(form) {
    return form ? form.querySelector("[data-global-search-content]") : null;
}

function globalAppSearchVisibleStatus(form) {
    return form ? form.querySelector("[data-global-search-visible-status]") : null;
}

function globalAppSearchQuery(form) {
    const input = globalAppSearchInput(form);
    return input ? String(input.value || "").trim() : "";
}

function globalAppSearchOpenDropdown(form) {
    const input = globalAppSearchInput(form);
    const dropdown = globalAppSearchDropdown(form);
    if (!input || !dropdown) {
        return;
    }
    dropdown.hidden = false;
    input.setAttribute("aria-expanded", "true");
}

function globalAppSearchCloseDropdown(form) {
    const input = globalAppSearchInput(form);
    const dropdown = globalAppSearchDropdown(form);
    if (!input || !dropdown) {
        return;
    }
    dropdown.hidden = true;
    input.setAttribute("aria-expanded", "false");
    input.removeAttribute("aria-activedescendant");
    form._globalSearchActiveIndex = -1;
}

function globalAppSearchIcon(form, iconName) {
    const icon = document.createElement("span");
    icon.className = "app-global-search-result-icon";
    icon.setAttribute("aria-hidden", "true");
    const template = form.querySelector(`[data-global-search-icon-template="${String(iconName || "pages")}"]`)
        || form.querySelector('[data-global-search-icon-template="pages"]');
    if (template && template.content) {
        icon.append(template.content.cloneNode(true));
    }
    return icon;
}

function globalAppSearchHighlightedTitle(title, query) {
    const fragment = document.createDocumentFragment();
    const value = String(title || "");
    const normalizedQuery = String(query || "").trim().toLocaleLowerCase();
    const matchIndex = normalizedQuery ? value.toLocaleLowerCase().indexOf(normalizedQuery) : -1;
    if (matchIndex < 0) {
        fragment.append(document.createTextNode(value));
        return fragment;
    }
    fragment.append(document.createTextNode(value.slice(0, matchIndex)));
    const mark = document.createElement("mark");
    mark.textContent = value.slice(matchIndex, matchIndex + normalizedQuery.length);
    fragment.append(mark, document.createTextNode(value.slice(matchIndex + normalizedQuery.length)));
    return fragment;
}

function globalAppSearchOptionUrl(form, result) {
    if (result.url) {
        return result.url;
    }
    const target = String(result.target || "");
    return `${window.location.origin}/${target ? `#${target}` : ""}`;
}

function globalAppSearchCreateOption(form, result, query, index) {
    const option = document.createElement("a");
    const input = globalAppSearchInput(form);
    option.id = `${input ? input.id : "globalSearch"}Option${index}`;
    option.className = "app-global-search-result";
    option.href = globalAppSearchOptionUrl(form, result);
    option.setAttribute("role", "option");
    option.setAttribute("aria-selected", "false");
    option.tabIndex = -1;
    option.dataset.globalSearchResult = String(index);
    if (result.target) {
        option.dataset.globalSearchPageTarget = result.target;
    }
    if (result.isViewAll) {
        option.classList.add("app-global-search-view-all");
    }

    if (result.thumbnail_url) {
        const thumbnail = document.createElement("img");
        thumbnail.className = "app-global-search-result-thumbnail";
        thumbnail.src = result.thumbnail_url;
        thumbnail.alt = "";
        thumbnail.loading = "lazy";
        thumbnail.decoding = "async";
        thumbnail.addEventListener("error", () => {
            thumbnail.replaceWith(globalAppSearchIcon(form, result.icon));
        }, { once: true });
        option.append(thumbnail);
    } else {
        option.append(globalAppSearchIcon(form, result.icon));
    }

    const copy = document.createElement("span");
    copy.className = "app-global-search-result-copy";
    const title = document.createElement("strong");
    title.append(globalAppSearchHighlightedTitle(result.title, query));
    const context = document.createElement("span");
    context.className = "app-global-search-result-context";
    const resultType = document.createElement("span");
    resultType.className = "app-global-search-result-type";
    resultType.textContent = result.type || "Result";
    context.append(resultType);
    if (result.secondary) {
        context.append(document.createTextNode(" • "));
        context.append(globalAppSearchHighlightedTitle(result.secondary, query));
    }
    copy.append(title, context);
    option.append(copy);
    return option;
}

function globalAppSearchSetActiveIndex(form, nextIndex) {
    const input = globalAppSearchInput(form);
    const options = [...form.querySelectorAll("[data-global-search-result]")];
    if (!input || !options.length) {
        return;
    }
    const normalizedIndex = ((nextIndex % options.length) + options.length) % options.length;
    options.forEach((option, index) => {
        const active = index === normalizedIndex;
        option.classList.toggle("is-active", active);
        option.setAttribute("aria-selected", active ? "true" : "false");
    });
    form._globalSearchActiveIndex = normalizedIndex;
    input.setAttribute("aria-activedescendant", options[normalizedIndex].id);
    options[normalizedIndex].scrollIntoView({ block: "nearest" });
}

function globalAppSearchMessage(form, message, state = "empty") {
    const content = globalAppSearchContent(form);
    const visibleStatus = globalAppSearchVisibleStatus(form);
    const input = globalAppSearchInput(form);
    if (!content || !visibleStatus) {
        return;
    }
    content.replaceChildren();
    content.hidden = true;
    visibleStatus.replaceChildren();
    visibleStatus.className = `app-global-search-state is-${state}`;
    const lines = Array.isArray(message) ? message : [message];
    lines.filter(Boolean).forEach(line => {
        const text = document.createElement("span");
        text.textContent = line;
        visibleStatus.append(text);
    });
    visibleStatus.hidden = false;
    form._globalSearchResults = [];
    form._globalSearchActiveIndex = -1;
    input?.removeAttribute("aria-activedescendant");
    globalAppSearchOpenDropdown(form);
    appShellSetSearchStatus(lines.filter(Boolean).join(" "));
}

function globalAppSearchShortcutResults(selector, group, query = "", limit = 3) {
    const normalizedQuery = normalizeAppShellSearchText(query);
    const seen = new Set();
    return [...document.querySelectorAll(selector)]
        .sort((left, right) => Number(left.dataset.globalSearchShortcutOrder || 0)
            - Number(right.dataset.globalSearchShortcutOrder || 0))
        .map(link => {
        const title = String(link.dataset.globalSearchTitle || link.textContent || "").trim().replace(/\s+/g, " ");
        const iconElement = link.querySelector(".app-nav-icon");
        const iconClass = iconElement
            ? [...iconElement.classList].find(className => className.startsWith("app-nav-icon-") && className !== "app-nav-icon")
            : "";
        return {
            title,
            type: group === "pages" ? "Page" : "Quick action",
            secondary: String(link.dataset.globalSearchSecondary || `Open ${title}`),
            icon: iconClass ? iconClass.replace("app-nav-icon-", "") : "pages",
            target: appShellNavTargetId(link),
            url: link.getAttribute("href") || "/",
            sourceNavLink: link,
            group,
        };
    }).filter(shortcut => {
        if (!shortcut.title || seen.has(shortcut.title)) {
            return false;
        }
        seen.add(shortcut.title);
        if (!normalizedQuery) {
            return true;
        }
        const searchable = normalizeAppShellSearchText(`${shortcut.title} ${shortcut.secondary} ${shortcut.target}`);
        return searchable.includes(normalizedQuery) || normalizedQuery.includes(normalizeAppShellSearchText(shortcut.title));
    }).slice(0, limit);
}

function globalAppSearchPageResults(form, query = "", limit = GLOBAL_APP_SEARCH_PAGE_LIMIT) {
    return globalAppSearchShortcutResults(
        ".app-sidebar-nav .app-nav-link[data-global-search-page-shortcut]",
        "pages",
        query,
        limit,
    );
}

function globalAppSearchQuickActionResults(form) {
    return globalAppSearchShortcutResults(
        ".app-sidebar-nav .app-nav-link[data-global-search-quick-action]",
        "quick-actions",
        "",
        GLOBAL_APP_SEARCH_QUICK_ACTION_LIMIT,
    );
}

function globalAppSearchNormalizedGroups(payload) {
    if (!payload || !Array.isArray(payload.groups)) {
        return [];
    }
    return payload.groups.map(group => ({
        key: String(group.key || "results"),
        label: String(group.label || group.key || "RESULTS").toUpperCase(),
        results: Array.isArray(group.results) ? group.results : [],
    })).filter(group => group.results.length);
}

function globalAppSearchRenderGroups(form, groups, query, options = {}) {
    const content = globalAppSearchContent(form);
    const visibleStatus = globalAppSearchVisibleStatus(form);
    const input = globalAppSearchInput(form);
    if (!content || !visibleStatus) {
        return;
    }
    visibleStatus.hidden = true;
    visibleStatus.replaceChildren();
    content.hidden = false;
    content.replaceChildren();
    const renderedResults = [];
    const maxOptions = options.includeViewAll === false
        ? GLOBAL_APP_SEARCH_OPTION_LIMIT
        : GLOBAL_APP_SEARCH_OPTION_LIMIT - 1;

    groups.forEach(group => {
        if (!group.results || !group.results.length || renderedResults.length >= maxOptions) {
            return;
        }
        const section = document.createElement("section");
        section.className = "app-global-search-group";
        section.setAttribute("role", "group");
        const heading = document.createElement("h2");
        const groupToken = String(group.key || "results").replace(/[^a-z0-9_-]+/gi, "-");
        heading.id = `${globalAppSearchInput(form)?.id || "globalSearch"}-${groupToken}-${renderedResults.length}`;
        heading.textContent = group.label;
        section.setAttribute("aria-labelledby", heading.id);
        section.append(heading);
        const list = document.createElement("div");
        list.className = "app-global-search-group-results";
        list.setAttribute("role", "presentation");
        group.results.forEach(result => {
            if (renderedResults.length >= maxOptions) {
                return;
            }
            const normalizedResult = { ...result, group: result.group || group.key };
            list.append(globalAppSearchCreateOption(form, normalizedResult, query, renderedResults.length));
            renderedResults.push(normalizedResult);
        });
        section.append(list);
        content.append(section);
    });

    if (!renderedResults.length) {
        const empty = document.createElement("div");
        empty.className = "app-global-search-state is-empty";
        empty.setAttribute("role", "status");
        empty.textContent = options.emptyMessage || "No results found.";
        content.append(empty);
    }

    if (options.includeViewAll !== false && String(query || "").trim().length >= GLOBAL_APP_SEARCH_MIN_QUERY_LENGTH) {
        const resultsUrl = new URL(form.dataset.globalSearchResultsUrl || "/search", window.location.origin);
        resultsUrl.searchParams.set("q", String(query || "").trim());
        const viewAll = {
            title: `View all results for “${String(query || "").trim()}”`,
            type: "Search",
            secondary: options.totalCount ? `${options.totalCount} matching records` : "Open grouped search results",
            icon: "pages",
            url: `${resultsUrl.pathname}${resultsUrl.search}`,
            isViewAll: true,
        };
        content.append(globalAppSearchCreateOption(form, viewAll, "", renderedResults.length));
        renderedResults.push(viewAll);
    }

    form._globalSearchResults = renderedResults;
    form._globalSearchActiveIndex = -1;
    input?.removeAttribute("aria-activedescendant");
    globalAppSearchOpenDropdown(form);
    appShellSetSearchStatus(renderedResults.length
        ? `${renderedResults.length} global search options available.`
        : (options.emptyMessage || "No global search results found."));
}

function globalAppSearchRecentResults(payload) {
    return globalAppSearchNormalizedGroups(payload)
        .filter(group => group.key === "recent")
        .flatMap(group => group.results)
        .slice(0, GLOBAL_APP_SEARCH_RECENT_LIMIT)
        .map(result => ({
            ...result,
            group: "recent",
            isRecent: true,
            trackingGroup: result.tracking_group || "",
        }));
}

function globalAppSearchRenderEmpty(form) {
    const groups = [];
    const recent = Array.isArray(form._globalSearchRecentResults)
        ? form._globalSearchRecentResults.slice(0, GLOBAL_APP_SEARCH_RECENT_LIMIT)
        : [];
    if (recent.length) {
        groups.push({ key: "recent", label: "RECENT", results: recent });
    }
    const quickActions = globalAppSearchQuickActionResults(form);
    if (quickActions.length) {
        groups.push({ key: "quick-actions", label: "QUICK ACTIONS", results: quickActions });
    }
    const pages = globalAppSearchPageResults(form);
    if (pages.length) {
        groups.push({ key: "pages", label: "PAGES", results: pages });
    }
    globalAppSearchRenderGroups(form, groups, "", { includeViewAll: false });
}

async function globalAppSearchFetchRecent(form) {
    if (form._globalSearchRecentLoaded || form._globalSearchRecentRequest) {
        return;
    }
    const endpoint = new URL(form.dataset.globalSearchEndpoint || "/api/global-search", window.location.origin);
    endpoint.searchParams.set("q", "");
    endpoint.searchParams.set("limit", String(GLOBAL_APP_SEARCH_RECENT_LIMIT));
    form._globalSearchRecentRequest = fetch(endpoint, {
        headers: { "X-Requested-With": "fetch" },
        credentials: "same-origin",
    });
    try {
        const response = await form._globalSearchRecentRequest;
        const payload = await response.json().catch(() => ({}));
        if (!response.ok || !payload.ok) {
            throw new Error(payload.error || "Recent AI Pantry items are unavailable.");
        }
        form._globalSearchRecentResults = globalAppSearchRecentResults(payload);
    } catch (error) {
        form._globalSearchRecentResults = [];
    } finally {
        form._globalSearchRecentLoaded = true;
        form._globalSearchRecentRequest = null;
        if (!globalAppSearchQuery(form)) {
            globalAppSearchRenderEmpty(form);
        }
    }
}

async function globalAppSearchFetch(form, query) {
    if (form._globalSearchAbortController) {
        form._globalSearchAbortController.abort();
    }
    const controller = new AbortController();
    form._globalSearchAbortController = controller;
    globalAppSearchInput(form)?.setAttribute("aria-busy", "true");
    globalAppSearchMessage(form, "Searching…", "loading");
    try {
        const endpoint = new URL(form.dataset.globalSearchEndpoint || "/api/global-search", window.location.origin);
        endpoint.searchParams.set("q", query);
        endpoint.searchParams.set("limit", String(GLOBAL_APP_SEARCH_RESULT_LIMIT));
        const response = await fetch(endpoint, {
            headers: { "X-Requested-With": "fetch" },
            credentials: "same-origin",
            signal: controller.signal,
        });
        const payload = await response.json().catch(() => ({}));
        if (!response.ok || !payload.ok) {
            throw new Error(payload.error || "Global search is unavailable.");
        }
        if (globalAppSearchQuery(form) !== query) {
            return;
        }
        const groups = globalAppSearchNormalizedGroups(payload)
            .filter(group => group.key !== "pages" && group.key !== "recent")
            .map(group => ({
                ...group,
                results: group.results.map(result => ({
                    ...result,
                    trackingGroup: group.key,
                })),
            }));
        const pages = globalAppSearchPageResults(form, query, GLOBAL_APP_SEARCH_TYPED_PAGE_LIMIT);
        if (pages.length) {
            groups.push({ key: "pages", label: "PAGES", results: pages });
        }
        if (!groups.length) {
            globalAppSearchMessage(form, `No results for “${query}”`, "empty");
            return;
        }
        globalAppSearchRenderGroups(form, groups, query, {
            totalCount: Number(payload.total_count || 0),
        });
    } catch (error) {
        if (error && error.name === "AbortError") {
            return;
        }
        globalAppSearchMessage(form, ["Search could not be completed.", "Try again."], "error");
    } finally {
        if (form._globalSearchAbortController === controller) {
            form._globalSearchAbortController = null;
            globalAppSearchInput(form)?.removeAttribute("aria-busy");
        }
    }
}

function globalAppSearchSchedule(form) {
    window.clearTimeout(form._globalSearchTimer);
    if (form._globalSearchAbortController) {
        form._globalSearchAbortController.abort();
        form._globalSearchAbortController = null;
        globalAppSearchInput(form)?.removeAttribute("aria-busy");
    }
    const query = globalAppSearchQuery(form);
    if (!query) {
        globalAppSearchRenderEmpty(form);
        globalAppSearchFetchRecent(form);
        return;
    }
    if (query.length < GLOBAL_APP_SEARCH_MIN_QUERY_LENGTH) {
        const pages = globalAppSearchPageResults(form, query);
        if (pages.length) {
            globalAppSearchRenderGroups(form, [{ key: "pages", label: "PAGES", results: pages }], query, {
                includeViewAll: false,
            });
        } else {
            globalAppSearchMessage(form, "Type at least 2 characters to search your AI Pantry records.", "hint");
        }
        return;
    }
    globalAppSearchMessage(form, "Searching…", "loading");
    form._globalSearchTimer = window.setTimeout(() => {
        globalAppSearchFetch(form, query);
    }, GLOBAL_APP_SEARCH_DEBOUNCE_MS);
}

function globalAppSearchRememberResult(form, result) {
    if (!result || !result.trackingGroup || result.id === undefined || result.id === null) {
        return;
    }
    fetch(form.dataset.globalSearchRecentUrl || "/api/global-search/recent", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ group: result.trackingGroup, id: result.id }),
        credentials: "same-origin",
        keepalive: true,
    }).catch(() => {
        // Search navigation should never be blocked by recent-history tracking.
    });
}

function globalAppSearchOpenResult(form, index) {
    const result = Array.isArray(form._globalSearchResults) ? form._globalSearchResults[index] : null;
    if (!result) {
        return false;
    }
    globalAppSearchRememberResult(form, result);
    globalAppSearchCloseDropdown(form);
    if (result.sourceNavLink && form.dataset.globalSearchSpa === "true") {
        const navLink = result.sourceNavLink;
        if (navLink) {
            appShellSetSearchStatus(`Opening ${result.title}.`);
            activateAppShellNavLink(navLink);
            return false;
        }
    }
    window.location.assign(globalAppSearchOptionUrl(form, result));
    return false;
}

function submitGlobalAppSearch(form) {
    const query = globalAppSearchQuery(form);
    const activeIndex = Number.isInteger(form?._globalSearchActiveIndex)
        ? form._globalSearchActiveIndex
        : -1;
    if (activeIndex >= 0) {
        return globalAppSearchOpenResult(form, activeIndex);
    }
    if (query.length < GLOBAL_APP_SEARCH_MIN_QUERY_LENGTH) {
        globalAppSearchSchedule(form);
        globalAppSearchInput(form)?.focus();
        return false;
    }
    const resultsUrl = new URL(form.dataset.globalSearchResultsUrl || "/search", window.location.origin);
    resultsUrl.searchParams.set("q", query);
    window.location.assign(`${resultsUrl.pathname}${resultsUrl.search}`);
    return false;
}

function initGlobalAppSearch() {
    document.querySelectorAll("[data-global-search-form]").forEach(form => {
        if (form.dataset.globalSearchBound === "1") {
            return;
        }
        form.dataset.globalSearchBound = "1";
        form._globalSearchActiveIndex = -1;
        const input = globalAppSearchInput(form);
        if (!input) {
            return;
        }
        input.addEventListener("focus", () => globalAppSearchSchedule(form));
        input.addEventListener("input", () => globalAppSearchSchedule(form));
        input.addEventListener("keydown", event => {
            if (event.key === "Escape") {
                event.preventDefault();
                globalAppSearchCloseDropdown(form);
                return;
            }
            if (event.key === "ArrowDown" || event.key === "ArrowUp") {
                event.preventDefault();
                if (globalAppSearchDropdown(form)?.hidden) {
                    globalAppSearchSchedule(form);
                }
                const options = [...form.querySelectorAll("[data-global-search-result]")];
                if (options.length) {
                    const current = Number.isInteger(form._globalSearchActiveIndex)
                        ? form._globalSearchActiveIndex
                        : -1;
                    const next = current < 0
                        ? (event.key === "ArrowDown" ? 0 : options.length - 1)
                        : current + (event.key === "ArrowDown" ? 1 : -1);
                    globalAppSearchSetActiveIndex(form, next);
                }
                return;
            }
            if (event.key === "Enter" && form._globalSearchActiveIndex >= 0) {
                event.preventDefault();
                globalAppSearchOpenResult(form, form._globalSearchActiveIndex);
            }
        });
        form.addEventListener("click", event => {
            const option = event.target && event.target.closest
                ? event.target.closest("[data-global-search-result]")
                : null;
            if (!option || !form.contains(option)) {
                return;
            }
            if (event.button !== 0 || event.ctrlKey || event.metaKey || event.shiftKey || event.altKey) {
                return;
            }
            event.preventDefault();
            globalAppSearchOpenResult(form, Number(option.dataset.globalSearchResult));
        });
        form.addEventListener("focusin", event => {
            const option = event.target && event.target.closest
                ? event.target.closest("[data-global-search-result]")
                : null;
            if (option && form.contains(option)) {
                globalAppSearchSetActiveIndex(form, Number(option.dataset.globalSearchResult));
            }
        });
        form.addEventListener("focusout", () => {
            window.setTimeout(() => {
                if (!form.contains(document.activeElement)) {
                    globalAppSearchCloseDropdown(form);
                }
            }, 0);
        });
    });

    if (document.documentElement.dataset.globalSearchOutsideBound !== "1") {
        document.documentElement.dataset.globalSearchOutsideBound = "1";
        document.addEventListener("pointerdown", event => {
            document.querySelectorAll("[data-global-search-form]").forEach(form => {
                if (!form.contains(event.target)) {
                    globalAppSearchCloseDropdown(form);
                }
            });
        });
    }
}

function recipeBrowseCards() {
    return [...document.querySelectorAll("#recipesPage [data-recipe-preview-card]")];
}

function toggleRecipeBrowseFilters(button) {
    const panel = document.getElementById("recipeBrowseFilters");
    if (!panel) {
        return false;
    }
    panel.hidden = !panel.hidden;
    button?.setAttribute("aria-expanded", panel.hidden ? "false" : "true");
    if (!panel.hidden) {
        panel.querySelector("input, select")?.focus();
    }
    return false;
}

function applyRecipeBrowseFilters() {
    const panel = document.getElementById("recipeBrowseFilters");
    const query = normalizeAppShellSearchText(panel?.querySelector("[data-recipe-browse-search]")?.value || "");
    const cookbook = normalizeAppShellSearchText(panel?.querySelector("[data-recipe-browse-cookbook]")?.value || "");
    let visibleCount = 0;
    recipeBrowseCards().forEach(card => {
        const searchable = normalizeAppShellSearchText(`${card.dataset.recipeName || ""} ${card.dataset.recipeCookbook || ""}`);
        const matchesQuery = !query || searchable.includes(query);
        const matchesCookbook = !cookbook || normalizeAppShellSearchText(card.dataset.recipeCookbook).includes(cookbook);
        card.hidden = !(matchesQuery && matchesCookbook);
        if (!card.hidden) {
            visibleCount += 1;
        }
    });
    const status = panel?.querySelector("[data-recipe-browse-status]");
    if (status) {
        status.textContent = `${visibleCount} visible recipe${visibleCount === 1 ? "" : "s"}.`;
    }
    return false;
}

function clearRecipeBrowseFilters() {
    const panel = document.getElementById("recipeBrowseFilters");
    const search = panel?.querySelector("[data-recipe-browse-search]");
    const cookbook = panel?.querySelector("[data-recipe-browse-cookbook]");
    if (search) {
        search.value = "";
    }
    if (cookbook) {
        cookbook.value = "";
    }
    applyRecipeBrowseFilters();
    search?.focus();
    return false;
}

