function parsePantryReviewDate(value) {
    const match = String(value || "").trim().match(/^(\d{4})-(\d{2})-(\d{2})$/);

    if (!match) {
        return null;
    }

    const year = Number(match[1]);
    const month = Number(match[2]) - 1;
    const day = Number(match[3]);
    const parsed = new Date(year, month, day);

    if (
        Number.isNaN(parsed.getTime())
        || parsed.getFullYear() !== year
        || parsed.getMonth() !== month
        || parsed.getDate() !== day
    ) {
        return null;
    }

    return parsed;
}

function pantryReviewTodayDate() {
    const now = new Date();
    return new Date(now.getFullYear(), now.getMonth(), now.getDate());
}

function pantryReviewDateDisplayLabel(value) {
    if (!(value instanceof Date) || Number.isNaN(value.getTime())) {
        return "";
    }

    return value.toLocaleDateString(undefined, {
        month: "short",
        day: "numeric",
        year: "numeric",
    });
}

function daysUntilPantryReviewDate(targetDate, today = pantryReviewTodayDate()) {
    return Math.round((targetDate.getTime() - today.getTime()) / 86400000);
}

function pantryReceiptDateStatus(field, value, today = pantryReviewTodayDate()) {
    const targetDate = parsePantryReviewDate(value);

    if (!targetDate || !["expiration_date", "freeze_by_date"].includes(field)) {
        return { urgency: "fresh", label: "" };
    }

    const daysUntil = daysUntilPantryReviewDate(targetDate, today);
    const isUseBy = field === "expiration_date";

    if (daysUntil < 0) {
        return {
            urgency: isUseBy ? "expired" : "freeze-expired",
            label: isUseBy ? "Past use by" : "Freeze window passed",
        };
    }
    if (daysUntil === 0) {
        return {
            urgency: "due-soon",
            label: isUseBy ? "Use today" : "Freeze today",
        };
    }
    if (daysUntil === 1) {
        return {
            urgency: "due-soon",
            label: isUseBy ? "Use by tomorrow" : "Freeze by tomorrow",
        };
    }

    return { urgency: "fresh", label: "" };
}

function pantryReceiptReviewDateInput(row, field) {
    const fieldElement = row
        ? row.querySelector(`[data-pantry-review-date-field="${field}"]`)
        : null;
    return fieldElement ? fieldElement.querySelector("input[type='date']") : null;
}

function pantryReceiptFrozenBestByLabel(row, frozenDate) {
    const freezerDays = Number.parseInt(row && row.dataset ? row.dataset.pantryReviewFreezerDays : "", 10);

    if (!Number.isFinite(freezerDays) || freezerDays <= 0 || !frozenDate) {
        return "";
    }

    const bestByDate = new Date(frozenDate.getFullYear(), frozenDate.getMonth(), frozenDate.getDate());
    bestByDate.setDate(bestByDate.getDate() + freezerDays);
    const bestByLabel = pantryReviewDateDisplayLabel(bestByDate);
    return bestByLabel ? `Best frozen until ${bestByLabel}` : "";
}

function pantryReceiptNextActionLabel(prefix, targetDate) {
    const dateLabel = pantryReviewDateDisplayLabel(targetDate);
    return dateLabel ? `Next: ${prefix} ${dateLabel}` : "";
}

function pantryReceiptStorageLabel(storage) {
    const rawStorage = String(storage || "").trim();
    const normalizedStorage = rawStorage.toLowerCase();

    switch (normalizedStorage) {
    case "pantry":
        return "Pantry";
    case "fridge":
        return "Fridge";
    case "freezer":
        return "Freezer";
    case "counter":
        return "Counter";
    default:
        return rawStorage
            ? rawStorage.replace(/[-_]+/g, " ").replace(/\b\w/g, letter => letter.toUpperCase())
            : "Review";
    }
}

function normalizePantryReceiptStorage(storage) {
    const normalizedStorage = String(storage || "").trim().toLowerCase();
    if (["pantry", "fridge", "freezer", "counter"].includes(normalizedStorage)) {
        return normalizedStorage;
    }
    return normalizedStorage && normalizedStorage !== "unknown"
        ? "custom"
        : "review";
}

function pantryReceiptReviewStorageValue(row) {
    const select = row ? row.querySelector("[data-pantry-review-storage-select]") : null;

    if (!select) {
        return row ? (row.dataset.pantryReviewSuggestedStorage || row.dataset.pantryReviewStorage || "") : "";
    }

    if (select.value === "__custom__") {
        const customInput = row.querySelector("[data-pantry-review-storage-custom]");
        return customInput ? customInput.value : "";
    }

    return select.value;
}

function syncPantryReceiptStorageCustomInput(row) {
    const select = row ? row.querySelector("[data-pantry-review-storage-select]") : null;
    const customInput = row ? row.querySelector("[data-pantry-review-storage-custom]") : null;

    if (!select || !customInput) {
        return;
    }

    customInput.hidden = select.value !== "__custom__";
}

function pantryReceiptStorageIsFreezer(storage) {
    return String(storage || "").trim().toLowerCase() === "freezer";
}

function pantryReceiptStorageBadgeClass(storage) {
    const normalizedStorage = normalizePantryReceiptStorage(storage);
    return ["pantry", "fridge", "freezer", "counter", "review", "unknown", "custom"].includes(normalizedStorage)
        ? normalizedStorage
        : "custom";
}

function updatePantryReceiptStorageBadge(row, storage) {
    const badge = row ? row.querySelector("[data-pantry-review-storage-badge]") : null;

    if (!badge) {
        return;
    }

    const normalizedStorage = pantryReceiptStorageBadgeClass(storage);
    ["pantry", "fridge", "freezer", "counter", "review", "unknown", "custom"].forEach(value => {
        badge.classList.remove(`ai-pantry-review-storage-${value}`);
    });
    badge.classList.add(`ai-pantry-review-storage-${normalizedStorage}`);
    badge.textContent = `Storage: ${pantryReceiptStorageLabel(storage)}`;
}

function setPantryReceiptDateFieldStatus(row, field, urgency, label) {
    const fieldElement = row
        ? row.querySelector(`[data-pantry-review-date-field="${field}"]`)
        : null;

    if (!fieldElement) {
        return;
    }

    PANTRY_RECEIPT_FIELD_STATUS_CLASSES.forEach(className => fieldElement.classList.remove(className));
    fieldElement.classList.add(`ai-pantry-date-field-${urgency || "fresh"}`);

    let statusElement = fieldElement.querySelector("[data-pantry-review-date-status]");

    if (!label) {
        if (statusElement) {
            statusElement.remove();
        }
        return;
    }

    if (!statusElement) {
        statusElement = document.createElement("small");
        statusElement.dataset.pantryReviewDateStatus = "";
        fieldElement.appendChild(statusElement);
    }

    statusElement.textContent = label;
}

function setPantryReceiptNextAction(row, nextAction) {
    const badges = row ? row.querySelector(".ai-pantry-review-badges") : null;
    let badge = row ? row.querySelector("[data-pantry-review-next-action]") : null;
    const label = nextAction && nextAction.label ? nextAction.label : "";
    const urgency = nextAction && nextAction.urgency ? nextAction.urgency : "fresh";

    if (!label) {
        if (badge) {
            badge.remove();
        }
        return;
    }

    if (!badge && badges) {
        badge = document.createElement("small");
        badge.dataset.pantryReviewNextAction = "";
        badges.insertBefore(badge, badges.firstChild);
    }

    if (badge) {
        badge.className = `ai-pantry-review-next-badge ai-pantry-review-next-${urgency}`;
        badge.textContent = label;
    }
}

function setPantryReceiptRowStatus(row, rowStatus, label) {
    if (!row) {
        return;
    }

    const normalizedStatus = rowStatus || "fresh";
    PANTRY_RECEIPT_ROW_STATUS_CLASSES.forEach(className => row.classList.remove(className));
    row.classList.add(`ai-pantry-review-row-${normalizedStatus}`);

    const meta = row.querySelector(".ai-pantry-review-meta");
    const badges = row.querySelector(".ai-pantry-review-badges");
    let badge = row.querySelector("[data-pantry-review-row-status]");

    if (!label) {
        if (badge) {
            badge.remove();
        }
        return;
    }

    if (!badge && (badges || meta)) {
        badge = document.createElement("small");
        badge.className = "ai-pantry-review-date-badge";
        badge.dataset.pantryReviewRowStatus = "";
        if (badges) {
            const storageBadge = badges.querySelector("[data-pantry-review-storage-badge]");
            badges.insertBefore(badge, storageBadge || null);
        } else {
            meta.appendChild(badge);
        }
    }

    if (badge) {
        badge.textContent = label;
    }
}

function pantryReceiptNextAction(row, options) {
    const useByDate = options.useByDate;
    const freezeByDate = options.freezeByDate;
    const frozenDate = options.frozenDate;
    const useByStatus = options.useByStatus || {};
    const freezeByStatus = options.freezeByStatus || {};
    const isStoredInFreezer = options.isStoredInFreezer;
    const frozenBestLabel = frozenDate ? pantryReceiptFrozenBestByLabel(row, frozenDate) : "";

    if (frozenBestLabel) {
        return { urgency: "safe", label: `Next: ${frozenBestLabel}` };
    }
    if (isStoredInFreezer) {
        if (useByDate && useByStatus.urgency === "expired") {
            return { urgency: "expired", label: pantryReceiptNextActionLabel("Past frozen best by", useByDate) };
        }
        if (useByDate) {
            return {
                urgency: useByStatus.urgency === "due-soon" ? "due-soon" : "safe",
                label: pantryReceiptNextActionLabel("Best frozen until", useByDate),
            };
        }
        return {};
    }
    if (useByDate && useByStatus.urgency === "expired") {
        return { urgency: "expired", label: pantryReceiptNextActionLabel("Past use by", useByDate) };
    }
    if (freezeByDate && freezeByStatus.urgency === "freeze-expired") {
        return { urgency: "warning", label: pantryReceiptNextActionLabel("Freeze window passed", freezeByDate) };
    }
    if (freezeByDate && freezeByStatus.urgency === "due-soon") {
        return { urgency: "due-soon", label: pantryReceiptNextActionLabel("Freeze by", freezeByDate) };
    }
    if (useByDate) {
        return {
            urgency: useByStatus.urgency === "due-soon" ? "due-soon" : "fresh",
            label: pantryReceiptNextActionLabel("Use by", useByDate),
        };
    }
    if (freezeByDate) {
        return { urgency: "fresh", label: pantryReceiptNextActionLabel("Freeze by", freezeByDate) };
    }
    return {};
}

function updatePantryReceiptReviewRow(row) {
    if (!row) {
        return;
    }

    const useByInput = pantryReceiptReviewDateInput(row, "expiration_date");
    const freezeByInput = pantryReceiptReviewDateInput(row, "freeze_by_date");
    const frozenInput = pantryReceiptReviewDateInput(row, "frozen_date");
    const useByValue = useByInput ? useByInput.value : "";
    const freezeByValue = freezeByInput ? freezeByInput.value : "";
    const frozenValue = frozenInput ? frozenInput.value : "";
    const useByDate = parsePantryReviewDate(useByValue);
    const freezeByDate = parsePantryReviewDate(freezeByValue);
    const frozenDate = parsePantryReviewDate(frozenValue);
    const deadlineDate = freezeByDate || useByDate;
    const today = pantryReviewTodayDate();
    const useByStatus = pantryReceiptDateStatus("expiration_date", useByValue, today);
    const freezeByStatus = pantryReceiptDateStatus("freeze_by_date", freezeByValue, today);
    const selectedStorageValue = pantryReceiptReviewStorageValue(row);
    const storageValue = String(selectedStorageValue || "").trim() || (frozenDate ? "freezer" : "");
    const isStoredInFreezer = pantryReceiptStorageIsFreezer(storageValue);
    const effectiveFreezeByStatus = isStoredInFreezer && !freezeByValue
        ? { urgency: "frozen-safe", label: "Already in freezer" }
        : freezeByStatus;
    updatePantryReceiptStorageBadge(row, storageValue);
    setPantryReceiptNextAction(row, pantryReceiptNextAction(row, {
        useByDate,
        freezeByDate,
        frozenDate,
        useByStatus,
        freezeByStatus: effectiveFreezeByStatus,
        isStoredInFreezer,
    }));

    if (frozenDate && deadlineDate && frozenDate.getTime() <= deadlineDate.getTime()) {
        setPantryReceiptDateFieldStatus(row, "expiration_date", useByValue ? "frozen-safe" : "fresh", useByValue ? "Original use by preserved" : "");
        setPantryReceiptDateFieldStatus(
            row,
            "freeze_by_date",
            freezeByValue ? "frozen-safe" : effectiveFreezeByStatus.urgency,
            freezeByValue ? "Freeze deadline met" : effectiveFreezeByStatus.label
        );
        setPantryReceiptDateFieldStatus(row, "frozen_date", "frozen-safe", pantryReceiptFrozenBestByLabel(row, frozenDate) || "Frozen before deadline");
        setPantryReceiptRowStatus(row, "frozen-in-time", "Frozen before deadline");
        return;
    }

    setPantryReceiptDateFieldStatus(row, "expiration_date", useByStatus.urgency, useByStatus.label);
    setPantryReceiptDateFieldStatus(row, "freeze_by_date", effectiveFreezeByStatus.urgency, effectiveFreezeByStatus.label);

    if (frozenDate && deadlineDate && frozenDate.getTime() > deadlineDate.getTime()) {
        setPantryReceiptDateFieldStatus(row, "frozen_date", "frozen-late", "Frozen after deadline");
    } else if (frozenDate) {
        setPantryReceiptDateFieldStatus(row, "frozen_date", "fresh", "Frozen date recorded");
    } else {
        setPantryReceiptDateFieldStatus(row, "frozen_date", "fresh", "");
    }

    if (useByStatus.urgency === "expired") {
        setPantryReceiptRowStatus(row, "use-expired", useByStatus.label || "Past use by");
    } else if (effectiveFreezeByStatus.urgency === "freeze-expired") {
        setPantryReceiptRowStatus(row, "freeze-expired", effectiveFreezeByStatus.label || "Freeze window passed");
    } else if (useByStatus.urgency === "due-soon") {
        setPantryReceiptRowStatus(row, "due-soon", useByStatus.label || "Use soon");
    } else if (effectiveFreezeByStatus.urgency === "due-soon") {
        setPantryReceiptRowStatus(row, "due-soon", effectiveFreezeByStatus.label || "Freeze soon");
    } else {
        setPantryReceiptRowStatus(row, "fresh", "");
    }
}

function bindPantryReceiptDateWarnings(root = document) {
    const context = root && root.querySelectorAll ? root : document;
    const rows = [];

    if (context.matches && context.matches("[data-pantry-review-row]")) {
        rows.push(context);
    }

    context.querySelectorAll("[data-pantry-review-row]").forEach(row => rows.push(row));
    rows.forEach(row => {
        if (row.dataset.pantryReviewWarningsBound === "1") {
            updatePantryReceiptReviewRow(row);
            return;
        }

        row.dataset.pantryReviewWarningsBound = "1";
        row.querySelectorAll(".ai-pantry-review-dates input[type='date']").forEach(input => {
            input.addEventListener("input", () => updatePantryReceiptReviewRow(row));
            input.addEventListener("change", () => updatePantryReceiptReviewRow(row));
        });
        row.querySelectorAll("[data-pantry-review-storage-select]").forEach(select => {
            select.addEventListener("change", () => {
                syncPantryReceiptStorageCustomInput(row);
                updatePantryReceiptReviewRow(row);
            });
        });
        row.querySelectorAll("[data-pantry-review-storage-custom]").forEach(input => {
            input.addEventListener("input", () => updatePantryReceiptReviewRow(row));
            input.addEventListener("change", () => updatePantryReceiptReviewRow(row));
        });
        syncPantryReceiptStorageCustomInput(row);
        updatePantryReceiptReviewRow(row);
    });
}

function pantryInventoryForFeelingPrompt() {
    return Array.from(document.querySelectorAll("[data-pantry-item]"))
        .map(item => {
            const ingredient = String(item.dataset.pantryIngredient || "").trim();
            const product = String(item.dataset.pantryProduct || "").trim();
            const quantity = String(item.dataset.pantryQuantity || "").trim();
            const unit = String(item.dataset.pantryUnit || "").trim();
            const category = String(item.dataset.pantryCategory || "").trim();
            const amount = [quantity, unit].filter(Boolean).join(" ");
            const details = [
                product && product !== ingredient ? product : "",
                amount,
                category,
            ].filter(Boolean);

            if (!ingredient) {
                return "";
            }

            return details.length ? `${ingredient} (${details.join(", ")})` : ingredient;
        })
        .filter(Boolean)
        .slice(0, 40);
}

function pantryRecipeTitlesForFeelingPrompt() {
    return Array.from(document.querySelectorAll("#aiPantryCookWithWhatIHave .ai-pantry-recipe-card h4"))
        .map(title => title.textContent.trim())
        .filter(Boolean)
        .slice(0, 12);
}

function setPantryFeelingStatus(message, isError = false) {
    const status = document.getElementById("pantryFeelingStatus");

    if (!status) {
        return;
    }

    status.textContent = message || "";
    status.classList.toggle("error", Boolean(isError));
}

function buildPantryFeelingPrompt(form) {
    const activeForm = form && form.querySelector
        ? form
        : document.querySelector(".ai-pantry-feeling-form");
    const feelingInput = activeForm ? activeForm.querySelector("#pantryFeelingInput") : null;
    const constraintsInput = activeForm ? activeForm.querySelector("#pantryFeelingConstraints") : null;
    const servingsInput = activeForm ? activeForm.querySelector("#pantryFeelingServings") : null;
    const output = activeForm ? activeForm.querySelector("#pantryFeelingPromptOutput") : null;
    const feeling = feelingInput ? feelingInput.value.trim() : "";
    const constraints = constraintsInput ? constraintsInput.value.trim() : "";
    const servings = servingsInput ? servingsInput.value.trim() : "";

    if (!feeling) {
        setPantryFeelingStatus("Enter a cuisine, mood, or genre first.", true);
        if (feelingInput) {
            feelingInput.focus();
        }
        return false;
    }

    const pantryItems = pantryInventoryForFeelingPrompt();
    const recipeTitles = pantryRecipeTitlesForFeelingPrompt();
    const promptParts = [
        `I want to cook something in this style or mood: ${feeling}.`,
        servings ? `Target servings: ${servings}.` : "",
        constraints ? `Constraints or preferences: ${constraints}.` : "",
        pantryItems.length
            ? `Pantry inventory I can use:\n- ${pantryItems.join("\n- ")}`
            : "No pantry inventory is saved yet, so suggest a practical recipe idea and list the missing ingredients clearly.",
        recipeTitles.length
            ? `Recipes already in my app that may be useful:\n- ${recipeTitles.join("\n- ")}`
            : "",
        "Suggest 3 meal ideas that fit the mood. Pick the best one, explain why, list ingredients I already have, list missing ingredients, and give concise cooking steps.",
    ].filter(Boolean);

    if (output) {
        output.value = promptParts.join("\n\n");
        output.focus();
        output.setSelectionRange(0, 0);
    }

    setPantryFeelingStatus("Prompt built.");
    return false;
}

async function copyPantryFeelingPrompt(button) {
    const form = button ? button.closest(".ai-pantry-feeling-form") : document.querySelector(".ai-pantry-feeling-form");
    const output = form ? form.querySelector("#pantryFeelingPromptOutput") : null;

    if (!output) {
        return false;
    }

    if (!output.value.trim()) {
        buildPantryFeelingPrompt(form);
    }

    if (!output.value.trim()) {
        return false;
    }

    try {
        if (navigator.clipboard && navigator.clipboard.writeText) {
            await navigator.clipboard.writeText(output.value);
        } else {
            output.select();
            document.execCommand("copy");
        }
        setPantryFeelingStatus("Prompt copied.");
    } catch (err) {
        console.warn("Unable to copy pantry feeling prompt.", err);
        output.select();
        setPantryFeelingStatus("Prompt selected. Use Ctrl+C to copy.", true);
    }

    return false;
}

