async function testLocalTitleImageGeneration(button) {
    const originalText = button ? button.textContent : "";

    if (button) {
        button.disabled = true;
        button.textContent = "Testing...";
    }
    setLocalTitleImageStatus("Testing local ComfyUI image generation...");

    try {
        const response = await fetch("/api/recipe_cover_image/test-local", {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
                "X-Requested-With": "fetch",
            },
            body: JSON.stringify({
                prompt: "A realistic cookbook photo of tomato soup with basil, natural window light, no text.",
            }),
        });
        let data = {};
        try {
            data = await response.json();
        } catch (_err) {
            data = {};
        }

        if (!response.ok || !data.ok) {
            throw new Error(data.error || "Local image generation failed.");
        }

        const byteCount = Number(data.byte_count || 0);
        const suffix = byteCount > 0 ? ` ${byteCount.toLocaleString()} bytes returned.` : "";
        setLocalTitleImageStatus(`${data.message || "Local image generation succeeded."}${suffix}`);
    } catch (err) {
        console.warn("Unable to test local title image generation.", err);
        setLocalTitleImageStatus(err.message || "Local image generation failed.", true);
    } finally {
        if (button && button.isConnected) {
            button.disabled = false;
            button.textContent = originalText || "Test Local Image Generation";
        }
    }

    return false;
}

function cloudflareOrphanPdfLabel(count) {
    return `Unlinked PDFs found: ${count}`;
}

function appendCloudflarePdfCell(row, value, className = "") {
    const cell = document.createElement("td");
    if (className) {
        cell.className = className;
    }
    cell.textContent = value || "";
    row.appendChild(cell);
    return cell;
}

function cloudflareUnlinkedPdfCheckboxes(panel = cloudflareOrphanPdfPanel()) {
    return Array.from(panel ? panel.querySelectorAll("[data-cloudflare-unlinked-pdf-key]") : []);
}

function selectedCloudflareUnlinkedPdfKeys(panel = cloudflareOrphanPdfPanel()) {
    return cloudflareUnlinkedPdfCheckboxes(panel)
        .filter((checkbox) => checkbox.checked && !checkbox.disabled)
        .map((checkbox) => checkbox.value)
        .filter(Boolean);
}

function cloudflareUnlinkedPdfKeysFromData(data) {
    const rows = Array.isArray(data.unlinked_pdfs)
        ? data.unlinked_pdfs
        : (Array.isArray(data.orphaned_pdfs) ? data.orphaned_pdfs : []);
    const seen = new Set();

    return rows
        .map((pdf) => String((pdf && pdf.object_key) || "").trim())
        .filter((key) => {
            if (!key || seen.has(key)) {
                return false;
            }
            seen.add(key);
            return true;
        });
}

function updateCloudflareUnlinkedDeleteButton() {
    const panel = cloudflareOrphanPdfPanel();
    const deleteButton = panel ? panel.querySelector("[data-cloudflare-orphan-pdf-delete]") : null;
    const checkboxes = cloudflareUnlinkedPdfCheckboxes(panel).filter((checkbox) => !checkbox.disabled);
    const selectedKeys = selectedCloudflareUnlinkedPdfKeys(panel);
    const selectAll = panel ? panel.querySelector("[data-cloudflare-unlinked-pdf-select-all]") : null;

    if (deleteButton) {
        deleteButton.disabled = selectedKeys.length === 0;
        deleteButton.dataset.selectedPdfCount = String(selectedKeys.length);
        deleteButton.title = selectedKeys.length > 0
            ? `Delete ${selectedKeys.length} selected unlinked PDF${selectedKeys.length === 1 ? "" : "s"}.`
            : "Select one or more unlinked PDFs to delete.";
    }

    if (selectAll) {
        selectAll.checked = checkboxes.length > 0 && selectedKeys.length === checkboxes.length;
        selectAll.indeterminate = selectedKeys.length > 0 && selectedKeys.length < checkboxes.length;
    }
}

function toggleAllCloudflareUnlinkedPdfs(checkbox) {
    const panel = cloudflareOrphanPdfPanel();
    cloudflareUnlinkedPdfCheckboxes(panel).forEach((item) => {
        if (!item.disabled) {
            item.checked = Boolean(checkbox && checkbox.checked);
        }
    });
    updateCloudflareUnlinkedDeleteButton();
}

function renderCloudflareOrphanPdfs(data) {
    const panel = cloudflareOrphanPdfPanel();
    const list = panel ? panel.querySelector("[data-cloudflare-orphan-pdf-list]") : null;
    const empty = panel ? panel.querySelector("[data-cloudflare-orphan-pdf-empty]") : null;
    const deleteButton = panel ? panel.querySelector("[data-cloudflare-orphan-pdf-delete]") : null;
    const summary = panel ? panel.querySelector("[data-cloudflare-orphan-pdf-summary]") : null;
    const unlinkedPdfs = Array.isArray(data.unlinked_pdfs)
        ? data.unlinked_pdfs
        : (Array.isArray(data.orphaned_pdfs) ? data.orphaned_pdfs : []);
    const unlinkedCount = Number(data.unlinked_pdf_count || data.orphaned_pdf_count || unlinkedPdfs.length || 0);

    if (summary) {
        summary.innerHTML = "";
        [
            cloudflareOrphanPdfLabel(unlinkedCount),
            `${Number(data.total_cloudflare_pdfs || 0)} checked`,
            `${Number(data.referenced_pdf_count || 0)} linked`,
        ].forEach((label) => {
            const item = document.createElement("span");
            item.textContent = label;
            summary.appendChild(item);
        });
    }

    if (deleteButton) {
        deleteButton.hidden = false;
        deleteButton.disabled = true;
        deleteButton.dataset.unlinkedPdfCount = String(unlinkedCount);
        deleteButton.dataset.selectedPdfCount = "0";
    }

    if (!list) {
        return;
    }

    list.innerHTML = "";
    list.hidden = unlinkedPdfs.length === 0;
    if (empty) {
        empty.hidden = unlinkedPdfs.length > 0;
    }

    if (unlinkedPdfs.length === 0) {
        updateCloudflareUnlinkedDeleteButton();
        return;
    }

    const table = document.createElement("table");
    table.className = "pdf-orphan-table";
    const head = document.createElement("thead");
    const headRow = document.createElement("tr");
    const selectHeader = document.createElement("th");
    const selectAll = document.createElement("input");
    selectHeader.scope = "col";
    selectHeader.className = "pdf-orphan-select";
    selectAll.type = "checkbox";
    selectAll.setAttribute("aria-label", "Select all unlinked PDFs");
    selectAll.setAttribute("data-cloudflare-unlinked-pdf-select-all", "true");
    selectAll.addEventListener("change", () => toggleAllCloudflareUnlinkedPdfs(selectAll));
    selectHeader.appendChild(selectAll);
    headRow.appendChild(selectHeader);
    [
        "PDF filename",
        "R2 object key/path",
        "File size",
        "Last modified",
        "Suspected type",
        "Reason",
    ].forEach((label) => {
        const header = document.createElement("th");
        header.scope = "col";
        header.textContent = label;
        headRow.appendChild(header);
    });
    head.appendChild(headRow);
    table.appendChild(head);

    const body = document.createElement("tbody");
    unlinkedPdfs.forEach((pdf) => {
        const row = document.createElement("tr");
        const objectKey = pdf.object_key || "";
        const selectCell = document.createElement("td");
        const checkbox = document.createElement("input");
        selectCell.className = "pdf-orphan-select";
        checkbox.type = "checkbox";
        checkbox.value = objectKey;
        checkbox.disabled = !objectKey;
        checkbox.setAttribute("data-cloudflare-unlinked-pdf-key", objectKey);
        checkbox.setAttribute("aria-label", `Select ${pdf.filename || objectKey || "PDF"} for deletion`);
        checkbox.addEventListener("change", updateCloudflareUnlinkedDeleteButton);
        selectCell.appendChild(checkbox);
        row.appendChild(selectCell);
        const filenameCell = document.createElement("td");
        filenameCell.className = "pdf-orphan-filename";
        if (pdf.public_url) {
            const link = document.createElement("a");
            link.className = "pdf-orphan-link";
            link.href = pdf.public_url;
            link.target = "_blank";
            link.rel = "noopener noreferrer";
            link.textContent = pdf.filename || "Unknown PDF";
            filenameCell.appendChild(link);
        } else {
            filenameCell.textContent = pdf.filename || "Unknown PDF";
        }
        row.appendChild(filenameCell);
        appendCloudflarePdfCell(row, objectKey || "Unknown key", "pdf-orphan-key");
        appendCloudflarePdfCell(row, pdf.size_label || "Unknown size");
        appendCloudflarePdfCell(row, pdf.last_modified_label || "Unknown modified date");
        appendCloudflarePdfCell(row, pdf.suspected_type || "unknown", "pdf-orphan-type");
        appendCloudflarePdfCell(
            row,
            pdf.reason || "No matching PDF reference was found in app records.",
            "pdf-orphan-reason"
        );
        body.appendChild(row);
    });
    table.appendChild(body);
    list.appendChild(table);
    updateCloudflareUnlinkedDeleteButton();
}

async function checkCloudflareOrphanPdfs(button) {
    const originalText = button ? button.textContent : "";

    if (button) {
        button.disabled = true;
        button.textContent = "Checking...";
    }
    setCloudflareOrphanPdfStatus("Checking Cloudflare PDFs...");

    try {
        const response = await fetch("/pdfs/cloudflare_unlinked", {
            method: "GET",
            headers: {
                "X-Requested-With": "fetch",
            },
        });
        const data = await response.json();

        if (!response.ok || !data.ok) {
            throw new Error(data.error || "Unable to check Cloudflare PDFs.");
        }

        renderCloudflareOrphanPdfs(data);
        const unlinkedCount = Number(data.unlinked_pdf_count || data.orphaned_pdf_count || 0);
        setCloudflareOrphanPdfStatus(
            unlinkedCount > 0 ? cloudflareOrphanPdfLabel(unlinkedCount) : "No unlinked PDFs found."
        );
    } catch (err) {
        console.warn("Unable to check Cloudflare unlinked PDFs.", err);
        setCloudflareOrphanPdfStatus(err.message || "Unable to check Cloudflare PDFs.", true);
    } finally {
        if (button && button.isConnected) {
            button.disabled = false;
            button.textContent = originalText || "Check Unlinked PDFs";
        }
    }

    return false;
}

async function deleteSelectedCloudflareUnlinkedPdfs(button) {
    const keys = selectedCloudflareUnlinkedPdfKeys();
    const originalText = button ? button.textContent : "";

    if (keys.length === 0) {
        setCloudflareOrphanPdfStatus("Select at least one unlinked PDF to delete.", true);
        updateCloudflareUnlinkedDeleteButton();
        return false;
    }

    const selectionLabel = `${keys.length} selected unlinked PDF${keys.length === 1 ? "" : "s"}`;
    if (!window.confirm(`Delete ${selectionLabel} from Cloudflare R2? This cannot be undone.`)) {
        return false;
    }

    if (button) {
        button.disabled = true;
        button.textContent = "Deleting...";
    }
    setCloudflareOrphanPdfStatus(`Deleting ${selectionLabel}...`);

    try {
        const response = await fetch("/pdfs/cloudflare_unlinked/delete", {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
                "X-Requested-With": "fetch",
            },
            body: JSON.stringify({
                object_keys: keys,
            }),
        });
        let data = {};
        try {
            data = await response.json();
        } catch (_err) {
            data = {};
        }

        if (Array.isArray(data.unlinked_pdfs) || Array.isArray(data.orphaned_pdfs)) {
            renderCloudflareOrphanPdfs(data);
        }

        if (!response.ok || !data.ok) {
            throw new Error(data.error || data.message || "Unable to delete selected unlinked PDFs.");
        }

        const deletedCount = Number(data.deleted_count || 0);
        const skippedCount = Number(data.skipped_count || 0);
        let message = data.message || `Deleted ${deletedCount} selected unlinked PDF${deletedCount === 1 ? "" : "s"}.`;
        if (skippedCount > 0 && deletedCount > 0) {
            message += ` ${skippedCount} skipped because they were no longer unlinked.`;
        }
        setCloudflareOrphanPdfStatus(message);
    } catch (err) {
        console.warn("Unable to delete selected Cloudflare unlinked PDFs.", err);
        setCloudflareOrphanPdfStatus(err.message || "Unable to delete selected unlinked PDFs.", true);
    } finally {
        if (button && button.isConnected) {
            button.textContent = originalText || "Delete Selected Unlinked PDFs";
        }
        updateCloudflareUnlinkedDeleteButton();
    }

    return false;
}

async function checkAndDeleteAllCloudflareUnlinkedPdfs(button) {
    const originalText = button ? button.textContent : "";

    if (button) {
        button.disabled = true;
        button.textContent = "Checking...";
    }
    setCloudflareOrphanPdfStatus("Checking Cloudflare PDFs before deletion...");

    try {
        const scanResponse = await fetch("/pdfs/cloudflare_unlinked", {
            method: "GET",
            headers: {
                "X-Requested-With": "fetch",
            },
        });
        const scanData = await scanResponse.json();

        if (!scanResponse.ok || !scanData.ok) {
            throw new Error(scanData.error || "Unable to check Cloudflare PDFs.");
        }

        renderCloudflareOrphanPdfs(scanData);
        const keys = cloudflareUnlinkedPdfKeysFromData(scanData);
        const unlinkedCount = Number(scanData.unlinked_pdf_count || scanData.orphaned_pdf_count || keys.length || 0);

        if (keys.length === 0) {
            setCloudflareOrphanPdfStatus("No unlinked PDFs found.");
            return false;
        }

        const allLabel = `${keys.length} unlinked PDF${keys.length === 1 ? "" : "s"}`;
        if (!window.confirm(`Delete all ${allLabel} from Cloudflare R2? This cannot be undone.`)) {
            setCloudflareOrphanPdfStatus(cloudflareOrphanPdfLabel(unlinkedCount));
            return false;
        }

        if (button) {
            button.textContent = "Deleting...";
        }
        setCloudflareOrphanPdfStatus(`Deleting all ${allLabel}...`);

        const deleteResponse = await fetch("/pdfs/cloudflare_unlinked/delete", {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
                "X-Requested-With": "fetch",
            },
            body: JSON.stringify({
                object_keys: keys,
            }),
        });
        let deleteData = {};
        try {
            deleteData = await deleteResponse.json();
        } catch (_err) {
            deleteData = {};
        }

        if (Array.isArray(deleteData.unlinked_pdfs) || Array.isArray(deleteData.orphaned_pdfs)) {
            renderCloudflareOrphanPdfs(deleteData);
        }

        if (!deleteResponse.ok || !deleteData.ok) {
            throw new Error(deleteData.error || deleteData.message || "Unable to delete all unlinked PDFs.");
        }

        const deletedCount = Number(deleteData.deleted_count || 0);
        const skippedCount = Number(deleteData.skipped_count || 0);
        let message = `Deleted ${deletedCount} unlinked PDF${deletedCount === 1 ? "" : "s"}.`;
        if (skippedCount > 0 && deletedCount > 0) {
            message += ` ${skippedCount} skipped because they were no longer unlinked.`;
        }
        setCloudflareOrphanPdfStatus(message);
    } catch (err) {
        console.warn("Unable to check and delete all Cloudflare unlinked PDFs.", err);
        setCloudflareOrphanPdfStatus(err.message || "Unable to delete all unlinked PDFs.", true);
    } finally {
        if (button && button.isConnected) {
            button.disabled = false;
            button.textContent = originalText || "Check and Delete All Unlinked PDFs";
        }
        updateCloudflareUnlinkedDeleteButton();
    }

    return false;
}

function deleteAllCloudflareOrphanPdfs(button) {
    return checkAndDeleteAllCloudflareUnlinkedPdfs(button);
}

function updatePdfShareRow(row, data) {
    const panel = row ? row.querySelector(".pdf-share-active") : null;
    const input = row ? row.querySelector(".pdf-share-url") : null;
    const expires = row ? row.querySelector(".pdf-share-expires") : null;
    const revokeButton = row ? row.querySelector(".pdf-share-action-btn.danger") : null;

    if (!row || !panel || !input) {
        return;
    }

    row.dataset.pdfShareToken = data.token || "";
    input.value = data.share_url || "";
    panel.hidden = !input.value;

    if (expires) {
        expires.textContent = data.expires_at ? `Expires ${data.expires_at}` : "";
    }

    if (revokeButton) {
        revokeButton.dataset.pdfShareToken = data.token || "";
    }
}

function updatePdfCloudflareRow(row, data) {
    const publicUrl = data.pdf_public_url || data.public_url || "";
    const openLink = row ? row.querySelector("[data-pdf-open-link]") : null;
    const panel = row ? row.querySelector(".pdf-cloudflare-active") : null;
    const input = row ? row.querySelector(".pdf-cloudflare-url") : null;

    if (!row || !publicUrl) {
        return;
    }

    row.dataset.pdfPublicUrl = publicUrl;

    if (openLink) {
        openLink.href = publicUrl;
    }

    if (input) {
        input.value = publicUrl;
    }

    if (panel) {
        panel.hidden = false;
    }
}

async function uploadPdfToCloudflare(button) {
    const row = pdfShareRowForButton(button);
    const pdfFilename = row ? row.dataset.pdfFilename : "";

    if (!row || !pdfFilename) {
        return false;
    }

    const originalText = button ? button.textContent : "";

    if (button) {
        button.disabled = true;
        button.textContent = "Uploading...";
    }

    try {
        const response = await fetch("/pdfs/cloudflare_upload", {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
                "X-Requested-With": "fetch",
            },
            body: JSON.stringify({ pdf_filename: pdfFilename }),
        });
        const data = await response.json();

        if (!response.ok || !data.success) {
            throw new Error(data.error || "Unable to upload PDF to Cloudflare.");
        }

        updatePdfCloudflareRow(row, data);
        setPdfShareStatus(
            row,
            data.already_exists
                ? "Cloudflare PDF link saved."
                : "Uploaded to Cloudflare."
        );
    } catch (err) {
        console.warn("Unable to upload PDF to Cloudflare.", err);
        setPdfShareStatus(row, err.message || "Unable to upload PDF to Cloudflare.", true);
    } finally {
        if (button && button.isConnected) {
            button.disabled = false;
            button.textContent = originalText || "Upload to Cloudflare";
        }
    }

    return false;
}

async function copyPdfCloudflareLink(button) {
    const row = pdfShareRowForButton(button);
    const input = row ? row.querySelector(".pdf-cloudflare-url") : null;
    const publicUrl = (
        (row && row.dataset.pdfPublicUrl ? row.dataset.pdfPublicUrl : "")
        || (input ? input.value.trim() : "")
    );

    if (!publicUrl) {
        setPdfShareStatus(row, "Cloudflare link is not ready yet.", true);
        return false;
    }

    if (!isShareablePublicPdfUrl(publicUrl)) {
        setPdfShareStatus(row, "Cloudflare PDF link is not ready yet.", true);
        return false;
    }

    try {
        if (navigator.clipboard && navigator.clipboard.writeText) {
            await navigator.clipboard.writeText(publicUrl);
        } else if (input) {
            input.select();
            document.execCommand("copy");
        }

        setPdfShareStatus(row, "Cloudflare link copied.");
    } catch (err) {
        console.warn("Unable to copy Cloudflare PDF link.", err);
        if (input) {
            input.select();
        }
        setPdfShareStatus(row, "PDF link selected. Use Ctrl+C to copy.", true);
    }

    return false;
}

