function normalizedRecipeEditorCacheKey(url) {
    return String(url || "").trim();
}

function recipeEditorCacheEntryIsFresh(entry) {
    return Boolean(
        entry
        && entry.recipe
        && Number.isFinite(entry.savedAt)
        && Date.now() - entry.savedAt < RECIPE_EDITOR_CACHE_TTL_MS
    );
}

function rememberRecipeEditorData(url, data) {
    const key = normalizedRecipeEditorCacheKey(url);
    const recipe = data && data.recipe ? data.recipe : data;

    if (!key || !recipe || typeof recipe !== "object") {
        return recipe || {};
    }

    recipeEditorDataCache.set(key, {
        savedAt: Date.now(),
        recipe,
        storeSections: Array.isArray(data && data.store_sections) ? data.store_sections : recipeEditStoreSections,
        foodRules: data && data.food_rules ? data.food_rules : recipeEditFoodRules,
    });

    return recipe;
}

function rememberRecipeFavoriteState(recipeUrls, favorite) {
    const targetUrls = new Set(
        (Array.isArray(recipeUrls) ? recipeUrls : [recipeUrls])
            .map(url => normalizedRecipeEditorCacheKey(url))
            .filter(Boolean)
    );
    if (!targetUrls.size) {
        return;
    }

    const isFavorite = Boolean(favorite);
    recipeEditorDataCache.forEach((entry, cacheUrl) => {
        const recipe = entry && entry.recipe;
        if (!recipe || typeof recipe !== "object") {
            return;
        }
        const candidateUrls = [
            cacheUrl,
            recipe.source_url,
            recipe.url,
            recipe.original_url,
            recipe.recipe_url,
        ].map(url => normalizedRecipeEditorCacheKey(url)).filter(Boolean);
        if (!candidateUrls.some(url => targetUrls.has(url))) {
            return;
        }
        recipe.favorite = isFavorite;
        entry.savedAt = Date.now();
    });

    const editorFavoriteButton = document.getElementById("recipeEditFavoriteButton");
    const editorRecipeUrl = normalizedRecipeEditorCacheKey(editorFavoriteButton?.dataset.recipeUrl || "");
    if (recipeEditOriginalSnapshot && targetUrls.has(editorRecipeUrl)) {
        recipeEditOriginalSnapshot.favorite = isFavorite;
    }
}

function applyRecipeEditorDataContext(entry) {
    if (!entry) {
        return;
    }

    recipeEditStoreSections = Array.isArray(entry.storeSections) ? entry.storeSections : [];
    recipeEditFoodRules = entry.foodRules || { require: [], avoid: [] };
}

function invalidateRecipeEditorCache(url = "") {
    const key = normalizedRecipeEditorCacheKey(url);

    if (key) {
        recipeEditorDataCache.delete(key);
        return;
    }

    recipeEditorDataCache.clear();
}

async function fetchRecipeEditorDataFromServer(url) {
    const response = await fetch(`/api/recipe?url=${encodeURIComponent(url)}`, {
        cache: "no-store",
    });
    const data = await response.json();

    if (!response.ok || !data.ok) {
        throw new Error((data && data.error) || "Unable to load recipe.");
    }

    return data;
}

async function fetchRecipeEditorData(url, options = {}) {
    const key = normalizedRecipeEditorCacheKey(url);
    const useCache = options.useCache !== false;
    const cached = useCache ? recipeEditorDataCache.get(key) : null;

    if (recipeEditorCacheEntryIsFresh(cached)) {
        applyRecipeEditorDataContext(cached);
        return cached.recipe;
    }
    if (useCache && cached && cached.promise) {
        await cached.promise;
        const fresh = recipeEditorDataCache.get(key);
        if (recipeEditorCacheEntryIsFresh(fresh)) {
            applyRecipeEditorDataContext(fresh);
            return fresh.recipe;
        }
    }

    const data = await fetchRecipeEditorDataFromServer(key);
    const recipe = rememberRecipeEditorData(key, data);
    const fresh = recipeEditorDataCache.get(key);
    applyRecipeEditorDataContext(fresh);
    return recipe;
}

function prefetchRecipeEditorData(url) {
    const key = normalizedRecipeEditorCacheKey(url);
    const cached = recipeEditorDataCache.get(key);

    if (!key || recipeEditorCacheEntryIsFresh(cached) || (cached && cached.promise)) {
        return;
    }

    const promise = fetchRecipeEditorDataFromServer(key)
        .then(data => {
            rememberRecipeEditorData(key, data);
        })
        .catch(err => {
            recipeEditorDataCache.delete(key);
            console.debug("Recipe editor prefetch skipped.", err);
        });

    recipeEditorDataCache.set(key, {
        savedAt: Date.now(),
        promise,
    });
}

function prefetchRecipeEditorDataFromTarget(target) {
    const trigger = target && target.closest
        ? target.closest(
            "[data-recipe-url][onclick*='openRecipeEditor'], "
            + "[data-recipe-url][onclick*='openRecipeFoodReviewFromRecipeView'], "
            + "[data-recipe-url][onclick*='openIngredientFoodReviewFromRecipeView'], "
            + "[data-recipe-url][onclick*='openRecipeEditPageFromMenu']"
        )
        : null;
    const recipeUrl = trigger ? trigger.dataset.recipeUrl || "" : "";

    if (recipeUrl) {
        prefetchRecipeEditorData(recipeUrl);
    }
}

function bindRecipeEditorPrefetch() {
    if (recipeEditorPrefetchBound || !document.body) {
        return;
    }

    recipeEditorPrefetchBound = true;
    document.body.addEventListener("pointerover", event => {
        prefetchRecipeEditorDataFromTarget(event.target);
    }, { passive: true });
    document.body.addEventListener("focusin", event => {
        prefetchRecipeEditorDataFromTarget(event.target);
    });
}

function recipeEditCategoryValuesFromRecipe(recipe = {}) {
    const values = {};

    RECIPE_EDIT_CATEGORY_FIELD_NAMES.forEach(field => {
        values[field] = String(recipe[field] || "").trim();
    });

    values.custom_categories = Array.isArray(recipe.custom_categories)
        ? recipe.custom_categories.join(", ")
        : String(recipe.custom_categories || "").trim();

    return values;
}

function recipeEditCategorySourcesFromRecipe(recipe = {}, values = null) {
    const categoryValues = values || recipeEditCategoryValuesFromRecipe(recipe);
    return Object.fromEntries(RECIPE_EDIT_CATEGORY_ALL_FIELD_NAMES.map(field => [
        field,
        normalizeCategorySource(
            recipe.category_metadata_sources ? recipe.category_metadata_sources[field] : "",
            field,
            categoryValues[field],
        ),
    ]));
}

function collectRecipeEditorCategoryValues() {
    const form = document.getElementById("recipeEditForm");
    const values = {};

    RECIPE_EDIT_CATEGORY_FIELD_NAMES.forEach(field => {
        const input = form ? form.elements[field] : null;
        values[field] = input ? String(input.value || "").trim() : "";
    });

    const customInput = form ? form.elements.custom_categories : null;
    values.custom_categories = customInput ? String(customInput.value || "").trim() : "";
    return values;
}

function collectRecipeEditorCategorySources() {
    return collectFormCategorySources(document.getElementById("recipeEditForm"));
}

function recipeEditCategorySnapshotKey(values = {}) {
    const normalized = {};

    RECIPE_EDIT_CATEGORY_FIELD_NAMES.forEach(field => {
        normalized[field] = String(values[field] || "").trim();
    });
    normalized.custom_categories = String(values.custom_categories || "").trim();
    return JSON.stringify(normalized);
}

function recipeEditCategorySourcesSnapshotKey(sources = {}, values = null) {
    const normalized = {};
    const categoryValues = values || collectRecipeEditorCategoryValues();

    RECIPE_EDIT_CATEGORY_ALL_FIELD_NAMES.forEach(field => {
        normalized[field] = normalizeCategorySource(sources[field], field, categoryValues[field]);
    });

    return JSON.stringify(normalized);
}

function originalRecipeEditCategoryValues() {
    const form = document.getElementById("recipeEditForm");

    if (!form || !form.dataset.originalCategoryValues) {
        return {};
    }

    try {
        return JSON.parse(form.dataset.originalCategoryValues) || {};
    } catch (err) {
        return {};
    }
}

function originalRecipeEditCategorySources() {
    const form = document.getElementById("recipeEditForm");

    if (!form || !form.dataset.originalCategorySources) {
        return {};
    }

    try {
        return JSON.parse(form.dataset.originalCategorySources) || {};
    } catch (err) {
        return {};
    }
}

function recipeEditCategoryValuesChanged() {
    const section = document.getElementById("recipeEditCategoriesSection");

    if (!section) {
        return false;
    }

    return recipeEditCategorySnapshotKey(collectRecipeEditorCategoryValues())
        !== recipeEditCategorySnapshotKey(originalRecipeEditCategoryValues())
        || recipeEditCategorySourcesSnapshotKey(collectRecipeEditorCategorySources(), collectRecipeEditorCategoryValues())
        !== recipeEditCategorySourcesSnapshotKey(originalRecipeEditCategorySources(), originalRecipeEditCategoryValues());
}

function recipeEditCategoryValuesHaveAny(values = {}) {
    return RECIPE_EDIT_CATEGORY_FIELD_NAMES.some(field => String(values[field] || "").trim())
        || Boolean(String(values.custom_categories || "").trim());
}

function populateRecipeEditCategories(recipe = {}) {
    const form = document.getElementById("recipeEditForm");
    const values = recipeEditCategoryValuesFromRecipe(recipe);
    const sources = recipeEditCategorySourcesFromRecipe(recipe, values);
    const recipeName = document.getElementById("recipeEditCategoryRecipeName");

    if (!form) {
        return;
    }

    form.dataset.originalCategoryValues = JSON.stringify(values);
    form.dataset.originalCategorySources = JSON.stringify(sources);
    form.dataset.categoryUserSet = recipe.category_metadata_user_set ? "1" : "0";
    setFormCategorySources(form, sources, values);

    RECIPE_EDIT_CATEGORY_FIELD_NAMES.forEach(field => {
        setCookbookCategoryFieldValue(form, field, values[field]);
    });
    updateRecipeEditorMenuSectionOptions(currentRecipeEditorCookbookId(), values.menu_section);
    setCookbookCategoryFieldValue(form, "custom_categories", values.custom_categories);

    if (recipeName) {
        recipeName.textContent = recipe.display_name || recipe.recipe_title || "Recipe";
    }

    const sourceLabel = recipe.category_metadata_source
        || (recipe.category_metadata_user_set ? "Saved" : "Blank");
    setRecipeEditCategorySourceLabel(sourceLabel);
    renderRecipeEditCuisineChips();
}

function bindRecipeEditCategorySourceTracking() {
    const form = document.getElementById("recipeEditForm");

    if (!form || form.dataset.categorySourceTrackingBound === "1") {
        return;
    }

    form.dataset.categorySourceTrackingBound = "1";
    RECIPE_EDIT_CATEGORY_ALL_FIELD_NAMES.forEach(field => {
        const input = form.elements[field];

        if (!input) {
            return;
        }

        const markUserSelected = () => {
            setFormCategorySource(form, field, CATEGORY_SOURCE_USER_SELECTED);
            setRecipeEditCategorySourceLabel("Saved");
        };

        input.addEventListener("change", markUserSelected);
        if (input.tagName !== "SELECT") {
            input.addEventListener("input", markUserSelected);
        }
    });
}

function currentRecipeEditorCookbookId() {
    const field = document.getElementById("recipeEditCookbookField");
    return field ? String(field.dataset.currentCookbookId || "").trim() : "";
}

function recipeEditorCategoryFormData(recipeUrl, values, confirmOverwrite = false) {
    const formData = new FormData();

    formData.set("recipe_url", recipeUrl || "");
    RECIPE_EDIT_CATEGORY_FIELD_NAMES.forEach(field => {
        formData.set(field, values[field] || "");
    });
    formData.set("custom_categories", values.custom_categories || "");
    formData.set("category_sources", JSON.stringify(collectRecipeEditorCategorySources()));

    if (confirmOverwrite) {
        formData.set("confirm_overwrite", "1");
    }

    return formData;
}

async function postRecipeEditorCategories(cookbookId, recipeUrl, values, confirmOverwrite = false) {
    const url = `/api/cookbooks/${encodeURIComponent(cookbookId)}/recipe_categories`;
    return submitCookbookApi(url, recipeEditorCategoryFormData(recipeUrl, values, confirmOverwrite));
}

async function postRecipeEditorCategoriesWithConfirmation(cookbookId, recipeUrl, values) {
    try {
        return await postRecipeEditorCategories(cookbookId, recipeUrl, values);
    } catch (err) {
        const needsConfirmation = err.status === 409
            && err.data
            && err.data.conflict === "cookbook_category_overwrite";

        if (!needsConfirmation) {
            throw err;
        }

        const recipeName = err.data.recipe_name || "this recipe";
        const confirmed = window.confirm(`Replace saved cookbook categories for ${recipeName}?`);

        if (!confirmed) {
            return { ok: true, canceled: true };
        }

        return postRecipeEditorCategories(cookbookId, recipeUrl, values, true);
    }
}

function shouldRetryRecipeCategoryFallback(err) {
    const message = String((err && err.message) || (err && err.data && err.data.error) || "").toLowerCase();
    return err && err.status === 400 && message.includes("not found");
}

async function saveRecipeEditorCategories(savedSourceUrl = "", fallbackUrl = "") {
    if (!recipeEditCategoryValuesChanged()) {
        return { skipped: true };
    }

    const cookbookId = currentRecipeEditorCookbookId();

    if (!cookbookId) {
        return { skipped: true, reason: "No cookbook assigned." };
    }

    const values = collectRecipeEditorCategoryValues();
    const primaryUrl = String(savedSourceUrl || fallbackUrl || recipeEditorCurrentUrl() || "").trim();
    const fallbackRecipeUrl = String(fallbackUrl || "").trim();

    try {
        const result = await postRecipeEditorCategoriesWithConfirmation(cookbookId, primaryUrl, values);
        if (result && result.canceled) {
            return { canceled: true };
        }
    } catch (err) {
        if (!fallbackRecipeUrl || fallbackRecipeUrl === primaryUrl || !shouldRetryRecipeCategoryFallback(err)) {
            throw err;
        }

        const fallbackResult = await postRecipeEditorCategoriesWithConfirmation(cookbookId, fallbackRecipeUrl, values);
        if (fallbackResult && fallbackResult.canceled) {
            return { canceled: true };
        }
    }

    return {
        saved: true,
        values,
        userSet: recipeEditCategoryValuesHaveAny(values),
    };
}

function recipeEditCategorySuggestionValue(categories, field) {
    const value = categories && categories[field];

    if (Array.isArray(value)) {
        return value
            .map(item => String(item || "").trim())
            .filter(Boolean)
            .join(", ");
    }

    return String(value || "").trim();
}

function formatRecipeEditCategorySourceLabel(label) {
    const normalized = String(label || "Blank").trim() || "Blank";
    return /^ai[\s_-]*inferred$/i.test(normalized) ? "AI Inferred" : normalized;
}

function setRecipeEditCategorySourceLabel(label) {
    const source = document.getElementById("recipeEditCategorySource");

    if (source) {
        const formattedLabel = formatRecipeEditCategorySourceLabel(label);
        source.textContent = `Categories: ${formattedLabel}`;
        source.dataset.categoryStatus = formattedLabel.toLowerCase().replace(/[^a-z0-9]+/g, "-");
    }
}

function setRecipeEditCategoriesExpanded(expanded, button = null) {
    const section = document.getElementById("recipeEditCategoriesSection");
    const region = document.getElementById("recipeEditCategoriesBody");
    const toggle = button || (section ? section.querySelector("[data-recipe-edit-category-collapse]") : null);
    const isExpanded = Boolean(expanded);

    if (!section || !region || !toggle) {
        return false;
    }

    section.classList.toggle("is-collapsed", !isExpanded);
    toggle.setAttribute("aria-expanded", isExpanded ? "true" : "false");
    toggle.setAttribute("aria-label", isExpanded ? "Collapse recipe categories" : "Expand recipe categories");
    toggle.title = isExpanded ? "Collapse recipe categories" : "Expand recipe categories";
    region.setAttribute("aria-hidden", isExpanded ? "false" : "true");
    region.toggleAttribute("inert", !isExpanded);
    return true;
}

function toggleRecipeEditCategories(button) {
    const isExpanded = button && button.getAttribute("aria-expanded") === "true";
    setRecipeEditCategoriesExpanded(!isExpanded, button);
    return false;
}

function applyRecipeEditCategorySuggestions(categories = {}, mode = "missing") {
    const form = document.getElementById("recipeEditForm");
    const overwrite = mode === "all";
    let applied = false;

    if (!form) {
        return;
    }

    RECIPE_EDIT_CATEGORY_AI_FIELD_NAMES.forEach(field => {
        const input = form.elements[field];
        const currentValue = input ? String(input.value || "").trim() : "";
        const nextValue = recipeEditCategorySuggestionValue(categories, field);

        if (input && overwrite) {
            setCookbookCategoryFieldValue(form, field, nextValue);
            setFormCategorySource(form, field, CATEGORY_SOURCE_AI_INFERRED);
            applied = true;
        } else if (input && nextValue && !currentValue) {
            setCookbookCategoryFieldValue(form, field, nextValue);
            setFormCategorySource(form, field, CATEGORY_SOURCE_AI_INFERRED);
            applied = true;
        }
    });

    const customInput = form.elements.custom_categories;
    const currentCustom = customInput ? String(customInput.value || "").trim() : "";
    const nextCustom = recipeEditCategorySuggestionValue(categories, "custom_categories");

    if (customInput && overwrite) {
        setCookbookCategoryFieldValue(form, "custom_categories", nextCustom);
        setFormCategorySource(form, "custom_categories", CATEGORY_SOURCE_AI_INFERRED);
        applied = true;
    } else if (customInput && nextCustom && !currentCustom) {
        setCookbookCategoryFieldValue(form, "custom_categories", nextCustom);
        setFormCategorySource(form, "custom_categories", CATEGORY_SOURCE_AI_INFERRED);
        applied = true;
    }

    if (applied) {
        setRecipeEditCategorySourceLabel("AI inferred");
    }
}

async function decideRecipeEditCategoriesWithChatGPT(button, mode = "missing", options = {}) {
    const decisionMode = mode === "all" ? "all" : "missing";
    const originalText = button ? button.textContent : "";
    const returnResult = Boolean(options.returnResult);
    const setStatusMessages = options.setStatus !== false;

    closeRecipeEditRowMenus();

    if (
        decisionMode === "all"
        && recipeEditCategoryValuesHaveAny(collectRecipeEditorCategoryValues())
        && options.confirmOverwrite !== false
        && !window.confirm("ChatGPT will replace the current category selections. Continue?")
    ) {
        return returnResult ? { ok: false, canceled: true } : false;
    }

    if (button) {
        button.disabled = true;
        button.textContent = "Asking...";
    }

    try {
        if (setStatusMessages) {
            setRecipeEditStatus("Asking ChatGPT to choose recipe categories...");
        }
        const payload = collectRecipeEditorPayload();
        const startData = await startBackgroundJob("/api/jobs/recipe-category-decision", {
            button,
            creatingText: "Starting...",
            payload: {
                recipe: payload.recipe,
                mode: decisionMode,
                trigger_source: `recipe_editor:${decisionMode}`,
                current_categories: collectRecipeEditorCategoryValues(),
            },
        });
        if (button) {
            button.disabled = true;
            button.textContent = "Asking...";
        }
        const finishedJob = await waitForJobCompletion(startData.job_id, {
            onUpdate(job) {
                if (setStatusMessages) {
                    setRecipeEditStatus(job.current_step || "Asking ChatGPT to choose recipe categories...");
                }
            },
        });
        const data = finishedJob && finishedJob.result_payload && typeof finishedJob.result_payload === "object"
            ? finishedJob.result_payload
            : {};
        syncOpenAiUsageDashboardFromResponse(data);

        if (!finishedJob || finishedJob.status !== "completed" || !data.ok) {
            throw new Error((finishedJob && finishedJob.error_message) || (data && data.error) || "Unable to choose recipe categories.");
        }

        applyRecipeEditCategorySuggestions(data.categories || {}, decisionMode);
        if (setStatusMessages) {
            setRecipeEditStatus(
                decisionMode === "all"
                    ? "ChatGPT filled recipe categories. Save Recipe to keep them."
                    : "ChatGPT filled missing recipe categories. Save Recipe to keep them."
            );
        }
        return returnResult ? { ok: true, data, categories: data.categories || {} } : false;
    } catch (err) {
        console.warn("Unable to choose recipe categories.", err);
        if (setStatusMessages) {
            setRecipeEditStatus(err.message || "Unable to choose recipe categories.", true);
        }
        if (options.throwOnError) {
            throw err;
        }
        return returnResult ? { ok: false, error: err } : false;
    } finally {
        if (button && button.isConnected) {
            button.disabled = false;
            button.textContent = originalText || (
                decisionMode === "all"
                    ? "Have ChatGPT Decide All"
                    : "Have ChatGPT Decide Missing"
            );
        }
    }
}

async function openRecipeEditor(button, options = {}) {
    const url = button ? button.dataset.recipeUrl || "" : "";
    let modal = document.getElementById("recipeEditModal");
    const optionObject = options && typeof options === "object" ? options : {};
    const shouldScrollToFoodReview = options === true || Boolean(options.scrollToFoodReview);
    const shouldActivateFoodReview = Boolean(optionObject.activateFoodReview);
    const shouldInferMissingDetails = Boolean(optionObject.inferMissingDetails);
    const targetIngredient = Object.keys(optionObject).length
        ? String(optionObject.ingredient || optionObject.scrollToIngredient || "").trim()
        : "";
    const targetSection = Object.keys(optionObject).length
        ? String(optionObject.section || optionObject.scrollToSection || "").trim()
        : "";

    if (!url) {
        return;
    }

    if (!modal && lazySectionElement("current-recipes")) {
        await loadLazySection("current-recipes", { allowDuringAuthCollapse: true });
        modal = document.getElementById("recipeEditModal");
    }

    if (!modal && lazySectionElement("recipe-view")) {
        await loadLazySection("recipe-view", { allowDuringAuthCollapse: true });
        modal = document.getElementById("recipeEditModal");
    }

    if (!modal) {
        console.warn("Unable to open recipe editor: modal markup is not loaded.");
        openRecipeEditPageFallback(button, url, options);
        return;
    }

    initRecipeEditTabs();
    initRecipeEditContextPanels();
    rememberRecipeEditorReturnState(button, url);
    recipeEditInferenceContext = {};
    syncRecipeEditSourceFilesDetails();
    setRecipeEditStatus("Loading recipe...");
    modal.classList.add("open");
    modal.setAttribute("aria-hidden", "false");
    document.body.classList.add("modal-open");
    document.body.classList.add("recipe-editor-open");
    await waitForNextPaint();

    try {
        const recipe = await fetchRecipeEditorData(url);
        populateRecipeEditor(recipe, url);
        requestAnimationFrame(updateRecipeEditStickyOffsets);
        setRecipeEditStatus("");
        if (shouldScrollToFoodReview) {
            await waitForNextPaint();
            const marker = scrollRecipeEditorToFoodReview({ focus: !shouldActivateFoodReview });
            if (shouldActivateFoodReview) {
                if (marker) {
                    await activateRecipeEditorFoodReviewMarker(marker);
                } else {
                    setRecipeEditStatus("No food review item found in this recipe.", true);
                }
            }
        } else if (targetIngredient) {
            await waitForNextPaint();
            const row = scrollRecipeEditorToIngredient(targetIngredient, { focus: !shouldActivateFoodReview });
            if (shouldActivateFoodReview) {
                const marker = recipeEditorFoodReviewMarkerForRow(row);
                if (marker) {
                    await activateRecipeEditorFoodReviewMarker(marker);
                } else {
                    setRecipeEditStatus(`Food review not found for: ${targetIngredient}`, true);
                }
            }
        } else if (targetSection) {
            await waitForNextPaint();
            scrollRecipeEditorToSection(targetSection);
        }
        if (shouldInferMissingDetails) {
            await waitForNextPaint();
            applyRecipeEditorInferenceOptions(optionObject);
            await inferMissingRecipeDetails(document.querySelector(".recipe-edit-ai-infer"));
        }
    } catch (err) {
        console.warn("Unable to open recipe editor.", err);
        setRecipeEditStatus("Unable to load recipe.", true);
    }
}

function openRecipeEditorFromMenu(button, options = {}, event = null) {
    const recipeUrl = button ? button.dataset.recipeUrl || "" : "";

    if (event && shouldLetRecipeEditorLinkNavigate(event)) {
        return true;
    }

    if (event) {
        event.preventDefault();
        event.stopPropagation();
    }

    closeRecipeEditRowMenus();

    if (!recipeUrl) {
        return false;
    }

    window.requestAnimationFrame(() => {
        openRecipeEditor(button, options);
    });
    return false;
}

function openRecipeEditPageFromMenu(link, event = null) {
    if (event && shouldLetRecipeEditorLinkNavigate(event)) {
        return true;
    }

    if (event) {
        event.stopPropagation();
    }

    rememberRecipeEditPageReturnState(link);
    closeRecipeEditRowMenus();
    return true;
}

function shouldLetRecipeEditorLinkNavigate(event) {
    return Boolean(
        event.defaultPrevented
        || event.button > 0
        || event.metaKey
        || event.ctrlKey
        || event.shiftKey
        || event.altKey
    );
}

function recipeEditorStandalonePageIsActive() {
    return Boolean(document.body && document.body.dataset.recipeEditPage === "true");
}

function recipeEditorSurfaceIsActive(modal) {
    return Boolean(modal && (modal.classList.contains("open") || recipeEditorStandalonePageIsActive()));
}

function recipeEditPageUrl(recipeUrl) {
    const normalizedUrl = String(recipeUrl || "").trim();

    if (!normalizedUrl) {
        return "";
    }

    return `/recipe/edit?url=${encodeURIComponent(normalizedUrl)}`;
}

function recipeEditPendingActionFromOptions(recipeUrl, options = {}) {
    const normalizedUrl = String(recipeUrl || "").trim();

    if (!normalizedUrl) {
        return null;
    }

    const action = {
        recipeUrl: normalizedUrl,
        createdAt: Date.now(),
    };
    const optionObject = options && typeof options === "object" ? options : {};
    const targetIngredient = String(optionObject.ingredient || optionObject.scrollToIngredient || "").trim();
    const targetSection = String(optionObject.section || optionObject.scrollToSection || "").trim();

    if (options === true || Boolean(optionObject.scrollToFoodReview)) {
        action.scrollToFoodReview = true;
    }

    if (targetIngredient) {
        action.scrollToIngredient = targetIngredient;
    }

    if (targetSection) {
        action.scrollToSection = targetSection;
    }

    if (Boolean(optionObject.activateFoodReview)) {
        action.activateFoodReview = true;
    }

    if (Boolean(optionObject.inferMissingDetails)) {
        action.inferMissingDetails = true;
        action.cookbookId = String(optionObject.cookbookId || optionObject.cookbook_id || "").trim();
        action.cookbookName = String(optionObject.cookbookName || optionObject.cookbook_name || "").trim();
        action.overwriteAiFields = Boolean(optionObject.overwriteAiFields);
        action.previewOnly = Boolean(optionObject.previewOnly);
    }

    return action;
}

function rememberRecipeEditPendingAction(recipeUrl, options = {}) {
    if (recipeEditorStandalonePageIsActive() || !window.sessionStorage) {
        return;
    }

    const action = recipeEditPendingActionFromOptions(recipeUrl, options);

    if (!action) {
        return;
    }

    safeStorageSet(sessionStorage, RECIPE_EDIT_PENDING_ACTION_KEY, JSON.stringify(action));
}

function consumeRecipeEditPendingAction(recipeUrl) {
    if (!window.sessionStorage) {
        return {};
    }

    let action = null;

    try {
        action = JSON.parse(safeStorageGet(sessionStorage, RECIPE_EDIT_PENDING_ACTION_KEY) || "null");
    } catch (err) {
        action = null;
    }

    if (!action || !action.recipeUrl) {
        return {};
    }

    const normalizedUrl = String(recipeUrl || "").trim();
    const actionUrl = String(action.recipeUrl || "").trim();
    const isStale = action.createdAt && Date.now() - Number(action.createdAt) > 10 * 60 * 1000;

    if (isStale || actionUrl === normalizedUrl) {
        safeStorageRemove(sessionStorage, RECIPE_EDIT_PENDING_ACTION_KEY);
    }

    if (isStale || actionUrl !== normalizedUrl) {
        return {};
    }

    return {
        scrollToFoodReview: Boolean(action.scrollToFoodReview),
        scrollToIngredient: String(action.scrollToIngredient || "").trim(),
        scrollToSection: String(action.scrollToSection || "").trim(),
        activateFoodReview: Boolean(action.activateFoodReview),
        inferMissingDetails: Boolean(action.inferMissingDetails),
        cookbookId: String(action.cookbookId || "").trim(),
        cookbookName: String(action.cookbookName || "").trim(),
        overwriteAiFields: Boolean(action.overwriteAiFields),
        previewOnly: Boolean(action.previewOnly),
    };
}

function openRecipeEditPageFallback(button, recipeUrl, options = {}) {
    if (recipeEditorStandalonePageIsActive()) {
        return false;
    }

    const pageUrl = recipeEditPageUrl(recipeUrl);

    if (!pageUrl) {
        return false;
    }

    rememberRecipeEditPageReturnState(button);
    rememberRecipeEditPendingAction(recipeUrl, options);
    window.location.assign(pageUrl);
    return true;
}

function recipeEditorSourceCardFromTrigger(triggerElement) {
    if (!triggerElement) {
        return null;
    }

    const triggerMenu = triggerElement.closest(".recipe-edit-row-menu");
    const anchorButton = triggerMenu && triggerMenu.recipeEditAnchorButton
        ? triggerMenu.recipeEditAnchorButton
        : null;

    return triggerElement.closest("[data-recipe-view-card], [data-current-recipe-row], [data-cookbook-recipe-card]")
        || (anchorButton
            ? anchorButton.closest("[data-recipe-view-card], [data-current-recipe-row], [data-cookbook-recipe-card]")
            : null);
}

function rememberRecipeEditorReturnState(trigger, recipeUrl) {
    if (recipeEditorStandalonePageIsActive()) {
        return;
    }

    const triggerElement = trigger && trigger.nodeType === 1 ? trigger : null;
    const sourceCard = recipeEditorSourceCardFromTrigger(triggerElement);

    recipeEditReturnState = {
        recipeUrl: String(recipeUrl || "").trim(),
        scrollX: window.scrollX,
        scrollY: window.scrollY,
        sourceSurface: recipeEditorReturnSurface(sourceCard),
    };
}

function rememberRecipeEditPageReturnState(trigger) {
    if (recipeEditorStandalonePageIsActive() || !window.sessionStorage) {
        return;
    }

    const triggerElement = trigger && trigger.nodeType === 1 ? trigger : null;
    const recipeUrl = triggerElement ? String(triggerElement.dataset.recipeUrl || "").trim() : "";
    const sourceCard = recipeEditorSourceCardFromTrigger(triggerElement);

    if (!recipeUrl) {
        return;
    }

    const state = {
        recipeUrl,
        scrollX: window.scrollX,
        scrollY: window.scrollY,
        sourceSurface: recipeEditorReturnSurface(sourceCard),
        pageUrl: window.location.href,
        createdAt: Date.now(),
    };

    try {
        sessionStorage.setItem(RECIPE_EDIT_PAGE_RETURN_STATE_KEY, JSON.stringify(state));
    } catch (err) {
        console.warn("Unable to remember recipe edit return location.", err);
    }
}

function recipeEditorReturnSurface(card) {
    if (!card || !card.matches) {
        return "";
    }

    if (card.matches("[data-recipe-view-card]")) {
        return "recipe-view";
    }

    if (card.matches("[data-current-recipe-row]")) {
        return "current-recipes";
    }

    if (card.matches("[data-cookbook-recipe-card]")) {
        return "cookbooks";
    }

    return "";
}

function recipeEditorReturnSelectors(state) {
    const recipeUrl = state && state.recipeUrl ? state.recipeUrl : "";

    if (!recipeUrl) {
        return [];
    }

    const escapedUrl = cssEscape(recipeUrl);
    const selectorsBySurface = {
        "recipe-view": `[data-recipe-view-card][data-recipe-view-url="${escapedUrl}"]`,
        "current-recipes": `[data-current-recipe-row][data-recipe-url="${escapedUrl}"]`,
        cookbooks: `[data-cookbook-recipe-card][data-recipe-url="${escapedUrl}"]`,
    };
    const preferredSelector = selectorsBySurface[state.sourceSurface] || "";
    const fallbackSelectors = [
        selectorsBySurface["recipe-view"],
        selectorsBySurface["current-recipes"],
        selectorsBySurface.cookbooks,
    ];

    return [preferredSelector, ...fallbackSelectors].filter((selector, index, selectors) => {
        return selector && selectors.indexOf(selector) === index;
    });
}

function elementIsVisibleForReturn(element) {
    return Boolean(
        element
        && element.getClientRects
        && element.getClientRects().length
        && window.getComputedStyle(element).visibility !== "hidden"
    );
}

function findRecipeEditorReturnTarget(state) {
    for (const selector of recipeEditorReturnSelectors(state)) {
        const matches = [...document.querySelectorAll(selector)];
        const visibleMatch = matches.find(elementIsVisibleForReturn);

        if (visibleMatch) {
            return visibleMatch;
        }

        if (matches.length) {
            return matches[0];
        }
    }

    return null;
}

function focusRecipeEditorReturnTarget(target) {
    if (!target) {
        return;
    }

    const focusTarget = target.querySelector(
        ".recipe-edit-row-menu-btn, [data-recipe-card-title-toggle], [data-recipe-url-summary-toggle], .recipe-view-name-link, .recipe-url-summary-name"
    ) || target;

    if (focusTarget && typeof focusTarget.focus === "function") {
        focusTarget.focus({ preventScroll: true });
    }
}

function restoreRecipeEditorReturnState() {
    const state = recipeEditReturnState;
    recipeEditReturnState = null;

    if (!state) {
        return;
    }

    const target = findRecipeEditorReturnTarget(state);

    if (target) {
        scrollRecipeJumpTargetIntoView(target);
        focusRecipeEditorReturnTarget(target);
        return;
    }

    restoreWindowScroll(state.scrollX, state.scrollY);
}

function loadRecipeEditorReturnSurface(state) {
    const sectionName = {
        "recipe-view": "recipe-view",
        "current-recipes": "current-recipes",
        cookbooks: "cookbooks",
    }[state && state.sourceSurface ? state.sourceSurface : ""];

    if (!sectionName || !lazySectionElement(sectionName)) {
        return Promise.resolve();
    }

    return loadLazySection(sectionName, { allowDuringAuthCollapse: true }).then(() => undefined);
}

function expandRecipeEditorReturnSurface(state) {
    const sourceSurface = state && state.sourceSurface ? state.sourceSurface : "";
    const collapseKey = {
        "current-recipes": "recipe-url-log",
        cookbooks: "cookbooks",
    }[sourceSurface] || "";

    if (collapseKey) {
        const content = document.querySelector(`[data-collapse-content="${collapseKey}"]`);
        if (content && content.classList.contains("collapsed")) {
            toggleCardCollapse(collapseKey);
        }
    }

    if (sourceSurface === "recipe-view" && typeof showView === "function") {
        showView("recipe");
    }
}

async function restoreRecipeEditPageReturnState() {
    if (recipeEditorStandalonePageIsActive() || !window.sessionStorage) {
        return;
    }

    let state = null;

    try {
        state = JSON.parse(sessionStorage.getItem(RECIPE_EDIT_PAGE_RETURN_STATE_KEY) || "null");
    } catch (err) {
        state = null;
    }

    if (!state || !state.recipeUrl) {
        return;
    }

    const stateUrl = (() => {
        try {
            return new URL(state.pageUrl || "", window.location.href);
        } catch (err) {
            return null;
        }
    })();

    if (stateUrl && stateUrl.origin === window.location.origin && stateUrl.pathname !== window.location.pathname) {
        return;
    }

    try {
        sessionStorage.removeItem(RECIPE_EDIT_PAGE_RETURN_STATE_KEY);
    } catch (err) {
        // Best effort only.
    }

    await loadRecipeEditorReturnSurface(state);
    expandRecipeEditorReturnSurface(state);
    await waitForNextPaint();

    const target = findRecipeEditorReturnTarget(state);

    if (target) {
        scrollRecipeJumpTargetIntoView(target);
        focusRecipeEditorReturnTarget(target);
        return;
    }

    restoreWindowScroll(state.scrollX, state.scrollY);
}

function recipeEditPageReturnUrlFromState() {
    if (!window.sessionStorage) {
        return "";
    }

    let state = null;

    try {
        state = JSON.parse(sessionStorage.getItem(RECIPE_EDIT_PAGE_RETURN_STATE_KEY) || "null");
    } catch (err) {
        return "";
    }

    if (!state || !state.pageUrl) {
        return "";
    }

    try {
        const returnUrl = new URL(state.pageUrl, window.location.href);

        if (returnUrl.origin !== window.location.origin || returnUrl.href === window.location.href) {
            return "";
        }

        return returnUrl.href;
    } catch (err) {
        return "";
    }
}

function openRecipeEditorSection(button, sectionKey) {
    closeRecipeEditRowMenus();
    openRecipeEditor(button, { scrollToSection: sectionKey });
    return false;
}

function openRecipeFoodReviewFromRecipeView(button, event = null) {
    if (event) {
        event.preventDefault();
        event.stopPropagation();
    }

    closeRecipeEditRowMenus();
    openRecipeEditor(button, {
        scrollToFoodReview: true,
        activateFoodReview: true,
    });
    return false;
}

function openIngredientFoodReviewFromRecipeView(button, event = null) {
    if (event) {
        event.preventDefault();
        event.stopPropagation();
    }

    const ingredientName = button ? button.dataset.ingredientName || "" : "";

    closeRecipeEditRowMenus();
    openRecipeEditor(button, {
        scrollToIngredient: ingredientName,
        activateFoodReview: true,
    });
    return false;
}

function closeRecipeEditor(options = {}) {
    const form = document.getElementById("recipeEditForm");
    if (options.force !== true && form && form.dataset.saving === "true") {
        setRecipeEditStatus("Please wait for the recipe save to finish.", true);
        return false;
    }
    const hasUnsavedChanges = options.force !== true && recipeEditorHasUnsavedChanges(form);
    if (
        options.force !== true
        && hasUnsavedChanges
        && !window.confirm("You have unsaved recipe changes. Discard them?")
    ) {
        return false;
    }
    if (hasUnsavedChanges) {
        rememberRecipeEditorSavedState(form);
    }
    closeRecipeImageChangeActions();
    closeRecipeEditAiAnalysis({ restoreFocus: false });
    closeRecipeDescriptionReview({ restoreFocus: false });
    const modal = document.getElementById("recipeEditModal");

    if (modal) {
        modal.classList.remove("open");
        modal.setAttribute("aria-hidden", "true");
        document.body.classList.remove("modal-open");
        document.body.classList.remove("recipe-editor-open");
    }

    if (recipeEditorStandalonePageIsActive()) {
        const returnUrl = recipeEditPageReturnUrlFromState();

        if (returnUrl) {
            window.location.assign(returnUrl);
            return true;
        }

        if (window.history.length > 1) {
            window.history.back();
        } else {
            window.location.href = "/";
        }
        return true;
    }

    restoreRecipeEditorReturnState();
    return true;
}

function populateRecipeEditor(recipe, originalUrl, options = {}) {
    const form = document.getElementById("recipeEditForm");
    const preserveSavedState = options.preserveSavedState === true;
    const previousOriginalSnapshot = recipeEditOriginalSnapshot;
    const previousRecipeId = document.getElementById("recipeEditId")?.value || "";
    const previousOriginalUrl = document.getElementById("recipeEditOriginalUrl")?.value || "";
    const previousCategoryValues = form ? form.dataset.originalCategoryValues : undefined;
    const previousCategorySources = form ? form.dataset.originalCategorySources : undefined;
    const previousCategoryUserSet = form ? form.dataset.categoryUserSet : undefined;
    recipeEditAiQualityReport = null;
    const coverImage = normalizeRecipeEditorCoverImage(recipe.cover_image || {});
    const coverImagePrompt = String(recipe.cover_image_prompt || "").trim();
    if (coverImagePrompt) {
        coverImage.prompt = coverImagePrompt;
        coverImage.image_prompt = coverImagePrompt;
    }

    recipeEditOriginalSnapshot = normalizeRecipeEditorSnapshot({
        display_name: recipe.display_name || "",
        recipe_title: recipe.recipe_title || "",
        description: recipe.description || "",
        source_url: recipe.source_url || originalUrl,
        quantity: recipe.quantity || "1",
        servings: recipe.servings || "",
        cover_image: coverImage,
        level: recipe.level || "",
        total_time: recipe.total_time || "",
        prep_time: recipe.prep_time || "",
        inactive_time: recipe.inactive_time || "",
        cook_time: recipe.cook_time || "",
        rating: recipe.rating || 0,
        recipe_notes: recipe.recipe_notes || [],
        reflection_notes: recipe.reflection_notes || [],
        chatgpt_feedback: recipe.chatgpt_feedback || "",
        chatgpt_feedback_created_at: recipe.chatgpt_feedback_created_at || "",
        scaling: recipe.scaling || {},
        ingredients: recipe.ingredients || [],
        equipment: recipe.equipment || [],
        instructions: recipe.instructions || [],
        nutrition: recipe.nutrition || [],
        menu_metadata: recipeMenuMetadataSnapshot(recipe),
        ai_inferred: Boolean(recipe.ai_inferred),
    });

    setValue("recipeEditOriginalUrl", originalUrl);
    setValue("recipeEditId", recipe.recipe_id || recipe.id || "");
    setValue("recipeEditDisplayName", recipe.display_name || "");
    const recipeBreadcrumbName = document.getElementById("recipeEditBreadcrumbName");
    if (recipeBreadcrumbName) {
        recipeBreadcrumbName.textContent = String(recipe.display_name || recipe.recipe_title || "Recipe").trim() || "Recipe";
    }
    setValue("recipeEditTitleInput", recipe.recipe_title || "");
    setValue("recipeEditDescription", recipe.description || "");
    syncRecipeEditorFavoriteControl(recipe, originalUrl);
    updateRecipeEditDescriptionCount();
    updateRecipeDescriptionAiActionLabel();
    setRecipeEditorSourceUrlField(recipe, originalUrl);
    setValue("recipeEditMenuItemUrl", recipe.menu_item_url || recipe.source_url || originalUrl);
    setValue("recipeEditDocumentSourceUrl", recipe.document_source_url || recipe.source_url || originalUrl);
    setValue("recipeEditQuantity", recipe.quantity || "1");
    setValue("recipeEditServings", recipe.servings || "");
    setRecipeEditDifficultyValue(recipe.level || "");
    setValue("recipeEditTotalTime", recipe.total_time || "");
    setValue("recipeEditPrepTime", recipe.prep_time || "");
    setValue("recipeEditInactiveTime", recipe.inactive_time || "");
    setValue("recipeEditCookTime", recipe.cook_time || "");
    setRecipeRating(recipe.rating || 0);
    setRecipeEditorCookbook(recipe, originalUrl);
    populateRecipeEditCategories(recipe);
    populateRecipeScalingControls(recipe.scaling || {}, recipe.servings || "");
    updateRecipeEditorPdfControls(recipe);
    syncRecipeEditSourceFilesDetails();
    populateRecipeMenuMetadata(recipe);
    setRecipeEditorCoverImage(coverImage, recipe.recipe_title || recipe.display_name || "Recipe title image");

    const ingredientWrap = document.getElementById("recipeEditIngredients");
    const equipmentWrap = document.getElementById("recipeEditEquipment");
    const instructionWrap = document.getElementById("recipeEditInstructions");
    const recipeNotesWrap = document.getElementById("recipeEditRecipeNotes");
    const nutritionWrap = document.getElementById("recipeEditNutrition");
    const reflectionWrap = document.getElementById("recipeEditReflectionNotes");

    if (ingredientWrap) {
        ingredientWrap.innerHTML = "";
        const hasIngredients = Boolean(recipe.ingredients && recipe.ingredients.length);
        if (hasIngredients) {
            (recipe.ingredients || []).forEach((item, index) => {
                addRecipeIngredientRow(item, { persistedIndex: index });
            });
            setRecipeIngredientsCollapsed(!recipeEditorStandalonePageIsActive());
        } else {
            setRecipeIngredientsCollapsed(false);
            addRecipeIngredientRow({}, { expanded: true });
        }
    }

    if (equipmentWrap) {
        equipmentWrap.innerHTML = recipeEquipmentHeaderHtml();
        const hasEquipment = Boolean(recipe.equipment && recipe.equipment.length);
        if (hasEquipment) {
            (recipe.equipment || []).forEach(item => addRecipeEquipmentRow(item));
            setRecipeEquipmentCollapsed(true);
        } else {
            setRecipeEquipmentCollapsed(true);
            addRecipeEquipmentRow("", { expanded: false });
        }
    }

    if (instructionWrap) {
        instructionWrap.innerHTML = recipeInstructionsHeaderHtml();
        (recipe.instructions || []).forEach((item, index) => addRecipeInstructionRow(item, index + 1));
        if (!recipe.instructions || !recipe.instructions.length) {
            addRecipeInstructionRow();
        }
    }

    if (recipeNotesWrap) {
        recipeNotesWrap.innerHTML = recipeNotesHeaderHtml();
        (recipe.recipe_notes || []).forEach(item => addRecipeNoteSectionRow(item));
    }

    if (nutritionWrap) {
        nutritionWrap.innerHTML = recipeNutritionHeaderHtml();
        (recipe.nutrition || []).forEach(item => addRecipeNutritionRow(item));
        if (!recipe.nutrition || !recipe.nutrition.length) {
            addRecipeNutritionRow();
        }
    }

    if (reflectionWrap) {
        reflectionWrap.innerHTML = "";
        (recipe.reflection_notes || []).forEach(item => addRecipeReflectionNoteRow(item));
    }

    setRecipeEditActiveTab("ingredients");
    updateRecipeEditAiConfidenceCard(recipe);
    updateRecipeEditContextPanels();
    updateRecipeEditStickyOffsets();
    if (preserveSavedState) {
        recipeEditOriginalSnapshot = previousOriginalSnapshot;
        setValue("recipeEditId", previousRecipeId);
        setValue("recipeEditOriginalUrl", previousOriginalUrl);
        if (form) {
            if (previousCategoryValues === undefined) {
                delete form.dataset.originalCategoryValues;
            } else {
                form.dataset.originalCategoryValues = previousCategoryValues;
            }
            if (previousCategorySources === undefined) {
                delete form.dataset.originalCategorySources;
            } else {
                form.dataset.originalCategorySources = previousCategorySources;
            }
            if (previousCategoryUserSet === undefined) {
                delete form.dataset.categoryUserSet;
            } else {
                form.dataset.categoryUserSet = previousCategoryUserSet;
            }
        }
        updateRecipeEditorDirtyState(form);
    } else {
        rememberRecipeEditorSavedState(form);
    }
    window.setTimeout(() => {
        applyKnownRecipeImageProgressItems();
        scheduleRecipeImageProgressPoll(750);
    }, 0);
}

function replaceRecipeEditorIngredients(ingredients = []) {
    const ingredientWrap = document.getElementById("recipeEditIngredients");

    if (!ingredientWrap) {
        return false;
    }

    ingredientWrap.innerHTML = "";
    const hasIngredients = Boolean(Array.isArray(ingredients) && ingredients.length);
    (hasIngredients ? ingredients : []).forEach(item => addRecipeIngredientRow(item));
    if (!ingredientWrap.querySelector(".recipe-edit-ingredient-row")) {
        setRecipeIngredientsCollapsed(false);
        addRecipeIngredientRow({}, { expanded: true });
    } else {
        setRecipeIngredientsCollapsed(!recipeEditorStandalonePageIsActive());
    }
    updateRecipeIngredientRowIndexes();
    updateRecipeEditorDirtyState();
    return true;
}

function replaceRecipeEditorRecipeNotes(recipeNotes = []) {
    const recipeNotesWrap = document.getElementById("recipeEditRecipeNotes");

    if (!recipeNotesWrap) {
        return false;
    }

    recipeNotesWrap.innerHTML = recipeNotesHeaderHtml();
    const notes = Array.isArray(recipeNotes) ? recipeNotes : [];
    notes.forEach(item => addRecipeNoteSectionRow(item));
    updateRecipeNotesEmptyState();
    updateRecipeEditorDirtyState();
    return true;
}

function recipeEditorCurrentUrl() {
    const input = document.getElementById("recipeEditOriginalUrl");
    return input ? String(input.value || "").trim() : "";
}

function recipeEditorIsOpen() {
    const modal = document.getElementById("recipeEditModal");
    return Boolean(modal && modal.classList.contains("open"));
}

function recipeObjectHasAnyAlias(recipe, aliases = []) {
    if (!recipe || typeof recipe !== "object") {
        return false;
    }

    return aliases.some(alias => Object.prototype.hasOwnProperty.call(recipe, alias));
}

function recipeObjectValueFromAliases(recipe, aliases = []) {
    if (!recipe || typeof recipe !== "object") {
        return "";
    }

    for (const alias of aliases) {
        const value = String(recipe[alias] || "").trim();
        if (value) {
            return value;
        }
    }

    return "";
}

function recipeMenuMetadataText(value) {
    if (Array.isArray(value)) {
        return value.map(recipeMenuMetadataText).filter(Boolean).join(", ");
    }
    if (typeof value === "boolean") {
        return value ? "true" : "false";
    }
    return String(value || "").trim();
}

function recipeMenuSourceOptionValue(restaurantId = "", menuId = "") {
    return `${recipeMenuMetadataText(restaurantId)}|${recipeMenuMetadataText(menuId)}`;
}

function recipeMenuSourceOptionsFromRecipe(recipe = {}) {
    const options = Array.isArray(recipe.menu_source_options)
        ? recipe.menu_source_options.filter(option => option && typeof option === "object")
        : [];
    const selectedValue = recipeMenuMetadataText(recipe.menu_source_value)
        || recipeMenuSourceOptionValue(recipe.restaurant_id, recipe.menu_id);

    if (!selectedValue || selectedValue === "|") {
        return options;
    }
    if (options.some(option => recipeMenuMetadataText(option.value) === selectedValue)) {
        return options;
    }

    return [
        {
            value: selectedValue,
            restaurant_id: recipe.restaurant_id || "",
            menu_id: recipe.menu_id || "",
            label: recipe.restaurant_name || recipe.source_menu_url || "Current restaurant source",
            restaurant_name: recipe.restaurant_name || "",
            restaurant_website_url: recipe.restaurant_website_url || "",
            source_menu_url: recipe.source_menu_url || "",
            restaurant_cuisine_tags: recipe.restaurant_cuisine_tags || "",
            restaurant_phone: recipe.restaurant_phone || "",
            restaurant_logo_url: recipe.restaurant_logo_url || "",
            restaurant_rating: recipe.restaurant_rating || "",
            restaurant_street_address: recipe.restaurant_street_address || "",
            restaurant_city: recipe.restaurant_city || "",
            restaurant_state: recipe.restaurant_state || "",
            restaurant_postal_code: recipe.restaurant_postal_code || "",
            restaurant_country: recipe.restaurant_country || "",
            restaurant_address: recipe.restaurant_address || "",
            restaurant_hours_text: recipe.restaurant_hours_text || "",
            restaurant_weekly_hours: recipe.restaurant_weekly_hours || {},
            restaurant_hours_notes: recipe.restaurant_hours_notes || "",
            restaurant_raw_hours_data: recipe.restaurant_raw_hours_data || "",
            restaurant_current_status: recipe.restaurant_current_status || "",
            restaurant_promotions: recipe.restaurant_promotions || "",
            restaurant_online_payment_available: recipe.restaurant_online_payment_available ?? "",
            restaurant_online_ordering_available: recipe.restaurant_online_ordering_available ?? "",
            restaurant_delivery_available: recipe.restaurant_delivery_available ?? "",
        },
        ...options,
    ];
}

function recipeMenuSourceOptionByValue(value) {
    const selectedValue = recipeMenuMetadataText(value);
    return recipeEditMenuSourceOptions.find(option => recipeMenuMetadataText(option.value) === selectedValue) || null;
}

function populateRecipeMenuSourceSelect(recipe = {}) {
    const select = document.getElementById("recipeEditMenuSourceSelect");

    recipeEditMenuSourceOptions = recipeMenuSourceOptionsFromRecipe(recipe);
    if (!select) {
        return;
    }

    const selectedValue = recipeMenuMetadataText(recipe.menu_source_value)
        || recipeMenuSourceOptionValue(recipe.restaurant_id, recipe.menu_id);
    select.innerHTML = "";
    const customOption = document.createElement("option");
    customOption.value = "";
    customOption.textContent = "Custom Source";
    select.appendChild(customOption);

    recipeEditMenuSourceOptions.forEach(option => {
        const optionValue = recipeMenuMetadataText(option.value)
            || recipeMenuSourceOptionValue(option.restaurant_id, option.menu_id);
        if (!optionValue || optionValue === "|") {
            return;
        }
        const optionElement = document.createElement("option");
        optionElement.value = optionValue;
        optionElement.textContent = recipeMenuMetadataText(option.label)
            || recipeMenuMetadataText(option.restaurant_name)
            || recipeMenuMetadataText(option.source_menu_url)
            || "Restaurant Source";
        select.appendChild(optionElement);
    });

    select.value = recipeMenuSourceOptionByValue(selectedValue) ? selectedValue : "";
}

function setRecipeMenuRelationFields(values = {}) {
    Object.entries(RECIPE_EDIT_MENU_RELATION_INPUT_IDS).forEach(([field, inputId]) => {
        const input = document.getElementById(inputId);
        if (input) {
            input.value = recipeMenuMetadataText(values[field]);
        }
    });
}

function applyRecipeMenuSourceSelection(select) {
    const option = recipeMenuSourceOptionByValue(select ? select.value : "");

    if (!option) {
        setRecipeMenuRelationFields({
            restaurant_id: "",
            menu_id: "",
            menu_section_id: "",
            menu_item_id: "",
        });
        return false;
    }

    setRecipeMenuRelationFields({
        restaurant_id: option.restaurant_id || "",
        menu_id: option.menu_id || "",
        menu_section_id: "",
        menu_item_id: "",
    });

    [
        "restaurant_name",
        "restaurant_website_url",
        "source_menu_url",
        "restaurant_cuisine_tags",
        "restaurant_phone",
        "restaurant_address",
        "restaurant_hours_text",
        "restaurant_current_status",
        "restaurant_promotions",
        "restaurant_online_payment_available",
        "restaurant_delivery_available",
    ].forEach(field => {
        const inputId = RECIPE_EDIT_MENU_METADATA_INPUT_IDS[field];
        if (inputId) {
            setValue(inputId, recipeMenuMetadataText(option[field]));
        }
    });
    bindRecipeMenuMetadataUrlLinks();
    return false;
}

function recipeMenuMetadataSnapshot(recipe = {}) {
    const snapshot = {};

    Object.keys(RECIPE_EDIT_MENU_METADATA_INPUT_IDS).forEach(field => {
        snapshot[field] = recipeMenuMetadataText(recipe[field]);
    });
    Object.keys(RECIPE_EDIT_MENU_RELATION_INPUT_IDS).forEach(field => {
        snapshot[field] = recipeMenuMetadataText(recipe[field]);
    });
    snapshot.menu_source_value = recipeMenuMetadataText(recipe.menu_source_value)
        || recipeMenuSourceOptionValue(snapshot.restaurant_id, snapshot.menu_id);

    return snapshot;
}

function recipeHasMenuMetadata(recipe = {}) {
    if (!recipe || typeof recipe !== "object") {
        return false;
    }

    if (recipe.is_menu_derived || recipe.menu_metadata_available) {
        return true;
    }

    if (["menu_item_inferred", "menu_item_stub"].includes(String(recipe.source_type || "").trim().toLowerCase())) {
        return true;
    }

    if (Object.keys(RECIPE_EDIT_MENU_RELATION_INPUT_IDS).some(field => recipeMenuMetadataText(recipe[field]))) {
        return true;
    }

    return Object.keys(RECIPE_EDIT_MENU_METADATA_INPUT_IDS).some(field => {
        return recipeMenuMetadataText(recipe[field]);
    });
}

function setRecipeMenuMetadataPanelVisibility(recipe = {}) {
    const metadataAvailable = recipeHasMenuMetadata(recipe);
    [
        document.getElementById("recipeEditRestaurantMenuSourceDetails"),
        document.getElementById("recipeEditMenuItemDetails"),
    ].forEach(panel => {
        if (!panel) {
            return;
        }
        panel.hidden = true;
        panel.setAttribute("aria-hidden", "true");
        panel.dataset.recipeMenuMetadataAvailable = metadataAvailable ? "true" : "false";
    });
}

function updateRecipeMenuMetadataUrlLink(inputId, linkId) {
    const input = document.getElementById(inputId);
    const link = document.getElementById(linkId);
    const url = input ? String(input.value || "").trim() : "";
    const canOpen = isLegitimateWebUrl(url);

    if (!link) {
        return;
    }

    link.href = canOpen ? url : "#";
    link.hidden = !canOpen;
    link.setAttribute("aria-disabled", canOpen ? "false" : "true");

    if (inputId === "recipeEditMenuOrderUrl") {
        updateRecipeEditMenuOrderButton(url, canOpen);
    }
    syncRecipeEditDocumentRows();
    updateRecipeEditRestaurantCard();
}

function updateRecipeEditMenuOrderButton(url, canOpen = isLegitimateWebUrl(url)) {
    const button = document.getElementById("recipeEditMenuOrderButton");

    if (!button) {
        return;
    }

    const openUrl = canOpen ? String(url || "").trim() : "";
    button.href = openUrl || "#";
    button.hidden = !openUrl;
    button.dataset.menuOrderUrl = openUrl;
    button.setAttribute("aria-disabled", openUrl ? "false" : "true");
}

function bindRecipeMenuMetadataUrlLinks() {
    RECIPE_EDIT_MENU_METADATA_URL_LINKS.forEach(([inputId, linkId]) => {
        const input = document.getElementById(inputId);
        if (input && input.dataset.menuMetadataLinkBound !== "true") {
            input.dataset.menuMetadataLinkBound = "true";
            input.addEventListener("input", () => updateRecipeMenuMetadataUrlLink(inputId, linkId));
        }
        updateRecipeMenuMetadataUrlLink(inputId, linkId);
    });
}

function populateRecipeMenuMetadata(recipe = {}) {
    recipeRestaurantDisplaySource = null;
    setRecipeMenuMetadataPanelVisibility(recipe);
    setRecipeMenuRelationFields(recipe);
    Object.entries(RECIPE_EDIT_MENU_METADATA_INPUT_IDS).forEach(([field, inputId]) => {
        const input = document.getElementById(inputId);
        if (input) {
            input.value = recipeMenuMetadataText(recipe[field]);
        }
    });
    populateRecipeMenuSourceSelect(recipe);
    bindRecipeMenuMetadataUrlLinks();
    normalizeRecipeEditPriceDisplay();
}

function recipeMenuMetadataStateAvailable() {
    return [
        document.getElementById("recipeEditRestaurantMenuSourceDetails"),
        document.getElementById("recipeEditMenuItemDetails"),
    ].some(panel => panel?.dataset.recipeMenuMetadataAvailable === "true");
}

function collectRecipeMenuMetadataPayload() {
    const payload = {};

    if (!recipeMenuMetadataStateAvailable()) {
        return payload;
    }

    Object.entries(RECIPE_EDIT_MENU_METADATA_INPUT_IDS).forEach(([field, inputId]) => {
        const input = document.getElementById(inputId);
        const value = input ? String(input.value || "").trim() : "";
        payload[field] = field === "menu_price" && value ? `$${value.replace(/^\$\s*/, "")}` : value;
    });
    Object.entries(RECIPE_EDIT_MENU_RELATION_INPUT_IDS).forEach(([field, inputId]) => {
        const input = document.getElementById(inputId);
        payload[field] = input ? String(input.value || "").trim() : "";
    });

    return payload;
}

function currentRecipeEditorPdfFieldValues() {
    return Object.fromEntries(Object.entries(RECIPE_EDIT_PDF_INPUT_IDS).map(([field, id]) => {
        const input = document.getElementById(id);
        return [field, input ? String(input.value || "").trim() : ""];
    }));
}

function normalizeRecipeEditorPdfValues(recipe = {}, fallbackUrl = "", options = {}) {
    const useCurrentForMissing = options.useCurrentForMissing === true;
    const current = useCurrentForMissing ? currentRecipeEditorPdfFieldValues() : {};
    const values = {};

    Object.entries(RECIPE_EDIT_PDF_FIELD_ALIASES).forEach(([field, aliases]) => {
        if (recipeObjectHasAnyAlias(recipe, aliases)) {
            values[field] = recipeObjectValueFromAliases(recipe, aliases);
        } else if (field === "source_url" && fallbackUrl) {
            values[field] = String(fallbackUrl || "").trim();
        } else {
            values[field] = current[field] || "";
        }
    });

    if (!values.source_url) {
        values.source_url = String(fallbackUrl || "").trim();
    }

    return values;
}

function setRecipeEditInputValueFromServer(input, value, options = {}) {
    if (!input) {
        return "";
    }

    const nextValue = String(value || "").trim();
    const currentValue = String(input.value || "").trim();
    const previousServerValue = Object.prototype.hasOwnProperty.call(input.dataset, "lastServerValue")
        ? String(input.dataset.lastServerValue || "").trim()
        : currentValue;
    const silent = options.silent === true;

    if (silent && options.skipEmpty === true && !nextValue) {
        return currentValue;
    }

    if (!silent || !currentValue || currentValue === previousServerValue) {
        input.value = nextValue;
        input.dataset.lastServerValue = nextValue;
        return nextValue;
    }

    return currentValue;
}

function setRecipeEditorSourceUrlField(recipe = {}, originalUrl = "", options = {}) {
    const sourceInput = document.getElementById("recipeEditSourceUrl");
    const canonicalSourceUrl = String(recipe.source_url || recipe.url || originalUrl || "").trim();
    const displaySourceUrl = String(recipe.source_display_url || "").trim();
    const visibleValue = displaySourceUrl || canonicalSourceUrl;
    const appliedValue = setRecipeEditInputValueFromServer(sourceInput, visibleValue, options);
    const updatedFromServer = !options.silent || appliedValue === visibleValue;

    if (sourceInput && updatedFromServer) {
        sourceInput.dataset.canonicalSourceUrl = canonicalSourceUrl;
        sourceInput.dataset.displaySourceUrl = displaySourceUrl;
        sourceInput.dataset.lastServerCanonicalValue = canonicalSourceUrl;
    }

    if (sourceInput && sourceInput.dataset.sourceLinkBound !== "true") {
        sourceInput.dataset.sourceLinkBound = "true";
        sourceInput.addEventListener("input", updateRecipeEditSourceUrlLink);
    }

    updateRecipeEditSourceUrlLink();
    return appliedValue;
}

function mergeRecipeEditorPdfFieldsIntoOpenEditor(recipe = {}, options = {}) {
    if (!recipeEditorIsOpen()) {
        return false;
    }

    const currentUrl = recipeEditorCurrentUrl();
    const expectedUrl = String(options.recipeUrl || "").trim();

    if (expectedUrl && currentUrl && expectedUrl !== currentUrl) {
        return false;
    }

    const serverValues = normalizeRecipeEditorPdfValues(recipe, currentUrl, {
        useCurrentForMissing: true,
    });
    const mergedValues = {};
    let changed = false;

    if (recipeObjectHasAnyAlias(recipe, RECIPE_EDIT_PDF_FIELD_ALIASES.source_url)) {
        const sourceInput = document.getElementById(RECIPE_EDIT_PDF_INPUT_IDS.source_url);
        const before = sourceInput ? String(sourceInput.value || "").trim() : "";
        const after = setRecipeEditorSourceUrlField({
            source_url: serverValues.source_url,
            source_display_url: recipe.source_display_url || "",
        }, currentUrl, {
            silent: true,
            skipEmpty: true,
        });

        mergedValues.source_url = recipeEditorSourceUrlForOpen() || serverValues.source_url || currentUrl;
        if (after !== before && recipeEditOriginalSnapshot) {
            recipeEditOriginalSnapshot.source_url = serverValues.source_url || "";
        }
        changed = changed || after !== before;
    } else {
        mergedValues.source_url = recipeEditorSourceUrlForOpen() || serverValues.source_url || currentUrl;
    }

    [
        "source_pdf_path",
        "source_cloudflare_pdf_url",
        "generated_pdf_path",
        "generated_cloudflare_pdf_url",
    ].forEach(field => {
        const input = document.getElementById(RECIPE_EDIT_PDF_INPUT_IDS[field]);
        const before = input ? String(input.value || "").trim() : "";
        const after = setRecipeEditInputValueFromServer(input, serverValues[field], {
            silent: true,
        });

        mergedValues[field] = after || serverValues[field] || "";
        changed = changed || after !== before;
    });

    updateRecipeEditorPdfControls({
        ...recipe,
        ...mergedValues,
    }, {
        updateInputValues: false,
        useCurrentForMissing: false,
    });

    if (changed) {
        rememberRecipeEditorFieldsAsSaved(document.getElementById("recipeEditForm"), [
            "source_pdf_path",
            "source_cloudflare_pdf_url",
            "generated_pdf_path",
            "generated_cloudflare_pdf_url",
        ]);
        updateRecipeEditorDirtyState();
    }

    return changed;
}

async function refreshOpenRecipeEditorPdfFieldsFromServer(options = {}) {
    if (!recipeEditorIsOpen()) {
        return false;
    }

    const currentUrl = recipeEditorCurrentUrl();
    const recipeUrl = String(options.recipeUrl || currentUrl || "").trim();

    if (!recipeUrl || (currentUrl && recipeUrl !== currentUrl)) {
        return false;
    }

    const recipe = await fetchRecipeEditorData(recipeUrl);
    return mergeRecipeEditorPdfFieldsIntoOpenEditor(recipe, {
        recipeUrl,
    });
}

function scheduleOpenRecipeEditorPdfRefresh(options = {}) {
    const recipeUrl = String(options.recipeUrl || recipeEditorCurrentUrl() || "").trim();

    if (!recipeEditorIsOpen() || !recipeUrl) {
        return;
    }

    if (recipeEditPdfRefreshTimer) {
        window.clearTimeout(recipeEditPdfRefreshTimer);
        recipeEditPdfRefreshTimer = null;
    }

    const token = ++recipeEditPdfRefreshToken;
    const startedAt = Date.now();
    const timeoutMs = Math.max(1000, Number(options.timeoutMs) || 15000);
    const intervalMs = Math.max(500, Number(options.intervalMs) || 1200);
    const waitForGeneratedCloudflare = options.waitForGeneratedCloudflare === true;
    const waitForSourceCloudflare = options.waitForSourceCloudflare === true;

    const poll = async () => {
        if (token !== recipeEditPdfRefreshToken || !recipeEditorIsOpen()) {
            return;
        }

        if (recipeEditorCurrentUrl() !== recipeUrl) {
            return;
        }

        try {
            await refreshOpenRecipeEditorPdfFieldsFromServer({ recipeUrl });
        } catch (err) {
            console.warn("Unable to silently refresh recipe PDF fields.", err);
        }

        const fields = currentRecipeEditorPdfFieldValues();
        const elapsed = Date.now() - startedAt;
        const generatedReady = Boolean(fields.generated_cloudflare_pdf_url || fields.generated_pdf_path);
        const sourceReady = Boolean(fields.source_cloudflare_pdf_url || fields.source_pdf_path);
        const anyPdfReady = generatedReady || sourceReady;
        const ready = (waitForGeneratedCloudflare || waitForSourceCloudflare)
            ? (
                (
                    waitForGeneratedCloudflare
                        ? Boolean(fields.generated_cloudflare_pdf_url)
                        : true
                ) && (
                    waitForSourceCloudflare
                        ? Boolean(fields.source_cloudflare_pdf_url)
                        : true
                )
            )
            : anyPdfReady;

        if (elapsed >= timeoutMs || ready) {
            return;
        }

        recipeEditPdfRefreshTimer = window.setTimeout(poll, intervalMs);
    };

    recipeEditPdfRefreshTimer = window.setTimeout(poll, Math.max(0, Number(options.initialDelay) || 0));
}

function updateRecipeEditorCookbookAssignment(recipeUrl, cookbookId, cookbookName, cookbookIsUnclassified = false) {
    const modal = document.getElementById("recipeEditModal");
    const currentUrl = recipeEditorCurrentUrl();

    if (!modal || !modal.classList.contains("open") || !currentUrl || currentUrl !== recipeUrl) {
        return;
    }

    setRecipeEditorCookbook({
        source_url: recipeUrl,
        cookbook_id: cookbookId || "",
        cookbook_name: cookbookName || "",
        cookbook_is_unclassified: Boolean(cookbookIsUnclassified),
    }, recipeUrl);
}

function setRecipeEditorCookbook(recipe, fallbackUrl = "") {
    const field = document.getElementById("recipeEditCookbookField");
    const cookbookName = document.getElementById("recipeEditCookbookName");
    const value = field ? field.querySelector(".recipe-edit-cookbook-value") : null;
    const name = recipe && recipe.cookbook_name
        ? String(recipe.cookbook_name).trim()
        : "";
    const cookbookId = recipe && recipe.cookbook_id
        ? String(recipe.cookbook_id).trim()
        : "";
    const recipeUrl = recipe && recipe.source_url
        ? String(recipe.source_url).trim()
        : String(fallbackUrl || "").trim();
    const isUnclassified = Boolean(recipe && recipe.cookbook_is_unclassified);

    if (!field || !cookbookName) {
        return;
    }

    field.dataset.recipeUrl = recipeUrl;
    field.dataset.currentCookbookId = cookbookId;
    field.dataset.currentCookbookName = name;

    cookbookName.textContent = name || "No cookbook assigned.";
    cookbookName.classList.toggle("muted", !name);
    cookbookName.title = name || "";

    if (value) {
        value.classList.toggle("muted", !name);
    }

    recipeEditorCookbookMenus(field).forEach(menu => {
        menu.dataset.recipeUrl = recipeUrl;
    });

    recipeEditorCookbookMenuButtons(field, "[data-recipe-edit-cookbook-action]").forEach(button => {
        button.dataset.recipeUrl = recipeUrl;
    });

    recipeEditorCookbookMenuButtons(field, "[data-recipe-edit-cookbook-option]").forEach(button => {
        const optionId = button.dataset.cookbookId || "";
        button.hidden = Boolean(cookbookId && optionId === cookbookId);
    });

    recipeEditorCookbookMenuButtons(field, "[data-recipe-edit-cookbook-delete]").forEach(button => {
        button.hidden = !name || isUnclassified;
    });

    updateRecipeEditorMenuSectionOptions(cookbookId);
}

function recipeEditorCookbookMenus(field = document.getElementById("recipeEditCookbookField")) {
    if (!field) {
        return [];
    }

    const menus = new Set(field.querySelectorAll(".recipe-edit-cookbook-menu"));
    document.querySelectorAll(".recipe-edit-cookbook-menu[data-recipe-edit-portaled='1']").forEach(menu => {
        const anchorField = menu.recipeEditAnchorButton
            ? menu.recipeEditAnchorButton.closest("#recipeEditCookbookField")
            : null;
        if (anchorField === field) {
            menus.add(menu);
        }
    });

    return Array.from(menus);
}

function recipeEditorCookbookMenuButtons(field, selector) {
    return recipeEditorCookbookMenus(field).flatMap(menu => Array.from(menu.querySelectorAll(selector)));
}

function recipeEditorMenuSectionField() {
    return document.getElementById("recipeEditMenuSectionField");
}

function recipeEditorMenuSectionFields() {
    return Array.from(document.querySelectorAll("[data-recipe-edit-menu-section-field]"));
}

function recipeEditorMenuSectionInput() {
    return document.getElementById("recipeEditCategoryMenuSection");
}

function recipeEditorMenuSectionMenus(field = null) {
    const fields = field ? [field] : recipeEditorMenuSectionFields();

    if (!fields.length) {
        return [];
    }

    const menus = new Set();
    fields.forEach(sectionField => {
        sectionField.querySelectorAll(".recipe-edit-menu-section-menu").forEach(menu => menus.add(menu));
    });

    document.querySelectorAll(".recipe-edit-menu-section-menu[data-recipe-edit-portaled='1']").forEach(menu => {
        const anchorField = menu.recipeEditAnchorButton
            ? menu.recipeEditAnchorButton.closest("[data-recipe-edit-menu-section-field]")
            : null;
        if (anchorField && fields.includes(anchorField)) {
            menus.add(menu);
        }
    });

    return Array.from(menus);
}

function recipeEditorMenuSectionButtons(field, selector) {
    return recipeEditorMenuSectionMenus(field).flatMap(menu => Array.from(menu.querySelectorAll(selector)));
}

function recipeEditorMenuSectionKey(value = "") {
    return String(value || "").trim().toLowerCase();
}

function recipeEditorMenuSectionRowFromControl(control) {
    return control && typeof control.closest === "function"
        ? control.closest("[data-recipe-edit-menu-section-row]")
        : null;
}

function recipeEditorMenuSectionRowKey(row) {
    return recipeEditorMenuSectionKey(row && row.dataset ? row.dataset.menuSection || "" : "");
}

function recipeEditorMenuSectionRowOrderAnchor(menu) {
    return menu ? menu.querySelector("[data-recipe-edit-menu-section-empty]") : null;
}

function recipeEditorMenuSectionVisibleRowsForMenu(menu, cookbookId = currentRecipeEditorCookbookId()) {
    const activeCookbookId = String(cookbookId || "").trim();

    if (!menu) {
        return [];
    }

    return Array.from(menu.querySelectorAll("[data-recipe-edit-menu-section-row]")).filter(row => {
        return row
            && !row.hidden
            && String(row.dataset.cookbookId || "").trim() === activeCookbookId
            && String(row.dataset.menuSection || "").trim();
    });
}

function recipeEditorMenuSectionVisibleRows(field = null, cookbookId = currentRecipeEditorCookbookId()) {
    return recipeEditorMenuSectionMenus(field).flatMap(menu => {
        return recipeEditorMenuSectionVisibleRowsForMenu(menu, cookbookId);
    });
}

function updateRecipeEditorMenuSectionMoveButtons(field = null, cookbookId = currentRecipeEditorCookbookId()) {
    recipeEditorMenuSectionMenus(field).forEach(menu => {
        const rows = recipeEditorMenuSectionVisibleRowsForMenu(menu, cookbookId);

        rows.forEach((row, index) => {
            row.querySelectorAll("[data-recipe-edit-menu-section-move]").forEach(button => {
                const direction = Number.parseInt(button.dataset.direction || "0", 10);
                button.disabled = (direction < 0 && index === 0)
                    || (direction > 0 && index === rows.length - 1)
                    || rows.length < 2;
            });
        });
    });
}

function createRecipeEditorMenuSectionOptionRow(section, cookbookId) {
    const row = document.createElement("div");
    row.className = "recipe-edit-menu-section-option-row";
    row.dataset.recipeEditMenuSectionRow = "";
    row.dataset.cookbookId = cookbookId;
    row.dataset.menuSection = section;

    const option = document.createElement("button");
    option.type = "button";
    option.className = "recipe-edit-menu-section-option";
    option.dataset.recipeEditMenuSectionOption = "";
    option.dataset.cookbookId = cookbookId;
    option.dataset.menuSection = section;
    option.textContent = section;
    option.onclick = function () {
        return selectRecipeEditMenuSection(this);
    };
    row.appendChild(option);

    const actions = document.createElement("div");
    actions.className = "recipe-edit-menu-section-order-actions";

    [-1, 1].forEach(direction => {
        const button = document.createElement("button");
        button.type = "button";
        button.className = "recipe-edit-menu-section-order-btn";
        button.dataset.recipeEditMenuSectionMove = "";
        button.dataset.cookbookId = cookbookId;
        button.dataset.menuSection = section;
        button.dataset.direction = String(direction);
        button.setAttribute("aria-label", `Move ${section} ${direction < 0 ? "up" : "down"}`);
        button.title = direction < 0 ? "Move section up" : "Move section down";
        button.onclick = function () {
            return moveRecipeEditMenuSection(this, direction);
        };

        const icon = document.createElement("span");
        icon.className = `recipe-edit-menu-section-order-icon recipe-edit-menu-section-order-icon-${direction < 0 ? "up" : "down"}`;
        icon.setAttribute("aria-hidden", "true");
        button.appendChild(icon);
        actions.appendChild(button);
    });

    row.appendChild(actions);
    return row;
}

function currentRecipeEditorMenuSectionValue() {
    const input = recipeEditorMenuSectionInput();
    return input ? String(input.value || "").trim() : "";
}

function setRecipeEditorMenuSectionValue(value = "", options = {}) {
    const input = recipeEditorMenuSectionInput();
    const nextValue = String(value || "").trim();

    if (input) {
        input.value = nextValue;
    }

    if (nextValue) {
        ensureRecipeEditorMenuSectionOption(nextValue, currentRecipeEditorCookbookId());
    }

    updateRecipeEditorMenuSectionDisplay(nextValue);
    updateRecipeEditorMenuSectionOptions(currentRecipeEditorCookbookId(), nextValue);

    if (options.userSelected) {
        const form = document.getElementById("recipeEditForm");
        setFormCategorySource(form, RECIPE_EDIT_MENU_SECTION_FIELD_NAME, CATEGORY_SOURCE_USER_SELECTED);
        setRecipeEditCategorySourceLabel("Saved");
    }
}

function updateRecipeEditorMenuSectionDisplay(value = currentRecipeEditorMenuSectionValue()) {
    const input = recipeEditorMenuSectionInput();
    const nextValue = String(value || (input && input.value) || "").trim();

    document.querySelectorAll("[data-recipe-edit-menu-section-name]").forEach(name => {
        name.textContent = nextValue || "No menu section";
        name.title = nextValue || "";
        name.classList.toggle("muted", !nextValue);
    });

    recipeEditorMenuSectionFields().forEach(field => {
        const wrapper = field.querySelector(".recipe-edit-menu-section-value");
        if (!wrapper) {
            return;
        }
        wrapper.classList.toggle("muted", !nextValue);
    });
}

function updateRecipeEditorMenuSectionOptions(cookbookId = currentRecipeEditorCookbookId(), currentValue = currentRecipeEditorMenuSectionValue()) {
    const activeCookbookId = String(cookbookId || "").trim();
    const currentSection = String(currentValue || "").trim();
    const activeKey = recipeEditorMenuSectionKey(currentSection);

    if (activeCookbookId && currentSection) {
        ensureRecipeEditorMenuSectionOption(currentSection, activeCookbookId);
    }

    recipeEditorMenuSectionMenus().forEach(menu => {
        const seen = new Set();
        let menuVisibleCount = 0;

        menu.querySelectorAll("[data-recipe-edit-menu-section-option]").forEach(button => {
            const optionCookbookId = String(button.dataset.cookbookId || "").trim();
            const section = String(button.dataset.menuSection || button.textContent || "").trim();
            const optionKey = `${optionCookbookId}|${recipeEditorMenuSectionKey(section)}`;
            const visible = Boolean(activeCookbookId && optionCookbookId === activeCookbookId && section && !seen.has(optionKey));
            const row = recipeEditorMenuSectionRowFromControl(button);

            button.hidden = !visible;
            if (row) {
                row.hidden = !visible;
            }
            button.classList.toggle("is-selected", visible && recipeEditorMenuSectionKey(section) === activeKey);
            button.setAttribute("aria-current", visible && recipeEditorMenuSectionKey(section) === activeKey ? "true" : "false");

            if (visible) {
                seen.add(optionKey);
                menuVisibleCount += 1;
            }
        });

        menu.querySelectorAll("[data-recipe-edit-menu-section-empty]").forEach(label => {
            label.hidden = menuVisibleCount > 0;
        });
    });

    updateRecipeEditorMenuSectionMoveButtons(null, activeCookbookId);
    updateRecipeEditorMenuSectionDisplay(currentSection);
}

function ensureRecipeEditorMenuSectionOption(value, cookbookId = currentRecipeEditorCookbookId()) {
    const section = String(value || "").trim();
    const activeCookbookId = String(cookbookId || "").trim();

    if (!section || !activeCookbookId) {
        return;
    }

    recipeEditorMenuSectionMenus().forEach(menu => {
        const existing = Array.from(menu.querySelectorAll("[data-recipe-edit-menu-section-option]")).some(button => {
            return String(button.dataset.cookbookId || "").trim() === activeCookbookId
                && recipeEditorMenuSectionKey(button.dataset.menuSection || button.textContent) === recipeEditorMenuSectionKey(section);
        });

        if (existing) {
            return;
        }

        const row = createRecipeEditorMenuSectionOptionRow(section, activeCookbookId);
        const empty = menu.querySelector("[data-recipe-edit-menu-section-empty]");
        menu.insertBefore(row, empty || null);
    });
}

function selectRecipeEditMenuSection(button) {
    const value = button ? String(button.dataset.menuSection || "").trim() : "";

    closeRecipeEditRowMenus();
    setRecipeEditorMenuSectionValue(value, { userSelected: true });
    return false;
}

function editRecipeEditMenuSection(button) {
    const currentValue = currentRecipeEditorMenuSectionValue();
    const nextValue = window.prompt("Menu section", currentValue);

    if (nextValue === null) {
        closeRecipeEditRowMenus();
        return false;
    }

    closeRecipeEditRowMenus();
    setRecipeEditorMenuSectionValue(nextValue, { userSelected: true });
    return false;
}

function recipeEditorMenuSectionOrderFromRows(cookbookId = currentRecipeEditorCookbookId()) {
    const activeCookbookId = String(cookbookId || "").trim();
    const sections = [];
    const seen = new Set();

    recipeEditorMenuSectionVisibleRows(recipeEditorMenuSectionField(), activeCookbookId).forEach(row => {
        const section = String(row.dataset.menuSection || "").trim();
        const key = recipeEditorMenuSectionKey(section);

        if (section && !seen.has(key)) {
            sections.push(section);
            seen.add(key);
        }
    });

    return sections;
}

function reorderRecipeEditorMenuSectionRows(cookbookId, orderedSections = []) {
    const activeCookbookId = String(cookbookId || "").trim();
    const orderedKeys = new Map(
        orderedSections.map((section, index) => [recipeEditorMenuSectionKey(section), index])
    );

    recipeEditorMenuSectionMenus().forEach(menu => {
        const rows = Array.from(menu.querySelectorAll("[data-recipe-edit-menu-section-row]"))
            .filter(row => String(row.dataset.cookbookId || "").trim() === activeCookbookId)
            .map((row, index) => ({ row, index }));
        const anchor = recipeEditorMenuSectionRowOrderAnchor(menu);

        rows
            .sort((left, right) => {
                const leftOrder = orderedKeys.has(recipeEditorMenuSectionRowKey(left.row))
                    ? orderedKeys.get(recipeEditorMenuSectionRowKey(left.row))
                    : Number.POSITIVE_INFINITY;
                const rightOrder = orderedKeys.has(recipeEditorMenuSectionRowKey(right.row))
                    ? orderedKeys.get(recipeEditorMenuSectionRowKey(right.row))
                    : Number.POSITIVE_INFINITY;

                return (leftOrder - rightOrder) || (left.index - right.index);
            })
            .forEach(({ row }) => {
                menu.insertBefore(row, anchor || null);
            });
    });

    updateRecipeEditorMenuSectionOptions(activeCookbookId, currentRecipeEditorMenuSectionValue());
}

function updateCookbookMenuSectionOrderData(cookbookId, orderedSections = []) {
    const activeCookbookId = String(cookbookId || "").trim();
    const orderedKeys = new Map(
        orderedSections.map((section, index) => [recipeEditorMenuSectionKey(section), index])
    );

    document.querySelectorAll("[data-cookbook-menu-section]").forEach(card => {
        if (String(card.dataset.cookbookId || "").trim() !== activeCookbookId) {
            return;
        }

        const key = recipeEditorMenuSectionKey(card.dataset.cookbookMenuSection || "");
        if (orderedKeys.has(key)) {
            card.dataset.cookbookMenuSectionOrder = String(orderedKeys.get(key));
        } else {
            card.dataset.cookbookMenuSectionOrder = String(orderedSections.length);
        }
    });

    document.querySelectorAll("[data-cookbook-card]").forEach(card => {
        if (
            String(card.dataset.cookbookId || "").trim() === activeCookbookId
            && card.dataset.cookbookSortKey === "menu_section"
            && card.dataset.cookbookSortDirection
        ) {
            applyCookbookRecipeSort(card, "menu_section", {
                direction: card.dataset.cookbookSortDirection,
                persist: false,
            });
            applyCookbookRecipeSearch();
        }
    });
}

async function moveRecipeEditMenuSection(button, direction) {
    const row = recipeEditorMenuSectionRowFromControl(button);
    const menu = row && typeof row.closest === "function"
        ? row.closest(".recipe-edit-menu-section-menu")
        : null;
    const cookbookId = String(
        (button && button.dataset ? button.dataset.cookbookId : "")
        || (row && row.dataset ? row.dataset.cookbookId : "")
        || currentRecipeEditorCookbookId()
        || ""
    ).trim();
    const section = String(
        (button && button.dataset ? button.dataset.menuSection : "")
        || (row && row.dataset ? row.dataset.menuSection : "")
        || ""
    ).trim();
    const numericDirection = Number.parseInt(direction, 10);
    const movingUp = numericDirection < 0;
    const visibleRows = recipeEditorMenuSectionVisibleRowsForMenu(menu, cookbookId);
    const currentIndex = visibleRows.indexOf(row);
    const originalTitle = button ? button.title : "";

    if (!cookbookId || !section) {
        setRecipeEditStatus("Choose a cookbook section before moving it.", true);
        return false;
    }

    if (currentIndex < 0 || (movingUp && currentIndex === 0) || (!movingUp && currentIndex === visibleRows.length - 1)) {
        setRecipeEditStatus(`Menu section is already at the ${movingUp ? "top" : "bottom"}.`);
        updateRecipeEditorMenuSectionMoveButtons(null, cookbookId);
        return false;
    }

    try {
        if (button) {
            button.disabled = true;
            button.title = movingUp ? "Moving section up..." : "Moving section down...";
        }

        setRecipeEditStatus(movingUp ? "Moving menu section up..." : "Moving menu section down...");

        const formData = new FormData();
        formData.set("menu_section", section);
        formData.set("direction", movingUp ? "-1" : "1");
        const data = await submitCookbookApi(
            `/api/cookbooks/${encodeURIComponent(cookbookId)}/menu_sections/reorder`,
            formData,
        );
        const orderedSections = Array.isArray(data.menu_section_order)
            ? data.menu_section_order
            : recipeEditorMenuSectionOrderFromRows(cookbookId);

        reorderRecipeEditorMenuSectionRows(cookbookId, orderedSections);
        updateCookbookMenuSectionOrderData(cookbookId, orderedSections);
        setRecipeEditStatus(movingUp ? "Menu section moved up." : "Menu section moved down.");
        showRecipeQuantityUpdatedMessage("", "", "", movingUp ? "Menu section moved up." : "Menu section moved down.");
    } catch (err) {
        console.warn("Unable to move menu section.", err);
        setRecipeEditStatus(err.message || "Unable to move menu section.", true);
        window.alert(err.message || "Unable to move menu section.");
    } finally {
        if (button && button.isConnected) {
            button.disabled = false;
            button.title = originalTitle || (movingUp ? "Move section up" : "Move section down");
        }
        updateRecipeEditorMenuSectionMoveButtons(null, cookbookId);
    }

    return false;
}

function updateRecipeEditorPdfControls(recipe, options = {}) {
    const sourcePdfPathInput = document.getElementById("recipeEditSourcePdfPath");
    const sourcePdfPathLink = document.getElementById("recipeEditSourcePdfPathLink");
    const sourceCloudflareInput = document.getElementById("recipeEditSourceCloudflarePdfUrl");
    const sourceCloudflareLink = document.getElementById("recipeEditSourceCloudflarePdfUrlLink");
    const generatedPdfPathInput = document.getElementById("recipeEditGeneratedPdfPath");
    const generatedPdfPathLink = document.getElementById("recipeEditGeneratedPdfPathLink");
    const generatedCloudflareInput = document.getElementById("recipeEditGeneratedCloudflarePdfUrl");
    const generatedCloudflareLink = document.getElementById("recipeEditGeneratedCloudflarePdfUrlLink");
    const pdfButton = document.getElementById("recipeEditPdfButton");
    const pdfMobileButton = document.getElementById("recipeEditPdfButtonMobile");
    const sourcePdfButton = document.getElementById("recipeEditSourcePdfButton");
    const sourcePdfMobileButton = document.getElementById("recipeEditSourcePdfButtonMobile");
    const pdfPanelButton = document.getElementById("recipeEditPdfButtonPanel");
    const pdfMenuButton = document.getElementById("recipeEditPdfMenuButton");
    const localPdfDownloadButton = document.getElementById("recipeEditLocalPdfDownloadButton");
    const deletePdfButton = document.getElementById("recipeEditDeletePdfButton");
    const copyPdfLinkButton = document.getElementById("recipeEditCopyPdfLinkButton");
    const uploadPdfButton = document.getElementById("recipeEditUploadPdfButton");
    const createPdfButtons = [
        document.getElementById("recipeEditCreatePdfButton"),
        document.getElementById("recipeEditCreatePdfButtonLegacy"),
    ];
    const pdfValues = normalizeRecipeEditorPdfValues(recipe || {}, recipeEditorCurrentUrl(), {
        useCurrentForMissing: options.useCurrentForMissing !== false,
    });
    const updateInputValues = options.updateInputValues !== false;
    const sourceUrl = pdfValues.source_url;
    const sourcePdfPath = pdfValues.source_pdf_path;
    const sourceCloudflareUrl = pdfValues.source_cloudflare_pdf_url;
    const generatedPdfPath = pdfValues.generated_pdf_path;
    const generatedCloudflareUrl = pdfValues.generated_cloudflare_pdf_url;
    const hasGeneratedLocalPdf = Boolean(recipe && sourceUrl && (
        recipe.generated_pdf_local_available
        || recipe.generated_recipe_pdf_local_available
        || generatedPdfPath
    ));
    const hasSourceLocalPdf = Boolean(recipe && sourceUrl && (
        recipe.source_pdf_local_available
        || recipe.webpage_backup_pdf_local_available
        || sourcePdfPath
    ));
    const generatedArchiveUrl = hasGeneratedLocalPdf
        ? recipeArchivePdfUrl(sourceUrl, "generated_recipe")
        : "";
    const generatedOpenUrl = generatedCloudflareUrl;
    const sourceArchiveUrl = hasSourceLocalPdf
        ? recipeArchivePdfUrl(sourceUrl, "webpage_backup")
        : "";
    const sourceOpenUrl = sourceCloudflareUrl;
    const hasGeneratedPdf = Boolean(generatedCloudflareUrl || generatedArchiveUrl);
    const requiresServingEstimate = isUploadedRecipeSourceUrl(sourceUrl) && !recipeHasPerServingEstimate(recipe || {});
    const createPdfUnavailableReason = "Estimate per serving basis is required before creating the recipe PDF.";

    setRecipePdfFieldOpenTarget(sourcePdfPathInput, sourcePdfPathLink, sourcePdfPath, sourceArchiveUrl, "Open Source PDF Path", {
        updateInput: updateInputValues,
    });
    setRecipePdfFieldOpenTarget(sourceCloudflareInput, sourceCloudflareLink, sourceCloudflareUrl, sourceCloudflareUrl, "Open Source Cloudflare PDF", {
        updateInput: updateInputValues,
    });
    setRecipePdfFieldOpenTarget(generatedPdfPathInput, generatedPdfPathLink, generatedPdfPath, generatedArchiveUrl, "Open Generated PDF", {
        updateInput: updateInputValues,
    });
    setRecipePdfFieldOpenTarget(generatedCloudflareInput, generatedCloudflareLink, generatedCloudflareUrl, generatedCloudflareUrl, "Open Generated Cloudflare PDF", {
        updateInput: updateInputValues,
    });

    [pdfButton, pdfMobileButton].forEach((button) => {
        if (button) {
            button.hidden = !generatedOpenUrl;
            button.href = generatedOpenUrl || "#";
            button.dataset.recipePdfUrl = generatedOpenUrl || "";
        }
    });

    [pdfPanelButton, pdfMenuButton].forEach((button) => {
        if (button) {
            button.hidden = !generatedOpenUrl;
            button.href = generatedOpenUrl || "#";
            button.dataset.recipePdfUrl = generatedOpenUrl || "";
        }
    });

    [sourcePdfButton, sourcePdfMobileButton].forEach((button) => {
        if (button) {
            button.hidden = !sourceOpenUrl;
            button.href = sourceOpenUrl || "#";
            button.dataset.recipePdfUrl = sourceOpenUrl || "";
        }
    });

    if (deletePdfButton) {
        deletePdfButton.hidden = !hasGeneratedPdf;
    }

    if (localPdfDownloadButton) {
        localPdfDownloadButton.hidden = !hasGeneratedLocalPdf;
        localPdfDownloadButton.href = hasGeneratedLocalPdf ? recipeArchivePdfDownloadUrl(sourceUrl, "generated_recipe") : "#";
    }

    if (copyPdfLinkButton) {
        copyPdfLinkButton.hidden = !generatedCloudflareUrl;
        copyPdfLinkButton.dataset.pdfPublicUrl = generatedCloudflareUrl;
    }

    if (uploadPdfButton) {
        uploadPdfButton.hidden = !sourceUrl || !hasGeneratedLocalPdf || Boolean(generatedCloudflareUrl);
    }

    createPdfButtons.forEach((button) => {
        if (!button) {
            return;
        }

        button.hidden = Boolean(generatedOpenUrl);
        button.disabled = requiresServingEstimate;
        button.title = requiresServingEstimate ? createPdfUnavailableReason : "Create recipe PDF";
        button.setAttribute("aria-label", requiresServingEstimate ? createPdfUnavailableReason : "Create recipe PDF");
    });
    syncRecipeEditDocumentRows();
}

function syncRecipeEditSourceFilesDetails() {
    const details = document.getElementById("recipeEditSourceFilesDetails");

    if (!details) {
        return;
    }

    const mobile = window.matchMedia
        ? window.matchMedia("(max-width: 760px)").matches
        : window.innerWidth <= 760;

    details.open = false;
}

function recipeEditTabKey(value) {
    const normalized = String(value || "").trim().toLowerCase().replace(/[^a-z]+/g, "");
    return {
        ingredient: "ingredients",
        ingredients: "ingredients",
        instruction: "instructions",
        instructions: "instructions",
        equipment: "equipment",
        nutrition: "nutrition",
        note: "notes",
        notes: "notes",
        reflection: "notes",
    }[normalized] || "ingredients";
}

function setRecipeEditActiveTab(tabKey, options = {}) {
    const activeKey = recipeEditTabKey(tabKey);
    const tabsRoot = document.querySelector("[data-recipe-edit-tabs]");

    if (!tabsRoot) {
        return false;
    }

    tabsRoot.querySelectorAll("[data-recipe-edit-tab]").forEach(tab => {
        const selected = recipeEditTabKey(tab.dataset.recipeEditTab) === activeKey;
        tab.classList.toggle("is-active", selected);
        tab.setAttribute("aria-selected", selected ? "true" : "false");
        tab.tabIndex = selected ? 0 : -1;
        if (selected && options.focus) {
            tab.focus({ preventScroll: true });
        }
    });

    tabsRoot.querySelectorAll("[data-recipe-edit-tab-panel]").forEach(panel => {
        panel.hidden = recipeEditTabKey(panel.dataset.recipeEditTabPanel) !== activeKey;
    });

    updateRecipeEditStickyOffsets();
    return true;
}

function initRecipeEditTabs() {
    const tabsRoot = document.querySelector("[data-recipe-edit-tabs]");

    if (!tabsRoot || tabsRoot.dataset.recipeEditTabsBound === "1") {
        return;
    }

    tabsRoot.dataset.recipeEditTabsBound = "1";

    tabsRoot.querySelectorAll("[data-recipe-edit-tab]").forEach(tab => {
        tab.addEventListener("click", () => {
            setRecipeEditActiveTab(tab.dataset.recipeEditTab, { focus: false });
        });
        tab.addEventListener("keydown", event => {
            const tabs = Array.from(tabsRoot.querySelectorAll("[data-recipe-edit-tab]"));
            const index = tabs.indexOf(tab);
            let nextIndex = -1;

            if (event.key === "ArrowRight" || event.key === "ArrowDown") {
                nextIndex = (index + 1) % tabs.length;
            } else if (event.key === "ArrowLeft" || event.key === "ArrowUp") {
                nextIndex = (index - 1 + tabs.length) % tabs.length;
            } else if (event.key === "Home") {
                nextIndex = 0;
            } else if (event.key === "End") {
                nextIndex = tabs.length - 1;
            }

            if (nextIndex >= 0) {
                event.preventDefault();
                setRecipeEditActiveTab(tabs[nextIndex].dataset.recipeEditTab, { focus: true });
            }
        });
    });

    setRecipeEditActiveTab("ingredients");
}

function recipeEditInputValue(id) {
    const input = document.getElementById(id);
    return input ? String(input.value || "").trim() : "";
}

function recipeEditFieldContainer(id) {
    const input = document.getElementById(id);
    return input ? input.closest("label, .recipe-edit-cookbook-field") : null;
}

function setRecipeEditFieldLabel(field, text) {
    if (!field) {
        return;
    }
    const label = field.querySelector(
        ":scope > .recipe-edit-cookbook-label, :scope > .recipe-edit-label-line > span:first-child, :scope > span:first-child"
    );
    if (label) {
        label.textContent = text;
    }
}

function appendRecipeEditWorkspaceChildren(parent, children) {
    if (!parent) {
        return;
    }
    children.filter(Boolean).forEach(child => parent.appendChild(child));
}

function addRecipeEditUnit(field, unit) {
    if (!field || field.querySelector("[data-recipe-edit-unit]")) {
        return;
    }
    field.classList.add("recipe-edit-compact-metadata-field");
    const input = field.querySelector("input");
    if (!input) return;
    const valueWrap = document.createElement("div");
    valueWrap.className = "recipe-edit-metadata-value";
    input.parentNode.insertBefore(valueWrap, input);
    valueWrap.appendChild(input);
    const unitLabel = document.createElement("span");
    unitLabel.className = "recipe-edit-metadata-unit";
    unitLabel.dataset.recipeEditUnit = unit;
    unitLabel.textContent = unit;
    valueWrap.appendChild(unitLabel);
}

function updateRecipeEditMetadataUnits() {
    document.querySelectorAll("[data-recipe-edit-unit]").forEach(unit => {
        const field = unit.closest("label");
        const input = field ? field.querySelector("input") : null;
        let value = input ? String(input.value || "").trim() : "";
        if (recipeEditorStandalonePageIsActive() && input) {
            value = value.replace(/\s*(people|persons?|servings?|minutes?|mins?)\s*$/i, "").trim();
            input.value = value;
            unit.hidden = false;
        } else {
            unit.hidden = /[a-z]/i.test(value);
        }
    });
}

function openRecipeEditCuisinePicker(button) {
    const select = document.getElementById("recipeEditCategoryCuisine");
    if (!select) {
        return false;
    }
    select.focus({ preventScroll: true });
    if (typeof select.showPicker === "function") {
        try {
            select.showPicker();
        } catch (err) {
            // Focus is a useful fallback when the browser restricts showPicker().
        }
    }
    return false;
}

function clearRecipeEditCuisineTag(button) {
    const select = document.getElementById("recipeEditCategoryCuisine");
    if (!select) {
        return false;
    }
    select.value = "";
    select.dispatchEvent(new Event("change", { bubbles: true }));
    return false;
}

function renderRecipeEditCuisineChips() {
    const select = document.getElementById("recipeEditCategoryCuisine");
    const field = select?.closest("label");
    const chips = field?.querySelector("[data-recipe-edit-cuisine-chips]");
    if (!select || !chips) return;
    const value = String(select.value || "").trim();
    const removeIcon = document.querySelector('[data-recipe-metadata-icon="x"]')?.innerHTML || "&times;";
    chips.innerHTML = value ? `
        <span class="recipe-edit-tag-chip">
            <span>${escapeHtml(value)}</span>
            <button type="button" aria-label="Remove ${escapeAttribute(value)}" onclick="return clearRecipeEditCuisineTag(this)">${removeIcon}</button>
        </span>
    ` : '<span class="recipe-edit-tag-empty">No cuisine tags selected</span>';
}

function recipeEditMetadataIcon(kind) {
    const template = document.querySelector(`[data-recipe-metadata-icon="${kind}"]`);
    return `<span class="recipe-edit-metadata-icon" aria-hidden="true">${template ? template.innerHTML : ""}</span>`;
}

function addRecipeEditMetadataIcon(field, kind) {
    if (field && !field.querySelector(".recipe-edit-metadata-icon")) {
        field.insertAdjacentHTML("afterbegin", recipeEditMetadataIcon(kind));
    }
}

function organizeRecipeEditMetadataField(field) {
    if (!field || field.querySelector(".recipe-edit-metadata-heading")) return;
    const icon = field.querySelector(":scope > .recipe-edit-metadata-icon");
    const labelLine = field.querySelector(":scope > .recipe-edit-label-line");
    const label = labelLine
        ? (labelLine.matches("span") && !labelLine.querySelector(":scope > span:first-child")
            ? labelLine
            : labelLine.querySelector(":scope > span:first-child"))
        : Array.from(field.children).find(child => child.tagName === "SPAN" && !child.classList.contains("recipe-edit-metadata-icon"));
    if (!icon || !label) return;
    const heading = document.createElement("div");
    heading.className = "recipe-edit-metadata-heading";
    field.insertBefore(heading, field.firstChild);
    heading.append(icon, label);
    if (labelLine && labelLine !== label) labelLine.hidden = true;

    const control = field.querySelector(":scope > input, :scope > select");
    if (control && !control.closest(".recipe-edit-metadata-value")) {
        const valueWrap = document.createElement("div");
        valueWrap.className = "recipe-edit-metadata-value";
        control.parentNode.insertBefore(valueWrap, control);
        valueWrap.appendChild(control);
    }
}

function normalizeRecipeEditPriceDisplay() {
    const input = document.getElementById("recipeEditMenuPrice");
    if (!input) return;
    const value = String(input.value || "").trim();
    if (value.startsWith("$")) input.value = value.slice(1).trim();
}

function setRecipeEditDifficultyValue(value) {
    const select = document.getElementById("recipeEditLevel");
    if (!select) return;
    const normalized = String(value || "").trim();
    const matchingOption = Array.from(select.options || [])
        .find(option => String(option.value || "").toLowerCase() === normalized.toLowerCase());
    if (matchingOption) {
        select.value = matchingOption.value;
        return;
    }
    if (normalized) {
        const option = document.createElement("option");
        option.value = normalized;
        option.textContent = normalized;
        select.appendChild(option);
    }
    select.value = normalized;
}

function updateRecipeEditDescriptionCount() {
    const textarea = document.getElementById("recipeEditDescription");
    const counter = document.querySelector("[data-recipe-edit-description-count]");
    if (textarea && counter) counter.textContent = `${String(textarea.value || "").length} characters`;
}

function organizeRecipeEditImageCard() {
    const imageCardContent = document.getElementById("recipeEditImageCardContent");
    const coverField = document.getElementById("recipeEditCoverField");
    if (!imageCardContent || !coverField) {
        return;
    }

    imageCardContent.appendChild(coverField);
    const actions = coverField.querySelector(".recipe-edit-cover-actions");
    const upload = actions ? actions.querySelector(".recipe-edit-cover-upload-button:not(.recipe-edit-cover-generate-button):not(.recipe-edit-cover-remove-button)") : null;
    const remove = document.getElementById("recipeEditCoverRemove");
    const uploadLabel = document.getElementById("recipeEditCoverUploadLabel");
    const generateLabel = document.getElementById("recipeEditCoverGenerateLabel");
    let generate = actions ? actions.querySelector("[data-recipe-edit-cover-generate-direct]") : null;

    if (uploadLabel) {
        uploadLabel.textContent = "Replace Image";
    }
    if (generateLabel) {
        generateLabel.textContent = "AI Generate";
    }
    if (actions && !generate) {
        generate = document.createElement("button");
        generate.type = "button";
        generate.className = "recipe-edit-cover-upload-button recipe-edit-cover-generate-direct";
        generate.dataset.recipeEditCoverGenerateDirect = "";
        generate.innerHTML = `${recipeEditSvgIcon("sparkles")}<span>AI Generate</span>`;
        generate.addEventListener("click", () => generateRecipeCoverImage(generate));
    }

    if (actions) {
        actions.classList.add("recipe-edit-cover-primary-actions");
        appendRecipeEditWorkspaceChildren(actions, [upload, generate, remove]);
    }

    closeRecipeImageChangeActions();
    if (upload) upload.setAttribute("aria-expanded", "false");

}

