const RECIPE_INGREDIENT_BUILT_IN_TYPES = [
    { value: "main", label: "Main" },
    { value: "optional", label: "Optional" },
    { value: "garnish", label: "Garnish" },
    { value: "topping", label: "Topping" },
    { value: "sauce", label: "Sauce" },
    { value: "substitute", label: "Substitute" },
];

function recipeIngredientTypeKey(value) {
    return String(value || "")
        .trim()
        .toLowerCase()
        .replace(/[_-]+/g, " ")
        .replace(/\s+/g, " ");
}

function recipeIngredientBuiltInType(value) {
    const key = recipeIngredientTypeKey(value);
    return RECIPE_INGREDIENT_BUILT_IN_TYPES.find(type => recipeIngredientTypeKey(type.value) === key) || null;
}

function recipeIngredientTypeValue(values = {}) {
    const explicitType = String(values.section || values.ingredient_type || values.type || "").trim();
    const optional = values.optional === true
        || ["1", "true", "yes", "on"].includes(String(values.optional || "").trim().toLowerCase());
    if (optional) {
        return "optional";
    }
    const builtIn = recipeIngredientBuiltInType(explicitType);
    return builtIn ? builtIn.value : explicitType || "main";
}

function recipeIngredientTypeLabel(values = {}) {
    const value = recipeIngredientTypeValue(values);
    const builtIn = recipeIngredientBuiltInType(value);
    return builtIn ? builtIn.label : value;
}

function recipeIngredientPluralUnit(unit, quantity) {
    const value = String(unit || "").trim();
    if (!value || /^(?:to taste|as needed)$/i.test(value)) {
        return value;
    }
    if (/^pieces?$/i.test(value)) {
        return "";
    }
    const numericQuantity = Number.parseFloat(String(quantity || "").trim());
    if (numericQuantity === 1 || /s$/i.test(value)) {
        return value;
    }
    const plurals = {
        tablespoon: "tablespoons",
        teaspoon: "teaspoons",
        cup: "cups",
        pint: "pints",
        quart: "quarts",
        gallon: "gallons",
        ounce: "ounces",
        pound: "pounds",
        clove: "cloves",
        piece: "pieces",
        can: "cans",
        package: "packages",
    };
    return plurals[value.toLowerCase()] || value;
}

function formatRecipeIngredientQuantity(values = {}) {
    const quantityText = String(values.quantity_text || "").trim();
    const quantity = String(values.quantity || values.amount || "").trim();
    const unit = String(values.unit || "").trim();
    const size = String(values.size || "").trim();
    const phrase = quantityText
        || (!/\d/.test(quantity) ? quantity : "")
        || (/^(?:to taste|as needed)$/i.test(unit) ? unit : "");
    if (phrase) {
        return phrase;
    }
    return [quantity, size, recipeIngredientPluralUnit(unit, quantity)]
        .filter((value, index, valuesList) => value && valuesList.indexOf(value) === index)
        .join(" ") || "\u2014";
}

function formatRecipeIngredientQuantityColumn(values = {}) {
    const quantityText = String(values.quantity_text || "").trim();
    const quantity = String(values.quantity || values.amount || "").trim();
    const unit = String(values.unit || "").trim();
    return quantityText
        || (!/\d/.test(quantity) ? quantity : "")
        || (/^(?:to taste|as needed)$/i.test(unit) ? unit : "")
        || quantity
        || "\u2014";
}

function formatRecipeIngredientUnitColumn(values = {}) {
    const quantityText = String(values.quantity_text || "").trim();
    const quantity = String(values.quantity || values.amount || "").trim();
    const unit = String(values.unit || "").trim();
    const size = String(values.size || "").trim();
    if (quantityText || (!/\d/.test(quantity) && quantity) || /^(?:to taste|as needed)$/i.test(unit)) {
        return "\u2014";
    }
    return size || recipeIngredientPluralUnit(unit, quantity) || "\u2014";
}

function recipeIngredientComparableText(value) {
    return String(value || "")
        .normalize("NFKD")
        .replace(/[\u0300-\u036f]/g, "")
        .toLowerCase()
        .replace(/[^a-z0-9]+/g, " ")
        .trim()
        .replace(/\s+/g, " ");
}

function recipeIngredientMeaningfulBuyAs(values = {}) {
    const ingredient = String(values.ingredient || "").trim();
    const buyAs = String(values.purchasable_item || values.buy_as || "").trim();
    if (!buyAs || recipeIngredientComparableText(ingredient) === recipeIngredientComparableText(buyAs)) {
        return "";
    }
    return buyAs;
}

function recipeIngredientSentenceCase(value) {
    const text = String(value || "").trim();
    return text ? text.charAt(0).toUpperCase() + text.slice(1) : "";
}

function recipeIngredientReadStatusHtml(item = {}) {
    const match = recipeIngredientMatchDetails(item);
    const pantryText = `${item.ingredient || ""} ${item.purchasable_item || item.buy_as || ""} ${item.store_section || ""}`.toUpperCase();
    const pantryStaple = recipeIngredientMatchFlag(item.pantry_staple)
        || recipeIngredientMatchFlag(item.is_pantry_staple)
        || pantryText.includes("BEAN")
        || pantryText.includes("LEGUME")
        || pantryText.includes("SPICE");
    const statusLabels = {
        "Review Match": "Review match",
        "Low Confidence": "Low confidence",
        "Multiple Matches": "Multiple matches",
    };
    const status = statusLabels[match.attentionStatus]
        || match.attentionStatus
        || (pantryStaple ? "Pantry staple" : "Good match");
    const statusClass = match.attentionStatus
        ? ` requires-review ${recipeIngredientTypeKey(match.attentionStatus).replace(/\s+/g, "-")}`
        : (pantryStaple ? " pantry-staple" : " good-match");
    const preparation = recipeIngredientSentenceCase(item.preparation);
    return `${preparation ? `<span class="recipe-edit-ingredient-read-preparation">${escapeHtml(preparation)}</span><span class="recipe-edit-ingredient-read-separator" aria-hidden="true">\u00b7</span>` : ""}<span class="recipe-edit-ingredient-read-match${statusClass}">${escapeHtml(status)}</span>`;
}

function recipeIngredientEditableFieldSnapshot(scope) {
    const values = {};
    if (!scope) {
        return values;
    }
    scope.querySelectorAll("[data-field]").forEach(input => {
        const optionRow = input.closest("[data-substitution-option-row]");
        if (optionRow && optionRow !== scope) {
            return;
        }
        values[input.dataset.field] = input.type === "checkbox" ? input.checked : input.value;
    });
    return values;
}

function restoreRecipeIngredientEditableFieldSnapshot(scope, values = {}) {
    if (!scope) {
        return;
    }
    scope.querySelectorAll("[data-field]").forEach(input => {
        const optionRow = input.closest("[data-substitution-option-row]");
        if (optionRow && optionRow !== scope) {
            return;
        }
        if (!Object.prototype.hasOwnProperty.call(values, input.dataset.field)) {
            return;
        }
        if (input.type === "checkbox") {
            input.checked = Boolean(values[input.dataset.field]);
        } else {
            input.value = values[input.dataset.field] == null ? "" : String(values[input.dataset.field]);
        }
        if (input.dataset.field === "store_section") {
            syncRecipeIngredientStoreSectionControl(input);
        }
        if (input.dataset.field === "section") {
            syncRecipeIngredientTypeControl(input);
        }
        if (input.dataset.field === "unit") {
            canonicalizeRecipeIngredientUnitControl(input, { allowCustom: true });
        }
    });
}

const RECIPE_INGREDIENT_MODAL_IMMEDIATE_FIELDS = new Set([
    "ingredient_image_url",
    "ingredient_image_generated_at",
    "ingredient_image_prompt",
]);

function recipeIngredientModalEditableFieldSnapshot(scope) {
    const values = recipeIngredientEditableFieldSnapshot(scope);
    RECIPE_INGREDIENT_MODAL_IMMEDIATE_FIELDS.forEach(field => delete values[field]);
    return values;
}

function recipeIngredientModalHasChanges(row) {
    const panel = row ? row.querySelector("[data-recipe-ingredient-edit-panel]") : null;
    if (!panel || !panel.dataset.editSnapshot) {
        return false;
    }
    try {
        return JSON.stringify(recipeIngredientModalEditableFieldSnapshot(row)) !== panel.dataset.editSnapshot;
    } catch (error) {
        console.warn("Unable to compare the ingredient edit values.", error);
        return true;
    }
}

function setRecipeIngredientModalStatus(panel, state = "", message = "") {
    const status = panel ? panel.querySelector("[data-recipe-ingredient-modal-status]") : null;
    if (!status) return;
    const labels = {
        dirty: "Unsaved changes",
        saving: "Saving\u2026",
        saved: "Saved",
    };
    const normalizedState = String(state || "").trim();
    status.dataset.state = normalizedState;
    status.textContent = String(message || labels[normalizedState] || "");
}

function updateRecipeIngredientModalDirtyStatus(row) {
    const panel = row ? row.querySelector("[data-recipe-ingredient-edit-panel]") : null;
    if (!panel || panel.dataset.saving === "true") return;
    setRecipeIngredientModalStatus(
        panel,
        recipeIngredientModalHasChanges(row) ? "dirty" : ""
    );
}

const RECIPE_INGREDIENT_MODAL_SCROLL_LOCK_CLASS = "recipe-ingredient-modal-scroll-locked";
const RECIPE_INGREDIENT_MODAL_SCROLL_CONTAINER_SELECTOR = [
    "[data-app-content]",
    ".app-sidebar",
    ".recipe-edit-ingredient-table-scroll",
].join(", ");

function captureRecipeIngredientModalScrollState() {
    const seen = new Set();
    const containers = Array.from(document.querySelectorAll(
        RECIPE_INGREDIENT_MODAL_SCROLL_CONTAINER_SELECTOR
    )).filter(element => {
        if (seen.has(element)) return false;
        seen.add(element);
        return true;
    }).map(element => {
        const wasLocked = element.classList.contains(RECIPE_INGREDIENT_MODAL_SCROLL_LOCK_CLASS);
        element.classList.add(RECIPE_INGREDIENT_MODAL_SCROLL_LOCK_CLASS);
        return {
            element,
            scrollLeft: element.scrollLeft,
            scrollTop: element.scrollTop,
            wasLocked,
        };
    });
    return {
        containers,
        windowX: window.scrollX,
        windowY: window.scrollY,
    };
}

function restoreRecipeIngredientModalScrollState() {
    const state = recipeEditIngredientModalScrollState;
    recipeEditIngredientModalScrollState = null;
    if (!state) return;
    const restore = () => {
        state.containers.forEach(({ element, scrollLeft, scrollTop, wasLocked }) => {
            if (!element.isConnected) return;
            if (!wasLocked) {
                element.classList.remove(RECIPE_INGREDIENT_MODAL_SCROLL_LOCK_CLASS);
            }
            element.scrollLeft = scrollLeft;
            element.scrollTop = scrollTop;
        });
        window.scrollTo({
            top: state.windowY,
            left: state.windowX,
            behavior: "auto",
        });
    };
    restore();
    window.requestAnimationFrame?.(restore);
}

function recipeIngredientModalImagePanel(row) {
    return row ? row.querySelector("[data-ingredient-image-panel]") : null;
}

function recipeIngredientModalHasImage(imagePanel) {
    const field = imagePanel ? imagePanel.querySelector('[data-field="ingredient_image_url"]') : null;
    return Boolean(field && String(field.value || "").trim());
}

function syncRecipeIngredientModalImageActions(imagePanel) {
    if (!imagePanel || !imagePanel.closest("[data-recipe-ingredient-edit-panel]")) {
        return;
    }
    const generateButton = imagePanel.querySelector("[data-ingredient-image-generate]");
    const uploadButton = imagePanel.querySelector("[data-recipe-image-upload-button]");
    const removeButton = imagePanel.querySelector("[data-ingredient-image-remove]");
    if (generateButton) {
        generateButton.textContent = "Generate Image";
        generateButton.title = "Generate an ingredient image with AI";
    }
    if (uploadButton) {
        uploadButton.textContent = recipeIngredientModalHasImage(imagePanel) ? "Change Image" : "Add Image";
        uploadButton.title = uploadButton.textContent;
    }
    if (removeButton) {
        removeButton.textContent = "Remove";
        removeButton.title = "Remove ingredient image";
    }
    const image = imagePanel.querySelector(".recipe-ingredient-image:not([hidden])");
    if (image) {
        image.tabIndex = 0;
        image.setAttribute("role", "button");
        image.setAttribute("aria-label", "Enlarge ingredient image");
        image.title = "Click to enlarge ingredient image";
    }
}

function mountRecipeIngredientModalImage(row, panel) {
    const imagePanel = recipeIngredientModalImagePanel(row);
    const slot = panel ? panel.querySelector("[data-recipe-ingredient-modal-image-slot]") : null;
    if (!imagePanel || !slot || imagePanel.closest("[data-recipe-ingredient-edit-panel]") === panel) {
        return;
    }
    const placeholder = document.createComment("recipe-ingredient-image-placeholder");
    imagePanel.parentNode?.insertBefore(placeholder, imagePanel);
    imagePanel.recipeIngredientModalPlaceholder = placeholder;
    imagePanel.classList.add("recipe-edit-ingredient-modal-image-panel");
    slot.appendChild(imagePanel);
    syncRecipeIngredientModalImageActions(imagePanel);
}

function restoreRecipeIngredientModalImage(row) {
    const imagePanel = recipeIngredientModalImagePanel(row);
    if (!imagePanel) return;
    const placeholder = imagePanel.recipeIngredientModalPlaceholder;
    if (placeholder && placeholder.parentNode) {
        placeholder.parentNode.insertBefore(imagePanel, placeholder);
        placeholder.remove();
    }
    delete imagePanel.recipeIngredientModalPlaceholder;
    imagePanel.classList.remove(
        "recipe-edit-ingredient-modal-image-panel",
        "recipe-ingredient-image-prompt-requested"
    );
    const generateButton = imagePanel.querySelector("[data-ingredient-image-generate]");
    if (generateButton) {
        generateButton.textContent = recipeIngredientModalHasImage(imagePanel)
            ? "Regenerate ingredient image"
            : "Generate ingredient image";
        generateButton.removeAttribute("title");
    }
    updateRecipeImagePanelUploadButton(imagePanel, "ingredient");
}

function recipeIngredientModalFieldError(input) {
    const field = String(input && input.dataset ? input.dataset.field || "field" : "field");
    const wrapper = input ? input.closest(".recipe-edit-ingredient-edit-field") : null;
    if (!wrapper) return null;
    let error = wrapper.querySelector(`[data-recipe-ingredient-field-error="${field}"]`);
    if (!error) {
        error = document.createElement("span");
        error.className = "recipe-edit-ingredient-field-error";
        error.dataset.recipeIngredientFieldError = field;
        error.setAttribute("role", "alert");
        error.hidden = true;
        wrapper.appendChild(error);
    }
    return error;
}

function setRecipeIngredientModalFieldError(input, message = "") {
    const error = recipeIngredientModalFieldError(input);
    if (!input || !error) return;
    const text = String(message || "").trim();
    input.toggleAttribute("aria-invalid", Boolean(text));
    error.textContent = text;
    error.hidden = !text;
}

function clearRecipeIngredientModalErrors(panel) {
    if (!panel) return;
    panel.querySelectorAll("[data-recipe-ingredient-field-error]").forEach(error => {
        error.textContent = "";
        error.hidden = true;
    });
    panel.querySelectorAll('[aria-invalid="true"]').forEach(input => input.removeAttribute("aria-invalid"));
    const error = panel.querySelector("[data-recipe-ingredient-modal-error]");
    if (error) {
        error.textContent = "";
        error.hidden = true;
    }
}

function setRecipeIngredientModalError(panel, message = "") {
    const error = panel ? panel.querySelector("[data-recipe-ingredient-modal-error]") : null;
    if (!error) return;
    error.textContent = String(message || "");
    error.hidden = !error.textContent;
    if (error.textContent) {
        setRecipeIngredientModalStatus(panel, "error", error.textContent);
    }
}

function validateRecipeIngredientModal(row, panel) {
    clearRecipeIngredientModalErrors(panel);
    const ingredient = row ? recipeIngredientDirectField(row, "ingredient") : null;
    const unit = row ? recipeIngredientDirectField(row, "unit") : null;
    let firstInvalid = null;
    if (!ingredient || !String(ingredient.value || "").trim()) {
        setRecipeIngredientModalFieldError(ingredient, "Ingredient Name is required.");
        firstInvalid = ingredient;
    }
    if (unit && !canonicalizeRecipeIngredientUnitControl(unit, { allowCustom: true })) {
        setRecipeIngredientModalFieldError(
            unit,
            unit.validationMessage || "Choose a unit from the list, add a custom unit, or leave it blank."
        );
        firstInvalid = firstInvalid || unit;
    }
    if (firstInvalid) {
        setRecipeIngredientModalError(panel, "Review the highlighted field before saving.");
        firstInvalid.focus({ preventScroll: true });
        firstInvalid.scrollIntoView({ block: "center", behavior: "smooth" });
        return false;
    }
    return true;
}

function recipeIngredientModalPersistedIndex(row) {
    const value = row && row.dataset ? row.dataset.recipeIngredientPersistedIndex : "";
    if (value === "" || value === undefined) return -1;
    const index = Number.parseInt(value, 10);
    return Number.isInteger(index) && index >= 0 ? index : -1;
}

function recipeIngredientModalInsertionIndex(row) {
    const rows = recipeEditIngredientRows();
    const currentIndex = rows.indexOf(row);
    for (let index = currentIndex + 1; index < rows.length; index += 1) {
        const persistedIndex = recipeIngredientModalPersistedIndex(rows[index]);
        if (persistedIndex >= 0) return persistedIndex;
    }
    for (let index = currentIndex - 1; index >= 0; index -= 1) {
        const persistedIndex = recipeIngredientModalPersistedIndex(rows[index]);
        if (persistedIndex >= 0) return persistedIndex + 1;
    }
    return 0;
}

function recipeIngredientModalReference(row, panel) {
    let original = {};
    try {
        original = JSON.parse(panel && panel.dataset.editSnapshot ? panel.dataset.editSnapshot : "{}");
    } catch (error) {
        original = {};
    }
    const create = Boolean(row && row.dataset.recipeIngredientNew === "true");
    const persistedIndex = recipeIngredientModalPersistedIndex(row);
    return {
        create,
        index: create
            ? recipeIngredientModalInsertionIndex(row)
            : (persistedIndex >= 0 ? persistedIndex : recipeEditIngredientRows().indexOf(row)),
        id: create ? "" : String(original.id || "").trim(),
        recipe_ingredient_id: create ? "" : String(original.recipe_ingredient_id || "").trim(),
        row_id: create ? "" : String(original.row_id || "").trim(),
        ingredient: create
            ? ""
            : String(original.ingredient || original.original_text || original.purchasable_item || "").trim(),
    };
}

function recipeIngredientModalRequestItem(row) {
    const item = fieldValuesFromRow(row);
    Object.assign(item, recipeIngredientMatchSnapshot(recipeIngredientMatchItemFromRow(row, item)));
    const foodReview = recipeIngredientFoodReviewPayload(row);
    if (foodReview) item.food_review = foodReview;
    delete item.substitutions;
    delete item.substitutions_text;
    if (row && row.dataset.recipeIngredientNew === "true") {
        item.id = "";
        item.recipe_ingredient_id = "";
        item.row_id = "";
    }
    return item;
}

function applyRecipeIngredientModalServerErrors(row, panel, fieldErrors = {}) {
    const fieldMap = {
        amount: "quantity",
        buy_as: "purchasable_item",
        requirement: "section",
    };
    let firstInvalid = null;
    Object.entries(fieldErrors && typeof fieldErrors === "object" ? fieldErrors : {}).forEach(([path, message]) => {
        const pathParts = String(path || "").split(".");
        const field = fieldMap[pathParts[pathParts.length - 1]] || pathParts[pathParts.length - 1];
        const input = recipeIngredientDirectField(row, field);
        if (!input) return;
        setRecipeIngredientModalFieldError(input, String(message || "This field needs attention."));
        firstInvalid = firstInvalid || input;
    });
    if (firstInvalid) {
        firstInvalid.focus({ preventScroll: true });
        firstInvalid.scrollIntoView({ block: "center", behavior: "smooth" });
    }
    return firstInvalid;
}

function applySavedRecipeIngredientToModalRow(row, ingredient = {}) {
    if (!row || !ingredient || typeof ingredient !== "object") return;
    restoreRecipeIngredientEditableFieldSnapshot(row, ingredient);
    row.dataset.ingredientMatchDetails = JSON.stringify(recipeIngredientMatchSnapshot(ingredient));
    updateRecipeIngredientSummary(row);
}

function updateRecipeIngredientPersistedPosition(row, persistedIndex, created = false) {
    if (!row || !Number.isInteger(persistedIndex) || persistedIndex < 0) return;
    if (created) {
        recipeEditIngredientRows().forEach(otherRow => {
            if (otherRow === row) return;
            const otherIndex = recipeIngredientModalPersistedIndex(otherRow);
            if (otherIndex >= persistedIndex) {
                otherRow.dataset.recipeIngredientPersistedIndex = String(otherIndex + 1);
            }
        });
    }
    row.dataset.recipeIngredientNew = "false";
    row.dataset.recipeIngredientPersistedIndex = String(persistedIndex);
}

function markRecipeIngredientRowsPersisted() {
    recipeEditIngredientRows().forEach((row, index) => {
        row.dataset.recipeIngredientNew = "false";
        row.dataset.recipeIngredientPersistedIndex = String(index);
    });
}

function rememberRecipeIngredientModalSave(row, ingredient, persistedIndex, created = false) {
    const form = row ? row.closest("#recipeEditForm") : null;
    const previousSnapshot = form ? recipeEditSavedFormSnapshots.get(form) : "";
    if (!form || !previousSnapshot || !Number.isInteger(persistedIndex) || persistedIndex < 0) return;
    try {
        const savedSnapshot = JSON.parse(previousSnapshot);
        const savedIngredients = savedSnapshot.payload && savedSnapshot.payload.recipe
            ? savedSnapshot.payload.recipe.ingredients
            : null;
        if (!Array.isArray(savedIngredients)) return;
        const previousIngredient = created ? null : savedIngredients[persistedIndex];
        const baselineIngredient = recipeIngredientModalRequestItem(row);
        const foodReview = baselineIngredient.food_review;
        delete baselineIngredient.food_review;
        baselineIngredient.substitutions = previousIngredient && Array.isArray(previousIngredient.substitutions)
            ? previousIngredient.substitutions
            : (Array.isArray(ingredient.substitutions) ? ingredient.substitutions : []);
        if (foodReview) baselineIngredient.food_review = foodReview;
        if (created) {
            savedIngredients.splice(persistedIndex, 0, baselineIngredient);
        } else {
            savedIngredients[persistedIndex] = baselineIngredient;
        }
        recipeEditSavedFormSnapshots.set(form, JSON.stringify(savedSnapshot));
        updateRecipeEditorDirtyState(form);
    } catch (error) {
        console.warn("Unable to update the saved ingredient state.", error);
    }
}

async function persistRecipeIngredientModal(row, panel) {
    const originalUrl = String(document.getElementById("recipeEditOriginalUrl")?.value || recipeEditorSourceUrlForOpen() || "").trim();
    const recipeId = String(document.getElementById("recipeEditId")?.value || "").trim();
    const response = await fetch("/api/recipe/ingredient", {
        method: "POST",
        headers: {
            "Content-Type": "application/json",
        },
        credentials: "same-origin",
        body: JSON.stringify({
            original_url: originalUrl,
            recipe_id: recipeId,
            ingredient_ref: recipeIngredientModalReference(row, panel),
            ingredient: recipeIngredientModalRequestItem(row),
        }),
    });
    const data = await recipeEditorJsonResponse(response);
    if (!response.ok || !(data.ok || data.success)) {
        const fieldErrors = data && data.field_errors && typeof data.field_errors === "object"
            ? data.field_errors
            : {};
        applyRecipeIngredientModalServerErrors(row, panel, fieldErrors);
        const message = String(
            (data && (data.message || data.error))
            || `The ingredient could not be saved (${response.status}).`
        );
        setRecipeIngredientModalError(panel, message);
        return null;
    }
    const ingredient = data.ingredient && typeof data.ingredient === "object"
        ? data.ingredient
        : recipeIngredientModalRequestItem(row);
    const persistedIndex = Number.parseInt(data.ingredient_index, 10);
    const created = Boolean(data.created);
    applySavedRecipeIngredientToModalRow(row, ingredient);
    updateRecipeIngredientPersistedPosition(row, persistedIndex, created);
    rememberRecipeIngredientModalSave(row, ingredient, persistedIndex, created);
    updateRecipeEditorSavedIdentity({
        recipe_id: data.recipe_id || recipeId,
        source_url: data.source_url || originalUrl,
        updated_at: data.updated_at || "",
    }, {
        original_url: originalUrl,
        recipe_id: recipeId,
    }, { updateSourceField: false });
    invalidateRecipeEditorCache(originalUrl);
    if (data.source_url && data.source_url !== originalUrl) {
        invalidateRecipeEditorCache(data.source_url);
    }
    return { data, ingredient, persistedIndex, created };
}

function updateRecipeIngredientModalNavigation(row) {
    const panel = row ? row.querySelector("[data-recipe-ingredient-edit-panel]") : null;
    if (!panel) return;
    const rows = recipeEditIngredientRows();
    const index = rows.indexOf(row);
    const previousButton = panel.querySelector("[data-recipe-ingredient-modal-previous]");
    const forwardButton = panel.querySelector("[data-recipe-ingredient-modal-forward]");
    const nextButton = panel.querySelector("[data-recipe-ingredient-modal-next]");
    if (previousButton) {
        previousButton.disabled = index <= 0;
    }
    if (forwardButton) {
        forwardButton.disabled = index < 0 || index >= rows.length - 1;
    }
    if (nextButton) {
        const isFinal = index < 0 || index >= rows.length - 1;
        nextButton.textContent = "Save & Next";
        nextButton.dataset.recipeIngredientFinal = isFinal ? "true" : "false";
    }
}

function setRecipeIngredientModalSaving(panel, saving) {
    if (!panel) return;
    panel.toggleAttribute("aria-busy", Boolean(saving));
    panel.querySelectorAll(
        "[data-recipe-ingredient-modal-save], [data-recipe-ingredient-modal-next], "
        + "[data-recipe-ingredient-modal-previous], [data-recipe-ingredient-modal-forward], "
        + "[data-recipe-ingredient-modal-close], "
        + "[data-recipe-ingredient-modal-delete]"
    ).forEach(button => { button.disabled = Boolean(saving); });
    if (saving) setRecipeIngredientModalStatus(panel, "saving");
    if (!saving) {
        updateRecipeIngredientModalNavigation(panel.closest(".recipe-edit-ingredient-row"));
    }
}

function hideRecipeIngredientDiscardConfirmation(panel, options = {}) {
    const confirmation = panel ? panel.querySelector("[data-recipe-ingredient-discard-confirmation]") : null;
    if (!confirmation || confirmation.hidden) return false;
    confirmation.hidden = true;
    panel.classList.remove("is-confirming-discard");
    const shell = panel.querySelector(".recipe-edit-ingredient-modal-shell");
    if (shell) shell.inert = false;
    const focusTarget = panel.recipeIngredientConfirmationReturnFocus;
    delete panel.recipeIngredientConfirmationReturnFocus;
    if (options.restoreFocus !== false && focusTarget && focusTarget.isConnected) {
        focusTarget.focus({ preventScroll: true });
    }
    return true;
}

function showRecipeIngredientDiscardConfirmation(panel, action, trigger = null) {
    const confirmation = panel ? panel.querySelector("[data-recipe-ingredient-discard-confirmation]") : null;
    if (!panel || !confirmation) return false;
    closeRecipeEditRowMenus();
    panel.recipeIngredientPendingAction = action || { type: "close" };
    panel.recipeIngredientConfirmationReturnFocus = trigger || document.activeElement;
    confirmation.hidden = false;
    panel.classList.add("is-confirming-discard");
    const shell = panel.querySelector(".recipe-edit-ingredient-modal-shell");
    if (shell) shell.inert = true;
    window.requestAnimationFrame(() => {
        confirmation.querySelector("[data-recipe-ingredient-discard-keep]")?.focus({ preventScroll: true });
    });
    return false;
}

function keepEditingRecipeIngredient(button) {
    const panel = button ? button.closest("[data-recipe-ingredient-edit-panel]") : null;
    if (panel) {
        delete panel.recipeIngredientPendingAction;
        hideRecipeIngredientDiscardConfirmation(panel);
    }
    return false;
}

function switchRecipeIngredientModal(currentRow, targetRow, options = {}) {
    if (!currentRow || !targetRow || currentRow === targetRow) return false;
    setRecipeIngredientEditMode(currentRow, false, {
        restore: Boolean(options.restore),
        restoreFocus: false,
        restoreScroll: false,
        keepModalSession: true,
    });
    const trigger = targetRow;
    return setRecipeIngredientEditMode(targetRow, true, {
        trigger,
        reuseModalSession: true,
    });
}

function discardRecipeIngredientChanges(button) {
    const panel = button ? button.closest("[data-recipe-ingredient-edit-panel]") : null;
    const row = panel ? panel.closest(".recipe-edit-ingredient-row") : null;
    const action = panel ? panel.recipeIngredientPendingAction : null;
    if (!panel || !row) return false;
    delete panel.recipeIngredientPendingAction;
    hideRecipeIngredientDiscardConfirmation(panel, { restoreFocus: false });
    if (action && action.type === "navigate" && action.targetRow) {
        return switchRecipeIngredientModal(row, action.targetRow, { restore: true });
    }
    return setRecipeIngredientEditMode(row, false, { restore: true });
}

function requestRecipeIngredientModalClose(control) {
    const panel = control && control.matches && control.matches("[data-recipe-ingredient-edit-panel]")
        ? control
        : (control ? control.closest("[data-recipe-ingredient-edit-panel]") : null);
    const row = panel ? panel.closest(".recipe-edit-ingredient-row") : null;
    if (!panel || !row || panel.dataset.saving === "true") return false;
    if (recipeIngredientModalHasChanges(row)) {
        const confirmationTrigger = control === panel ? document.activeElement : control;
        return showRecipeIngredientDiscardConfirmation(panel, { type: "close" }, confirmationTrigger);
    }
    return setRecipeIngredientEditMode(row, false);
}

function previousRecipeIngredientModal(button) {
    const panel = button ? button.closest("[data-recipe-ingredient-edit-panel]") : null;
    const row = panel ? panel.closest(".recipe-edit-ingredient-row") : null;
    const rows = recipeEditIngredientRows();
    const index = rows.indexOf(row);
    const targetRow = index > 0 ? rows[index - 1] : null;
    if (!panel || !row || !targetRow || panel.dataset.saving === "true") return false;
    if (recipeIngredientModalHasChanges(row)) {
        return showRecipeIngredientDiscardConfirmation(
            panel,
            { type: "navigate", targetRow },
            button
        );
    }
    return switchRecipeIngredientModal(row, targetRow);
}

function nextRecipeIngredientModal(button) {
    const panel = button ? button.closest("[data-recipe-ingredient-edit-panel]") : null;
    const row = panel ? panel.closest(".recipe-edit-ingredient-row") : null;
    const rows = recipeEditIngredientRows();
    const index = rows.indexOf(row);
    const targetRow = index >= 0 && index < rows.length - 1 ? rows[index + 1] : null;
    if (!panel || !row || !targetRow || panel.dataset.saving === "true") return false;
    if (recipeIngredientModalHasChanges(row)) {
        return showRecipeIngredientDiscardConfirmation(
            panel,
            { type: "navigate", targetRow },
            button
        );
    }
    return switchRecipeIngredientModal(row, targetRow);
}

function handleRecipeIngredientModalKeydown(event, panel) {
    const confirmation = panel ? panel.querySelector("[data-recipe-ingredient-discard-confirmation]") : null;
    if (!event || !confirmation || confirmation.hidden) return;
    if (event.key === "Escape") {
        event.preventDefault();
        event.stopPropagation();
        keepEditingRecipeIngredient(confirmation.querySelector("[data-recipe-ingredient-discard-keep]"));
        return;
    }
    if (event.key !== "Tab") return;
    const focusable = [...confirmation.querySelectorAll("button:not([disabled])")];
    if (!focusable.length) return;
    const first = focusable[0];
    const last = focusable[focusable.length - 1];
    if (event.shiftKey && document.activeElement === first) {
        event.preventDefault();
        last.focus();
    } else if (!event.shiftKey && document.activeElement === last) {
        event.preventDefault();
        first.focus();
    }
}

async function commitRecipeIngredientModal(button, options = {}) {
    const panel = button ? button.closest("[data-recipe-ingredient-edit-panel]") : null;
    const row = panel ? panel.closest(".recipe-edit-ingredient-row") : null;
    if (!panel || !row || panel.dataset.saving === "true") return false;
    panel.dataset.saving = "true";
    setRecipeIngredientModalSaving(panel, true);
    try {
        await new Promise(resolve => {
            if (typeof window.requestAnimationFrame === "function") {
                window.requestAnimationFrame(resolve);
            } else {
                window.setTimeout(resolve, 0);
            }
        });
        if (!validateRecipeIngredientModal(row, panel)) {
            return false;
        }
        const saved = await persistRecipeIngredientModal(row, panel);
        if (!saved) {
            return false;
        }
        panel.dataset.editSnapshot = JSON.stringify(recipeIngredientModalEditableFieldSnapshot(row));
        setRecipeIngredientModalStatus(panel, "saved");
        await new Promise(resolve => window.setTimeout(resolve, 320));
        const rows = recipeEditIngredientRows();
        const index = rows.indexOf(row);
        const nextRow = index >= 0 && index < rows.length - 1 ? rows[index + 1] : null;
        if (options.advance && nextRow) {
            return switchRecipeIngredientModal(row, nextRow);
        }
        return setRecipeIngredientEditMode(row, false);
    } catch (error) {
        console.error("Unable to save the ingredient edit.", error);
        setRecipeIngredientModalError(
            panel,
            error && error.message
                ? error.message
                : "Unable to save this ingredient. Please try again."
        );
        return false;
    } finally {
        delete panel.dataset.saving;
        setRecipeIngredientModalSaving(panel, false);
    }
}

function updateRecipeIngredientAlternativeComponentSummary(optionRow) {
    const summary = optionRow ? optionRow.querySelector("[data-alternative-component-summary]") : null;
    if (!summary) {
        return;
    }
    const values = fieldValuesFromRow(optionRow);
    const name = String(values.ingredient || "").trim() || "Unnamed replacement ingredient";
    const buyAs = recipeIngredientMeaningfulBuyAs(values);
    const storeSection = recipeStoreSectionDisplayLabel(values.store_section || "");
    const amount = formatRecipeIngredientQuantity(values);
    const details = [
        recipeIngredientSentenceCase(values.preparation),
        storeSection,
    ].filter(value => value && value !== "\u2014").join(" \u00b7 ");
    const nameElement = summary.querySelector("[data-alternative-component-name]");
    const statusElement = summary.querySelector("[data-alternative-component-status]");
    const amountElement = summary.querySelector("[data-alternative-component-amount]");
    const factsElement = summary.querySelector("[data-alternative-component-facts]");
    const buyAsElement = summary.querySelector("[data-alternative-component-buy-as]");
    if (nameElement) nameElement.textContent = name;
    if (statusElement) {
        const status = recipeIngredientAlternativeStatusLabel(values);
        statusElement.textContent = status;
        statusElement.hidden = !status;
    }
    if (amountElement) amountElement.textContent = amount;
    if (factsElement) {
        factsElement.textContent = details;
        factsElement.hidden = !details;
    }
    if (buyAsElement) {
        buyAsElement.textContent = buyAs ? `Buy as: ${buyAs}` : "";
        buyAsElement.hidden = !buyAs;
    }
}

function recipeIngredientAlternativeStatusLabel(values = {}) {
    const key = recipeIngredientTypeKey(values.match_status || values.matching_status || "");
    const labels = {
        "best match": "Best match",
        "good match": "Good match",
        "review match": "Review match",
        "low confidence": "Low confidence",
        "multiple matches": "Multiple matches",
        unmatched: "Unmatched",
    };
    if (labels[key]) {
        return labels[key];
    }
    if (!key) {
        return "";
    }
    const quality = recipeIngredientSubstitutionMatchQuality(values).label;
    return quality === "Good" ? "Good match" : quality;
}

function organizeRecipeEditSubstitutionOptionRow(optionRow) {
    if (!optionRow || optionRow.dataset.recipeEditCompactOption === "1") {
        return;
    }

    optionRow.dataset.recipeEditCompactOption = "1";
    optionRow.classList.add("recipe-edit-alternative-component");
    optionRow.setAttribute("role", "group");
    const image = optionRow.querySelector(":scope > .recipe-edit-substitution-thumbnail");
    const name = optionRow.querySelector(":scope > .recipe-edit-ingredient-name-label");
    const metadata = name ? name.querySelector(".recipe-edit-ingredient-metadata-inline") : null;
    const size = metadata ? metadata.querySelector(".recipe-edit-size-inline") : null;
    const preparation = metadata ? metadata.querySelector(".recipe-edit-preparation-inline") : null;
    const notes = metadata ? metadata.querySelector(".recipe-edit-notes-inline") : null;
    const originalText = name ? name.querySelector(".recipe-edit-original-text-label") : null;
    const quantity = optionRow.querySelector(":scope > .recipe-edit-qty-label");
    const quantityText = optionRow.querySelector(":scope > .recipe-edit-quantity-text-inline");
    const unit = optionRow.querySelector(":scope > .recipe-edit-unit-label");
    const buyAs = optionRow.querySelector(":scope > .recipe-edit-buy-as-label");
    const storeSection = optionRow.querySelector(":scope > .recipe-edit-store-section-label");
    const optional = optionRow.querySelector(":scope > .recipe-edit-optional-label");
    const preferred = optionRow.querySelector(":scope > .recipe-edit-preferred-label");
    const menuWrap = optionRow.querySelector(":scope > .recipe-edit-row-menu-wrap");

    const ingredientLabel = name ? name.querySelector(":scope > .sr-only") : null;
    if (ingredientLabel) {
        ingredientLabel.className = "recipe-edit-alternative-field-label";
        ingredientLabel.textContent = "Ingredient / Buy As";
    }
    const buyAsLabel = buyAs ? buyAs.querySelector(":scope > span") : null;
    if (buyAsLabel) {
        buyAsLabel.textContent = "Purchasing name (if different)";
    }

    const summary = document.createElement("div");
    summary.className = "recipe-edit-alternative-component-summary";
    summary.dataset.alternativeComponentSummary = "";
    summary.innerHTML = `
        <span class="recipe-edit-alternative-component-copy">
            <span class="recipe-edit-alternative-component-title-line">
                <strong data-alternative-component-name></strong>
                <span class="recipe-edit-alternative-component-status" data-alternative-component-status hidden></span>
            </span>
            <strong class="recipe-edit-alternative-component-amount" data-alternative-component-amount></strong>
            <span class="recipe-edit-alternative-component-meta" data-alternative-component-facts hidden></span>
            <span class="recipe-edit-alternative-component-buy-as" data-alternative-component-buy-as hidden></span>
        </span>
        <span class="recipe-edit-alternative-component-actions">
            <button type="button"
                    class="recipe-edit-alternative-component-edit"
                    aria-label="Edit replacement ingredient"
                    title="Edit Ingredient"
                    onclick="return editRecipeIngredientAlternativeComponent(this)">
                ${recipeEditSvgIcon("edit")}<span>Edit Ingredient</span>
            </button>
            <button type="button"
                    class="recipe-edit-alternative-component-read-remove"
                    data-alternative-component-remove
                    aria-label="Remove replacement ingredient"
                    title="Remove Ingredient"
                    onclick="return removeRecipeIngredientAlternativeComponent(this)">
                ${recipeEditSvgIcon("trash")}<span>Remove Ingredient</span>
            </button>
        </span>
    `;
    if (image) {
        summary.insertBefore(image, summary.firstChild);
    }
    optionRow.insertBefore(summary, optionRow.firstChild);

    const editGrid = document.createElement("div");
    editGrid.className = "recipe-edit-alternative-component-edit-grid";
    editGrid.dataset.alternativeComponentEdit = "";
    editGrid.hidden = true;
    [
        [name, "field-ingredient"],
        [quantity, "field-amount"],
        [unit, "field-unit"],
        [size, "field-size"],
        [quantityText, "field-quantity-text"],
        [preparation, "field-preparation"],
        [storeSection, "field-store-section"],
        [preferred, "field-preferred"],
        [notes, "field-notes"],
    ].forEach(([field, className]) => {
        if (!field) return;
        field.classList.add("recipe-edit-alternative-edit-field", className);
        editGrid.appendChild(field);
    });

    const sourceDetails = document.createElement("details");
    sourceDetails.className = "recipe-edit-alternative-source-details";
    sourceDetails.innerHTML = `
        <summary>Source details</summary>
        <div class="recipe-edit-alternative-source-grid"></div>
    `;
    const sourceGrid = sourceDetails.querySelector(".recipe-edit-alternative-source-grid");
    [buyAs, originalText].filter(Boolean).forEach(field => {
        field.classList.add("recipe-edit-alternative-edit-field");
        sourceGrid.appendChild(field);
    });

    const sourceValues = fieldValuesFromRow(optionRow);
    const sourceMetadata = [
        ["Match source", recipeIngredientMatchFlag(sourceValues.inferred) ? "AI inference" : "Recipe data"],
        ["Match confidence", sourceValues.match_confidence || sourceValues.confidence_score || sourceValues.confidence || "Not available"],
        ["AI reasoning", sourceValues.reason || "Not available"],
    ];
    const metadataList = document.createElement("dl");
    metadataList.className = "recipe-edit-alternative-source-metadata";
    sourceMetadata.forEach(([label, value]) => {
        const term = document.createElement("dt");
        const description = document.createElement("dd");
        term.textContent = label;
        description.textContent = String(value);
        metadataList.append(term, description);
    });
    sourceGrid.appendChild(metadataList);
    editGrid.appendChild(sourceDetails);
    if (optional) {
        optional.hidden = true;
        optional.classList.add("recipe-edit-alternative-legacy-field");
        editGrid.appendChild(optional);
    }
    const removeComponent = document.createElement("button");
    removeComponent.type = "button";
    removeComponent.className = "recipe-edit-alternative-component-remove";
    removeComponent.dataset.alternativeComponentRemove = "";
    removeComponent.textContent = "Remove ingredient";
    removeComponent.addEventListener("click", () => removeRecipeIngredientAlternativeComponent(removeComponent));
    editGrid.appendChild(removeComponent);
    optionRow.appendChild(editGrid);

    if (metadata && !metadata.children.length) metadata.remove();
    if (menuWrap) {
        menuWrap.classList.add("recipe-edit-alternative-component-menu");
        menuWrap.hidden = true;
    }
    updateRecipeIngredientAlternativeComponentSummary(optionRow);
}

function editRecipeIngredientSubstitutionFields(button) {
    return setRecipeIngredientAlternativeEditMode(button, true);
}

function ensureRecipeIngredientModalIdentityStack(editPanel) {
    const identityGrid = editPanel
        ? editPanel.querySelector("[data-recipe-ingredient-modal-identity]")
        : null;
    if (!identityGrid) {
        return null;
    }

    let identityFields = identityGrid.querySelector(":scope > .recipe-edit-ingredient-modal-identity-fields");
    if (!identityFields) {
        identityFields = document.createElement("div");
        identityFields.className = "recipe-edit-ingredient-modal-identity-fields";
        identityGrid.appendChild(identityFields);
    }

    const name = identityGrid.querySelector(":scope > .recipe-edit-ingredient-modal-name-field")
        || identityFields.querySelector(":scope > .recipe-edit-ingredient-modal-name-field");
    const buyAs = identityGrid.querySelector(":scope > .recipe-edit-ingredient-modal-buy-as-field")
        || identityFields.querySelector(":scope > .recipe-edit-ingredient-modal-buy-as-field");
    const requirement = identityGrid.querySelector(":scope > .recipe-edit-ingredient-modal-requirement-field")
        || identityFields.querySelector(":scope > .recipe-edit-ingredient-modal-requirement-field");
    if (name) {
        identityFields.appendChild(name);
    }
    if (buyAs) {
        identityFields.appendChild(buyAs);
    }
    if (requirement) {
        identityFields.appendChild(requirement);
    }
    return identityFields;
}

function setActiveRecipeIngredientModalSection(panel, sectionKey) {
    if (!panel) return;
    const activeKey = String(sectionKey || "overview").trim() || "overview";
    panel.querySelectorAll("[data-recipe-ingredient-modal-nav]").forEach(button => {
        const isActive = button.dataset.recipeIngredientModalNav === activeKey;
        button.classList.toggle("is-active", isActive);
        if (isActive) {
            button.setAttribute("aria-current", "page");
        } else {
            button.removeAttribute("aria-current");
        }
    });
}

function syncRecipeIngredientModalSectionNavigation(panel) {
    const scrollPane = panel ? panel.querySelector("[data-recipe-ingredient-modal-scroll]") : null;
    if (!scrollPane) return;
    const sections = Array.from(scrollPane.querySelectorAll("[data-recipe-ingredient-modal-section]"));
    const paneTop = scrollPane.getBoundingClientRect().top;
    let activeKey = sections.length ? sections[0].dataset.recipeIngredientModalSection : "overview";
    sections.forEach(section => {
        if (section.getBoundingClientRect().top - paneTop <= 72) {
            activeKey = section.dataset.recipeIngredientModalSection || activeKey;
        }
    });
    setActiveRecipeIngredientModalSection(panel, activeKey);
}

function navigateRecipeIngredientModalSection(button) {
    const panel = button ? button.closest("[data-recipe-ingredient-edit-panel]") : null;
    const targetId = button ? button.getAttribute("aria-controls") : "";
    const target = targetId ? document.getElementById(targetId) : null;
    if (!panel || !target || !panel.contains(target)) return false;
    setActiveRecipeIngredientModalSection(panel, button.dataset.recipeIngredientModalNav);
    target.scrollIntoView({ behavior: "smooth", block: "start" });
    return false;
}

function toggleRecipeIngredientModalAnalysis(button) {
    const panel = button ? button.closest("[data-recipe-ingredient-edit-panel]") : null;
    const details = panel ? panel.querySelector("[data-recipe-ingredient-modal-analysis]") : null;
    if (!button || !details) return false;
    const shouldOpen = details.hidden;
    details.hidden = !shouldOpen;
    button.setAttribute("aria-expanded", String(shouldOpen));
    button.textContent = shouldOpen ? "Hide Details" : "View Details";
    return false;
}

function removeRecipeIngredientFromModal(button) {
    const row = button ? button.closest(".recipe-edit-ingredient-row") : null;
    if (!row) return false;
    setRecipeIngredientEditMode(row, false, { restoreFocus: false });
    return removeRecipeEditRow(button);
}

