let recipeSourceDocumentsSnapshot = "";
let recipeSourceDocumentsTrigger = null;

function recipeSourceDocumentsForm() {
    return document.querySelector("[data-source-documents-edit-form]");
}

function recipeSourceDocumentsValues(form = recipeSourceDocumentsForm()) {
    const values = {};
    form?.querySelectorAll("[data-source-documents-edit-field]").forEach(input => {
        values[input.dataset.sourceDocumentsEditField] = String(input.value || "").trim();
    });
    return values;
}

function updateRecipeSourceDocumentsModalState(form = recipeSourceDocumentsForm()) {
    const save = form?.querySelector("[data-source-documents-edit-save]");
    if (save && !form.dataset.saving) {
        save.disabled = JSON.stringify(recipeSourceDocumentsValues(form)) === recipeSourceDocumentsSnapshot;
    }
}

function syncRecipeSourceDocumentModalRows(form = recipeSourceDocumentsForm()) {
    const linkIds = {
        recipeEditSourcePdfPath: "recipeEditSourcePdfPathLink",
        recipeEditGeneratedPdfPath: "recipeEditGeneratedPdfPathLink",
        recipeEditSourceCloudflarePdfUrl: "recipeEditSourceCloudflarePdfUrlLink",
        recipeEditGeneratedCloudflarePdfUrl: "recipeEditGeneratedCloudflarePdfUrlLink",
    };
    form?.querySelectorAll("[data-source-document-modal-row]").forEach(row => {
        const inputId = row.dataset.documentInputId;
        const value = recipeEditInputValue(inputId);
        const status = row.querySelector("[data-source-document-modal-status]");
        const open = row.querySelector("[data-source-document-modal-open]");
        const download = row.querySelector("[data-source-document-modal-download]");
        const actions = row.querySelector("[data-source-document-modal-actions]");
        const linked = document.getElementById(linkIds[inputId]);
        const href = linked && !linked.hidden ? linked.href : "";
        if (status) {
            status.textContent = value ? recipeEditDocumentDisplayValue(value, inputId) : "Unavailable";
            status.title = value || "";
        }
        if (open) {
            open.hidden = !value || !href || href === "#";
            open.href = !open.hidden ? href : "#";
        }
        if (download) {
            download.hidden = !value || !href || href === "#";
            download.href = !download.hidden ? href : "#";
        }
        if (actions) {
            actions.hidden = !Array.from(actions.querySelectorAll("a, button")).some(action => !action.hidden);
        }
    });
}

function editRecipeSourceDocuments(button, event = null) {
    event?.preventDefault();
    event?.stopPropagation();
    const modal = document.querySelector("[data-source-documents-edit-modal]");
    const form = recipeSourceDocumentsForm();
    if (!modal || !form) return false;
    const initial = {
        document_source_url: recipeEditInputValue("recipeEditDocumentSourceUrl") || recipeEditorSourceUrlForOpen(),
        source_menu_url: recipeEditInputValue("recipeEditSourceMenuUrl"),
        menu_item_url: recipeEditInputValue("recipeEditMenuItemUrl"),
    };
    form.querySelectorAll("[data-source-documents-edit-field]").forEach(input => {
        input.value = initial[input.dataset.sourceDocumentsEditField] || "";
        if (input.dataset.sourceDocumentsBound !== "1") {
            input.dataset.sourceDocumentsBound = "1";
            input.addEventListener("input", () => updateRecipeSourceDocumentsModalState(form));
        }
    });
    recipeSourceDocumentsSnapshot = JSON.stringify(recipeSourceDocumentsValues(form));
    recipeSourceDocumentsTrigger = button;
    if (modal.parentElement !== document.body) document.body.appendChild(modal);
    modal.hidden = false;
    document.body.classList.add("source-documents-modal-open");
    form.querySelector("[data-source-documents-edit-error]").hidden = true;
    form.querySelector(".recipe-edit-source-documents-advanced").open = false;
    syncRecipeSourceDocumentModalRows(form);
    updateRecipeSourceDocumentsModalState(form);
    form.querySelector("[data-source-documents-edit-field]")?.focus();
    return false;
}

function closeRecipeSourceDocumentsModal(options = {}) {
    const modal = document.querySelector("[data-source-documents-edit-modal]");
    const form = recipeSourceDocumentsForm();
    if (!modal || !form || form.dataset.saving) return false;
    const changed = JSON.stringify(recipeSourceDocumentsValues(form)) !== recipeSourceDocumentsSnapshot;
    if (!options.force && changed && !window.confirm("Discard unsaved source and document changes?")) return false;
    modal.hidden = true;
    document.body.classList.remove("source-documents-modal-open");
    recipeSourceDocumentsSnapshot = "";
    const trigger = recipeSourceDocumentsTrigger;
    recipeSourceDocumentsTrigger = null;
    trigger?.focus({ preventScroll: true });
    return false;
}

function copyRecipeSourceDocumentsField(button) {
    const form = button?.closest("[data-source-documents-edit-form]");
    const field = form?.querySelector(`[data-source-documents-edit-field="${button.dataset.sourceDocumentsCopy}"]`);
    button.dataset.copyValue = String(field?.value || "").trim();
    return copyRecipeEditorDocumentValue(button);
}

async function saveRecipeSourceDocuments(form) {
    if (!form || form.dataset.saving) return false;
    const invalid = form.querySelector(":is(input, select, textarea):invalid");
    const error = form.querySelector("[data-source-documents-edit-error]");
    const save = form.querySelector("[data-source-documents-edit-save]");
    if (invalid) {
        error.textContent = invalid.validationMessage || "Enter valid HTTP or HTTPS URLs.";
        error.hidden = false;
        invalid.focus();
        return false;
    }
    form.dataset.saving = "1";
    save.disabled = true;
    save.textContent = "Saving...";
    error.hidden = true;
    try {
        const response = await fetch("/api/recipe/source-documents", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ recipe_url: recipeEditorSourceUrlForOpen(), ...recipeSourceDocumentsValues(form) }),
        });
        const data = await response.json();
        if (!response.ok || !data.ok) throw new Error(data.error || "Unable to save source links.");
        setValue("recipeEditDocumentSourceUrl", data.document_source_url || "");
        setValue("recipeEditSourceMenuUrl", data.source_menu_url || "");
        setValue("recipeEditMenuItemUrl", data.menu_item_url || "");
        bindRecipeMenuMetadataUrlLinks();
        syncRecipeEditDocumentRows();
        delete form.dataset.saving;
        closeRecipeSourceDocumentsModal({ force: true });
    } catch (err) {
        error.textContent = err.message || "Unable to save source links.";
        error.hidden = false;
    } finally {
        delete form.dataset.saving;
        save.textContent = "Save Changes";
        updateRecipeSourceDocumentsModalState(form);
    }
    return false;
}

document.addEventListener("pointerdown", event => {
    const popover = document.getElementById("recipeEditSourceDocumentsHelp");
    const button = document.querySelector(".recipe-edit-source-documents-help");
    if (!popover || popover.hidden || popover.contains(event.target) || button?.contains(event.target)) return;
    closeRecipeSourceDocumentsHelp();
});

document.addEventListener("focusin", event => {
    const popover = document.getElementById("recipeEditSourceDocumentsHelp");
    const button = document.querySelector(".recipe-edit-source-documents-help");
    if (!popover || popover.hidden || popover.contains(event.target) || button?.contains(event.target)) return;
    closeRecipeSourceDocumentsHelp();
});

document.addEventListener("keydown", event => {
    const sourceModal = document.querySelector("[data-source-documents-edit-modal]");
    if (sourceModal && !sourceModal.hidden) {
        if (event.key === "Escape") {
            event.preventDefault();
            closeRecipeSourceDocumentsModal({ force: false });
            return;
        }
        if (event.key === "Tab") {
            const focusable = Array.from(sourceModal.querySelectorAll('button:not([disabled]), input:not([disabled]), a[href], summary')).filter(element => !element.hidden && element.offsetParent !== null);
            const first = focusable[0];
            const last = focusable[focusable.length - 1];
            if (first && event.shiftKey && document.activeElement === first) { event.preventDefault(); last.focus(); }
            else if (last && !event.shiftKey && document.activeElement === last) { event.preventDefault(); first.focus(); }
        }
        return;
    }
    if (event.key === "Escape" && !document.getElementById("recipeEditSourceDocumentsHelp")?.hidden) {
        closeRecipeSourceDocumentsHelp();
        document.querySelector(".recipe-edit-source-documents-help")?.focus();
    }
});

async function uploadRecipeSourcePdfToCloudflare(button) {
    if (!button || button.disabled) return false;
    const recipeUrl = recipeEditorSourceUrlForOpen();
    if (!recipeUrl) return false;
    button.disabled = true;
    button.setAttribute("aria-busy", "true");
    try {
        const response = await fetch("/api/recipe_pdf/cloudflare_upload", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ url: recipeUrl, kind: "webpage_backup" }),
        });
        const data = await response.json();
        if (!response.ok || !data.ok) throw new Error(data.error || "Unable to upload Source PDF to Cloudflare.");
        const publicUrl = String(data.source_cloudflare_pdf_url || data.public_url || "").trim();
        setValue("recipeEditSourceCloudflarePdfUrl", publicUrl);
        const link = document.getElementById("recipeEditSourceCloudflarePdfUrlLink");
        if (link) {
            link.href = publicUrl || "#";
            link.hidden = !publicUrl;
        }
        syncRecipeEditDocumentRows();
        setRecipeEditStatus("Source PDF uploaded to Cloudflare.");
    } catch (err) {
        setRecipeEditStatus(err.message || "Unable to upload Source PDF to Cloudflare.", true);
    } finally {
        button.disabled = false;
        button.removeAttribute("aria-busy");
    }
    return false;
}

function recipeEditDocumentSlug(value, fallback = "document") {
    return String(value || "")
        .toLowerCase()
        .replace(/[^a-z0-9]+/g, "-")
        .replace(/^-+|-+$/g, "")
        .slice(0, 64) || fallback;
}

function recipeEditRestaurantSourceSlug() {
    const source = recipeEditInputValue("recipeEditSourceMenuUrl") || recipeEditorSourceUrlForOpen();
    try {
        const url = new URL(source, window.location.origin);
        const segments = url.pathname.split("/").filter(Boolean);
        const menuIndex = segments.findIndex(segment => segment.toLowerCase() === "menu");
        if (menuIndex > 0) {
            return recipeEditDocumentSlug(segments[menuIndex - 1], "restaurant");
        }
    } catch (err) {
        // Fall back to the saved restaurant name below.
    }
    return recipeEditDocumentSlug(recipeEditInputValue("recipeEditRestaurantName"), "restaurant");
}

function recipeEditDocumentDisplayValue(value, inputId = "") {
    const text = String(value || "").trim();
    if (!text) {
        return "";
    }
    if (["recipeEditSourcePdfPath", "recipeEditSourceCloudflarePdfUrl"].includes(inputId)) {
        return `${recipeEditRestaurantSourceSlug()}-menu.pdf`;
    }
    if (["recipeEditGeneratedPdfPath", "recipeEditGeneratedCloudflarePdfUrl"].includes(inputId)) {
        const recipeName = recipeEditInputValue("recipeEditTitleInput") || recipeEditInputValue("recipeEditDisplayName");
        return `${recipeEditDocumentSlug(recipeName, "generated-recipe")}.pdf`;
    }
    try {
        const url = new URL(text, window.location.origin);
        if (/^https?:$/i.test(url.protocol)) {
            const path = url.pathname === "/" ? "" : url.pathname.replace(/\/$/, "");
            return `${url.hostname}${path}`;
        }
    } catch (err) {
        // Local and storage paths are formatted below.
    }
    const normalized = text.replace(/\\/g, "/");
    return normalized.split("/").filter(Boolean).pop() || text;
}

function copyRecipeEditorDocumentValue(button) {
    const value = button ? String(button.dataset.copyValue || "").trim() : "";

    if (!value) {
        return false;
    }

    const finish = () => {
        const row = button.closest("[data-recipe-edit-document-row]");
        const status = row ? row.querySelector("[data-document-status]") : null;
        const menu = button.closest(".recipe-edit-document-more");
        if (menu) {
            menu.open = false;
        }
        if (status) {
            status.textContent = "Copied";
        }
    };

    if (navigator.clipboard && navigator.clipboard.writeText) {
        navigator.clipboard.writeText(value).then(finish).catch(() => {});
    } else {
        const textarea = document.createElement("textarea");
        textarea.value = value;
        textarea.setAttribute("readonly", "");
        textarea.style.position = "fixed";
        textarea.style.left = "-9999px";
        document.body.appendChild(textarea);
        textarea.select();
        try {
            document.execCommand("copy");
            finish();
        } finally {
            textarea.remove();
        }
    }

    return false;
}

function updateRecipeEditRestaurantCard() {
    const name = recipeEditInputValue("recipeEditRestaurantName");
    const website = recipeEditInputValue("recipeEditRestaurantWebsiteUrl");
    const menu = recipeEditInputValue("recipeEditSourceMenuUrl");
    const phone = recipeEditInputValue("recipeEditRestaurantPhone");
    const address = recipeEditInputValue("recipeEditRestaurantAddress");
    const cuisine = recipeEditInputValue("recipeEditRestaurantCuisineTags");
    const selectedSource = currentRecipeRestaurantSourceOption() || {};
    const logoUrl = recipeMenuMetadataText(selectedSource.restaurant_logo_url);
    const restaurantRating = Number.parseFloat(recipeMenuMetadataText(selectedSource.restaurant_rating));
    const setText = (selector, value, fallback = "") => {
        const element = document.querySelector(selector);
        if (element) {
            element.textContent = value || fallback;
            element.hidden = !value && !fallback;
        }
    };
    const setAction = (nameValue, href) => {
        const link = document.querySelector(`[data-restaurant-action="${nameValue}"]`);
        if (!link) {
            return;
        }
        link.hidden = !href;
        link.href = href || "#";
    };

    setText('[data-restaurant-field="name"]', name, "No restaurant source");
    setText('[data-restaurant-field="cuisine"]', cuisine);
    setText('[data-restaurant-field="address"]', address);
    const phoneDigits = phone.replace(/\D/g, "");
    const displayPhone = phoneDigits.length === 10
        ? `(${phoneDigits.slice(0, 3)}) ${phoneDigits.slice(3, 6)}-${phoneDigits.slice(6)}`
        : phone;
    setText('[data-restaurant-field="phone"]', displayPhone);
    setText('[data-restaurant-field="website"]', website);
    const phoneRow = document.querySelector('[data-restaurant-detail-row="phone"]');
    const addressRow = document.querySelector('[data-restaurant-detail-row="address"]');
    if (phoneRow) phoneRow.hidden = !phone;
    if (addressRow) addressRow.hidden = !address;

    const websiteDetail = document.querySelector('[data-restaurant-detail="website"]');
    if (websiteDetail) {
        const canOpenWebsite = isLegitimateWebUrl(website);
        websiteDetail.hidden = !canOpenWebsite;
        websiteDetail.href = canOpenWebsite ? website : "#";
        websiteDetail.title = canOpenWebsite ? website : "";
    }

    const rating = document.querySelector("[data-restaurant-rating]");
    if (rating) {
        const normalizedRating = Number.isFinite(restaurantRating)
            ? Math.max(0, Math.min(5, restaurantRating))
            : 0;
        rating.hidden = normalizedRating <= 0;
        rating.setAttribute("aria-label", normalizedRating > 0 ? `${normalizedRating} out of 5 stars` : "");
        rating.querySelectorAll("[data-restaurant-rating-star]").forEach((star, index) => {
            star.classList.toggle("is-filled", index < Math.round(normalizedRating));
        });
    }

    const logo = document.querySelector("[data-restaurant-logo]");
    if (logo) {
        const image = logo.querySelector("img");
        const fallback = logo.querySelector("[data-restaurant-logo-fallback]");
        const initials = (name || "Restaurant").trim().split(/\s+/).slice(0, 2).map(part => part[0] || "").join("").toUpperCase();
        if (fallback) {
            fallback.textContent = initials || "R";
            fallback.hidden = Boolean(logoUrl);
        }
        if (image) {
            image.hidden = !logoUrl;
            image.src = logoUrl || "";
            image.alt = logoUrl ? `${name || "Restaurant"} logo` : "";
            image.onerror = () => {
                image.hidden = true;
                if (fallback) fallback.hidden = false;
            };
        }
    }
    setAction("website", isLegitimateWebUrl(website) ? website : "");
    setAction("menu", isLegitimateWebUrl(menu) ? menu : "");
    setAction("map", address ? `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(address)}` : "");
}

