function hydrateRecipeRestaurantOrderingLinks(form, value) {
    const editor = form?.querySelector("[data-restaurant-ordering-links-editor]");
    const rows = editor?.querySelector("[data-restaurant-ordering-links-rows]");
    if (!editor || !rows) return;
    rows.replaceChildren();
    const links = normalizeRecipeRestaurantOrderingLinks(value);
    (links.length ? links : [{ provider: "official_online_ordering", url: "", is_active: true }]).forEach(link => {
        rows.append(recipeRestaurantOrderingLinkRow(editor, link));
    });
    syncRecipeRestaurantOrderingLinks(editor, { updateState: false });
}

function syncRecipeRestaurantOrderingLinks(editor, options = {}) {
    const form = editor?.closest("[data-restaurant-edit-form]");
    const hidden = editor?.querySelector('[data-restaurant-edit-field="restaurant_ordering_links"]');
    if (!form || !hidden) return;
    const rows = Array.from(editor.querySelectorAll("[data-restaurant-ordering-link-row]"));
    const providerCounts = rows.reduce((counts, row) => {
        const provider = row.querySelector("[data-restaurant-ordering-provider]")?.value || "other";
        if (provider !== "other") counts.set(provider, (counts.get(provider) || 0) + 1);
        return counts;
    }, new Map());
    rows.forEach(row => {
        const control = row.querySelector("[data-restaurant-ordering-provider]");
        const duplicate = control?.value !== "other" && providerCounts.get(control?.value) > 1;
        control?.setCustomValidity(duplicate ? "This ordering provider is already listed." : "");
    });
    const links = rows.map(row => {
        const provider = row.querySelector("[data-restaurant-ordering-provider]")?.value || "other";
        return {
            provider,
            url: String(row.querySelector("[data-restaurant-ordering-url]")?.value || "").trim(),
            is_active: Boolean(row.querySelector("[data-restaurant-ordering-active]")?.checked),
            ...(provider === "other" && row.dataset.restaurantOrderingProviderName
                ? { provider_name: row.dataset.restaurantOrderingProviderName }
                : {}),
            ...(row.dataset.restaurantOrderingSourceUrl ? { source_url: row.dataset.restaurantOrderingSourceUrl } : {}),
        };
    }).filter(item => item.url);
    hidden.value = JSON.stringify(links);
    if (options.updateState !== false) updateRecipeRestaurantEditState(form);
}

function addRecipeRestaurantOrderingLink(button) {
    const editor = button?.closest("[data-restaurant-ordering-links-editor]");
    const rows = editor?.querySelector("[data-restaurant-ordering-links-rows]");
    if (!editor || !rows) return false;
    const usedProviders = new Set(Array.from(rows.querySelectorAll("[data-restaurant-ordering-provider]"), control => control.value));
    const provider = recipeRestaurantOrderingProviders.find(([key]) => key === "other" || !usedProviders.has(key))?.[0] || "other";
    const row = recipeRestaurantOrderingLinkRow(editor, { provider, url: "", is_active: true });
    rows.append(row);
    row.querySelector("[data-restaurant-ordering-provider]")?.focus();
    return false;
}

function removeRecipeRestaurantOrderingLink(button) {
    const editor = button?.closest("[data-restaurant-ordering-links-editor]");
    const row = button?.closest("[data-restaurant-ordering-link-row]");
    if (!editor || !row) return false;
    row.remove();
    if (!editor.querySelector("[data-restaurant-ordering-link-row]")) {
        editor.querySelector("[data-restaurant-ordering-links-rows]")?.append(
            recipeRestaurantOrderingLinkRow(editor, { provider: "official_online_ordering", url: "", is_active: true })
        );
    }
    syncRecipeRestaurantOrderingLinks(editor);
    return false;
}

function recipeRestaurantRecordSecondary(record) {
    const city = recipeRestaurantRecordValue(record, "restaurant_city");
    const state = recipeRestaurantRecordValue(record, "restaurant_state");
    const location = [city, state].filter(Boolean).join(", ");
    if (location) return location;
    const street = recipeRestaurantRecordValue(record, "restaurant_street_address");
    if (street) return street;
    const website = recipeRestaurantRecordValue(record, "restaurant_website_url");
    try {
        return website ? new URL(website, window.location.origin).hostname.replace(/^www\./i, "") : "";
    } catch (err) {
        return website;
    }
}

function recipeRestaurantSelectorElements() {
    const root = document.querySelector("[data-restaurant-selector]");
    return {
        root,
        input: root?.querySelector("[data-restaurant-selector-input]"),
        list: root?.querySelector("[data-restaurant-selector-list]"),
        status: root?.querySelector("[data-restaurant-selector-status]"),
        clear: root?.querySelector("[data-restaurant-selector-clear]"),
    };
}

function updateRecipeRestaurantSelectorClearButton() {
    const { input, clear } = recipeRestaurantSelectorElements();
    if (!clear) return;
    const hasSelectedRestaurant = !recipeRestaurantEditCreateMode
        && Boolean(recipeRestaurantRecordId(recipeRestaurantEditSelection));
    clear.hidden = !hasSelectedRestaurant || !String(input?.value || "").trim();
    clear.disabled = Boolean(input?.disabled);
}

function setRecipeRestaurantSelectorExpanded(expanded) {
    const { input, list } = recipeRestaurantSelectorElements();
    if (!input || !list) return;
    list.hidden = !expanded;
    input.setAttribute("aria-expanded", expanded ? "true" : "false");
    if (!expanded) {
        input.removeAttribute("aria-activedescendant");
        recipeRestaurantSelectorActiveIndex = -1;
    }
}

function recipeRestaurantSelectorOptions() {
    return Array.from(recipeRestaurantSelectorElements().list?.querySelectorAll(
        "[data-restaurant-selector-id], [data-restaurant-selector-create]"
    ) || []);
}

function setRecipeRestaurantSelectorActive(index) {
    const { input } = recipeRestaurantSelectorElements();
    const options = recipeRestaurantSelectorOptions();
    if (!options.length) return;
    recipeRestaurantSelectorActiveIndex = (index + options.length) % options.length;
    options.forEach((option, optionIndex) => option.classList.toggle("is-active", optionIndex === recipeRestaurantSelectorActiveIndex));
    const active = options[recipeRestaurantSelectorActiveIndex];
    input?.setAttribute("aria-activedescendant", active.id);
    active?.scrollIntoView({ block: "nearest" });
}

function renderRecipeRestaurantSelector(restaurants = recipeRestaurantDirectory, options = {}) {
    const { list, status } = recipeRestaurantSelectorElements();
    if (!list) return;
    const selectedId = recipeRestaurantRecordId(recipeRestaurantEditSelection);
    const rows = restaurants.map((restaurant, index) => {
        const id = recipeRestaurantRecordId(restaurant);
        const secondary = recipeRestaurantRecordSecondary(restaurant);
        return `<button type="button"
                        id="recipeEditRestaurantOption${index}"
                        class="recipe-edit-restaurant-selector-option"
                        role="option"
                        aria-selected="${id && id === selectedId ? "true" : "false"}"
                        data-restaurant-selector-id="${escapeAttribute(id)}"
                        onclick="return selectRecipeRestaurantFromSelector(this)">
                    <strong>${escapeHtml(recipeRestaurantRecordName(restaurant))}</strong>
                    ${secondary ? `<small>${escapeHtml(secondary)}</small>` : ""}
                </button>`;
    });
    if (!restaurants.length && !options.loading) {
        rows.push('<span class="recipe-edit-restaurant-selector-empty">No restaurants found</span>');
    }
    rows.push(`<button type="button"
                       id="recipeEditRestaurantCreateOption"
                       class="recipe-edit-restaurant-selector-create"
                       role="option"
                       aria-selected="${recipeRestaurantEditCreateMode ? "true" : "false"}"
                       data-restaurant-selector-create
                       onclick="return beginCreateRecipeRestaurant(this)">+ Create New Restaurant</button>`);
    list.innerHTML = rows.join("");
    if (status) status.textContent = options.loading
        ? "Loading restaurants…"
        : recipeRestaurantEditCreateMode ? "Creating new restaurant" : "";
    recipeRestaurantSelectorActiveIndex = -1;
    updateRecipeRestaurantSelectorClearButton();
}

async function loadRecipeRestaurantDirectory(query = "") {
    const requestId = ++recipeRestaurantDirectoryRequest;
    const { input, status } = recipeRestaurantSelectorElements();
    if (input) input.setAttribute("aria-busy", "true");
    if (status) status.textContent = "Loading restaurants…";
    renderRecipeRestaurantSelector(recipeRestaurantDirectory, { loading: true });
    try {
        const response = await fetch(`/api/recipe/restaurants?q=${encodeURIComponent(String(query || "").trim())}`);
        const data = await response.json();
        if (!response.ok || !data.ok) throw new Error(data.error || "Unable to load restaurants.");
        if (requestId !== recipeRestaurantDirectoryRequest) return;
        recipeRestaurantDirectory = Array.isArray(data.restaurants) ? data.restaurants : [];
        renderRecipeRestaurantSelector();
    } catch (err) {
        if (requestId !== recipeRestaurantDirectoryRequest) return;
        recipeRestaurantDirectory = [];
        renderRecipeRestaurantSelector();
        if (status) status.textContent = "Restaurant list unavailable.";
    } finally {
        if (requestId === recipeRestaurantDirectoryRequest) input?.removeAttribute("aria-busy");
    }
}

function openRecipeRestaurantSelector(input) {
    if (input?.dataset.restaurantSelectorSuppressOpen === "1") {
        delete input.dataset.restaurantSelectorSuppressOpen;
        return;
    }
    setRecipeRestaurantSelectorExpanded(true);
    if (!recipeRestaurantDirectory.length) {
        if (input?.getAttribute("aria-busy") !== "true") {
            const selectedName = recipeRestaurantEditCreateMode ? "" : recipeRestaurantRecordName(recipeRestaurantEditSelection);
            loadRecipeRestaurantDirectory(input?.value === selectedName ? "" : input?.value || "");
        }
        return;
    }
    renderRecipeRestaurantSelector();
}

function searchRecipeRestaurantSelector(query) {
    updateRecipeRestaurantSelectorClearButton();
    setRecipeRestaurantSelectorExpanded(true);
    window.clearTimeout(recipeRestaurantSelectorDebounce);
    recipeRestaurantSelectorDebounce = window.setTimeout(() => loadRecipeRestaurantDirectory(query), 250);
}

function closeRecipeRestaurantSelector(options = {}) {
    const { input } = recipeRestaurantSelectorElements();
    window.clearTimeout(recipeRestaurantSelectorDebounce);
    setRecipeRestaurantSelectorExpanded(false);
    if (input && options.restoreValue !== false) {
        input.value = recipeRestaurantEditCreateMode ? "" : recipeRestaurantRecordName(recipeRestaurantEditSelection);
    }
    updateRecipeRestaurantSelectorClearButton();
}

function clearRecipeRestaurantSelector(button, event = null) {
    if (event) {
        event.preventDefault();
        event.stopPropagation();
    }
    const { input, status } = recipeRestaurantSelectorElements();
    window.clearTimeout(recipeRestaurantSelectorDebounce);
    setRecipeRestaurantSelectorExpanded(false);
    if (input) {
        input.value = "";
        input.removeAttribute("aria-activedescendant");
        input.dataset.restaurantSelectorSuppressOpen = "1";
        input.focus({ preventScroll: true });
        window.setTimeout(() => {
            if (input.dataset.restaurantSelectorSuppressOpen === "1") {
                delete input.dataset.restaurantSelectorSuppressOpen;
            }
        }, 0);
    }
    if (status) status.textContent = "";
    updateRecipeRestaurantSelectorClearButton();
    return false;
}

function handleRecipeRestaurantSelectorKeydown(input, event) {
    const options = recipeRestaurantSelectorOptions();
    if (["ArrowDown", "ArrowUp"].includes(event.key)) {
        event.preventDefault();
        if (recipeRestaurantSelectorElements().list?.hidden) openRecipeRestaurantSelector(input);
        setRecipeRestaurantSelectorActive(recipeRestaurantSelectorActiveIndex + (event.key === "ArrowDown" ? 1 : -1));
        return false;
    }
    if (event.key === "Enter" && recipeRestaurantSelectorActiveIndex >= 0) {
        event.preventDefault();
        options[recipeRestaurantSelectorActiveIndex]?.click();
        return false;
    }
    if (event.key === "Escape") {
        const selectorList = recipeRestaurantSelectorElements().list;
        if (!selectorList || selectorList.hidden) return true;
        event.preventDefault();
        event.stopPropagation();
        closeRecipeRestaurantSelector({ restoreValue: true });
        return false;
    }
    if (event.key === "Tab") closeRecipeRestaurantSelector({ restoreValue: true });
    return true;
}

function currentRecipeRestaurantSourceOption() {
    const linkedRestaurantId = recipeEditInputValue("recipeEditRestaurantId");
    if (recipeRestaurantDisplaySource
        && linkedRestaurantId
        && recipeRestaurantRecordId(recipeRestaurantDisplaySource) === linkedRestaurantId) {
        return recipeRestaurantDisplaySource;
    }
    const selectValue = document.getElementById("recipeEditMenuSourceSelect")?.value || "";
    const selected = recipeMenuSourceOptionByValue(selectValue);
    if (selected) {
        recipeRestaurantDisplaySource = selected;
        return selected;
    }
    if (recipeRestaurantDisplaySource) {
        return recipeRestaurantDisplaySource;
    }
    const restaurantId = recipeEditInputValue("recipeEditRestaurantId");
    const menuId = recipeEditInputValue("recipeEditMenuId");
    const restaurantName = recipeEditInputValue("recipeEditRestaurantName");
    if (!restaurantId && !restaurantName) return null;
    recipeRestaurantDisplaySource = {
        value: recipeMenuSourceOptionValue(restaurantId, menuId),
        restaurant_id: restaurantId,
        menu_id: menuId,
        restaurant_name: restaurantName,
        restaurant_phone: recipeEditInputValue("recipeEditRestaurantPhone"),
        restaurant_website_url: recipeEditInputValue("recipeEditRestaurantWebsiteUrl"),
        source_menu_url: recipeEditInputValue("recipeEditSourceMenuUrl"),
        restaurant_street_address: recipeEditInputValue("recipeEditRestaurantAddress"),
        restaurant_city: "",
        restaurant_state: "",
        restaurant_postal_code: "",
        restaurant_country: "",
        restaurant_logo_url: "",
        restaurant_rating: "",
        restaurant_hours_text: recipeEditInputValue("recipeEditRestaurantHoursText"),
        restaurant_weekly_hours: recipeRestaurantWeeklyHoursFromText(recipeEditInputValue("recipeEditRestaurantHoursText")),
        restaurant_hours_notes: "",
        restaurant_raw_hours_data: recipeEditInputValue("recipeEditRestaurantHoursText"),
        restaurant_online_ordering_available: recipeEditInputValue("recipeEditRestaurantOnlineOrderingAvailable"),
        menu_item_url: recipeEditInputValue("recipeEditMenuItemUrl") || recipeEditorSourceUrlForOpen(),
        restaurant_address: recipeEditInputValue("recipeEditRestaurantAddress"),
    };
    return recipeRestaurantDisplaySource;
}

function recipeRestaurantFallbackFromEditor() {
    const menuItemUrl = recipeEditInputValue("recipeEditMenuItemUrl")
        || recipeEditInputValue("recipeEditDocumentSourceUrl")
        || recipeEditInputValue("recipeEditSourceUrl")
        || recipeEditorSourceUrlForOpen();
    const hoursText = recipeEditInputValue("recipeEditRestaurantHoursText");
    const hoursNoteLine = hoursText.split(/\r?\n/).find(value => /^Notes:/i.test(value));
    return {
        value: "|",
        restaurant_id: "",
        menu_id: recipeEditInputValue("recipeEditMenuId"),
        restaurant_name: recipeEditInputValue("recipeEditRestaurantName"),
        restaurant_phone: recipeEditInputValue("recipeEditRestaurantPhone"),
        restaurant_website_url: recipeEditInputValue("recipeEditRestaurantWebsiteUrl"),
        source_menu_url: recipeEditInputValue("recipeEditSourceMenuUrl"),
        restaurant_street_address: recipeEditInputValue("recipeEditRestaurantAddress"),
        restaurant_city: "",
        restaurant_state: "",
        restaurant_postal_code: "",
        restaurant_country: "",
        restaurant_hours_text: hoursText,
        restaurant_weekly_hours: recipeRestaurantWeeklyHoursFromText(hoursText),
        restaurant_hours_notes: hoursNoteLine ? hoursNoteLine.replace(/^Notes:\s*/i, "") : "",
        restaurant_raw_hours_data: hoursText,
        restaurant_current_status: recipeEditInputValue("recipeEditRestaurantCurrentStatus") || "unknown",
        restaurant_promotions: recipeEditInputValue("recipeEditRestaurantPromotions"),
        restaurant_online_payment_available: recipeEditInputValue("recipeEditRestaurantOnlinePaymentAvailable"),
        restaurant_online_ordering_available: recipeEditInputValue("recipeEditRestaurantOnlineOrderingAvailable"),
        restaurant_delivery_available: recipeEditInputValue("recipeEditRestaurantDeliveryAvailable"),
        menu_item_url: menuItemUrl,
    };
}

function recipeRestaurantEditComparableState(form = recipeRestaurantEditForm()) {
    return {
        restaurant_id: recipeRestaurantRecordId(recipeRestaurantEditSelection),
        create_mode: recipeRestaurantEditCreateMode,
        values: recipeRestaurantEditValues(form),
    };
}

function bindRecipeRestaurantEditFields(form) {
    form?.querySelectorAll("[data-restaurant-edit-field]").forEach(input => {
        if (input.dataset.restaurantEditBound === "1") return;
        input.dataset.restaurantEditBound = "1";
        input.addEventListener("input", () => updateRecipeRestaurantEditState(form));
    });
    const logoUrlInput = form?.querySelector('[data-restaurant-edit-field="restaurant_logo_url"]');
    if (logoUrlInput && logoUrlInput.dataset.restaurantLogoUrlBound !== "1") {
        logoUrlInput.dataset.restaurantLogoUrlBound = "1";
        logoUrlInput.addEventListener("input", () => {
            const action = form.querySelector('[data-restaurant-edit-field="restaurant_logo_action"]');
            if (action) action.value = "url";
            const dataInput = form.querySelector('[data-restaurant-edit-field="restaurant_logo_data_url"]');
            if (dataInput) dataInput.value = "";
            updateRecipeRestaurantEditState(form);
        });
    }
}

function populateRecipeRestaurantEditForm(record, options = {}) {
    const form = recipeRestaurantEditForm();
    if (!form) return;
    const keepMenuItemUrl = String(options.menuItemUrl ?? recipeRestaurantOriginalMenuItemUrl ?? "").trim();
    form.querySelectorAll("[data-restaurant-edit-field]").forEach(input => {
        const field = input.dataset.restaurantEditField;
        let savedValue = "";
        if (field === "menu_item_url") savedValue = keepMenuItemUrl;
        else if (field === "restaurant_logo_data_url") savedValue = "";
        else if (field === "restaurant_logo_action") savedValue = "keep";
        else if (field === "restaurant_social_links") savedValue = JSON.stringify(recipeRestaurantSocialLinksFromRecord(record));
        else if (field === "restaurant_ordering_links") savedValue = JSON.stringify(recipeRestaurantOrderingLinksFromRecord(record));
        else if (field === "restaurant_active_promotions") savedValue = recipeRestaurantActivePromotionsFromRecord(record);
        else if (field === "restaurant_ordering_provider_urls") savedValue = recipeRestaurantStructuredArray(
            record?.restaurant_ordering_provider_urls ?? record?.ordering_provider_urls ?? []
        ).map(item => recipeMenuMetadataText(item)).filter(Boolean).join("\n");
        else if (field === "restaurant_ordering_providers") {
            const providers = recipeRestaurantStructuredArray(
                record?.restaurant_ordering_providers ?? record?.ordering_providers ?? []
            );
            savedValue = providers.length ? JSON.stringify(providers, null, 2) : "";
        }
        else savedValue = recipeRestaurantRecordValue(record, field);
        if (options.clearShared && field === "restaurant_current_status") savedValue = "unknown";
        if (input.tagName === "SELECT" && savedValue && !Array.from(input.options).some(option => option.value === savedValue)) {
            input.querySelector("[data-restaurant-legacy-option]")?.remove();
            const legacy = document.createElement("option");
            legacy.value = savedValue;
            legacy.textContent = `Saved value: ${savedValue}`;
            legacy.dataset.restaurantLegacyOption = "1";
            input.prepend(legacy);
        }
        input.value = savedValue;
    });
    bindRecipeRestaurantEditFields(form);
    hydrateRecipeRestaurantSocialLinks(form, recipeRestaurantSocialLinksFromRecord(record));
    hydrateRecipeRestaurantOrderingLinks(form, recipeRestaurantOrderingLinksFromRecord(record));
    closeRecipeRestaurantLogoChooser(form.querySelector("[data-restaurant-logo-chooser]"));
    hydrateRecipeRestaurantStructuredHours(form, record || {});
    updateRecipeRestaurantEditState(form);
}

function setRecipeRestaurantUsageEmpty() {
    recipeRestaurantUsageRecipes = [];
    recipeRestaurantUsageRestaurantId = "";
    recipeRestaurantUsagePage = 1;
    recipeRestaurantUsageHasMore = false;
    recipeRestaurantUsageQuery = "";
    recipeRestaurantUsageTotal = 0;
    recipeRestaurantUsageReviewOnly = false;
    recipeRestaurantUsageReviewCount = 0;
    recipeRestaurantUsageRestaurantName = "";
    recipeRestaurantUsageMigrationStatus = {};
    const count = document.querySelector("[data-restaurant-usage-recipes]");
    const cookbooks = document.querySelector("[data-restaurant-usage-cookbooks]");
    const note = document.querySelector("[data-restaurant-usage-note]");
    const view = document.querySelector("[data-restaurant-usage-view]");
    const repair = document.querySelector("[data-restaurant-usage-repair]");
    const backfill = document.querySelector("[data-restaurant-usage-backfill]");
    const loadMore = document.querySelector("[data-restaurant-usage-load-more]");
    const reviewToggle = document.querySelector("[data-restaurant-usage-review-only]");
    const reviewLabel = document.querySelector("[data-restaurant-usage-review-label]");
    if (count) count.textContent = "Not currently used by any recipes.";
    if (cookbooks) cookbooks.hidden = true;
    if (note) note.hidden = true;
    if (view) view.hidden = true;
    if (repair) repair.hidden = true;
    if (backfill) backfill.hidden = true;
    if (loadMore) loadMore.hidden = true;
    if (reviewToggle) {
        reviewToggle.checked = false;
        reviewToggle.setAttribute("aria-checked", "false");
    }
    if (reviewLabel) reviewLabel.textContent = "Review Items Only";
    renderRecipeRestaurantUsageList();
}

function setRecipeRestaurantEditMode(record, options = {}) {
    const form = recipeRestaurantEditForm();
    if (!form) return;
    recipeRestaurantEditCreateMode = Boolean(options.create);
    recipeRestaurantEditSelection = recipeRestaurantEditCreateMode ? null : record;
    populateRecipeRestaurantEditForm(record || {}, {
        clearShared: recipeRestaurantEditCreateMode,
        menuItemUrl: recipeRestaurantOriginalMenuItemUrl,
    });
    renderRecipeRestaurantSelector();
    const { input, status } = recipeRestaurantSelectorElements();
    if (input) {
        input.value = recipeRestaurantEditCreateMode ? "" : recipeRestaurantRecordName(record);
        input.placeholder = recipeRestaurantEditCreateMode ? "Creating new restaurant" : "Search restaurants";
    }
    updateRecipeRestaurantSelectorClearButton();
    if (status) status.textContent = recipeRestaurantEditCreateMode ? "Creating new restaurant" : "";
    const save = form.querySelector("[data-restaurant-edit-save]");
    if (save && !form.dataset.saving) save.textContent = recipeRestaurantEditCreateMode ? "Create Restaurant" : "Save Changes";
    updateRecipeRestaurantScanActionLabel(record);
    closeRecipeRestaurantDuplicatePanel(form.querySelector("[data-restaurant-duplicate-panel]"));
    closeRecipeRestaurantUsagePanel();
    closeRecipeRestaurantFetchReview({ restoreFocus: false });
    closeRecipeRestaurantDuplicateReview({ restoreFocus: false });
    if (recipeRestaurantEditCreateMode) setRecipeRestaurantUsageEmpty();
    else {
        recipeRestaurantUsageQuery = "";
        recipeRestaurantUsageReviewOnly = false;
        const search = document.querySelector("[data-restaurant-usage-search]");
        if (search) search.value = "";
        loadRecipeRestaurantUsage(recipeRestaurantRecordId(record), { query: "", reviewOnly: false });
    }
    updateRecipeRestaurantEditState(form);
}

function recipeRestaurantMenuIdForSave(selected) {
    if (recipeRestaurantEditCreateMode) return "";
    const selectedRestaurantId = recipeRestaurantRecordId(selected);
    const selectedMenuId = String(selected?.menu_id || "").trim();
    if (selectedMenuId) return selectedMenuId;
    return selectedRestaurantId === recipeRestaurantOriginalRestaurantId ? recipeRestaurantOriginalMenuId : "";
}

function syncRecipeRestaurantMenuSourceSelection(savedRestaurant) {
    const restaurantId = recipeRestaurantRecordId(savedRestaurant);
    const menuId = String(savedRestaurant?.menu_id || "").trim();
    const value = recipeMenuSourceOptionValue(restaurantId, menuId);
    const previousRestaurantId = recipeEditInputValue("recipeEditRestaurantId");
    const previousMenuId = recipeEditInputValue("recipeEditMenuId");
    const relationshipChanged = previousRestaurantId !== restaurantId || previousMenuId !== menuId;
    const normalizedOption = {
        ...savedRestaurant,
        restaurant_id: restaurantId,
        menu_id: menuId,
        value,
        label: recipeRestaurantRecordName(savedRestaurant),
    };
    const existingIndex = recipeEditMenuSourceOptions.findIndex(option => {
        return recipeMenuSourceOptionValue(option.restaurant_id, option.menu_id) === value;
    });
    if (existingIndex >= 0) recipeEditMenuSourceOptions.splice(existingIndex, 1, normalizedOption);
    else recipeEditMenuSourceOptions.unshift(normalizedOption);

    const select = document.getElementById("recipeEditMenuSourceSelect");
    if (select) {
        let option = Array.from(select.options).find(item => item.value === value);
        if (!option) {
            option = document.createElement("option");
            option.value = value;
            select.appendChild(option);
        }
        option.textContent = normalizedOption.label || "Restaurant Source";
        select.value = value;
    }
    setRecipeMenuRelationFields({
        restaurant_id: restaurantId,
        menu_id: menuId,
        menu_section_id: relationshipChanged ? "" : recipeEditInputValue("recipeEditMenuSectionId"),
        menu_item_id: relationshipChanged ? "" : recipeEditInputValue("recipeEditMenuItemId"),
    });
}

async function switchRecipeRestaurantSelection(restaurantId, options = {}) {
    const form = recipeRestaurantEditForm();
    const id = String(restaurantId || "").trim();
    if (!form || !id || form.dataset.saving) return false;
    if (!recipeRestaurantEditCreateMode && id === recipeRestaurantRecordId(recipeRestaurantEditSelection)) {
        closeRecipeRestaurantSelector({ restoreValue: true });
        return false;
    }
    if (!options.skipConfirm && recipeRestaurantEditHasChanges(form)
        && !window.confirm("You have unsaved restaurant changes. Discard them and switch restaurants?")) {
        closeRecipeRestaurantSelector({ restoreValue: true });
        return false;
    }
    recipeRestaurantOriginalMenuItemUrl = form.querySelector('[data-restaurant-edit-field="menu_item_url"]')?.value.trim()
        || recipeRestaurantOriginalMenuItemUrl;
    const { input, status } = recipeRestaurantSelectorElements();
    if (input) {
        input.disabled = true;
        input.setAttribute("aria-busy", "true");
    }
    updateRecipeRestaurantSelectorClearButton();
    if (status) status.textContent = "Loading restaurant...";
    try {
        const response = await fetch(`/api/recipe/restaurants/${encodeURIComponent(id)}`);
        const data = await response.json();
        if (!response.ok || !data.ok) throw new Error(data.error || "Unable to load restaurant.");
        setRecipeRestaurantEditMode(data.restaurant || data, { create: false });
        closeRecipeRestaurantSelector({ restoreValue: true });
    } catch (err) {
        const error = form.querySelector("[data-restaurant-edit-error]");
        if (error) {
            error.textContent = err.message || "Unable to load restaurant.";
            error.hidden = false;
        }
        closeRecipeRestaurantSelector({ restoreValue: true });
    } finally {
        if (input) {
            input.disabled = false;
            input.removeAttribute("aria-busy");
        }
        updateRecipeRestaurantSelectorClearButton();
        if (status && !recipeRestaurantEditCreateMode) status.textContent = "";
    }
    return false;
}

function selectRecipeRestaurantFromSelector(button) {
    return switchRecipeRestaurantSelection(button?.dataset.restaurantSelectorId || "");
}

function beginCreateRecipeRestaurant(button, options = {}) {
    const form = recipeRestaurantEditForm();
    if (!form) return false;
    if (!options.skipConfirm && recipeRestaurantEditHasChanges(form)
        && !window.confirm("You have unsaved restaurant changes. Discard them and switch restaurants?")) {
        closeRecipeRestaurantSelector({ restoreValue: true });
        return false;
    }
    recipeRestaurantOriginalMenuItemUrl = form.querySelector('[data-restaurant-edit-field="menu_item_url"]')?.value.trim()
        || recipeRestaurantOriginalMenuItemUrl;
    setRecipeRestaurantEditMode(null, { create: true });
    closeRecipeRestaurantSelector({ restoreValue: false });
    form.querySelector('[data-restaurant-edit-field="restaurant_name"]')?.focus();
    return false;
}

function recipeRestaurantEditForm() {
    return document.querySelector("[data-restaurant-edit-form]");
}

function recipeRestaurantEditModal() {
    return document.querySelector("[data-restaurant-edit-modal]");
}

function handleRecipeRestaurantUsageThumbnailError(image) {
    const thumbnail = image?.closest(".recipe-edit-restaurant-usage-thumbnail");
    if (image) image.hidden = true;
    thumbnail?.classList.add("is-fallback");
}

function renderRecipeRestaurantUsageList(recipes = recipeRestaurantUsageRecipes) {
    const list = document.querySelector("[data-restaurant-usage-list]");
    if (!list) return;
    if (!recipes.length) {
        if (recipeRestaurantUsageReviewOnly && recipeRestaurantUsageQuery) {
            list.innerHTML = '<div class="recipe-edit-restaurant-usage-empty"><strong>No review items match your search</strong></div>';
        } else if (recipeRestaurantUsageReviewOnly) {
            list.innerHTML = '<div class="recipe-edit-restaurant-usage-empty"><strong>No recipes need review</strong><span>All recipes using this restaurant currently pass the available review checks.</span></div>';
        } else {
            list.innerHTML = '<div class="recipe-edit-restaurant-usage-empty"><strong>No recipes currently reference this restaurant.</strong></div>';
        }
        return;
    }
    list.innerHTML = recipes.map(recipe => {
        const url = String(recipe.url || "").trim();
        const title = String(recipe.title || "Untitled Recipe").trim();
        const thumbnailUrl = String(recipe.thumbnail_url || "").trim();
        const metadata = [recipe.total_time, recipe.calories_per_serving].map(value => String(value || "").trim()).filter(Boolean);
        const category = String(recipe.category_label || "").trim();
        const duplicateBadge = String(recipe.duplicate_badge || "").trim();
        const duplicateGroupId = String(recipe.duplicate_group_id || "").trim();
        const reviewLabels = Array.isArray(recipe.review_reason_labels)
            ? recipe.review_reason_labels.map(value => String(value || "").trim()).filter(Boolean)
            : [];
        const visibleReviewLabels = reviewLabels.filter(label => {
            if (label === "Possible duplicate" && duplicateBadge) return false;
            if (label === "Needs restaurant link" && recipe.relationship_status === "legacy_clear") return false;
            return true;
        }).slice(0, 2);
        const relationship = recipe.relationship_status === "legacy_clear"
            ? '<small class="recipe-edit-restaurant-usage-link-status">Needs restaurant link</small>'
            : "";
        return `<article>
            <span class="recipe-edit-restaurant-usage-thumbnail${thumbnailUrl ? "" : " is-fallback"}" aria-hidden="true">
                <span class="recipe-edit-restaurant-usage-thumbnail-placeholder"></span>
                ${thumbnailUrl ? `<img src="${escapeAttribute(thumbnailUrl)}" alt="" loading="lazy" decoding="async" onerror="handleRecipeRestaurantUsageThumbnailError(this)">` : ""}
            </span>
            <div class="recipe-edit-restaurant-usage-summary">
                <span class="recipe-edit-restaurant-usage-title-row">
                    <a class="recipe-edit-restaurant-usage-name" href="/recipe/edit?url=${encodeURIComponent(url)}" aria-label="Open ${escapeAttribute(title)}" title="${escapeAttribute(title)}">${escapeHtml(title)}</a>
                    ${duplicateBadge ? `<button type="button" class="recipe-edit-restaurant-duplicate-badge" data-restaurant-duplicate-group="${escapeAttribute(duplicateGroupId)}" aria-label="Review ${escapeAttribute(duplicateBadge)} recipes named ${escapeAttribute(title)}" title="Compare these recipes" onclick="return openRecipeRestaurantDuplicateReview(this)">${escapeHtml(duplicateBadge)}</button>` : ""}
                </span>
                ${metadata.length ? `<span>${escapeHtml(metadata.join(" · "))}</span>` : ""}
                ${category ? `<small class="recipe-edit-restaurant-usage-category">${escapeHtml(category)}</small>` : ""}
                ${visibleReviewLabels.length ? `<span class="recipe-edit-restaurant-review-reasons">${visibleReviewLabels.map(label => `<small>${escapeHtml(label)}</small>`).join("")}</span>` : ""}
                ${relationship}
            </div>
        </article>`;
    }).join("");
}

function applyRecipeRestaurantUsageResponse(data, options = {}) {
    const count = document.querySelector("[data-restaurant-usage-recipes]");
    const cookbooks = document.querySelector("[data-restaurant-usage-cookbooks]");
    const note = document.querySelector("[data-restaurant-usage-note]");
    const view = document.querySelector("[data-restaurant-usage-view]");
    const repair = document.querySelector("[data-restaurant-usage-repair]");
    const backfill = document.querySelector("[data-restaurant-usage-backfill]");
    const loadMore = document.querySelector("[data-restaurant-usage-load-more]");
    const reviewToggle = document.querySelector("[data-restaurant-usage-review-only]");
    const reviewLabel = document.querySelector("[data-restaurant-usage-review-label]");
    const panelTitle = document.querySelector("[data-restaurant-usage-panel-title]");
    const rows = Array.isArray(data.recipes) ? data.recipes : [];
    if (options.append) {
        const renderedGroups = new Set(recipeRestaurantUsageRecipes.map(recipe => recipe.duplicate_group_id).filter(Boolean));
        rows.forEach(recipe => {
            if (renderedGroups.has(recipe.duplicate_group_id)) delete recipe.duplicate_badge;
            else if (recipe.duplicate_group_id) renderedGroups.add(recipe.duplicate_group_id);
        });
    }
    recipeRestaurantUsageRecipes = options.append ? [...recipeRestaurantUsageRecipes, ...rows] : rows;
    recipeRestaurantUsagePage = Number(data.page) || 1;
    recipeRestaurantUsageHasMore = Boolean(data.has_more);
    recipeRestaurantUsageTotal = Number(data.recipe_count) || 0;
    recipeRestaurantUsageReviewOnly = Boolean(data.review_only);
    recipeRestaurantUsageReviewCount = Number(data.review_recipe_count) || 0;
    recipeRestaurantUsageRestaurantName = String(data.restaurant_name || recipeRestaurantRecordName(recipeRestaurantEditSelection) || "This Restaurant").trim();
    recipeRestaurantUsageMigrationStatus = data.migration_status || {};
    const cookbookCount = Number(data.cookbook_count) || 0;
    const legacyCount = Number(recipeRestaurantUsageMigrationStatus.legacy_possible_match_count) || 0;
    const ambiguousCount = Number(recipeRestaurantUsageMigrationStatus.ambiguous_match_count) || 0;
    const duplicateCount = Number(data.duplicate_restaurant_count) || 0;
    if (count) {
        count.innerHTML = recipeRestaurantUsageTotal > 0
            ? `Used by <strong>${recipeRestaurantUsageTotal} recipe${recipeRestaurantUsageTotal === 1 ? "" : "s"}</strong>`
            : "Not currently used by any recipes.";
    }
    if (cookbooks) {
        cookbooks.textContent = `Across ${cookbookCount} cookbook${cookbookCount === 1 ? "" : "s"}`;
        cookbooks.hidden = recipeRestaurantUsageTotal <= 0;
    }
    const notices = [];
    if (legacyCount > 0) notices.push(`${legacyCount} additional legacy recipe${legacyCount === 1 ? "" : "s"} may need restaurant linking.`);
    if (ambiguousCount > 0) notices.push(`${ambiguousCount} ambiguous match${ambiguousCount === 1 ? "" : "es"} require review.`);
    if (duplicateCount > 0) notices.push(`${duplicateCount} possible duplicate restaurant record${duplicateCount === 1 ? "" : "s"} found.`);
    if (!notices.length && data.included_current_recipe) notices.push("Includes the current recipe.");
    if (note) {
        note.textContent = notices.join(" ");
        note.hidden = !notices.length;
    }
    if (view) {
        view.hidden = false;
        view.disabled = recipeRestaurantUsageTotal <= 0;
        view.textContent = "View Recipes";
        view.dataset.restaurantUsageMode = "view";
        view.dataset.restaurantId = recipeRestaurantUsageRestaurantId;
    }
    if (repair) {
        repair.hidden = legacyCount <= 0 && ambiguousCount <= 0 && duplicateCount <= 0;
        repair.dataset.restaurantId = recipeRestaurantUsageRestaurantId;
    }
    if (backfill) {
        backfill.hidden = legacyCount <= 0;
        backfill.dataset.restaurantId = recipeRestaurantUsageRestaurantId;
        backfill.textContent = `Link ${legacyCount} Clear Match${legacyCount === 1 ? "" : "es"}`;
    }
    if (loadMore) loadMore.hidden = !recipeRestaurantUsageHasMore;
    if (reviewToggle) {
        reviewToggle.checked = recipeRestaurantUsageReviewOnly;
        reviewToggle.setAttribute("aria-checked", String(recipeRestaurantUsageReviewOnly));
    }
    if (reviewLabel) reviewLabel.textContent = `Review Items Only (${recipeRestaurantUsageReviewCount})`;
    if (panelTitle) panelTitle.textContent = `Recipes Using ${recipeRestaurantUsageRestaurantName} — ${recipeRestaurantUsageTotal}`;
    const searchWrap = document.querySelector("[data-restaurant-usage-search-wrap]");
    if (searchWrap) searchWrap.hidden = recipeRestaurantUsageTotal <= 20;
    renderRecipeRestaurantUsageList();
}

async function loadRecipeRestaurantUsage(restaurantId, options = {}) {
    const count = document.querySelector("[data-restaurant-usage-recipes]");
    const cookbooks = document.querySelector("[data-restaurant-usage-cookbooks]");
    const note = document.querySelector("[data-restaurant-usage-note]");
    const view = document.querySelector("[data-restaurant-usage-view]");
    const repair = document.querySelector("[data-restaurant-usage-repair]");
    const loadMore = document.querySelector("[data-restaurant-usage-load-more]");
    const page = Math.max(1, Number(options.page) || 1);
    const append = Boolean(options.append);
    const query = String(options.query ?? recipeRestaurantUsageQuery ?? "").trim();
    const reviewOnly = options.reviewOnly === undefined
        ? recipeRestaurantUsageReviewOnly
        : Boolean(options.reviewOnly);
    const requestId = ++recipeRestaurantUsageRequest;
    recipeRestaurantUsageRestaurantId = String(restaurantId || recipeRestaurantUsageRestaurantId || "").trim();
    recipeRestaurantUsageQuery = query;
    recipeRestaurantUsageReviewOnly = reviewOnly;
    if (!append) recipeRestaurantUsageRecipes = [];
    if (page === 1 && !query) {
        if (count) count.textContent = "Loading usage…";
        if (cookbooks) cookbooks.hidden = true;
        if (note) note.hidden = true;
        if (repair) repair.hidden = true;
    }
    try {
        if (view && page === 1 && !query) {
            view.hidden = false;
            view.disabled = true;
            view.textContent = "View Recipes";
            view.dataset.restaurantUsageMode = "loading";
            view.dataset.restaurantId = recipeRestaurantUsageRestaurantId;
        }
        if (loadMore) {
            loadMore.disabled = true;
            loadMore.textContent = "Loading…";
        }
        const params = new URLSearchParams({
            restaurant_id: recipeRestaurantUsageRestaurantId,
            page: String(page),
            per_page: "50",
            current_recipe_url: recipeEditorSourceUrlForOpen() || "",
        });
        if (query) params.set("q", query);
        if (reviewOnly) params.set("review_only", "1");
        const response = await fetch(`/api/recipe/restaurant-usage?${params.toString()}`);
        const data = await response.json();
        if (!response.ok || !data.ok) throw new Error(data.error || "Unable to load restaurant usage.");
        if (requestId !== recipeRestaurantUsageRequest) return;
        applyRecipeRestaurantUsageResponse(data, { append });
    } catch (err) {
        if (requestId !== recipeRestaurantUsageRequest) return;
        if (page === 1 && !query && count) count.textContent = "Usage data unavailable.";
        if (page === 1 && !query && cookbooks) cookbooks.hidden = true;
        if (page === 1 && !query && note) note.hidden = true;
        if (view) {
            view.hidden = false;
            view.disabled = false;
            view.textContent = "Retry";
            view.dataset.restaurantUsageMode = "retry";
        }
    } finally {
        if (requestId !== recipeRestaurantUsageRequest) return;
        if (loadMore) {
            loadMore.disabled = false;
            loadMore.textContent = "Load More";
            loadMore.hidden = !recipeRestaurantUsageHasMore;
        }
    }
}

function handleRecipeRestaurantUsageAction(button) {
    if (!button || button.disabled) return false;
    if (button.dataset.restaurantUsageMode === "retry") {
        loadRecipeRestaurantUsage(button.dataset.restaurantId || "");
        return false;
    }
    return openRecipeRestaurantUsagePanel(button);
}

function openRecipeRestaurantUsagePanel(button) {
    const panel = document.querySelector("[data-restaurant-usage-panel]");
    if (!panel) return false;
    panel.hidden = false;
    renderRecipeRestaurantUsageList();
    const search = panel.querySelector("[data-restaurant-usage-search]");
    (search && !search.closest("[hidden]") ? search : panel.querySelector("button"))?.focus();
    return false;
}

function reviewUnlinkedRecipeRestaurants(button) {
    openRecipeRestaurantUsagePanel(button);
    document.querySelector("[data-restaurant-usage-backfill]")?.focus();
    return false;
}

async function backfillUnlinkedRecipeRestaurants(button) {
    const restaurantId = String(button?.dataset.restaurantId || recipeRestaurantUsageRestaurantId || "").trim();
    const count = Number(recipeRestaurantUsageMigrationStatus.legacy_possible_match_count) || 0;
    if (!restaurantId || count <= 0 || button?.disabled) return false;
    if (!window.confirm(`Link ${count} clear legacy restaurant match${count === 1 ? "" : "es"} to ${recipeRestaurantUsageRestaurantName}? Ambiguous matches will remain unchanged.`)) return false;
    button.disabled = true;
    const originalText = button.textContent;
    button.textContent = "Linking…";
    try {
        const response = await fetch("/api/recipe/restaurant-usage/backfill", {
            method: "POST",
            headers: { "Content-Type": "application/json", "Accept": "application/json" },
            body: JSON.stringify({ restaurant_id: restaurantId }),
        });
        const data = await response.json();
        if (!response.ok || !data.ok) throw new Error(data.error || "Unable to link restaurant recipes.");
        recipeRestaurantUsageQuery = "";
        const search = document.querySelector("[data-restaurant-usage-search]");
        if (search) search.value = "";
        await loadRecipeRestaurantUsage(restaurantId, {
            page: 1,
            query: "",
            reviewOnly: recipeRestaurantUsageReviewOnly,
        });
    } catch (err) {
        setRecipeRestaurantFetchError(err.message || "Unable to link restaurant recipes.");
    } finally {
        button.disabled = false;
        button.textContent = originalText;
    }
    return false;
}

function loadMoreRecipeRestaurantUsage(button) {
    if (button?.disabled || !recipeRestaurantUsageHasMore) return false;
    loadRecipeRestaurantUsage(recipeRestaurantUsageRestaurantId, {
        page: recipeRestaurantUsagePage + 1,
        append: true,
        query: recipeRestaurantUsageQuery,
        reviewOnly: recipeRestaurantUsageReviewOnly,
    });
    return false;
}

function closeRecipeRestaurantUsagePanel() {
    const panel = document.querySelector("[data-restaurant-usage-panel]");
    if (panel) panel.hidden = true;
    document.querySelector("[data-restaurant-usage-view]")?.focus({ preventScroll: true });
    return false;
}

function filterRecipeRestaurantUsage(value) {
    const query = String(value || "").trim();
    recipeRestaurantUsageQuery = query;
    window.clearTimeout(recipeRestaurantUsageSearchDebounce);
    recipeRestaurantUsageSearchDebounce = window.setTimeout(() => {
        loadRecipeRestaurantUsage(recipeRestaurantUsageRestaurantId, {
            page: 1,
            query,
            reviewOnly: recipeRestaurantUsageReviewOnly,
        });
    }, 250);
}

function toggleRecipeRestaurantUsageReviewOnly(input) {
    recipeRestaurantUsageReviewOnly = Boolean(input?.checked);
    input?.setAttribute("aria-checked", String(recipeRestaurantUsageReviewOnly));
    loadRecipeRestaurantUsage(recipeRestaurantUsageRestaurantId, {
        page: 1,
        query: recipeRestaurantUsageQuery,
        reviewOnly: recipeRestaurantUsageReviewOnly,
    });
    return false;
}

function recipeRestaurantDuplicateReviewPanel() {
    return recipeRestaurantEditForm()?.querySelector("[data-restaurant-duplicate-review]");
}

function recipeRestaurantDuplicateDate(value) {
    const date = new Date(value || "");
    return Number.isNaN(date.getTime()) ? "" : date.toLocaleDateString();
}

function setRecipeRestaurantDuplicateError(message = "") {
    const error = recipeRestaurantDuplicateReviewPanel()?.querySelector("[data-restaurant-duplicate-error]");
    if (!error) return;
    error.textContent = message;
    error.hidden = !message;
}

function syncRecipeRestaurantDuplicateSelections() {
    const panel = recipeRestaurantDuplicateReviewPanel();
    const primary = panel?.querySelector('[data-restaurant-duplicate-primary]:checked')?.value || "";
    panel?.querySelectorAll("[data-restaurant-duplicate-selected]").forEach(checkbox => {
        checkbox.disabled = checkbox.value === primary;
        if (checkbox.disabled) checkbox.checked = false;
    });
}

function renderRecipeRestaurantDuplicateReview(data) {
    const panel = recipeRestaurantDuplicateReviewPanel();
    const records = panel?.querySelector("[data-restaurant-duplicate-records]");
    const title = panel?.querySelector("[data-restaurant-duplicate-title]");
    const confidence = panel?.querySelector("[data-restaurant-duplicate-confidence]");
    const preview = panel?.querySelector("[data-restaurant-duplicate-preview]");
    if (!panel || !records) return;
    recipeRestaurantDuplicateReviewData = data;
    recipeRestaurantDuplicatePendingPreview = null;
    if (title) title.textContent = `Compare ${data.count || 0} Possible Duplicates — ${data.display_name || "Recipe"}`;
    if (confidence) {
        const label = data.match_type === "exact" ? "Exact duplicate" : `${String(data.match_type || "possible").replace(/^./, char => char.toUpperCase())} match`;
        const evidence = Array.isArray(data.evidence) && data.evidence.length ? ` based on ${data.evidence.join(", ")}` : "";
        confidence.textContent = `${label}${evidence}. Review before changing records.`;
    }
    records.innerHTML = (data.records || []).map((record, index) => {
        const url = String(record.source_url || record.url || "").trim();
        const thumbnail = String(record.thumbnail_url || "").trim();
        const cookbookNames = (record.cookbooks || []).map(item => item.cookbook_name).filter(Boolean).join(", ");
        const metadata = [record.total_time, record.calories_per_serving].filter(Boolean).join(" · ");
        const dates = [
            record.created_at ? `Created ${recipeRestaurantDuplicateDate(record.created_at)}` : "",
            record.updated_at ? `Updated ${recipeRestaurantDuplicateDate(record.updated_at)}` : "",
        ].filter(Boolean).join(" · ");
        return `<article class="recipe-edit-restaurant-duplicate-record" data-duplicate-record-url="${escapeAttribute(url)}">
            <div class="recipe-edit-restaurant-duplicate-record-heading">
                <span class="recipe-edit-restaurant-usage-thumbnail${thumbnail ? "" : " is-fallback"}" aria-hidden="true">
                    <span class="recipe-edit-restaurant-usage-thumbnail-placeholder"></span>
                    ${thumbnail ? `<img src="${escapeAttribute(thumbnail)}" alt="" loading="lazy" decoding="async" onerror="handleRecipeRestaurantUsageThumbnailError(this)">` : ""}
                </span>
                <div>
                    <strong>${escapeHtml(record.title || "Untitled Recipe")}</strong>
                    <span>${escapeHtml([record.restaurant_name, record.menu_section].filter(Boolean).join(" · "))}</span>
                    ${metadata ? `<span>${escapeHtml(metadata)}</span>` : ""}
                </div>
                <div class="recipe-edit-restaurant-duplicate-choices">
                    <label><input type="radio" name="recipeRestaurantDuplicatePrimary" value="${escapeAttribute(record.record_key)}" data-restaurant-duplicate-primary onchange="syncRecipeRestaurantDuplicateSelections()" ${index === 0 ? "checked" : ""}> Canonical</label>
                    <label><input type="checkbox" value="${escapeAttribute(record.record_key)}" data-restaurant-duplicate-selected ${index === 0 ? "" : "checked"}> Select</label>
                </div>
            </div>
            <dl>
                <div><dt>Source</dt><dd title="${escapeAttribute(record.menu_item_url || url)}">${escapeHtml(record.menu_item_url || url)}</dd></div>
                <div><dt>Cookbooks</dt><dd>${escapeHtml(cookbookNames || "None")}</dd></div>
                <div><dt>Ingredients</dt><dd>${escapeHtml(record.ingredients_summary || "None saved")}${record.ingredients_count ? ` (${record.ingredients_count})` : ""}</dd></div>
                <div><dt>Instructions</dt><dd>${escapeHtml(record.instructions_summary || "None saved")}${record.instructions_count ? ` (${record.instructions_count})` : ""}</dd></div>
                ${dates ? `<div><dt>Dates</dt><dd>${escapeHtml(dates)}</dd></div>` : ""}
            </dl>
            <a href="/recipe/edit?url=${encodeURIComponent(url)}">Open Recipe</a>
        </article>`;
    }).join("");
    if (preview) {
        preview.hidden = true;
        preview.innerHTML = "";
    }
    setRecipeRestaurantDuplicateError();
    panel.hidden = false;
    syncRecipeRestaurantDuplicateSelections();
    panel.querySelector("button")?.focus();
}

async function openRecipeRestaurantDuplicateReview(button) {
    const groupId = String(button?.dataset.restaurantDuplicateGroup || "").trim();
    if (!groupId) return false;
    recipeRestaurantDuplicateReviewTrigger = button;
    button.disabled = true;
    try {
        const response = await fetch(`/api/recipe/restaurant-duplicates/${encodeURIComponent(groupId)}?restaurant_id=${encodeURIComponent(recipeRestaurantUsageRestaurantId)}`);
        const data = await response.json();
        if (!response.ok || !data.ok) throw new Error(data.error || "Unable to load duplicate comparison.");
        renderRecipeRestaurantDuplicateReview(data);
    } catch (err) {
        setRecipeRestaurantFetchError(err.message || "Unable to load duplicate comparison.");
    } finally {
        button.disabled = false;
    }
    return false;
}

function closeRecipeRestaurantDuplicateReview(options = {}) {
    const panel = recipeRestaurantDuplicateReviewPanel();
    if (panel) panel.hidden = true;
    recipeRestaurantDuplicateReviewData = null;
    recipeRestaurantDuplicatePendingPreview = null;
    const trigger = recipeRestaurantDuplicateReviewTrigger;
    recipeRestaurantDuplicateReviewTrigger = null;
    if (options.restoreFocus !== false) trigger?.focus({ preventScroll: true });
    return false;
}

async function setRecipeRestaurantDuplicateDisposition(disposition) {
    const groupId = recipeRestaurantDuplicateReviewData?.group_id;
    if (!groupId) return false;
    try {
        const response = await fetch(`/api/recipe/restaurant-duplicates/${encodeURIComponent(groupId)}/disposition`, {
            method: "POST",
            headers: { "Content-Type": "application/json", "Accept": "application/json" },
            body: JSON.stringify({ restaurant_id: recipeRestaurantUsageRestaurantId, disposition }),
        });
        const data = await response.json();
        if (!response.ok || !data.ok) throw new Error(data.error || "Unable to save duplicate review.");
        closeRecipeRestaurantDuplicateReview();
        loadRecipeRestaurantUsage(recipeRestaurantUsageRestaurantId, { page: 1, query: recipeRestaurantUsageQuery, reviewOnly: recipeRestaurantUsageReviewOnly });
    } catch (err) {
        setRecipeRestaurantDuplicateError(err.message || "Unable to save duplicate review.");
    }
    return false;
}

function recipeRestaurantDuplicateSelection() {
    const panel = recipeRestaurantDuplicateReviewPanel();
    const primaryRecordKey = panel?.querySelector('[data-restaurant-duplicate-primary]:checked')?.value || "";
    const secondaryRecordKeys = Array.from(panel?.querySelectorAll('[data-restaurant-duplicate-selected]:checked') || []).map(input => input.value).filter(key => key !== primaryRecordKey);
    return { primaryRecordKey, secondaryRecordKeys };
}

function renderRecipeRestaurantDuplicateMergePreview(data) {
    const preview = recipeRestaurantDuplicateReviewPanel()?.querySelector("[data-restaurant-duplicate-preview]");
    if (!preview) return;
    recipeRestaurantDuplicatePendingPreview = { type: "merge", data };
    const conflicts = (data.conflicts || []).map(conflict => `<label>
        <span>${escapeHtml(conflict.label)}</span>
        <select data-restaurant-duplicate-conflict="${escapeAttribute(conflict.field)}">
            ${(conflict.options || []).map(option => `<option value="${escapeAttribute(option.record_key)}" ${option.record_key === data.primary_record_key ? "selected" : ""}>Keep from ${escapeHtml(option.recipe_title)} — ${escapeHtml(option.display_value)}</option>`).join("")}
        </select>
    </label>`).join("");
    const affectedCookbooks = (data.impacts?.secondaries || []).reduce((total, item) => total + Number(item.cookbook_count || 0), 0);
    preview.innerHTML = `<h4>Merge Preview</h4>
        <p>The canonical recipe ID and URL will be preserved. ${data.secondary_urls.length} secondary record${data.secondary_urls.length === 1 ? "" : "s"} and ${affectedCookbooks} cookbook relationship${affectedCookbooks === 1 ? "" : "s"} will be reassigned.</p>
        ${conflicts ? `<div class="recipe-edit-restaurant-duplicate-conflicts"><h5>Choose conflicting values</h5>${conflicts}</div>` : "<p>No non-empty field conflicts were found.</p>"}
        <button type="button" class="primary" onclick="return commitRecipeRestaurantDuplicateMerge(this)">Confirm Merge</button>`;
    preview.hidden = false;
    preview.scrollIntoView({ block: "nearest" });
}

async function previewRecipeRestaurantDuplicateMerge(button) {
    const { primaryRecordKey, secondaryRecordKeys } = recipeRestaurantDuplicateSelection();
    if (!primaryRecordKey || !secondaryRecordKeys.length) {
        setRecipeRestaurantDuplicateError("Choose one canonical recipe and at least one different selected duplicate.");
        return false;
    }
    button.disabled = true;
    try {
        const response = await fetch(`/api/recipe/restaurant-duplicates/${encodeURIComponent(recipeRestaurantDuplicateReviewData.group_id)}/merge`, {
            method: "POST",
            headers: { "Content-Type": "application/json", "Accept": "application/json" },
            body: JSON.stringify({ restaurant_id: recipeRestaurantUsageRestaurantId, primary_record_key: primaryRecordKey, secondary_record_keys: secondaryRecordKeys }),
        });
        const data = await response.json();
        if (!response.ok || !data.ok) throw new Error(data.error || "Unable to preview merge.");
        renderRecipeRestaurantDuplicateMergePreview(data);
    } catch (err) {
        setRecipeRestaurantDuplicateError(err.message || "Unable to preview merge.");
    } finally {
        button.disabled = false;
    }
    return false;
}

async function commitRecipeRestaurantDuplicateMerge(button) {
    const preview = recipeRestaurantDuplicatePendingPreview?.data;
    if (!preview || button?.disabled) return false;
    const panel = recipeRestaurantDuplicateReviewPanel();
    const fieldChoices = {};
    panel?.querySelectorAll("[data-restaurant-duplicate-conflict]").forEach(select => { fieldChoices[select.dataset.restaurantDuplicateConflict] = select.value; });
    if (!window.confirm(`Merge ${preview.secondary_urls.length} selected duplicate${preview.secondary_urls.length === 1 ? "" : "s"} into the canonical recipe? This removes secondary records only after every relationship is reassigned.`)) return false;
    button.disabled = true;
    try {
        const response = await fetch(`/api/recipe/restaurant-duplicates/${encodeURIComponent(recipeRestaurantDuplicateReviewData.group_id)}/merge`, {
            method: "POST",
            headers: { "Content-Type": "application/json", "Accept": "application/json" },
            body: JSON.stringify({ restaurant_id: recipeRestaurantUsageRestaurantId, primary_record_key: preview.primary_record_key, secondary_record_keys: preview.secondary_record_keys, field_choices: fieldChoices, commit: true, confirm_merge: true }),
        });
        const data = await response.json();
        if (!response.ok || !data.ok) throw new Error(data.error || "Unable to merge duplicate recipes.");
        closeRecipeRestaurantDuplicateReview();
        loadRecipeRestaurantUsage(recipeRestaurantUsageRestaurantId, { page: 1, query: recipeRestaurantUsageQuery, reviewOnly: recipeRestaurantUsageReviewOnly });
    } catch (err) {
        setRecipeRestaurantDuplicateError(err.message || "Unable to merge duplicate recipes.");
    } finally {
        button.disabled = false;
    }
    return false;
}

function renderRecipeRestaurantDuplicateDeletePreview(data) {
    const preview = recipeRestaurantDuplicateReviewPanel()?.querySelector("[data-restaurant-duplicate-preview]");
    if (!preview) return;
    recipeRestaurantDuplicatePendingPreview = { type: "delete", data };
    const impacts = data.impacts || {};
    const retainedRelationships = impacts.relationships_retained
        ? ` Another record uses the same source URL, so its cookbook, menu, and ingredient relationships will be retained.`
        : "";
    preview.innerHTML = `<h4>Delete Duplicate Preview</h4>
        <p>Delete only <strong>${escapeHtml(data.recipe?.title || "this recipe")}</strong>. This affects ${Number(impacts.cookbook_count || 0)} cookbook relationship${Number(impacts.cookbook_count || 0) === 1 ? "" : "s"}, ${Number(impacts.menu_relationship_count || 0)} menu relationship${Number(impacts.menu_relationship_count || 0) === 1 ? "" : "s"}, and ${Number(impacts.ingredient_relationship_count || 0)} saved ingredient relationship${Number(impacts.ingredient_relationship_count || 0) === 1 ? "" : "s"}.${retainedRelationships}</p>
        <button type="button" class="delete" onclick="return commitRecipeRestaurantDuplicateDelete(this)">Confirm Delete Duplicate</button>`;
    preview.hidden = false;
    preview.scrollIntoView({ block: "nearest" });
}

async function previewRecipeRestaurantDuplicateDelete(button) {
    const selected = Array.from(recipeRestaurantDuplicateReviewPanel()?.querySelectorAll('[data-restaurant-duplicate-selected]:checked') || []);
    if (selected.length !== 1) {
        setRecipeRestaurantDuplicateError("Select exactly one duplicate recipe to delete.");
        return false;
    }
    button.disabled = true;
    try {
        const response = await fetch(`/api/recipe/restaurant-duplicates/${encodeURIComponent(recipeRestaurantDuplicateReviewData.group_id)}/delete`, {
            method: "POST",
            headers: { "Content-Type": "application/json", "Accept": "application/json" },
            body: JSON.stringify({ restaurant_id: recipeRestaurantUsageRestaurantId, recipe_record_key: selected[0].value }),
        });
        const data = await response.json();
        if (!response.ok || !data.ok) throw new Error(data.error || "Unable to preview duplicate deletion.");
        renderRecipeRestaurantDuplicateDeletePreview(data);
    } catch (err) {
        setRecipeRestaurantDuplicateError(err.message || "Unable to preview duplicate deletion.");
    } finally {
        button.disabled = false;
    }
    return false;
}

async function commitRecipeRestaurantDuplicateDelete(button) {
    const preview = recipeRestaurantDuplicatePendingPreview?.data;
    if (!preview || button?.disabled) return false;
    if (!window.confirm(`Permanently delete only ${preview.recipe?.title || "the selected duplicate"}? The restaurant and unrelated recipes will not be changed.`)) return false;
    button.disabled = true;
    try {
        const response = await fetch(`/api/recipe/restaurant-duplicates/${encodeURIComponent(recipeRestaurantDuplicateReviewData.group_id)}/delete`, {
            method: "POST",
            headers: { "Content-Type": "application/json", "Accept": "application/json" },
            body: JSON.stringify({ restaurant_id: recipeRestaurantUsageRestaurantId, recipe_record_key: preview.recipe.record_key, commit: true, confirm_delete: true }),
        });
        const data = await response.json();
        if (!response.ok || !data.ok) throw new Error(data.error || "Unable to delete duplicate recipe.");
        closeRecipeRestaurantDuplicateReview();
        loadRecipeRestaurantUsage(recipeRestaurantUsageRestaurantId, { page: 1, query: recipeRestaurantUsageQuery, reviewOnly: recipeRestaurantUsageReviewOnly });
    } catch (err) {
        setRecipeRestaurantDuplicateError(err.message || "Unable to delete duplicate recipe.");
    } finally {
        button.disabled = false;
    }
    return false;
}

