function recipeRestaurantFetchReviewPanel() {
    return recipeRestaurantEditForm()?.querySelector("[data-restaurant-fetch-review]");
}

const recipeRestaurantWeekdays = [
    ["monday", "Monday"], ["tuesday", "Tuesday"], ["wednesday", "Wednesday"],
    ["thursday", "Thursday"], ["friday", "Friday"], ["saturday", "Saturday"],
    ["sunday", "Sunday"],
];

function recipeRestaurantNormalizeHoursTime(value, options = {}) {
    const text = String(value || "").trim();
    if (options.allowEndOfDay && /^24:00(?::00)?$/.test(text)) return "24:00";
    const match = text.match(/^(\d{1,2}):(\d{2})(?::\d{2})?$/);
    if (!match) return "";
    const hour = Number(match[1]);
    const minute = Number(match[2]);
    if (!Number.isInteger(hour) || !Number.isInteger(minute) || hour > 23 || minute > 59) return "";
    return `${String(hour).padStart(2, "0")}:${String(minute).padStart(2, "0")}`;
}

function normalizeRecipeRestaurantWeeklyHours(value) {
    let source = value;
    if (typeof source === "string") {
        try {
            source = JSON.parse(source);
        } catch (err) {
            source = {};
        }
    }
    source = source && typeof source === "object" && !Array.isArray(source) ? source : {};
    const normalized = {};
    recipeRestaurantWeekdays.forEach(([key]) => {
        const rawDay = source[key] ?? source[key[0].toUpperCase() + key.slice(1)];
        if (!rawDay || typeof rawDay !== "object") return;
        const closed = rawDay.closed === true || String(rawDay.status || "").toLowerCase() === "closed";
        const rawRanges = Array.isArray(rawDay.ranges) ? rawDay.ranges : [];
        const ranges = rawRanges.slice(0, 2).map(range => {
            const opens = recipeRestaurantNormalizeHoursTime(range?.opens);
            const closes = recipeRestaurantNormalizeHoursTime(range?.closes, { allowEndOfDay: true });
            return opens && closes ? { opens, closes } : null;
        }).filter(Boolean);
        const open24 = !closed && (rawDay.open_24_hours === true
            || String(rawDay.status || "").toLowerCase() === "open_24_hours"
            || ranges.some(range => range.opens === "00:00" && ["23:59", "24:00"].includes(range.closes)));
        normalized[key] = {
            closed,
            open_24_hours: open24,
            ranges: closed ? [] : (open24 ? [{ opens: "00:00", closes: "24:00" }] : ranges),
        };
    });
    return normalized;
}

function recipeRestaurantWeeklyHoursFromText(value) {
    const weekly = {};
    String(value || "").split(/\r?\n/).forEach(line => {
        const separator = line.indexOf(":");
        if (separator < 0) return;
        const rawDay = line.slice(0, separator).trim().toLowerCase();
        const day = recipeRestaurantWeekdays.find(([, label]) => label.toLowerCase() === rawDay)?.[0];
        if (!day) return;
        const detail = line.slice(separator + 1).trim();
        if (/^closed$/i.test(detail)) {
            weekly[day] = { closed: true, open_24_hours: false, ranges: [] };
            return;
        }
        if (/open\s+24\s+hours?/i.test(detail)) {
            weekly[day] = { closed: false, open_24_hours: true, ranges: [{ opens: "00:00", closes: "24:00" }] };
            return;
        }
        const ranges = [...detail.matchAll(/(\d{1,2}:\d{2})\s*[-\u2013\u2014]\s*(\d{1,2}:\d{2}|24:00)/g)]
            .slice(0, 2)
            .map(match => ({
                opens: recipeRestaurantNormalizeHoursTime(match[1]),
                closes: recipeRestaurantNormalizeHoursTime(match[2], { allowEndOfDay: true }),
            }))
            .filter(range => range.opens && range.closes);
        weekly[day] = { closed: false, open_24_hours: false, ranges };
    });
    return normalizeRecipeRestaurantWeeklyHours(weekly);
}

function recipeRestaurantWeeklyHoursFromForm(form = recipeRestaurantEditForm()) {
    const weekly = {};
    form?.querySelectorAll("[data-restaurant-hours-day]").forEach(row => {
        const day = String(row.dataset.restaurantHoursDay || "").trim().toLowerCase();
        if (!day) return;
        const status = row.querySelector("[data-hours-state]")?.value || "open";
        if (status === "closed") {
            weekly[day] = { closed: true, open_24_hours: false, ranges: [] };
            return;
        }
        if (status === "open_24_hours") {
            weekly[day] = { closed: false, open_24_hours: true, ranges: [{ opens: "00:00", closes: "24:00" }] };
            return;
        }
        const ranges = [
            [row.querySelector("[data-hours-open]")?.value, row.querySelector("[data-hours-close]")?.value],
            [row.querySelector("[data-hours-open-two]")?.value, row.querySelector("[data-hours-close-two]")?.value],
        ].map(([opens, closes]) => ({
            opens: recipeRestaurantNormalizeHoursTime(opens),
            closes: recipeRestaurantNormalizeHoursTime(closes, { allowEndOfDay: true }),
        })).filter(range => range.opens && range.closes);
        if (!ranges.length) return;
        weekly[day] = { closed: false, open_24_hours: false, ranges };
    });
    return normalizeRecipeRestaurantWeeklyHours(weekly);
}

function recipeRestaurantWeeklyHoursText(weeklyHours, notes = "") {
    const normalized = normalizeRecipeRestaurantWeeklyHours(weeklyHours);
    const lines = recipeRestaurantWeekdays.map(([key, label]) => {
        const day = normalized[key];
        if (!day) return "";
        if (day.closed) return `${label}: Closed`;
        if (day.open_24_hours) return `${label}: Open 24 hours`;
        const ranges = day.ranges.map(range => `${range.opens}-${range.closes}`);
        return `${label}: ${ranges.join(", ") || "Open"}`;
    }).filter(Boolean);
    if (String(notes || "").trim()) lines.push(`Notes: ${String(notes).trim()}`);
    return lines.join("\n");
}

function recipeRestaurantFetchDisplayValue(key, value) {
    if (value === null || value === undefined || value === "" || (Array.isArray(value) && !value.length)) return "Not set";
    if (key === "weekly_hours" && typeof value === "object") return recipeRestaurantWeeklyHoursText(value) || "Not found";
    if (["online_payment", "online_ordering", "pickup", "delivery", "reservations"].includes(key)) {
        if (value === true || String(value) === "true") return "Yes";
        if (value === false || String(value) === "false") return "No";
        return "Unknown";
    }
    if (key === "current_status") {
        return String(value).replaceAll("_", " ").replace(/\b\w/g, character => character.toUpperCase());
    }
    if (key === "ordering_providers" && Array.isArray(value)) {
        return value.map(provider => [provider?.provider_name, provider?.website_url].filter(Boolean).join(" — ")).filter(Boolean).join("\n");
    }
    if (key === "ordering_link" && value && typeof value === "object") {
        return [value.provider_name || "Ordering provider", value.url].filter(Boolean).join("\n");
    }
    if (Array.isArray(value)) return value.join("\n");
    if (value && typeof value === "object") return JSON.stringify(value, null, 2);
    return String(value);
}

function recipeRestaurantFetchCandidateHtml(key, candidate) {
    const value = candidate?.value;
    if (key === "weekly_hours" && value && typeof value === "object") {
        const text = recipeRestaurantWeeklyHoursText(value);
        const dayCount = Object.keys(value).length;
        return `<details class="recipe-edit-restaurant-scan-hours"><summary>${dayCount} day${dayCount === 1 ? "" : "s"} parsed</summary><pre>${escapeHtml(text)}</pre></details>`;
    }
    if (key === "street_address" && candidate?.formatted_address) {
        const lines = String(candidate.formatted_address).split(/\r?\n/).filter(Boolean);
        return `<address class="recipe-edit-restaurant-scan-address">${lines.map(line => `<span>${escapeHtml(line)}</span>`).join("")}</address>`;
    }
    if (key === "ordering_providers" && Array.isArray(value)) {
        return `<div class="recipe-edit-restaurant-scan-providers">${value.map(provider => `
            <span><strong>${escapeHtml(provider?.provider_name || "Ordering provider")}</strong>${provider?.website_url ? `<a href="${escapeAttribute(provider.website_url)}" target="_blank" rel="noopener noreferrer">${escapeHtml(provider.website_url)}</a>` : ""}</span>
        `).join("")}</div>`;
    }
    if (key === "ordering_link" && value && typeof value === "object") {
        return `<span class="recipe-edit-restaurant-scan-ordering-link">
            <strong>${escapeHtml(value.provider_name || "Ordering provider")}</strong>
            <a href="${escapeAttribute(value.url || "#")}" target="_blank" rel="noopener noreferrer" title="${escapeAttribute(value.url || "")}">${escapeHtml(value.url || "URL unavailable")}</a>
            <small>${value.is_active ? "Active" : "Verification needed"}</small>
        </span>`;
    }
    return `<span data-restaurant-scan-value>${escapeHtml(recipeRestaurantFetchDisplayValue(key, value))}</span>`;
}

function recipeRestaurantScanCandidate(row, candidateId = "") {
    const candidates = Array.isArray(row?.candidates) ? row.candidates : [];
    return candidates.find(candidate => candidate.candidate_id === candidateId) || row?.recommended || candidates[0] || null;
}

function recipeRestaurantScanSourceStatus(source) {
    const status = String(source?.status || "");
    if (source?.classification_warning) return { icon: "!", label: "Possible misclassified platform URL", className: "is-warning" };
    if (status === "success") return { icon: "✓", label: source.status_label || "Reached and parsed", className: "is-success" };
    if (status === "not_configured") return { icon: "–", label: source.status_label || "Not configured", className: "is-neutral" };
    if (status === "mismatch") return { icon: "!", label: source.status_label || "Restaurant mismatch", className: "is-warning" };
    return { icon: "×", label: source.status_label || source?.reason || "Source fetch failed", className: "is-error" };
}

function recipeRestaurantScanReviewStatus(row, recommended) {
    const backendStatus = String(row?.status || "").trim().toLowerCase().replaceAll("_", " ");
    const backendLabels = {
        new: "New", changed: "Changed", "already saved": "Already saved",
        conflict: "Conflict", unresolved: "Unresolved", invalid: "Invalid", applied: "Applied",
    };
    if (backendLabels[backendStatus]) return backendLabels[backendStatus];
    if (row?.invalid) return "Invalid";
    if (!recommended) return "Unresolved";
    if (row?.conflict) return "Conflict";
    if (!row?.changed) return "Already saved";
    const current = row?.current_normalized_value ?? row?.current_value;
    const emptyCurrent = current === null || current === undefined || current === ""
        || (Array.isArray(current) && !current.length)
        || (current && typeof current === "object" && !Object.keys(current).length);
    return emptyCurrent ? "New" : "Changed";
}

function recipeRestaurantScanRowCanApply(row, status, recommended) {
    const field = String(row?.field || "");
    const hasFormDestination = Boolean(recipeRestaurantFetchFieldDefinitions[field]?.field)
        || ["weekly_hours", "raw_hours_text", "hours_notes", "ordering_link"].includes(field);
    return Boolean(hasFormDestination && recommended && row?.selectable && !row?.locked
        && !["Already saved", "Unresolved", "Invalid", "Applied"].includes(status));
}

function updateRecipeRestaurantOrderingScanResolution(select) {
    const row = select?.closest("[data-restaurant-fetch-field]");
    const accept = row?.querySelector(".recipe-edit-restaurant-fetch-accept input");
    if (accept && !accept.disabled) accept.checked = select.value === "replace";
    updateRecipeRestaurantScanApplyActions();
}

function recipeRestaurantOrderingScanRowHtml(row) {
    const key = String(row?.row_key || "");
    const recommended = recipeRestaurantScanCandidate(row);
    const reviewStatus = recipeRestaurantScanReviewStatus(row, recommended);
    const canApply = recipeRestaurantScanRowCanApply(row, reviewStatus, recommended);
    const highConfidenceEligible = canApply && ["New", "Changed"].includes(reviewStatus)
        && row.confidence_label === "High" && !row.conflict && !row.requires_explicit_review;
    const current = recipeRestaurantFetchDisplayValue("ordering_link", row.current_value);
    const sourceUrl = String(recommended?.source_url || "");
    const resolution = row.conflict ? `
        <label class="recipe-edit-restaurant-scan-ordering-resolution">
            <span>Conflict action</span>
            <select data-ordering-link-resolution aria-label="Choose how to handle this ordering link conflict" onchange="updateRecipeRestaurantOrderingScanResolution(this)">
                <option value="keep">Keep existing</option>
                <option value="replace">Replace existing</option>
            </select>
        </label>` : "";
    const acceptControl = canApply
        ? `<label class="recipe-edit-restaurant-fetch-accept"><input type="checkbox" ${highConfidenceEligible ? "checked" : ""} aria-label="Accept ${escapeAttribute(recommended?.normalized_value?.provider_name || "ordering and delivery link")}" onchange="updateRecipeRestaurantScanApplyActions()"></label>`
        : '<span class="recipe-edit-restaurant-fetch-accept" aria-hidden="true"></span>';
    return `<article class="recipe-edit-restaurant-fetch-row recipe-edit-restaurant-fetch-ordering-row${row.conflict ? " has-conflict" : ""}${row.locked ? " is-locked" : ""}${reviewStatus === "Already saved" ? " is-no-change" : ""}" data-restaurant-fetch-field="${escapeAttribute(key)}" data-restaurant-lock-field="ordering_providers" data-recommended-candidate="${escapeAttribute(recommended?.candidate_id || "")}" data-scan-status="${escapeAttribute(reviewStatus)}" data-high-confidence-eligible="${highConfidenceEligible ? "true" : "false"}">
        ${acceptControl}
        <strong>Ordering &amp; Delivery Link</strong>
        <span class="recipe-edit-restaurant-fetch-current">${escapeHtml(current)}</span>
        <span class="recipe-edit-restaurant-fetch-proposed">${recipeRestaurantFetchCandidateHtml("ordering_link", recommended)}${resolution}</span>
        <span class="recipe-edit-restaurant-scan-confidence is-${String(row.confidence_label || "low").toLowerCase()}"><b data-restaurant-scan-status>${escapeHtml(reviewStatus)}</b><small>${escapeHtml(row.confidence_label || "Low")} · ${Math.round(Number(recommended?.confidence || 0) * 100)}%</small></span>
        <span class="recipe-edit-restaurant-fetch-evidence">
            ${sourceUrl ? `<a href="${escapeAttribute(sourceUrl)}" target="_blank" rel="noopener noreferrer" title="${escapeAttribute(sourceUrl)}">View exact source</a>` : "Source unavailable"}
            <small data-restaurant-scan-method title="${escapeAttribute(recommended?.evidence || "")}">${escapeHtml(String(recommended?.extraction_method || "").replaceAll("_", " "))}</small>
            <label class="recipe-edit-restaurant-scan-lock"><input type="checkbox" data-restaurant-scan-lock ${row.locked ? "checked" : ""}> Lock existing</label>
            ${row.requires_explicit_review && reviewStatus !== "Already saved" ? "<em>Explicit review required</em>" : ""}
        </span>
    </article>`;
}

function updateRecipeRestaurantScanApplyActions() {
    const panel = recipeRestaurantFetchReviewPanel();
    if (!panel) return;
    const rows = Array.from(panel.querySelectorAll("[data-restaurant-fetch-field]"));
    const selectedCount = rows.filter(row => {
        const accept = row.querySelector(".recipe-edit-restaurant-fetch-accept input");
        return accept?.checked && !accept.disabled
            && !["Already saved", "Unresolved", "Invalid", "Applied"].includes(row.dataset.scanStatus);
    }).length;
    let highCount = rows.filter(row => row.dataset.highConfidenceEligible === "true"
        && row.dataset.scanStatus !== "Applied").length;
    if (Number(panel.dataset.highConfidenceChangeCount || 0) === 0) highCount = 0;
    const selectedButton = panel.querySelector("[data-restaurant-scan-apply-selected]");
    const highButton = panel.querySelector("[data-restaurant-scan-apply-high]");
    const message = panel.querySelector("[data-restaurant-scan-apply-message]");
    if (selectedButton) selectedButton.disabled = selectedCount === 0;
    if (highButton) highButton.disabled = highCount === 0;
    if (message) message.textContent = highCount === 0 ? "No high-confidence changes available" : "";
}

function renderRecipeRestaurantFetchReview(data) {
    const panel = recipeRestaurantFetchReviewPanel();
    const list = panel?.querySelector("[data-restaurant-fetch-review-list]");
    const summary = panel?.querySelector("[data-restaurant-fetch-summary]");
    const metrics = panel?.querySelector("[data-restaurant-scan-metrics]");
    const sources = panel?.querySelector("[data-restaurant-scan-sources]");
    const unresolved = panel?.querySelector("[data-restaurant-scan-unresolved]");
    const unresolvedList = panel?.querySelector("[data-restaurant-scan-unresolved-list]");
    if (!panel || !list) return;
    recipeRestaurantInformationScan = data || {};
    recipeRestaurantFetchedProposals = data?.proposals || {};
    const fieldRows = Object.entries(data?.fields || {});
    const orderingRows = Array.isArray(data?.ordering_link_recommendations)
        ? data.ordering_link_recommendations : [];
    const unresolvedOrdering = Array.isArray(data?.unresolved_ordering_providers)
        ? data.unresolved_ordering_providers : [];
    const scanSummary = data?.summary || {};
    panel.dataset.highConfidenceChangeCount = String(Number(scanSummary.high_confidence_changes) || 0);
    if (metrics) {
        const values = [
            ["Sources scanned", scanSummary.sources_scanned], ["Sources reached", scanSummary.sources_reached],
            ["Fields discovered", scanSummary.fields_discovered], ["High-confidence changes", scanSummary.high_confidence_changes],
            ["Conflicts", scanSummary.conflicts], ["Unresolved", scanSummary.unresolved],
        ];
        metrics.innerHTML = values.map(([label, value]) => `<span><strong>${Number(value) || 0}</strong>${escapeHtml(label)}</span>`).join("");
    }
    if (sources) {
        sources.innerHTML = (data?.sources || []).map(source => {
            const status = recipeRestaurantScanSourceStatus(source);
            const label = String(source.label || source.source_type || "Source").replaceAll("_", " ");
            return `<span class="${status.className}" title="${escapeAttribute(source.classification_warning || source.reason || status.label)}"><b aria-hidden="true">${status.icon}</b><span>${escapeHtml(label)}: ${escapeHtml(status.label)}</span></span>`;
        }).join("");
    }
    const orderingHtml = orderingRows.length || unresolvedOrdering.length ? `
        <section class="recipe-edit-restaurant-scan-group" aria-labelledby="restaurant-scan-ordering-heading">
            <h3 id="restaurant-scan-ordering-heading">Ordering &amp; Delivery Links</h3>
            ${orderingRows.map(recipeRestaurantOrderingScanRowHtml).join("")}
            ${unresolvedOrdering.map(item => `<article class="recipe-edit-restaurant-fetch-row recipe-edit-restaurant-fetch-ordering-row is-not-found">
                <span class="recipe-edit-restaurant-fetch-accept" aria-hidden="true"></span>
                <strong>Ordering &amp; Delivery Link</strong>
                <span class="recipe-edit-restaurant-fetch-current">Not set</span>
                <span class="recipe-edit-restaurant-fetch-proposed"><strong>${escapeHtml(item.label || "Ordering provider")}</strong><small>${escapeHtml(item.reason || "No reliable source value found.")}</small></span>
                <span class="recipe-edit-restaurant-scan-confidence is-low"><b>Unresolved</b></span>
                <span class="recipe-edit-restaurant-fetch-evidence">No verified source</span>
            </article>`).join("")}
        </section>` : "";
    const fieldHtml = fieldRows.length ? fieldRows.map(([key, row]) => {
        const definition = recipeRestaurantFetchFieldDefinitions[key] || { label: key.replaceAll("_", " ") };
        const recommended = recipeRestaurantScanCandidate(row);
        const reviewStatus = recipeRestaurantScanReviewStatus(row, recommended);
        const canApply = recipeRestaurantScanRowCanApply(row, reviewStatus, recommended);
        const highConfidenceEligible = canApply && ["New", "Changed"].includes(reviewStatus)
            && row.confidence_label === "High" && !row.conflict && !row.requires_explicit_review;
        const defaultAccept = highConfidenceEligible;
        const imagePreview = key === "image_url" && recommended
            ? `<img src="${escapeAttribute(recommended.value)}" alt="Discovered restaurant logo preview">`
            : "";
        const logoActions = key === "image_url" && recommended
            ? `<span class="recipe-edit-restaurant-logo-scan-actions"><button type="button" onclick="return chooseRecipeRestaurantScannedLogo(this, false)">Keep Current Logo</button><button type="button" onclick="return chooseRecipeRestaurantScannedLogo(this, true)">Apply New Logo</button></span>`
            : "";
        const conflictPicker = row.conflict
            ? `<select data-restaurant-scan-candidate aria-label="Choose ${escapeAttribute(definition.label)} candidate" onchange="updateRecipeRestaurantScanCandidate(this)">${row.candidates.map(candidate => `<option value="${escapeAttribute(candidate.candidate_id)}" ${candidate.candidate_id === recommended?.candidate_id ? "selected" : ""}>${escapeHtml(recipeRestaurantFetchDisplayValue(key, candidate.value))}</option>`).join("")}</select>`
            : recipeRestaurantFetchCandidateHtml(key, recommended);
        const sourceUrl = String(recommended?.source_url || "");
        const noChange = reviewStatus === "Already saved";
        const acceptControl = canApply
            ? `<label class="recipe-edit-restaurant-fetch-accept"><input type="checkbox" ${defaultAccept ? "checked" : ""} aria-label="Accept ${escapeAttribute(definition.label)}" onchange="updateRecipeRestaurantScanApplyActions()"></label>`
            : '<span class="recipe-edit-restaurant-fetch-accept" aria-hidden="true"></span>';
        return `<article class="recipe-edit-restaurant-fetch-row${row.conflict ? " has-conflict" : ""}${row.locked ? " is-locked" : ""}${noChange ? " is-no-change" : ""}" data-restaurant-fetch-field="${escapeAttribute(key)}" data-recommended-candidate="${escapeAttribute(recommended?.candidate_id || "")}" data-scan-status="${escapeAttribute(reviewStatus)}" data-high-confidence-eligible="${highConfidenceEligible ? "true" : "false"}">
                    ${acceptControl}
                    <strong>${escapeHtml(definition.label)}</strong>
                    <span class="recipe-edit-restaurant-fetch-current">${escapeHtml(recipeRestaurantFetchDisplayValue(key, row.current_value))}</span>
                    <span class="recipe-edit-restaurant-fetch-proposed">${imagePreview}${conflictPicker}${logoActions}</span>
                    <span class="recipe-edit-restaurant-scan-confidence is-${String(row.confidence_label || "low").toLowerCase()}"><b data-restaurant-scan-status>${escapeHtml(reviewStatus)}</b><small>${Math.round(Number(recommended?.confidence || 0) * 100)}%</small></span>
                    <span class="recipe-edit-restaurant-fetch-evidence">
                        ${sourceUrl ? `<a href="${escapeAttribute(sourceUrl)}" target="_blank" rel="noopener noreferrer" title="${escapeAttribute(sourceUrl)}">View source</a>` : "Source unavailable"}
                        <small data-restaurant-scan-method title="${escapeAttribute(recommended?.evidence || "")}">${escapeHtml(recommended?.provider ? `${recommended.provider} · ${String(recommended?.extraction_method || "").replaceAll("_", " ")}` : String(recommended?.extraction_method || "").replaceAll("_", " "))}</small>
                        <label class="recipe-edit-restaurant-scan-lock"><input type="checkbox" data-restaurant-scan-lock ${row.locked ? "checked" : ""}> Lock existing</label>
                        ${row.requires_explicit_review && !noChange ? "<em>Explicit review required</em>" : ""}
                    </span>
                </article>`;
    }).join("") : (orderingRows.length || unresolvedOrdering.length ? "" : '<p class="recipe-edit-restaurant-scan-empty">No matching restaurant fields were discovered. Review the source statuses above and try Rescan after correcting the source URLs.</p>');
    list.innerHTML = orderingHtml + fieldHtml;
    const unresolvedFields = Array.isArray(data?.unresolved_fields) ? data.unresolved_fields : [];
    if (unresolved && unresolvedList) {
        unresolved.hidden = !unresolvedFields.length;
        unresolvedList.innerHTML = unresolvedFields.map(item => {
            const field = typeof item === "string" ? item : String(item?.field || "");
            const reason = typeof item === "object"
                ? String(item?.reason || "No reliable source value found.")
                : "No reliable source value found.";
            return `<span><strong>${escapeHtml(recipeRestaurantFetchFieldDefinitions[field]?.label || field.replaceAll("_", " "))}</strong><small>${escapeHtml(reason)}</small></span>`;
        }).join("");
    }
    if (summary) summary.textContent = data?.message || "Review evidence-backed restaurant information.";
    panel.hidden = false;
    updateRecipeRestaurantScanApplyActions();
    panel.querySelector('input:not([disabled]), button')?.focus();
}

function updateRecipeRestaurantScanCandidate(select) {
    const rowElement = select?.closest("[data-restaurant-fetch-field]");
    const field = rowElement?.dataset.restaurantFetchField;
    const row = recipeRestaurantInformationScan?.fields?.[field];
    const candidate = recipeRestaurantScanCandidate(row, select?.value);
    if (!rowElement || !candidate) return;
    const link = rowElement.querySelector(".recipe-edit-restaurant-fetch-evidence a");
    const method = rowElement.querySelector("[data-restaurant-scan-method]");
    if (link) {
        link.href = candidate.source_url || "#";
        link.title = candidate.source_url || "";
    }
    if (method) {
        method.textContent = String(candidate.extraction_method || "").replaceAll("_", " ");
        method.title = candidate.evidence || "";
    }
}

function chooseRecipeRestaurantScannedLogo(button, applyNew) {
    const row = button?.closest("[data-restaurant-fetch-field]");
    const accept = row?.querySelector(".recipe-edit-restaurant-fetch-accept input");
    if (accept && !accept.disabled) accept.checked = Boolean(applyNew);
    updateRecipeRestaurantScanApplyActions();
    return false;
}

function closeRecipeRestaurantFetchReview(options = {}) {
    const panel = recipeRestaurantFetchReviewPanel();
    if (panel) panel.hidden = true;
    recipeRestaurantFetchedProposals = {};
    recipeRestaurantInformationScan = null;
    if (options.restoreFocus !== false) recipeRestaurantEditForm()?.querySelector("[data-restaurant-fetch-button]")?.focus();
    return false;
}

function setRecipeRestaurantFetchError(message) {
    const error = recipeRestaurantEditForm()?.querySelector("[data-restaurant-edit-error]");
    if (error) {
        error.textContent = message || "Restaurant details could not be fetched.";
        error.hidden = false;
        error.scrollIntoView({ block: "nearest" });
    }
}

function updateRecipeRestaurantScanActionLabel(record = recipeRestaurantEditSelection) {
    const label = recipeRestaurantEditForm()?.querySelector("[data-restaurant-fetch-label]");
    if (label) label.textContent = record?.restaurant_information_last_scanned_at
        ? "Refresh Restaurant Information"
        : "Scan Restaurant Information";
}

async function fetchRecipeRestaurantDetails(button, force = false) {
    const form = button?.closest("[data-restaurant-edit-form]") || recipeRestaurantEditForm();
    const restaurantId = recipeRestaurantRecordId(recipeRestaurantEditSelection);
    if (!form || button?.disabled) return false;
    if (!restaurantId || recipeRestaurantEditCreateMode) {
        setRecipeRestaurantFetchError("Select an existing normalized restaurant before fetching details.");
        return false;
    }
    const label = button.querySelector("[data-restaurant-fetch-label]");
    const error = form.querySelector("[data-restaurant-edit-error]");
    closeRecipeRestaurantFetchReview({ restoreFocus: false });
    button.disabled = true;
    button.setAttribute("aria-busy", "true");
    const originalLabel = label?.textContent || button.textContent.trim();
    if (label) label.textContent = "Scanning restaurant information…";
    else button.textContent = "Scanning…";
    if (error) error.hidden = true;
    try {
        const response = await fetch(`/api/recipe/restaurants/${encodeURIComponent(restaurantId)}/fetch-details`, {
            method: "POST",
            headers: { "Accept": "application/json", "Content-Type": "application/json" },
            body: JSON.stringify({
                force,
                restaurant_name: form.querySelector('[data-restaurant-edit-field="restaurant_name"]')?.value || "",
                restaurant_phone: form.querySelector('[data-restaurant-edit-field="restaurant_phone"]')?.value || "",
                restaurant_website_url: form.querySelector('[data-restaurant-edit-field="restaurant_website_url"]')?.value || "",
                source_menu_url: form.querySelector('[data-restaurant-edit-field="source_menu_url"]')?.value || "",
                menu_item_url: form.querySelector('[data-restaurant-edit-field="menu_item_url"]')?.value || "",
                restaurant_street_address: form.querySelector('[data-restaurant-edit-field="restaurant_street_address"]')?.value || "",
                restaurant_city: form.querySelector('[data-restaurant-edit-field="restaurant_city"]')?.value || "",
                restaurant_state: form.querySelector('[data-restaurant-edit-field="restaurant_state"]')?.value || "",
                restaurant_postal_code: form.querySelector('[data-restaurant-edit-field="restaurant_postal_code"]')?.value || "",
                restaurant_country: form.querySelector('[data-restaurant-edit-field="restaurant_country"]')?.value || "",
            }),
        });
        const data = await response.json().catch(() => ({}));
        if (!response.ok || !data.ok) throw new Error(data.error || "Restaurant information could not be scanned.");
        renderRecipeRestaurantFetchReview(data);
    } catch (err) {
        setRecipeRestaurantFetchError(err.message || "Restaurant information could not be scanned.");
    } finally {
        button.disabled = false;
        button.removeAttribute("aria-busy");
        if (label) label.textContent = originalLabel;
        else button.textContent = originalLabel;
    }
    return false;
}

function applyRecipeRestaurantScanValuesToForm(form, appliedValues = {}) {
    const updatedFields = [];
    const hourFields = ["weekly_hours", "raw_hours_text", "hours_notes"];
    if (hourFields.some(field => Object.prototype.hasOwnProperty.call(appliedValues, field))) {
        const weeklyHours = Object.prototype.hasOwnProperty.call(appliedValues, "weekly_hours")
            ? normalizeRecipeRestaurantWeeklyHours(appliedValues.weekly_hours)
            : recipeRestaurantWeeklyHoursFromForm(form);
        const hoursNotes = Object.prototype.hasOwnProperty.call(appliedValues, "hours_notes")
            ? String(appliedValues.hours_notes || "")
            : form.querySelector("[data-hours-notes]")?.value || "";
        const rawHours = Object.prototype.hasOwnProperty.call(appliedValues, "raw_hours_text")
            ? String(appliedValues.raw_hours_text || "")
            : form.querySelector('[data-restaurant-edit-field="restaurant_raw_hours_data"]')?.value || "";
        hydrateRecipeRestaurantStructuredHours(form, {
            restaurant_weekly_hours: weeklyHours,
            restaurant_hours_notes: hoursNotes,
            restaurant_raw_hours_data: rawHours,
        });
        hourFields.forEach(field => {
            if (Object.prototype.hasOwnProperty.call(appliedValues, field)) updatedFields.push(field);
        });
    }

    Object.entries(appliedValues).forEach(([key, proposedValue]) => {
        if (hourFields.includes(key)) return;
        const field = recipeRestaurantFetchFieldDefinitions[key]?.field;
        if (!field) return;
        const input = form.querySelector(`[data-restaurant-edit-field="${field}"]`);
        if (!input) return;
        if (key === "social_urls") {
            hydrateRecipeRestaurantSocialLinks(form, proposedValue);
            const orderingFromSocial = normalizeRecipeRestaurantOrderingLinks(
                recipeRestaurantStructuredArray(proposedValue).filter(item => (
                    recipeRestaurantOrderingProviderForUrl(item?.url || item?.href || item)
                ))
            );
            if (orderingFromSocial.length) {
                const current = recipeRestaurantStructuredArray(
                    form.querySelector('[data-restaurant-edit-field="restaurant_ordering_links"]')?.value
                );
                hydrateRecipeRestaurantOrderingLinks(form, [...current, ...orderingFromSocial]);
            }
            updatedFields.push(key);
            return;
        }
        if (["ordering_provider_urls", "ordering_providers"].includes(key)) {
            const current = recipeRestaurantStructuredArray(
                form.querySelector('[data-restaurant-edit-field="restaurant_ordering_links"]')?.value
            );
            const proposed = recipeRestaurantStructuredArray(proposedValue).map((item, index) => {
                if (key !== "ordering_provider_urls" || (item && typeof item === "object")) return item;
                return {
                    provider: recipeRestaurantOrderingProviderForUrl(item) || (index === 0 ? "official_online_ordering" : "other"),
                    url: item,
                    is_active: true,
                };
            });
            const replaceProviders = new Set(proposed.filter(item => item?.replace_existing)
                .map(item => String(item.provider || "").trim()).filter(Boolean));
            const retained = current.filter(item => !replaceProviders.has(String(item?.provider || "").trim()));
            const cleaned = proposed.map(item => {
                if (!item || typeof item !== "object") return item;
                const { replace_existing: ignored, ...value } = item;
                return value;
            });
            hydrateRecipeRestaurantOrderingLinks(form, [...retained, ...cleaned]);
            updatedFields.push(key);
            return;
        }
        let value = proposedValue;
        if (["online_payment", "online_ordering", "pickup", "delivery", "reservations"].includes(key)) {
            value = proposedValue === true || String(proposedValue) === "true"
                ? "true"
                : proposedValue === false || String(proposedValue) === "false" ? "false" : "";
        } else if (key === "promotions" && Array.isArray(value)) {
            value = value.map(item => recipeMenuMetadataText(item)).filter(Boolean).join("\n");
        } else if (value && typeof value === "object") {
            value = JSON.stringify(value);
        }
        input.value = value == null ? "" : String(value);
        if (key === "image_url") {
            const action = form.querySelector('[data-restaurant-edit-field="restaurant_logo_action"]');
            const dataInput = form.querySelector('[data-restaurant-edit-field="restaurant_logo_data_url"]');
            if (action) action.value = "url";
            if (dataInput) dataInput.value = "";
        }
        updatedFields.push(key);
    });
    if (["latitude", "longitude"].some(key => Object.prototype.hasOwnProperty.call(appliedValues, key))) {
        const details = form.querySelector("[data-restaurant-advanced-location]");
        if (details) details.open = true;
    }
    if (Object.prototype.hasOwnProperty.call(appliedValues, "image_url")) {
        const details = form.querySelector("[data-restaurant-advanced-media]");
        if (details) details.open = true;
    }
    if (["reservations", "allergy_information_note"].some(
        key => Object.prototype.hasOwnProperty.call(appliedValues, key)
    )) {
        const details = form.querySelector("[data-restaurant-additional-raw-data]");
        if (details) details.open = true;
    }
    updateRecipeRestaurantEditLogo(form);
    updateRecipeRestaurantEditState(form);
    console.debug("restaurant-scan-apply", {
        event: "form_fields_updated_after_apply",
        field_count: updatedFields.length,
        fields: updatedFields,
        weekly_hours: Object.prototype.hasOwnProperty.call(appliedValues, "weekly_hours")
            ? recipeRestaurantWeeklyHoursFromForm(form)
            : undefined,
    });
    return updatedFields;
}

function markRecipeRestaurantScanRowsApplied(panel, appliedFields = []) {
    appliedFields.forEach(field => {
        const row = panel?.querySelector(`[data-restaurant-fetch-field="${field}"]`);
        if (!row) return;
        row.dataset.scanStatus = "Applied";
        row.dataset.highConfidenceEligible = "false";
        row.classList.add("is-applied");
        const status = row.querySelector("[data-restaurant-scan-status]");
        if (status) status.textContent = "Applied";
        const accept = row.querySelector(".recipe-edit-restaurant-fetch-accept input");
        if (accept) {
            accept.checked = false;
            accept.disabled = true;
        }
    });
}

async function applyRecipeRestaurantInformationScan(button, mode = "selected") {
    const form = recipeRestaurantEditForm();
    const panel = recipeRestaurantFetchReviewPanel();
    const restaurantId = recipeRestaurantRecordId(recipeRestaurantEditSelection);
    if (!form || !panel || !restaurantId || !recipeRestaurantInformationScan?.scan_id || button?.disabled) return false;
    const selections = {};
    const lockUpdates = {};
    const orderingLinkResolutions = {};
    panel.querySelectorAll("[data-restaurant-fetch-field]").forEach(row => {
        const field = row.dataset.restaurantFetchField;
        const accept = row.querySelector(".recipe-edit-restaurant-fetch-accept input");
        const candidate = row.querySelector("[data-restaurant-scan-candidate]")?.value || row.dataset.recommendedCandidate;
        const status = row.dataset.scanStatus;
        const eligible = !["Already saved", "Unresolved", "Invalid", "Applied"].includes(status);
        if (eligible && accept?.checked && !accept.disabled && candidate) selections[field] = candidate;
        const lock = row.querySelector("[data-restaurant-scan-lock]");
        if (lock) {
            const lockField = row.dataset.restaurantLockField || field;
            lockUpdates[lockField] = Object.prototype.hasOwnProperty.call(lockUpdates, lockField)
                ? lockUpdates[lockField] || lock.checked
                : lock.checked;
        }
        const orderingResolution = row.querySelector("[data-ordering-link-resolution]");
        if (orderingResolution) orderingLinkResolutions[field] = orderingResolution.value;
    });
    const message = panel.querySelector("[data-restaurant-scan-apply-message]");
    if (mode === "selected" && !Object.keys(selections).length) {
        if (message) message.textContent = "Select at least one valid change.";
        updateRecipeRestaurantScanApplyActions();
        return false;
    }
    if (mode === "high_confidence" && button.disabled) {
        if (message) message.textContent = "No high-confidence changes available";
        return false;
    }
    const selectedFieldKeys = mode === "high_confidence"
        ? Array.from(panel.querySelectorAll('[data-high-confidence-eligible="true"]'))
            .filter(row => row.dataset.scanStatus !== "Applied")
            .map(row => row.dataset.restaurantFetchField)
        : Object.keys(selections);
    console.debug("restaurant-scan-apply", {
        event: mode === "high_confidence" ? "apply_all_high_confidence_selected" : "apply_selected_rows",
        field_count: selectedFieldKeys.length,
        fields: selectedFieldKeys,
    });
    button.disabled = true;
    const originalText = button.textContent;
    button.textContent = "Applying…";
    try {
        const response = await fetch(`/api/recipe/restaurants/${encodeURIComponent(restaurantId)}/apply-information-scan`, {
            method: "POST",
            headers: { "Accept": "application/json", "Content-Type": "application/json" },
            body: JSON.stringify({
                scan_id: recipeRestaurantInformationScan.scan_id,
                mode,
                selections,
                lock_updates: lockUpdates,
                ordering_link_resolutions: orderingLinkResolutions,
            }),
        });
        const data = await response.json().catch(() => ({}));
        if (!response.ok || !data.ok) throw new Error(data.error || "Restaurant information could not be applied.");
        const appliedValues = data.applied_values && typeof data.applied_values === "object"
            ? data.applied_values
            : {};
        const appliedFields = Array.isArray(data.applied_fields) ? data.applied_fields : Object.keys(appliedValues);
        applyRecipeRestaurantScanValuesToForm(form, appliedValues);
        markRecipeRestaurantScanRowsApplied(panel, appliedFields);
        if (message) message.textContent = appliedFields.length
            ? `${appliedFields.length} change${appliedFields.length === 1 ? "" : "s"} applied to the pending form.`
            : "No eligible changes were applied.";
        updateRecipeRestaurantScanApplyActions();
    } catch (err) {
        setRecipeRestaurantFetchError(err.message || "Restaurant information could not be applied.");
    } finally {
        button.disabled = false;
        button.textContent = originalText;
        updateRecipeRestaurantScanApplyActions();
    }
    return false;
}

function recipeRestaurantEditHasChanges(form = recipeRestaurantEditForm()) {
    return Boolean(recipeRestaurantEditSnapshot)
        && JSON.stringify(recipeRestaurantEditComparableState(form)) !== recipeRestaurantEditSnapshot;
}

function recipeRestaurantEditValues(form = recipeRestaurantEditForm()) {
    const values = {};
    form?.querySelectorAll("[data-restaurant-edit-field]").forEach(input => {
        values[input.dataset.restaurantEditField] = String(input.value || "").trim();
    });
    const weeklyHours = recipeRestaurantWeeklyHoursFromForm(form);
    const hoursNotes = form?.querySelector("[data-hours-notes]")?.value.trim() || "";
    values.restaurant_weekly_hours = weeklyHours;
    values.restaurant_hours_notes = hoursNotes;
    values.restaurant_hours_text = recipeRestaurantWeeklyHoursText(weeklyHours, hoursNotes);
    values.restaurant_promotions = [
        values.restaurant_rewards_program,
        values.restaurant_active_promotions,
    ].filter(Boolean).join("\n");
    return values;
}

function updateRecipeRestaurantEditLogo(form = recipeRestaurantEditForm()) {
    if (!form) return;
    const values = recipeRestaurantEditValues(form);
    const preview = form.querySelector("[data-restaurant-edit-logo]");
    const image = preview?.querySelector("img");
    const fallback = preview?.querySelector("[data-restaurant-edit-logo-fallback]");
    const initials = (values.restaurant_name || "Restaurant").split(/\s+/).slice(0, 2).map(part => part[0] || "").join("").toUpperCase();
    const previewUrl = values.restaurant_logo_data_url || values.restaurant_logo_url;
    if (fallback) {
        fallback.textContent = initials || "R";
        fallback.hidden = Boolean(previewUrl);
    }
    if (image) {
        image.src = previewUrl || "";
        image.alt = previewUrl ? `${values.restaurant_name || "Restaurant"} logo preview` : "";
        image.hidden = !previewUrl;
        image.onerror = () => {
            image.hidden = true;
            if (fallback) fallback.hidden = false;
            const error = form.querySelector("[data-restaurant-logo-error]");
            if (error && values.restaurant_logo_url && !values.restaurant_logo_data_url) {
                error.textContent = "The logo image could not be loaded from that URL.";
                error.hidden = false;
            }
        };
    }
}

function sharedRatingControl(source) {
    if (source?.matches?.("[data-shared-rating-control]")) return source;
    return source?.closest?.("[data-shared-rating-control]") || null;
}

function sharedRatingInput(control) {
    return sharedRatingControl(control)?.parentElement?.querySelector("[data-rating-input]") || null;
}

function updateSharedRatingControl(source, rating, options = {}) {
    const control = sharedRatingControl(source);
    if (!control) return;
    const normalizedRating = normalizeRecipeRatingValue(rating);
    const hasPreview = options.previewRating != null;
    const displayRating = hasPreview ? normalizeRecipeRatingValue(options.previewRating) : normalizedRating;
    control.querySelectorAll(".recipe-edit-rating-star").forEach(button => {
        const value = normalizeRecipeRatingValue(button.dataset.ratingValue);
        const active = value > 0 && value <= displayRating;
        button.classList.toggle("active", active);
        button.classList.toggle("is-preview", hasPreview && active);
        button.setAttribute("aria-checked", value === normalizedRating ? "true" : "false");
        button.textContent = active ? "\u2605" : "\u2606";
    });
    const clear = control.querySelector(".recipe-edit-rating-clear");
    if (clear) clear.hidden = normalizedRating <= 0;
}

function setSharedRatingValue(source, value, options = {}) {
    const control = sharedRatingControl(source);
    const input = sharedRatingInput(control);
    if (!control || !input) return false;
    const requestedRating = normalizeRecipeRatingValue(value);
    const currentRating = normalizeRecipeRatingValue(input.value);
    const allowToggle = options.allowToggle === true;
    const nextRating = allowToggle && requestedRating > 0 && currentRating === requestedRating
        ? 0
        : requestedRating;
    input.value = control.dataset.ratingMode === "restaurant" && nextRating === 0 ? "" : String(nextRating);
    updateSharedRatingControl(control, nextRating);
    if (control.dataset.ratingMode === "restaurant") {
        updateRecipeRestaurantEditState(control.closest("[data-restaurant-edit-form]"));
    } else if (control.dataset.ratingMode === "recipe") {
        updateRecipeEditorDirtyState(control.closest("#recipeEditForm"));
    }
    return false;
}

function setSharedRatingFromButton(button, rating, options = {}) {
    const control = sharedRatingControl(button);
    const allowToggle = options.allowToggle === false
        ? false
        : control?.dataset.ratingToggleSelected === "true";
    return setSharedRatingValue(control, rating, { allowToggle });
}

function clearSharedRating(button) {
    return setSharedRatingValue(button, 0, { allowToggle: false });
}

function previewSharedRating(button, rating) {
    const control = sharedRatingControl(button);
    const input = sharedRatingInput(control);
    updateSharedRatingControl(control, input?.value || 0, { previewRating: rating });
}

function clearSharedRatingPreview(button) {
    const control = sharedRatingControl(button);
    updateSharedRatingControl(control, sharedRatingInput(control)?.value || 0);
}

function handleSharedRatingKeydown(button, event) {
    if (!event || !["ArrowLeft", "ArrowRight", "ArrowUp", "ArrowDown", "Home", "End"].includes(event.key)) return true;
    event.preventDefault();
    const current = normalizeRecipeRatingValue(button.dataset.ratingValue) || 1;
    const next = event.key === "Home" ? 1 : event.key === "End" ? 5
        : Math.max(1, Math.min(5, current + (["ArrowRight", "ArrowUp"].includes(event.key) ? 1 : -1)));
    const control = sharedRatingControl(button);
    const target = control?.querySelector(`[data-rating-value="${next}"]`);
    setSharedRatingFromButton(target, next, { allowToggle: false });
    target?.focus();
    return false;
}

function updateRecipeRestaurantRatingEditor(form = recipeRestaurantEditForm()) {
    const control = form?.querySelector('[data-shared-rating-control][data-rating-mode="restaurant"]');
    updateSharedRatingControl(control, sharedRatingInput(control)?.value || 0);
}

function updateRecipeRestaurantEditState(form = recipeRestaurantEditForm()) {
    if (!form) return;
    const save = form.querySelector("[data-restaurant-edit-save]");
    const changed = recipeRestaurantEditHasChanges(form);
    const canNormalizeFallback = recipeRestaurantEditCreateMode
        && !recipeRestaurantOriginalRestaurantId
        && Boolean(form.querySelector('[data-restaurant-edit-field="restaurant_name"]')?.value.trim());
    if (save && !form.dataset.saving) save.disabled = !changed && !canNormalizeFallback;
    updateRecipeRestaurantEditLogo(form);
    updateRecipeRestaurantRatingEditor(form);
}

function editRecipeRestaurantSource(button, event = null) {
    if (event) {
        event.preventDefault();
        event.stopPropagation();
    }
    const modal = recipeRestaurantEditModal();
    const form = recipeRestaurantEditForm();
    const linkedSource = currentRecipeRestaurantSourceOption();
    const selected = linkedSource || recipeRestaurantFallbackFromEditor();
    const hasNormalizedRestaurant = Boolean(recipeRestaurantRecordId(selected));
    if (!modal || !form) return false;
    recipeRestaurantOriginalMenuItemUrl = recipeEditInputValue("recipeEditMenuItemUrl")
        || recipeRestaurantRecordValue(selected, "menu_item_url")
        || recipeEditorSourceUrlForOpen();
    recipeRestaurantOriginalMenuId = String(selected.menu_id || recipeEditInputValue("recipeEditMenuId") || "").trim();
    recipeRestaurantOriginalRestaurantId = recipeRestaurantRecordId(selected)
        || recipeEditInputValue("recipeEditRestaurantId");
    recipeRestaurantEditSelection = hasNormalizedRestaurant ? selected : null;
    recipeRestaurantEditCreateMode = !hasNormalizedRestaurant;
    populateRecipeRestaurantEditForm(selected, { menuItemUrl: recipeRestaurantOriginalMenuItemUrl });
    const { input: selectorInput, status: selectorStatus } = recipeRestaurantSelectorElements();
    if (selectorInput) {
        selectorInput.value = hasNormalizedRestaurant ? recipeRestaurantRecordName(selected) : "";
        selectorInput.placeholder = hasNormalizedRestaurant ? "Search restaurants" : "Creating new restaurant";
    }
    updateRecipeRestaurantSelectorClearButton();
    if (selectorStatus) selectorStatus.textContent = hasNormalizedRestaurant ? "" : "Creating new restaurant";
    const save = form.querySelector("[data-restaurant-edit-save]");
    if (save) save.textContent = hasNormalizedRestaurant ? "Save Changes" : "Create Restaurant";
    updateRecipeRestaurantScanActionLabel(selected);
    recipeRestaurantDirectory = [];
    loadRecipeRestaurantDirectory();
    closeRecipeRestaurantUsagePanel();
    closeRecipeRestaurantFetchReview({ restoreFocus: false });
    closeRecipeRestaurantDuplicateReview({ restoreFocus: false });
    if (hasNormalizedRestaurant) loadRecipeRestaurantUsage(recipeRestaurantRecordId(selected));
    else setRecipeRestaurantUsageEmpty();
    recipeRestaurantEditSnapshot = JSON.stringify(recipeRestaurantEditComparableState(form));
    recipeRestaurantEditTrigger = button;
    closeRecipeRestaurantModalBackgroundPopovers();
    if (modal.parentElement !== document.body) {
        document.body.appendChild(modal);
    }
    recipeRestaurantModalScrollState = captureRecipeRestaurantModalScrollState();
    recipeRestaurantModalInertElements = Array.from(document.body.children)
        .filter(element => element !== modal)
        .map(element => ({ element, wasInert: Boolean(element.inert) }));
    recipeRestaurantModalInertElements.forEach(item => { item.element.inert = true; });
    modal.hidden = false;
    document.body.classList.add("restaurant-source-modal-open");
    const error = form.querySelector("[data-restaurant-edit-error]");
    if (error) error.hidden = true;
    closeRecipeRestaurantDuplicatePanel(form.querySelector("[data-restaurant-duplicate-panel]"));
    updateRecipeRestaurantEditState(form);
    form.querySelector('[data-restaurant-edit-field="restaurant_name"]')?.focus();
    return false;
}

function cancelRecipeRestaurantSourceEdit(button) {
    return closeRecipeRestaurantSourceModal({ force: false });
}

function closeRecipeRestaurantSourceModal(options = {}) {
    const modal = recipeRestaurantEditModal();
    const form = recipeRestaurantEditForm();
    if (!modal || !form || form.dataset.saving) return false;
    if (!options.force && recipeRestaurantEditHasChanges(form)
        && !window.confirm("Discard unsaved restaurant changes?")) {
        return false;
    }
    document.querySelector("[data-restaurant-usage-panel]")?.setAttribute("hidden", "");
    const fetchReview = recipeRestaurantFetchReviewPanel();
    if (fetchReview) fetchReview.hidden = true;
    closeRecipeRestaurantDuplicateReview({ restoreFocus: false });
    recipeRestaurantFetchedProposals = {};
    recipeRestaurantInformationScan = null;
    closeRecipeRestaurantSelector({ restoreValue: false });
    closeRecipeRestaurantDuplicatePanel(form.querySelector("[data-restaurant-duplicate-panel]"));
    modal.hidden = true;
    document.body.classList.remove("restaurant-source-modal-open");
    recipeRestaurantModalInertElements.forEach(item => { item.element.inert = item.wasInert; });
    recipeRestaurantModalInertElements = [];
    restoreRecipeRestaurantModalScrollState();
    recipeRestaurantEditSnapshot = "";
    recipeRestaurantEditSelection = null;
    recipeRestaurantEditCreateMode = false;
    recipeRestaurantOriginalMenuItemUrl = "";
    recipeRestaurantOriginalMenuId = "";
    recipeRestaurantOriginalRestaurantId = "";
    const trigger = recipeRestaurantEditTrigger;
    recipeRestaurantEditTrigger = null;
    trigger?.focus({ preventScroll: true });
    return false;
}

function recipeRestaurantModalFocusableElements() {
    const modal = recipeRestaurantEditModal();
    const duplicateReview = recipeRestaurantDuplicateReviewPanel();
    const review = recipeRestaurantFetchReviewPanel();
    const scope = duplicateReview && !duplicateReview.hidden
        ? duplicateReview
        : (review && !review.hidden ? review : modal);
    return scope ? Array.from(scope.querySelectorAll(
        'button:not([disabled]), input:not([disabled]), select:not([disabled]), textarea:not([disabled]), a[href]'
    )).filter(element => !element.hidden && element.offsetParent !== null) : [];
}

document.addEventListener("keydown", event => {
    const modal = recipeRestaurantEditModal();
    if (!modal || modal.hidden) return;
    if (event.key === "Escape") {
        event.preventDefault();
        const selectorList = recipeRestaurantSelectorElements().list;
        if (selectorList && !selectorList.hidden) {
            closeRecipeRestaurantSelector({ restoreValue: true });
            recipeRestaurantSelectorElements().input?.focus();
            return;
        }
        const duplicateReview = recipeRestaurantDuplicateReviewPanel();
        if (duplicateReview && !duplicateReview.hidden) {
            closeRecipeRestaurantDuplicateReview();
            return;
        }
        const fetchReview = recipeRestaurantFetchReviewPanel();
        if (fetchReview && !fetchReview.hidden) {
            closeRecipeRestaurantFetchReview();
            return;
        }
        const usagePanel = document.querySelector("[data-restaurant-usage-panel]");
        if (usagePanel && !usagePanel.hidden) {
            closeRecipeRestaurantUsagePanel();
            return;
        }
        closeRecipeRestaurantSourceModal({ force: false });
        return;
    }
    if (event.key !== "Tab") return;
    const focusable = recipeRestaurantModalFocusableElements();
    if (!focusable.length) return;
    const first = focusable[0];
    const last = focusable[focusable.length - 1];
    const activeElement = document.activeElement;
    if (!modal.contains(activeElement)) {
        event.preventDefault();
        (event.shiftKey ? last : first).focus();
    } else if (event.shiftKey && activeElement === first) {
        event.preventDefault();
        last.focus();
    } else if (!event.shiftKey && activeElement === last) {
        event.preventDefault();
        first.focus();
    }
});

document.addEventListener("pointerdown", event => {
    const { root, list } = recipeRestaurantSelectorElements();
    if (!root || !list || list.hidden || root.contains(event.target)) return;
    closeRecipeRestaurantSelector({ restoreValue: true });
});

function toggleRecipeRestaurantLogoChooser(button) {
    const chooser = button?.closest("[data-restaurant-edit-form]")?.querySelector("[data-restaurant-logo-chooser]");
    if (chooser) chooser.hidden = !chooser.hidden;
    chooser?.querySelector("button")?.focus();
    return false;
}

function closeRecipeRestaurantLogoChooser(button) {
    const chooser = button?.matches?.("[data-restaurant-logo-chooser]")
        ? button
        : button?.closest("[data-restaurant-logo-chooser]");
    if (chooser) chooser.hidden = true;
    return false;
}

function chooseRecipeRestaurantLogoUpload(button) {
    const chooser = button?.closest("[data-restaurant-logo-chooser]");
    const fileInput = chooser?.querySelector("[data-restaurant-logo-file]");
    if (!fileInput) return false;
    if (fileInput.dataset.restaurantLogoBound !== "1") {
        fileInput.dataset.restaurantLogoBound = "1";
        fileInput.addEventListener("change", () => {
            const file = fileInput.files?.[0];
            const form = fileInput.closest("[data-restaurant-edit-form]");
            const error = form?.querySelector("[data-restaurant-logo-error]");
            if (!file) return;
            if (!["image/png", "image/jpeg", "image/webp"].includes(file.type) || file.size > 5 * 1024 * 1024) {
                if (error) {
                    error.textContent = "Choose a PNG, JPG, JPEG, or WebP image no larger than 5 MB.";
                    error.hidden = false;
                }
                fileInput.value = "";
                return;
            }
            const reader = new FileReader();
            reader.onload = () => {
                const dataInput = form.querySelector('[data-restaurant-edit-field="restaurant_logo_data_url"]');
                if (dataInput) dataInput.value = String(reader.result || "");
                const action = form.querySelector('[data-restaurant-edit-field="restaurant_logo_action"]');
                if (action) action.value = "upload";
                if (error) error.hidden = true;
                updateRecipeRestaurantEditState(form);
                closeRecipeRestaurantLogoChooser(fileInput);
            };
            reader.onerror = () => {
                if (error) { error.textContent = "The selected logo image could not be read."; error.hidden = false; }
            };
            reader.readAsDataURL(file);
        });
    }
    fileInput.click();
    return false;
}

function chooseRecipeRestaurantLogoUrl(button) {
    const form = button?.closest("[data-restaurant-edit-form]");
    const chooser = button?.closest("[data-restaurant-logo-chooser]");
    const details = form?.querySelector("[data-restaurant-advanced-media]");
    const panel = form?.querySelector("[data-restaurant-logo-url-panel]");
    if (details) details.open = true;
    if (chooser) chooser.hidden = true;
    panel?.querySelector("input")?.focus();
    return false;
}

function removeRecipeRestaurantLogo(button) {
    const form = button?.closest("[data-restaurant-edit-form]");
    if (!form || !window.confirm("Remove this restaurant logo?")) return false;
    form.querySelectorAll('[data-restaurant-edit-field="restaurant_logo_url"], [data-restaurant-edit-field="restaurant_logo_data_url"]').forEach(input => { input.value = ""; });
    const action = form.querySelector('[data-restaurant-edit-field="restaurant_logo_action"]');
    if (action) action.value = "remove";
    updateRecipeRestaurantEditState(form);
    return false;
}

function setRecipeRestaurantRating(button, rating, options = {}) {
    return setSharedRatingFromButton(button, rating, { allowToggle: options.allowToggle !== false });
}

function previewRecipeRestaurantRating(button, rating) {
    previewSharedRating(button, rating);
}

function clearRecipeRestaurantRatingPreview(button) {
    clearSharedRatingPreview(button);
}

function handleRecipeRestaurantRatingKeydown(button, event) {
    return handleSharedRatingKeydown(button, event);
}

function recipeRestaurantHoursTimeLabel(value) {
    const [rawHour, minute] = String(value || "").split(":");
    const hour = Number.parseInt(rawHour, 10);
    if (!Number.isFinite(hour) || !minute) return "";
    const suffix = hour >= 12 ? "PM" : "AM";
    return `${hour % 12 || 12}:${minute} ${suffix}`;
}

function hydrateRecipeRestaurantStructuredHours(form = recipeRestaurantEditForm(), record = {}) {
    if (!form) return;
    const persisted = normalizeRecipeRestaurantWeeklyHours(
        record?.restaurant_weekly_hours ?? record?.weekly_hours ?? {}
    );
    const legacyText = recipeRestaurantRecordValue(record, "restaurant_hours_text")
        || recipeRestaurantRecordValue(record, "restaurant_raw_hours_data");
    const weekly = Object.keys(persisted).length ? persisted : recipeRestaurantWeeklyHoursFromText(legacyText);
    const rawHours = recipeRestaurantRecordValue(record, "restaurant_raw_hours_data");
    const noteLine = String(legacyText || "").split(/\r?\n/).find(value => /^Notes:/i.test(value));
    const hoursNotes = recipeRestaurantRecordValue(record, "restaurant_hours_notes")
        || (noteLine ? noteLine.replace(/^Notes:\s*/i, "") : "");
    console.debug("restaurant-hours-hydration", {
        event: "persisted_weekly_hours_loaded",
        day_count: Object.keys(weekly).length,
        has_raw_hours: Boolean(rawHours),
        has_hours_notes: Boolean(hoursNotes),
        weekly_hours: weekly,
    });

    form.querySelectorAll("[data-restaurant-hours-day]").forEach(row => {
        const dayKey = String(row.dataset.restaurantHoursDay || "").toLowerCase();
        const day = weekly[dayKey];
        const state = row.querySelector("[data-hours-state]");
        const split = row.querySelector("[data-hours-split]");
        const splitButton = row.querySelector("[data-hours-add-split]");
        row.querySelectorAll('input[type="time"]').forEach(input => { input.value = ""; });
        if (state) state.value = day?.closed ? "closed" : day?.open_24_hours ? "open_24_hours" : "open";
        const ranges = Array.isArray(day?.ranges) && !day?.open_24_hours ? day.ranges : [];
        if (ranges[0]) {
            row.querySelector("[data-hours-open]").value = ranges[0].opens || "";
            row.querySelector("[data-hours-close]").value = ranges[0].closes === "24:00" ? "" : ranges[0].closes || "";
        }
        if (ranges[1]) {
            row.querySelector("[data-hours-open-two]").value = ranges[1].opens || "";
            row.querySelector("[data-hours-close-two]").value = ranges[1].closes === "24:00" ? "" : ranges[1].closes || "";
        }
        if (split) split.hidden = !ranges[1];
        if (splitButton) splitButton.textContent = ranges[1] ? "Remove split" : "+ Split hours";
        syncRecipeRestaurantHoursRow(row);
    });
    const notes = form.querySelector("[data-hours-notes]");
    if (notes) {
        notes.value = hoursNotes;
        if (notes.dataset.restaurantHoursBound !== "1") {
            notes.dataset.restaurantHoursBound = "1";
            notes.addEventListener("input", () => updateRecipeRestaurantStructuredHours(notes));
        }
    }
    const raw = form.querySelector('[data-restaurant-edit-field="restaurant_raw_hours_data"]');
    if (raw) raw.value = rawHours;
    console.debug("restaurant-hours-hydration", {
        event: "weekly_hours_mapped_to_form",
        day_count: form.querySelectorAll("[data-restaurant-hours-day]").length,
        weekly_hours: recipeRestaurantWeeklyHoursFromForm(form),
    });
}

function initializeRecipeRestaurantStructuredHours(form = recipeRestaurantEditForm()) {
    hydrateRecipeRestaurantStructuredHours(form, {
        restaurant_weekly_hours: recipeRestaurantWeeklyHoursFromForm(form),
        restaurant_hours_notes: form?.querySelector("[data-hours-notes]")?.value || "",
        restaurant_raw_hours_data: form?.querySelector('[data-restaurant-edit-field="restaurant_raw_hours_data"]')?.value || "",
    });
}

function syncRecipeRestaurantHoursRow(row) {
    if (!row) return;
    const status = row.querySelector("[data-hours-state]")?.value || "open";
    const closed = status === "closed";
    const open24 = status === "open_24_hours";
    row.classList.toggle("is-closed", closed);
    row.classList.toggle("is-open-24-hours", open24);
    row.querySelectorAll('input[type="time"]').forEach(input => { input.disabled = closed || open24; });
    const splitButton = row.querySelector("[data-hours-add-split]");
    if (splitButton) splitButton.disabled = closed || open24;
    if ((closed || open24) && row.querySelector("[data-hours-split]")) {
        row.querySelector("[data-hours-split]").hidden = true;
        if (splitButton) splitButton.textContent = "+ Split hours";
    }
}

function updateRecipeRestaurantStructuredHours(control) {
    const form = control?.closest("[data-restaurant-edit-form]");
    if (!form) return false;
    form.querySelectorAll("[data-restaurant-hours-day]").forEach(syncRecipeRestaurantHoursRow);
    updateRecipeRestaurantEditState(form);
    return false;
}

function toggleRecipeRestaurantSplitHours(button) {
    const row = button?.closest("[data-restaurant-hours-day]");
    const split = row?.querySelector("[data-hours-split]");
    if (!split || row?.querySelector("[data-hours-state]")?.value !== "open") return false;
    split.hidden = !split.hidden;
    button.textContent = split.hidden ? "+ Split hours" : "Remove split";
    if (split.hidden) {
        split.querySelectorAll("input").forEach(input => { input.value = ""; });
        updateRecipeRestaurantStructuredHours(button);
    } else {
        split.querySelector("input")?.focus();
    }
    return false;
}

function showRecipeRestaurantDuplicatePanel(duplicates) {
    const form = recipeRestaurantEditForm();
    const panel = form?.querySelector("[data-restaurant-duplicate-panel]");
    if (!panel) return;
    recipeRestaurantDuplicateCandidates = Array.isArray(duplicates) ? duplicates : [];
    const summary = panel.querySelector("[data-restaurant-duplicate-summary]");
    if (summary) {
        const names = recipeRestaurantDuplicateCandidates.slice(0, 3).map(recipeRestaurantRecordName);
        summary.textContent = names.length ? names.join(", ") : "Choose how to continue.";
    }
    const select = panel.querySelector("button");
    if (select) select.disabled = !recipeRestaurantDuplicateCandidates.length;
    panel.hidden = false;
    panel.scrollIntoView({ block: "nearest" });
    (select && !select.disabled ? select : panel.querySelectorAll("button")[1])?.focus();
}

function closeRecipeRestaurantDuplicatePanel(button) {
    const panel = button?.matches?.("[data-restaurant-duplicate-panel]")
        ? button
        : button?.closest?.("[data-restaurant-duplicate-panel]");
    if (panel) panel.hidden = true;
    recipeRestaurantDuplicateCandidates = [];
    return false;
}

function selectExistingDuplicateRestaurant(button) {
    const duplicates = [...recipeRestaurantDuplicateCandidates];
    const duplicate = duplicates[0];
    closeRecipeRestaurantDuplicatePanel(button);
    if (duplicates.length > 1) {
        recipeRestaurantDirectory = duplicates;
        renderRecipeRestaurantSelector(duplicates);
        const { input, status } = recipeRestaurantSelectorElements();
        if (input) input.value = "";
        setRecipeRestaurantSelectorExpanded(true);
        input?.focus();
        if (status) status.textContent = "Select a matching restaurant";
        return false;
    }
    return switchRecipeRestaurantSelection(recipeRestaurantRecordId(duplicate), { skipConfirm: true });
}

function createDuplicateRestaurantAnyway(button) {
    const form = button?.closest("[data-restaurant-edit-form]");
    closeRecipeRestaurantDuplicatePanel(button);
    return saveRecipeRestaurantSource(form, { createAnyway: true });
}

async function saveRecipeRestaurantSource(form, options = {}) {
    if (!form || form.dataset.saving) return false;
    const values = recipeRestaurantEditValues(form);
    const error = form.querySelector("[data-restaurant-edit-error]");
    const save = form.querySelector("[data-restaurant-edit-save]");
    if (!values.restaurant_name) {
        if (error) { error.textContent = "Restaurant Name is required."; error.hidden = false; }
        return false;
    }
    const invalid = form.querySelector("input:invalid");
    if (invalid) {
        if (error) { error.textContent = invalid.validationMessage || "Please correct the highlighted field."; error.hidden = false; }
        invalid.focus();
        return false;
    }
    const selected = recipeRestaurantEditSelection || currentRecipeRestaurantSourceOption() || {};
    const selectedMenuId = recipeRestaurantMenuIdForSave(selected);
    if (!recipeRestaurantEditCreateMode && !recipeRestaurantRecordId(selected)) return false;
    form.dataset.saving = "1";
    if (save) { save.disabled = true; save.textContent = "Saving..."; }
    if (error) error.hidden = true;
    console.debug("restaurant-editor-save", {
        event: "save_payload_produced",
        field_count: Object.keys(values).length,
        fields: Object.keys(values),
        weekly_hours: values.restaurant_weekly_hours,
    });
    try {
        const response = await fetch("/api/recipe/restaurant-source", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                action: recipeRestaurantEditCreateMode ? "create" : "update",
                create_anyway: Boolean(options.createAnyway),
                assign_restaurant: true,
                recipe_url: recipeEditorSourceUrlForOpen(),
                restaurant_id: recipeRestaurantRecordId(selected),
                menu_id: selectedMenuId,
                ...values,
            }),
        });
        const data = await response.json();
        if (response.status === 409 && data.duplicate_detected) {
            showRecipeRestaurantDuplicatePanel(data.duplicates);
            return false;
        }
        if (!response.ok || !data.ok) throw new Error(data.error || "Unable to save restaurant source.");
        const savedRestaurant = { ...selected, ...(data.restaurant || {}) };
        savedRestaurant.menu_item_url = values.menu_item_url || recipeRestaurantOriginalMenuItemUrl;
        savedRestaurant.menu_id = savedRestaurant.menu_id || selectedMenuId;
        recipeRestaurantEditSelection = savedRestaurant;
        recipeRestaurantDisplaySource = savedRestaurant;
        syncRecipeRestaurantMenuSourceSelection(savedRestaurant);
        setValue("recipeEditRestaurantName", recipeRestaurantRecordValue(savedRestaurant, "restaurant_name"));
        setValue("recipeEditRestaurantWebsiteUrl", recipeRestaurantRecordValue(savedRestaurant, "restaurant_website_url"));
        setValue("recipeEditSourceMenuUrl", recipeRestaurantRecordValue(savedRestaurant, "source_menu_url"));
        setValue("recipeEditMenuItemUrl", values.menu_item_url || recipeRestaurantOriginalMenuItemUrl);
        setValue("recipeEditRestaurantPhone", recipeRestaurantRecordValue(savedRestaurant, "restaurant_phone"));
        const savedAddress = savedRestaurant.restaurant_address || [
            recipeRestaurantRecordValue(savedRestaurant, "restaurant_street_address"),
            recipeRestaurantRecordValue(savedRestaurant, "restaurant_city"),
            recipeRestaurantRecordValue(savedRestaurant, "restaurant_state"),
            recipeRestaurantRecordValue(savedRestaurant, "restaurant_postal_code"),
            recipeRestaurantRecordValue(savedRestaurant, "restaurant_country"),
        ].filter(Boolean).join(", ");
        setValue("recipeEditRestaurantAddress", savedAddress);
        setValue("recipeEditRestaurantHoursText", recipeRestaurantRecordValue(savedRestaurant, "restaurant_hours_text"));
        setValue("recipeEditRestaurantCurrentStatus", recipeRestaurantRecordValue(savedRestaurant, "restaurant_current_status"));
        setValue("recipeEditRestaurantPromotions", recipeRestaurantRecordValue(savedRestaurant, "restaurant_promotions"));
        setValue("recipeEditRestaurantOnlinePaymentAvailable", recipeRestaurantRecordValue(savedRestaurant, "restaurant_online_payment_available"));
        setValue("recipeEditRestaurantDeliveryAvailable", recipeRestaurantRecordValue(savedRestaurant, "restaurant_delivery_available"));
        recipeRestaurantDirectory = [];
        bindRecipeMenuMetadataUrlLinks();
        syncRecipeEditDocumentRows();
        delete form.dataset.saving;
        closeRecipeRestaurantSourceModal({ force: true });
        updateRecipeEditRestaurantCard();
    } catch (err) {
        if (error) { error.textContent = err.message || "Unable to save restaurant source."; error.hidden = false; }
    } finally {
        delete form.dataset.saving;
        if (save) {
            save.textContent = recipeRestaurantEditCreateMode ? "Create Restaurant" : "Save Changes";
            updateRecipeRestaurantEditState(form);
        }
    }
    return false;
}

function recipeEditGalleryImageUrl(row) {
    const input = row ? row.querySelector('[data-field="ingredient_image_url"]') : null;
    return input ? String(input.value || "").trim() : "";
}

function updateRecipeEditIngredientGallery() {
    const gallery = document.getElementById("recipeEditIngredientGallery");

    if (!gallery) {
        return;
    }

    const toggle = document.getElementById("recipeEditIngredientGalleryToggle");
    const expanded = Boolean(toggle && toggle.getAttribute("aria-expanded") === "true");
    const allRows = recipeEditIngredientRows().filter(row => {
        const values = fieldValuesFromRow(row);
        return Boolean(String(values.ingredient || values.purchasable_item || "").trim() || recipeEditGalleryImageUrl(row));
    });
    const rows = allRows.slice(0, expanded ? 18 : 6);

    if (!rows.length) {
        gallery.innerHTML = '<span class="recipe-edit-context-empty">No ingredients yet.</span>';
        if (toggle) {
            toggle.hidden = true;
        }
        return;
    }

    if (toggle) {
        toggle.hidden = allRows.length <= 6;
        toggle.textContent = expanded ? "Show Fewer Ingredients" : "Show All Ingredients";
    }

    gallery.innerHTML = rows.map(row => {
        const values = fieldValuesFromRow(row);
        const name = values.ingredient || values.purchasable_item || "Ingredient";
        const imageUrl = recipeEditGalleryImageUrl(row);
        const displayUrl = imageUrl ? recipeImageVariantUrl(imageUrl, "thumb") : "";
        const initials = name.trim().slice(0, 2).toUpperCase() || "--";

        return `
            <span class="recipe-edit-gallery-item" title="${escapeAttribute(name)}">
                ${displayUrl
                    ? `<img src="${escapeAttribute(displayUrl)}" alt="${escapeAttribute(name)}">`
                    : `<span class="recipe-edit-gallery-placeholder" aria-hidden="true">${escapeHtml(initials)}</span>`}
                <span>${escapeHtml(name)}</span>
            </span>
        `;
    }).join("");
}

function toggleRecipeEditIngredientGallery(button) {
    if (!button) {
        return false;
    }
    const expanded = button.getAttribute("aria-expanded") === "true";
    button.setAttribute("aria-expanded", expanded ? "false" : "true");
    updateRecipeEditIngredientGallery();
    return false;
}

function beginRecipeIngredientReorder(button) {
    setRecipeIngredientsCollapsed(false);
    const handle = document.querySelector("#recipeEditIngredients .recipe-edit-drag-handle, #recipeEditIngredients [draggable='true']");
    if (handle) {
        handle.focus({ preventScroll: true });
    }
    setRecipeEditStatus("Drag ingredient handles to reorder the table.");
    return false;
}

function focusRecipeIngredientGrouping(button) {
    setRecipeIngredientsCollapsed(false);
    const row = document.querySelector("#recipeEditIngredients > .recipe-edit-ingredient-row");
    if (row) {
        setRecipeIngredientEditMode(row, true);
        const group = row.querySelector("[data-recipe-edit-type-trigger]");
        if (group) group.focus({ preventScroll: false });
    }
    setRecipeEditStatus("Use the Type fields to group related ingredients.");
    return false;
}

function beginRecipeInstructionReorder(button) {
    const list = document.getElementById("recipeEditInstructions");
    const label = button ? button.querySelector("span:last-child") : null;
    const active = Boolean(list && !list.classList.contains("recipe-edit-instruction-reorder-mode"));

    if (!list) {
        return false;
    }

    list.classList.toggle("recipe-edit-instruction-reorder-mode", active);
    if (button) {
        button.classList.toggle("is-active", active);
        button.setAttribute("aria-pressed", active ? "true" : "false");
    }
    if (label) {
        label.textContent = active ? "Done Reordering" : "Reorder";
    }

    if (active) {
        list.querySelectorAll(":scope > .recipe-edit-instruction-row").forEach(row => {
            if (row.classList.contains("is-editing")) {
                setRecipeInstructionEditMode(row, false);
            }
            setRecipeEditRowImageToolsVisible(row, false);
        });
    }

    const firstHandle = list.querySelector(".recipe-edit-instruction-row .recipe-edit-row-handle");
    if (active && firstHandle) {
        firstHandle.focus({ preventScroll: false });
    }
    setRecipeEditStatus(active
        ? "Drag the step handles to reorder instructions."
        : "Instruction order updated. Save Recipe to keep it.");
    return false;
}

function recipeEditMetadataFields(source, keys = []) {
    const values = [];
    keys.forEach(key => {
        const value = source && source[key];
        if (Array.isArray(value)) {
            values.push(...value);
        } else if (value && typeof value === "object") {
            values.push(...Object.entries(value).filter(([, enabled]) => Boolean(enabled)).map(([name]) => name));
        } else if (typeof value === "string") {
            values.push(...value.split(/[,;\n]/));
        }
    });
    return [...new Set(values.map(value => {
        if (value && typeof value === "object") {
            return value.field || value.name || value.label || value.message || "";
        }
        return String(value || "");
    }).map(value => String(value || "").trim()).filter(Boolean))];
}

function recipeEditHealthSectionKey(label) {
    return String(label || "").trim().toLowerCase().replace(/\s+/g, "_");
}

function recipeEditCompletenessStatus(label, complete) {
    if (!complete) {
        return { label: "Missing", className: "missing", icon: "x" };
    }

    const source = recipeEditAiInsightSource || {};
    const section = recipeEditHealthSectionKey(label);
    const verifiedFields = recipeEditMetadataFields(source, ["user_verified_fields", "verified_fields", "confirmed_fields"])
        .map(recipeEditHealthSectionKey);
    const lockedFields = recipeEditMetadataFields(source, ["locked_fields", "ai_locked_fields", "user_locked_fields"])
        .map(recipeEditHealthSectionKey);
    const reviewFields = recipeEditMetadataFields(source, ["needs_review_fields", "review_required_fields", "warning_fields"])
        .map(recipeEditHealthSectionKey);
    const inferredFields = recipeEditMetadataFields(source, ["ai_generated_fields", "ai_inferred_fields", "inferred_fields", "cookbook_item_inferred_fields"])
        .map(recipeEditHealthSectionKey);
    const ingredients = collectRecipeIngredientRows();
    const nutrition = collectRecipeNutritionRows();
    const ingredientNeedsReview = section === "ingredients" && ingredients.some(item => (
        item.warning || item.food_review?.needs_review || item.food_review?.status === "needs_review"
    ));
    const ingredientInferred = section === "ingredients" && ingredients.some(item => recipeIngredientInferredValue(item) === "true");
    const nutritionInferred = section === "nutrition" && /estimated|ai[_\s-]?inferred/i.test(JSON.stringify({
        nutrition,
        serving_basis: source.nutrition_serving_basis || source.serving_basis || "",
        nutrition_source: source.nutrition_source || "",
    }));

    if (verifiedFields.includes(section)) {
        return { label: "Complete", className: "confirmed", icon: "check" };
    }
    if (lockedFields.includes(section)) {
        return { label: "Locked", className: "locked", icon: "lock" };
    }
    if (reviewFields.includes(section) || ingredientNeedsReview) {
        return { label: "Needs Review", className: "needs-review", icon: "bot" };
    }
    if (
        inferredFields.includes(section)
        || ingredientInferred
        || nutritionInferred
        || (Boolean(source.ai_inferred) && inferredFields.length === 0)
    ) {
        return { label: "AI Inferred", className: "inferred", icon: "warning" };
    }
    return { label: "Complete", className: "confirmed", icon: "check" };
}

function recipeEditHealthChecks() {
    return [
        ["Title", Boolean(recipeEditInputValue("recipeEditTitleInput") || recipeEditInputValue("recipeEditDisplayName"))],
        ["Description", Boolean(recipeEditInputValue("recipeEditDescription") || recipeEditInputValue("recipeEditMenuDescription"))],
        ["Ingredients", collectRecipeIngredientRows().length > 0],
        ["Instructions", collectRecipeInstructionRows().length > 0],
        ["Equipment", collectRecipeEquipmentRows().length > 0],
        ["Nutrition", collectRecipeNutritionRows().length > 0],
        ["Recipe image", Boolean(recipeEditInputValue("recipeEditCoverPath") || recipeEditInputValue("recipeEditCoverUrl"))],
        ["Cookbook assignment", Boolean(recipeEditInputValue("recipeEditCookbookId") || (document.getElementById("recipeEditCookbookName") || {}).textContent && !/No cookbook assigned/i.test(document.getElementById("recipeEditCookbookName").textContent))],
        ["Source information", Boolean(recipeEditorSourceUrlForOpen() || recipeEditInputValue("recipeEditSourceMenuUrl") || recipeEditInputValue("recipeEditGeneratedCloudflarePdfUrl"))],
    ];
}

function updateRecipeEditorHealth() {
    const list = document.getElementById("recipeEditHealthList");
    const checks = recipeEditHealthChecks();

    if (!list) {
        return;
    }

    const visibleChecks = checks.filter(([label]) => label !== "Description");
    list.innerHTML = visibleChecks.map(([label, complete]) => {
        const status = recipeEditCompletenessStatus(label, complete);
        const displayLabel = label.replace(/^Recipe image$/i, "Recipe Image")
            .replace(/^Cookbook assignment$/i, "Cookbook Assignment")
            .replace(/^Source information$/i, "Source Information");
        const qualifier = status.className === "confirmed" ? "" : ` <small>(${escapeHtml(status.label)})</small>`;
        return `
            <div class="recipe-edit-health-row ${status.className}"
                 data-recipe-edit-health-item
                 data-health-status="${escapeAttribute(status.className)}"
                 aria-label="${escapeAttribute(`${displayLabel}: ${status.label}`)}">
                ${recipeEditSvgIcon(status.icon)}
                <span class="recipe-edit-health-label">${escapeHtml(displayLabel)}${qualifier}</span>
            </div>
        `;
    }).join("");

    const completed = checks.filter(([, complete]) => complete).length;
    const percent = checks.length ? Math.round((completed / checks.length) * 100) : 0;
    const percentElement = document.getElementById("recipeEditHealthPercent");
    const ring = document.getElementById("recipeEditHealthRing");
    const ringProgress = document.getElementById("recipeEditHealthRingProgress");
    const grade = document.getElementById("recipeEditHealthLabel");
    if (percentElement) {
        percentElement.textContent = `${percent}%`;
    }
    if (ring) {
        ring.setAttribute("aria-valuenow", String(percent));
    }
    if (ringProgress) {
        ringProgress.style.strokeDashoffset = String(100 - percent);
    }
    if (grade) {
        grade.textContent = percent >= 90 ? "Excellent" : percent >= 75 ? "Good" : percent >= 50 ? "Fair" : "Needs Attention";
    }
    const attention = document.getElementById("recipeEditHealthAttention");
    if (attention) {
        const issueCount = checks.filter(([, complete]) => !complete).length;
        attention.textContent = issueCount
            ? `${issueCount} item${issueCount === 1 ? "" : "s"} need attention`
            : "All checks complete";
        attention.classList.toggle("is-clear", issueCount === 0);
    }

    const missingFields = document.getElementById("recipeEditAiMissingFields");
    if (missingFields) {
        const missing = checks.filter(([, complete]) => !complete).map(([label]) => label);
        missingFields.innerHTML = missing.length
            ? `<span>Missing or incomplete:</span>${missing.map(label => `<strong>${escapeHtml(label)}</strong>`).join("")}`
            : "<span>All tracked fields are complete.</span>";
    }
}

function recipeEditNumericConfidence(recipe) {
    const source = recipe && typeof recipe === "object" ? recipe : {};
    const candidates = [
        source.ai_confidence,
        source.ai_confidence_score,
        source.inference_confidence_score,
        source.confidence_score,
    ];
    for (const candidate of candidates) {
        const normalized = String(candidate == null ? "" : candidate).trim().replace(/%$/, "");
        if (!normalized || !/^\d+(?:\.\d+)?$/.test(normalized)) {
            continue;
        }
        let value = Number(normalized);
        if (value > 0 && value <= 1) {
            value *= 100;
        }
        if (Number.isFinite(value) && value >= 0 && value <= 100) {
            return Math.round(value);
        }
    }
    return null;
}

function recipeEditConfidenceValue(value) {
    return recipeEditNumericConfidence({ confidence_score: value });
}

function recipeEditAverageConfidence(items = []) {
    const values = items.map(item => recipeEditConfidenceValue(item?.confidence ?? item?.confidence_score)).filter(value => value != null);
    return values.length ? Math.round(values.reduce((total, value) => total + value, 0) / values.length) : null;
}

function recipeEditAiConfidenceModel(source = {}) {
    const ingredients = Array.isArray(source.ingredients) ? source.ingredients : [];
    const instructions = Array.isArray(source.instructions) ? source.instructions : [];
    const nutrition = Array.isArray(source.nutrition) ? source.nutrition : [];
    const inferredFields = recipeEditMetadataFields(source, ["ai_generated_fields", "ai_inferred_fields", "inferred_fields", "cookbook_item_inferred_fields"]);
    const verifiedFields = recipeEditMetadataFields(source, ["user_verified_fields", "verified_fields", "confirmed_fields"]);
    const estimatedFields = recipeEditMetadataFields(source, ["estimated_fields", "ai_estimated_fields"]);
    const explicitSourceQuality = recipeEditConfidenceValue(source.source_quality_score ?? source.source_quality_confidence);
    const sourceQuality = explicitSourceQuality;
    const ingredientConfidence = recipeEditAverageConfidence(ingredients);
    const instructionConfidence = recipeEditAverageConfidence(instructions);
    const nutritionConfidence = recipeEditConfidenceValue(
        source.nutrition_confidence_score ?? source.nutrition_confidence ?? source.nutrition?.confidence
    );
    const duplicateConfidence = recipeEditConfidenceValue(
        source.duplicate_detection_confidence ?? source.duplicate_confidence_score
    );
    const extractionConfidence = recipeEditConfidenceValue(
        source.extraction_confidence_score ?? source.inference_confidence_score ?? source.inference_confidence
    ) ?? ingredientConfidence ?? instructionConfidence;
    const aiCertainty = recipeEditNumericConfidence(source)
        ?? recipeEditConfidenceValue(source.ai_certainty ?? source.category_confidence ?? source.ingredients_inference_confidence);
    const verificationConfidence = recipeEditConfidenceValue(source.user_verification_confidence)
        ?? (verifiedFields.length ? 95 : null);
    const savedConfidence = recipeEditNumericConfidence(source);
    const hasAiConfidenceEvidence = aiCertainty != null || extractionConfidence != null;
    const confidence = savedConfidence;
    const fieldList = value => value.length ? value.join(", ") : "Not recorded";
    const scoreLabel = value => value == null ? "Not scored" : `${value}%`;
    const sectionScores = [
        ["Ingredients", ingredientConfidence],
        ["Instructions", instructionConfidence],
        ["Nutrition", nutritionConfidence],
    ].filter(([, value]) => value != null).map(([label, value]) => `${label} ${value}%`);
    const warnings = recipeEditMetadataFields(source, ["warnings", "ai_warnings", "confidence_warnings"]);
    ingredients.forEach(item => {
        if (item?.warning) warnings.push(String(item.warning));
    });
    const normalizedWarnings = [...new Set(warnings.map(value => String(value || "").trim()).filter(Boolean))];
    const recommendations = [];
    if (sourceQuality == null || sourceQuality < 70) recommendations.push("Verify the recipe source.");
    if (ingredientConfidence != null && ingredientConfidence < 70) recommendations.push("Review low-confidence ingredient normalization.");
    if (nutrition.length && nutritionConfidence == null) recommendations.push("Review nutrition values that do not include confidence metadata.");
    if (normalizedWarnings.length) recommendations.push("Resolve saved AI warnings before publishing.");
    if (savedConfidence == null && !hasAiConfidenceEvidence) recommendations.push("Add confidence metadata by reviewing or re-running the existing AI analysis workflow.");
    if (!recommendations.length) recommendations.push("No confidence-specific action is currently required.");

    return {
        confidence,
        summary: String(source.ai_analysis || source.inference_analysis || source.ai_confidence_analysis || "").trim(),
        items: [
            ["Source Quality", scoreLabel(sourceQuality)],
            ["Confidence by section", sectionScores.length ? sectionScores.join(" · ") : "No section scores recorded"],
            ["AI generated fields", fieldList(inferredFields)],
            ["User verified fields", fieldList(verifiedFields)],
            ["Estimated fields", fieldList(estimatedFields)],
            ["Nutrition confidence", scoreLabel(nutritionConfidence)],
            ["Ingredient normalization confidence", scoreLabel(ingredientConfidence)],
            ["Duplicate detection confidence", scoreLabel(duplicateConfidence)],
            ["Warnings", normalizedWarnings.length ? normalizedWarnings.join(" · ") : "No saved warnings"],
            ["Recommended actions", recommendations.join(" ")],
        ],
    };
}

function updateRecipeEditAiConfidenceCard(recipe = null) {
    const card = document.getElementById("recipeEditAiConfidenceCard");
    if (!card) {
        return;
    }
    if (recipe && typeof recipe === "object") {
        recipeEditAiInsightSource = recipe;
    }
    const source = recipeEditAiInsightSource || recipeEditOriginalSnapshot || {};
    const model = recipeEditAiConfidenceModel(source);
    const confidence = recipeEditAiQualityReport?.overall_confidence ?? model.confidence;
    const percent = document.getElementById("recipeEditAiConfidencePercent");
    const bar = document.getElementById("recipeEditAiConfidenceBar");
    const track = document.getElementById("recipeEditAiConfidenceTrack");
    if (percent) {
        percent.textContent = confidence == null ? "Not available" : `${confidence}%`;
    }
    if (bar) {
        bar.style.width = `${confidence ?? 0}%`;
    }
    if (track) {
        track.setAttribute("aria-valuenow", String(confidence ?? 0));
        track.setAttribute("aria-valuetext", confidence == null ? "AI confidence not available" : `${confidence} percent`);
    }
}

function recipeEditAiReportActionHtml(action, options = {}) {
    if (!action || !action.key || !action.label) return "";
    const classes = ["recipe-edit-ai-report-action", options.className || ""].filter(Boolean).join(" ");
    if (action.key === "open_original_image" && action.url) {
        return `<a class="${classes}" href="${escapeAttribute(action.url)}" target="_blank" rel="noopener noreferrer">${escapeHtml(action.label)}</a>`;
    }
    return `<button type="button"
                    class="${classes}"
                    data-ai-report-action="${escapeAttribute(action.key)}"
                    data-ai-report-target="${escapeAttribute(action.target || "")}"
                    data-ai-report-index="${escapeAttribute(action.index == null ? "" : action.index)}"
                    data-ai-report-document="${escapeAttribute(action.document || "")}"
                    onclick="return runRecipeAiQualityReportAction(this)">${escapeHtml(action.label)}</button>`;
}

function recipeEditAiReportStatusIcon(status, score = null) {
    const normalized = String(status || "").toLowerCase();
    const icon = ["verified", "extracted", "manual", "high"].includes(normalized) || (score != null && score >= 75)
        ? "check"
        : ["missing", "low", "conflicting"].includes(normalized) || (score != null && score < 50)
            ? "x"
            : "warning";
    return recipeEditSvgIcon(icon);
}

function recipeEditAiReportScore(value) {
    return value == null ? "Not available" : `${value}%`;
}

function renderRecipeAiQualityReportCategories(categories = {}) {
    const container = document.getElementById("recipeEditAiAnalysisCategories");
    if (!container) return;
    const rows = Object.values(categories || {}).filter(Boolean);
    container.innerHTML = rows.length ? rows.map(item => {
        const score = item.score == null ? null : Number(item.score);
        const status = score == null ? "unavailable" : (item.status || "unavailable");
        const explanation = score == null
            ? "This score has not been calculated."
            : (item.explanation || "No explanation is available.");
        return `<article class="recipe-edit-ai-report-category is-${escapeAttribute(status)}">
            <div class="recipe-edit-ai-report-category-heading">
                <span class="recipe-edit-ai-report-status-icon">${recipeEditAiReportStatusIcon(status, score)}</span>
                <strong>${escapeHtml(item.label || "Confidence")}</strong>
                <span>${escapeHtml(recipeEditAiReportScore(score))}</span>
            </div>
            <div class="recipe-edit-ai-report-progress"
                 role="progressbar"
                 aria-label="${escapeAttribute(item.label || "Confidence")}"
                 aria-valuemin="0"
                 aria-valuemax="100"
                 aria-valuenow="${score == null ? 0 : score}"
                 aria-valuetext="${escapeAttribute(recipeEditAiReportScore(score))}">
                <span style="width:${score == null ? 0 : Math.max(0, Math.min(100, score))}%"></span>
            </div>
            <p>${escapeHtml(explanation)}</p>
        </article>`;
    }).join("") : '<p class="recipe-edit-ai-report-empty">No saved confidence categories are available.</p>';
}

