function updateRecipeAiQualityReportNotice(report = {}) {
    const notice = document.getElementById("recipeEditAiAnalysisUnavailableNotice");
    const message = document.getElementById("recipeEditAiAnalysisUnavailableMessage");
    if (!notice || !message) return;
    const categories = Object.values(report.categories || {}).filter(Boolean);
    const unavailableCount = categories.filter(item => item.score == null).length;
    const overallUnavailable = report.overall_confidence == null;
    const severalCategoriesUnavailable = unavailableCount >= 2;
    notice.hidden = !overallUnavailable && !severalCategoriesUnavailable;
    if (notice.hidden) {
        message.textContent = "";
        return;
    }
    if (severalCategoriesUnavailable) {
        message.textContent = "Some confidence categories are unavailable because this recipe was imported before field-level analysis was added. Reanalyze the recipe to calculate them.";
    } else {
        message.textContent = "Overall confidence has not been calculated or stored for this recipe. Reanalyze the recipe to calculate it.";
    }
}

function updateRecipeAiQualityReportSafeFixes(report = {}) {
    const button = document.querySelector("[data-ai-report-safe-fixes]");
    const tooltip = document.querySelector("[data-ai-report-safe-fixes-tooltip]");
    const help = document.getElementById("recipeEditAiAnalysisSafeFixesHelp");
    if (!button) return;
    const count = Number(report.safe_fix_count || 0);
    const available = report.safe_fixes_available === true || count > 0;
    const unavailableMessage = "No deterministic safe fixes are available for this recipe.";
    button.disabled = !available;
    button.toggleAttribute("aria-describedby", !available);
    button.title = available ? "" : unavailableMessage;
    if (tooltip) tooltip.title = available ? "" : unavailableMessage;
    if (help) help.textContent = unavailableMessage;
}

function renderRecipeAiQualityReport(report = {}) {
    recipeEditAiQualityReport = report && typeof report === "object" ? report : {};
    const overall = document.getElementById("recipeEditAiAnalysisOverall");
    const overallGroup = document.getElementById("recipeEditAiAnalysisOverallGroup");
    const label = document.getElementById("recipeEditAiAnalysisLabel");
    const name = document.getElementById("recipeEditAiAnalysisRecipeName");
    const timestamp = document.getElementById("recipeEditAiAnalysisTimestamp");
    const summary = document.getElementById("recipeEditAiAnalysisSummary");
    const overallUnavailable = report.overall_confidence == null;
    if (overall) overall.textContent = overallUnavailable ? "Not calculated" : `${report.overall_confidence}%`;
    if (overallGroup) overallGroup.classList.toggle("is-unavailable", overallUnavailable);
    if (label) label.textContent = overallUnavailable ? "Confidence unavailable" : `${report.confidence_label || "Unknown"} confidence`;
    if (name) name.textContent = report.recipe_name || "Untitled Recipe";
    if (timestamp) {
        timestamp.hidden = !report.last_analyzed;
        timestamp.textContent = report.last_analyzed ? `Last analyzed ${report.last_analyzed}` : "";
    }
    if (summary) summary.textContent = report.summary || "No stored analysis summary is available.";
    updateRecipeAiQualityReportNotice(report);
    renderRecipeAiQualityReportCategories(report.categories);
    renderRecipeAiQualityReportHealth(report.field_analysis || []);
    renderRecipeAiQualityReportIngredients(report.ingredient_analysis || []);
    renderRecipeAiQualityReportEvidence(report.source_evidence || []);
    renderRecipeAiQualityReportRestaurant(report.restaurant_analysis || {});
    renderRecipeAiQualityReportImage(report.image_analysis || {});
    renderRecipeAiQualityReportRecommendations(report.recommendations || []);
    updateRecipeAiQualityReportSafeFixes(report);
    document.getElementById("recipeEditAiAnalysisLoading")?.setAttribute("hidden", "");
    document.getElementById("recipeEditAiAnalysisError")?.setAttribute("hidden", "");
    document.getElementById("recipeEditAiAnalysisContent")?.removeAttribute("hidden");
    document.getElementById("recipeEditAiAnalysisBody")?.setAttribute("aria-busy", "false");
    updateRecipeEditAiConfidenceCard();
}

async function loadRecipeAiQualityReport(options = {}) {
    const url = recipeEditorCurrentUrl();
    const loading = document.getElementById("recipeEditAiAnalysisLoading");
    const error = document.getElementById("recipeEditAiAnalysisError");
    const content = document.getElementById("recipeEditAiAnalysisContent");
    const body = document.getElementById("recipeEditAiAnalysisBody");
    if (!url) {
        if (loading) loading.hidden = true;
        if (error) { error.hidden = false; error.textContent = "The current recipe URL is unavailable."; }
        if (body) body.setAttribute("aria-busy", "false");
        return null;
    }
    if (recipeEditAiQualityReport && !options.force) {
        renderRecipeAiQualityReport(recipeEditAiQualityReport);
        return recipeEditAiQualityReport;
    }
    if (recipeEditAiQualityReportRequest && !options.force) return recipeEditAiQualityReportRequest;
    if (loading) { loading.hidden = false; loading.textContent = options.force ? "Reanalyzing the saved recipe…" : "Loading saved AI analysis…"; }
    if (error) error.hidden = true;
    if (content) content.hidden = true;
    if (body) body.setAttribute("aria-busy", "true");
    updateRecipeAiQualityReportSafeFixes({});
    const request = fetch(`/api/recipe/ai-quality-report?url=${encodeURIComponent(url)}`, { cache: "no-store" })
        .then(async response => {
            const data = await response.json().catch(() => ({}));
            if (!response.ok || !data.ok) throw new Error(data.error || "Unable to load the AI Quality Report.");
            renderRecipeAiQualityReport(data.report || {});
            return data.report || {};
        })
        .catch(err => {
            if (loading) loading.hidden = true;
            if (content) content.hidden = true;
            if (error) { error.hidden = false; error.textContent = err.message || "Unable to load the AI Quality Report."; }
            if (body) body.setAttribute("aria-busy", "false");
            return null;
        })
        .finally(() => { if (recipeEditAiQualityReportRequest === request) recipeEditAiQualityReportRequest = null; });
    recipeEditAiQualityReportRequest = request;
    return request;
}

function recipeEditAiReportFocusables() {
    const panel = document.getElementById("recipeEditAiAnalysisPanel");
    return panel ? Array.from(panel.querySelectorAll('button:not([disabled]), a[href], summary, [tabindex]:not([tabindex="-1"])')).filter(element => !element.hidden && element.getClientRects().length) : [];
}

function openRecipeEditAiAnalysis(button) {
    const backdrop = document.getElementById("recipeEditAiAnalysisBackdrop");
    const panel = document.getElementById("recipeEditAiAnalysisPanel");
    if (!backdrop || !panel) return false;
    if (!backdrop.hidden) return closeRecipeEditAiAnalysis();
    if (backdrop.parentElement !== document.body) document.body.appendChild(backdrop);
    backdrop.hidden = false;
    document.body.classList.add("recipe-edit-ai-report-open");
    if (button) button.setAttribute("aria-expanded", "true");
    document.getElementById("recipeEditAiAnalysisTitle")?.focus({ preventScroll: true });
    loadRecipeAiQualityReport();
    return false;
}

function closeRecipeEditAiAnalysis(options = {}) {
    const backdrop = document.getElementById("recipeEditAiAnalysisBackdrop");
    const button = document.getElementById("recipeEditAiAnalysisButton");
    if (backdrop) backdrop.hidden = true;
    document.body.classList.remove("recipe-edit-ai-report-open");
    if (button) {
        button.setAttribute("aria-expanded", "false");
        if (options.restoreFocus !== false) button.focus({ preventScroll: true });
    }
    return false;
}

function focusRecipeAiQualityIngredient(index, field = "ingredient") {
    setRecipeEditActiveTab("ingredients", { focus: false });
    const rows = Array.from(document.querySelectorAll("#recipeEditIngredients .recipe-edit-ingredient-row"));
    const row = rows[Number(index)] || rows[0];
    if (!row) return;
    row.classList.add("recipe-edit-row-expanded");
    setRecipeIngredientEditMode(row, true);
    row.scrollIntoView({ block: "center", behavior: "smooth" });
    (row.querySelector(`[data-field="${field}"]`) || row.querySelector("input, textarea, select, button"))?.focus({ preventScroll: true });
}

function runRecipeAiQualityReportAction(button) {
    const action = button?.dataset.aiReportAction || "";
    const target = button?.dataset.aiReportTarget || "";
    const index = button?.dataset.aiReportIndex || "0";
    closeRecipeEditAiAnalysis({ restoreFocus: false });
    window.setTimeout(() => {
        if (action === "switch_tab") {
            setRecipeEditActiveTab(target, { focus: true });
        } else if (action === "focus_field") {
            document.getElementById(target)?.focus({ preventScroll: false });
        } else if (["review_ingredient", "change_match"].includes(action)) {
            focusRecipeAiQualityIngredient(index, "ingredient");
        } else if (action === "normalize_unit") {
            focusRecipeAiQualityIngredient(index, "unit");
        } else if (action === "add_missing_amount") {
            focusRecipeAiQualityIngredient(index, "quantity");
        } else if (action === "open_source_documents") {
            const card = document.querySelector("[data-source-documents-card]");
            if (card) { card.open = true; card.scrollIntoView({ block: "center" }); card.querySelector("summary")?.focus(); }
        } else if (["edit_restaurant", "refresh_restaurant"].includes(action)) {
            document.querySelector(".recipe-edit-restaurant-edit")?.click();
            if (action === "refresh_restaurant") window.setTimeout(() => document.querySelector("[data-restaurant-fetch-button]")?.focus(), 0);
        } else if (action === "open_restaurant_website") {
            document.querySelector('[data-restaurant-action="website"]')?.click();
        } else if (action === "open_restaurant_menu") {
            document.querySelector('[data-restaurant-action="menu"]')?.click();
        } else if (action === "open_restaurant_map") {
            document.querySelector('[data-restaurant-action="map"]')?.click();
        } else if (action === "change_image") {
            openRecipeCoverUpload();
        } else if (action === "regenerate_image") {
            document.getElementById("recipeEditCoverGenerate")?.click();
        } else if (action === "review_image_prompt") {
            const prompt = document.getElementById("recipeEditCoverPrompt");
            if (prompt) { prompt.hidden = false; prompt.scrollIntoView({ block: "center" }); document.getElementById("recipeEditCoverPromptToggle")?.focus(); }
        } else if (action === "open_document") {
            const row = document.querySelector(`[data-document-input-id="${CSS.escape(button.dataset.aiReportDocument || "")}"]`);
            row?.querySelector("[data-document-open]")?.click();
        }
    }, 0);
    return false;
}

async function reanalyzeRecipeAiQualityReport(button) {
    if (button?.disabled) return false;
    const buttons = Array.from(document.querySelectorAll("[data-ai-report-reanalyze]"));
    buttons.forEach(control => { control.disabled = true; });
    const status = document.getElementById("recipeEditAiAnalysisActionStatus");
    if (status) status.textContent = "Reanalyzing saved recipe…";
    recipeEditAiQualityReport = null;
    const report = await loadRecipeAiQualityReport({ force: true });
    if (status) status.textContent = report ? "Report recalculated from the saved recipe." : "Reanalysis failed.";
    buttons.forEach(control => { control.disabled = false; });
    return false;
}

function applyRecipeAiQualitySafeUpdatesToEditor(updates = []) {
    const ingredientRows = Array.from(document.querySelectorAll("#recipeEditIngredients .recipe-edit-ingredient-row"));
    const recipeFields = {
        source_url: "recipeEditSourceUrl",
        source_pdf_path: "recipeEditSourcePdfPath",
        generated_pdf_path: "recipeEditGeneratedPdfPath",
        source_menu_url: "recipeEditSourceMenuUrl",
    };
    let applied = 0;
    let skipped = 0;
    (Array.isArray(updates) ? updates : []).forEach(update => {
        const field = String(update?.field || "");
        const before = String(update?.before ?? "");
        const after = String(update?.after ?? "");
        let control = null;
        if (update?.scope === "ingredient") {
            control = ingredientRows[Number(update.index)]?.querySelector(`[data-field="${CSS.escape(field)}"]`) || null;
        } else if (update?.scope === "recipe" && recipeFields[field]) {
            control = document.getElementById(recipeFields[field]);
        }
        if (!control || String(control.value ?? "") !== before) {
            skipped += 1;
            return;
        }
        control.value = after;
        control.dispatchEvent(new Event("input", { bubbles: true }));
        control.dispatchEvent(new Event("change", { bubbles: true }));
        applied += 1;
    });
    return { applied, skipped };
}

async function applyRecipeAiQualitySafeFixes(button) {
    if (button?.disabled) return false;
    const url = recipeEditorCurrentUrl();
    const status = document.getElementById("recipeEditAiAnalysisActionStatus");
    if (!url) return false;
    if (button) button.disabled = true;
    if (status) status.textContent = "Applying deterministic safe fixes…";
    try {
        const response = await fetch("/api/recipe/ai-quality-report/safe-fixes", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ url }),
        });
        const data = await response.json().catch(() => ({}));
        if (!response.ok || !data.ok) throw new Error(data.error || "Unable to apply safe fixes.");
        invalidateRecipeEditorCache(url);
        const synchronized = applyRecipeAiQualitySafeUpdatesToEditor(data.safe_updates || []);
        renderRecipeAiQualityReport(data.report || {});
        if (status) {
            status.textContent = data.changed_count
                ? `${data.changed_count} safe fix${data.changed_count === 1 ? "" : "es"} saved.${synchronized.skipped ? " Unsaved form values were preserved." : ""}`
                : "No deterministic safe fixes were needed.";
        }
    } catch (err) {
        if (status) status.textContent = err.message || "Unable to apply safe fixes.";
    } finally {
        updateRecipeAiQualityReportSafeFixes(recipeEditAiQualityReport || {});
    }
    return false;
}

function updateRecipeEditContextPanels() {
    syncRecipeEditDocumentRows();
    updateRecipeEditRestaurantCard();
    updateRecipeEditIngredientGallery();
    updateRecipeEditorHealth();
    updateRecipeEditMetadataUnits();
    const priceField = recipeEditFieldContainer("recipeEditMenuPrice");
    if (priceField) {
        priceField.hidden = !recipeEditInputValue("recipeEditMenuPrice") && !recipeMenuMetadataStateAvailable();
    }
}

function initRecipeEditContextPanels() {
    if (document.documentElement.dataset.recipeEditContextPanelsBound === "1") {
        return;
    }

    document.documentElement.dataset.recipeEditContextPanelsBound = "1";
    document.addEventListener("input", event => {
        if (event.target && event.target.closest && event.target.closest("#recipeEditForm")) {
            updateRecipeEditContextPanels();
            updateRecipeEditorDirtyState(event.target.closest("#recipeEditForm"));
        }
    });
    document.addEventListener("change", event => {
        if (event.target && event.target.closest && event.target.closest("#recipeEditForm")) {
            updateRecipeEditContextPanels();
            updateRecipeEditorDirtyState(event.target.closest("#recipeEditForm"));
        }
    });
    window.addEventListener("beforeunload", event => {
        if (!recipeEditorHasUnsavedChanges()) {
            return;
        }
        event.preventDefault();
        event.returnValue = "";
    });
    document.addEventListener("keydown", event => {
        const backdrop = document.getElementById("recipeEditAiAnalysisBackdrop");
        if (!backdrop || backdrop.hidden) return;
        if (event.key === "Escape") {
            event.preventDefault();
            closeRecipeEditAiAnalysis();
            return;
        }
        if (event.key === "Tab") {
            const focusable = recipeEditAiReportFocusables();
            if (!focusable.length) {
                event.preventDefault();
                document.getElementById("recipeEditAiAnalysisPanel")?.focus();
                return;
            }
            const first = focusable[0];
            const last = focusable[focusable.length - 1];
            if (!focusable.includes(document.activeElement)) {
                event.preventDefault();
                (event.shiftKey ? last : first).focus();
            } else if (event.shiftKey && document.activeElement === first) {
                event.preventDefault();
                last.focus();
            } else if (!event.shiftKey && document.activeElement === last) {
                event.preventDefault();
                first.focus();
            }
        }
    });
}

function previewRecipeFromEditor() {
    const url = recipeEditorCurrentUrl();

    if (!url) {
        setRecipeEditStatus("Unable to preview recipe: missing recipe URL.", true);
        return false;
    }

    if (recipeEditorStandalonePageIsActive()) {
        const form = document.getElementById("recipeEditForm");
        if (form && form.dataset.saving === "true") {
            setRecipeEditStatus("Please wait for the recipe save to finish.", true);
            return false;
        }
        const hasUnsavedChanges = recipeEditorHasUnsavedChanges(form);
        if (hasUnsavedChanges && !window.confirm("You have unsaved recipe changes. Discard them?")) {
            return false;
        }
        if (hasUnsavedChanges) {
            rememberRecipeEditorSavedState(form);
        }
        window.location.assign(recipeEditPageReturnUrlFromState() || "/#shoppingViewsSection");
        return false;
    }

    if (!closeRecipeEditor()) {
        return false;
    }

    Promise.resolve(
        typeof loadLazySection === "function"
            ? loadLazySection("recipe-view", { allowDuringAuthCollapse: true })
            : null
    ).then(() => {
        if (typeof showView === "function") {
            showView("recipeView");
        }
        if (typeof jumpToRecipeViewRecipe === "function") {
            jumpToRecipeViewRecipe({ dataset: { recipeUrl: url } });
        }
    });

    return false;
}

function setRecipePdfFieldOpenTarget(input, link, value, openUrl, label, options = {}) {
    const textValue = String(value || "").trim();
    const targetUrl = String(openUrl || "").trim();
    const canOpen = Boolean(textValue && targetUrl && targetUrl !== "#");

    if (input && options.updateInput !== false) {
        input.value = textValue;
        input.dataset.lastServerValue = textValue;
    }

    if (!link) {
        return;
    }

    link.href = canOpen ? targetUrl : "#";
    link.dataset.recipePdfUrl = canOpen ? targetUrl : "";
    link.hidden = !canOpen;
    link.setAttribute("aria-disabled", canOpen ? "false" : "true");
    link.title = canOpen ? label : "No PDF value";
    link.setAttribute("aria-label", canOpen ? label : "No PDF value");
}

function recipeArchivePdfUrl(sourceUrl, kind = "") {
    const kindValue = String(kind || "").trim();
    const kindQuery = kindValue ? `&kind=${encodeURIComponent(kindValue)}` : "";
    return `/recipe_archive_pdf?url=${encodeURIComponent(sourceUrl || "")}${kindQuery}`;
}

function recipeArchivePdfDownloadUrl(sourceUrl, kind = "") {
    const kindValue = String(kind || "").trim();
    const kindQuery = kindValue ? `&kind=${encodeURIComponent(kindValue)}` : "";
    return `/recipe_archive_pdf?url=${encodeURIComponent(sourceUrl || "")}&download=1${kindQuery}`;
}

function openRecipeEditorPdf(link, event) {
    if (event) {
        event.preventDefault();
        event.stopPropagation();
    }

    const url = link && (link.dataset.recipePdfUrl || link.getAttribute("href"));

    if (!url || url === "#") {
        setRecipeEditStatus("Recipe PDF is not ready yet.", true);
        return false;
    }

    try {
        const targetWindow = isScreenPreviewFrame() && window.top ? window.top : window;
        const opened = targetWindow.open(url, "_blank");

        if (opened) {
            try {
                opened.opener = null;
            } catch (err) {
                // Some PDF viewers do not expose opener; the tab still opened.
            }
            return false;
        }
    } catch (err) {
        // If a mobile browser blocks the popup, the fallback below still opens the PDF.
    }

    window.location.assign(url);
    return false;
}

function updateRecipeEditStickyOffsets() {
    document.querySelectorAll(".recipe-edit-equipment-section, .recipe-edit-instructions-section, .recipe-edit-nutrition-section, .recipe-edit-reflection-section")
        .forEach(section => {
            const sectionHeader = section.querySelector(".recipe-edit-section-header");

            if (!sectionHeader) {
                return;
            }

            const stickyTop = parseFloat(getComputedStyle(sectionHeader).top) || 0;
            const tableTop = stickyTop + sectionHeader.offsetHeight;
            section.style.setProperty("--recipe-edit-table-sticky-top", `${Math.ceil(tableTop)}px`);
        });
}

function setValue(id, value) {
    const element = document.getElementById(id);

    if (element) {
        element.value = value;
    }
}

function normalizeRecipeRatingValue(value) {
    const rating = parseInt(value, 10);

    if (!Number.isFinite(rating)) {
        return 0;
    }

    return Math.max(0, Math.min(5, rating));
}

function currentRecipeRating() {
    const input = document.getElementById("recipeEditRating");
    return normalizeRecipeRatingValue(input ? input.value : 0);
}

function setRecipeRating(value) {
    const rating = normalizeRecipeRatingValue(value);
    return setSharedRatingValue(document.getElementById("recipeEditRatingStars"), rating, { allowToggle: false });
}

function updateRecipeRatingStars(rating) {
    updateSharedRatingControl(document.getElementById("recipeEditRatingStars"), rating);
}

function setRecipeEditStatus(message, isError = false) {
    const status = document.getElementById("recipeEditStatus");

    if (!status) {
        return;
    }

    status.textContent = message || "";
    status.classList.toggle("visible", Boolean(message));
    status.classList.toggle("error", Boolean(isError));
    status.setAttribute("role", isError ? "alert" : "status");
    status.setAttribute("aria-live", isError ? "assertive" : "polite");
}

function recipeEditorCurrentSaveSnapshot(form = document.getElementById("recipeEditForm")) {
    if (!form) {
        return "";
    }

    try {
        return JSON.stringify({
            payload: collectRecipeEditorPayload(),
            category_values: collectRecipeEditorCategoryValues(),
            category_sources: collectRecipeEditorCategorySources(),
        });
    } catch (err) {
        return "";
    }
}

function rememberRecipeEditorSavedState(form = document.getElementById("recipeEditForm")) {
    if (!form) {
        return;
    }

    const snapshot = recipeEditorCurrentSaveSnapshot(form);
    if (snapshot) {
        recipeEditSavedFormSnapshots.set(form, snapshot);
    }
    form.dataset.recipeEditDirty = "false";
    form.querySelectorAll("[data-recipe-edit-save]").forEach(button => {
        button.dataset.dirty = "false";
        if (form.dataset.saving !== "true") {
            button.disabled = true;
        }
    });
}

function recipeEditorSubmittedSnapshotWithIdentity(submittedSnapshot, identity = {}, options = {}) {
    if (!submittedSnapshot) {
        return "";
    }
    try {
        const snapshot = JSON.parse(submittedSnapshot);
        const savedSourceUrl = String(identity.source_url || "").trim();
        const savedRecipeId = String(identity.recipe_id || "").trim();
        if (snapshot.payload && savedSourceUrl) {
            snapshot.payload.original_url = savedSourceUrl;
        }
        if (snapshot.payload && savedRecipeId) {
            snapshot.payload.recipe_id = savedRecipeId;
            if (snapshot.payload.recipe && typeof snapshot.payload.recipe === "object") {
                snapshot.payload.recipe.recipe_id = savedRecipeId;
            }
        }
        if (options.preserveCategoriesFrom) {
            const previousSnapshot = JSON.parse(options.preserveCategoriesFrom);
            snapshot.category_values = previousSnapshot.category_values || {};
            snapshot.category_sources = previousSnapshot.category_sources || {};
        }
        return JSON.stringify(snapshot);
    } catch (err) {
        return submittedSnapshot;
    }
}

function rememberRecipeEditorSubmittedState(form, submittedSnapshot, identity = {}, options = {}) {
    if (!form) {
        return "";
    }
    const savedSnapshot = recipeEditorSubmittedSnapshotWithIdentity(submittedSnapshot, identity, options);
    if (savedSnapshot) {
        recipeEditSavedFormSnapshots.set(form, savedSnapshot);
    }
    return savedSnapshot;
}

function rememberRecipeEditorSubmittedCategories(form, submittedSnapshot) {
    if (!form || !submittedSnapshot) {
        return;
    }
    try {
        const snapshot = JSON.parse(submittedSnapshot);
        form.dataset.originalCategoryValues = JSON.stringify(snapshot.category_values || {});
        form.dataset.originalCategorySources = JSON.stringify(snapshot.category_sources || {});
    } catch (err) {
        // The saved baseline still protects the recipe fields if category metadata is unavailable.
    }
}

function rememberRecipeEditorFieldsAsSaved(form, fieldNames = []) {
    if (!form || !recipeEditSavedFormSnapshots.has(form)) {
        return;
    }
    try {
        const current = JSON.parse(recipeEditorCurrentSaveSnapshot(form));
        const saved = JSON.parse(recipeEditSavedFormSnapshots.get(form));
        const currentRecipe = current.payload && current.payload.recipe;
        const savedRecipe = saved.payload && saved.payload.recipe;
        if (!currentRecipe || !savedRecipe) {
            return;
        }
        fieldNames.forEach(field => {
            savedRecipe[field] = currentRecipe[field];
        });
        recipeEditSavedFormSnapshots.set(form, JSON.stringify(saved));
    } catch (err) {
        // A later successful load can refresh the saved snapshot if the form changed shape.
    }
}

function rememberRecipeEditorCoverImageAsSaved(form = document.getElementById("recipeEditForm")) {
    rememberRecipeEditorFieldsAsSaved(form, [
        "cover_image",
        "cover_image_prompt",
    ]);
    updateRecipeEditorDirtyState(form);
}

function updateRecipeEditorDirtyState(form = document.getElementById("recipeEditForm")) {
    if (!form || !recipeEditSavedFormSnapshots.has(form)) {
        return false;
    }

    const snapshot = recipeEditorCurrentSaveSnapshot(form);
    const dirty = Boolean(snapshot && snapshot !== recipeEditSavedFormSnapshots.get(form));
    form.dataset.recipeEditDirty = dirty ? "true" : "false";
    form.querySelectorAll("[data-recipe-edit-save]").forEach(button => {
        button.dataset.dirty = dirty ? "true" : "false";
        if (form.dataset.saving !== "true") {
            button.disabled = !dirty;
        }
    });
    return dirty;
}

function recipeEditorHasUnsavedChanges(form = document.getElementById("recipeEditForm")) {
    if (!form) {
        return false;
    }
    return updateRecipeEditorDirtyState(form);
}

function clearRecipeEditorValidation(form = document.getElementById("recipeEditForm")) {
    if (!form) {
        return;
    }

    form.querySelectorAll("[data-recipe-edit-validation-invalid]").forEach(control => {
        control.removeAttribute("data-recipe-edit-validation-invalid");
        if (!control.validationMessage) {
            control.removeAttribute("aria-invalid");
        }
    });
    form.querySelectorAll(".recipe-edit-has-validation-error").forEach(container => {
        container.classList.remove("recipe-edit-has-validation-error");
    });

    const summary = document.getElementById("recipeEditValidationSummary");
    const list = summary ? summary.querySelector("[data-recipe-edit-validation-errors]") : null;
    if (list) {
        list.replaceChildren();
    }
    if (summary) {
        summary.hidden = true;
    }
}

function recipeEditorValidationContainer(control) {
    return control && control.closest
        ? control.closest("label, .recipe-edit-ingredient-row, .recipe-edit-instruction-row, .recipe-edit-equipment-row, .recipe-edit-nutrition-row, .recipe-edit-note-section-row, .recipe-edit-reflection-note-row")
        : null;
}

function addRecipeEditorValidationError(errors, message, control = null, field = "") {
    if (control) {
        control.setAttribute("aria-invalid", "true");
        control.dataset.recipeEditValidationInvalid = "true";
        const container = recipeEditorValidationContainer(control);
        if (container) {
            container.classList.add("recipe-edit-has-validation-error");
        }
    }
    errors.push({ message, control, field });
}

function recipeEditorNumericExpressionIsMalformed(value, options = {}) {
    let text = String(value || "").trim();
    if (!text || !/\d/.test(text)) {
        return false;
    }
    if (options.allowUnitSuffix) {
        text = text.replace(/\s*(?:[A-Za-z%µμ].*)$/, "").trim();
    } else if (/[A-Za-z]/.test(text)) {
        return false;
    }
    if (!text) {
        return false;
    }
    if (/(?:\.\.|,,|\/\/|--+)/.test(text)) {
        return true;
    }
    if (!/^[\d\s./+\-–—]+$/.test(text)) {
        return false;
    }

    const numberPart = "(?:\\d+(?:\\.\\d+)?|\\.\\d+|\\d+\\s+\\d+\\/\\d+|\\d+\\/\\d+)";
    const expression = new RegExp(`^${numberPart}(?:\\s*(?:-|–|—)\\s*${numberPart})?$`);
    if (!expression.test(text)) {
        return true;
    }

    return text.split(/\s*(?:-|–|—)\s*/).some(part => {
        const fraction = part.match(/(?:^|\s)(\d+)\/(\d+)$/);
        return Boolean(fraction && Number(fraction[2]) === 0);
    });
}

function recipeEditorControlForFieldPath(path, form = document.getElementById("recipeEditForm")) {
    if (!form) {
        return null;
    }

    const normalized = String(path || "").replace(/\[(\d+)\]/g, ".$1");
    const parts = normalized.split(".").filter(Boolean);
    const topLevelIds = {
        display_name: "recipeEditDisplayName",
        recipe_title: "recipeEditTitleInput",
        description: "recipeEditDescription",
        source_url: "recipeEditSourceUrl",
        servings: "recipeEditServings",
        total_time: "recipeEditTotalTime",
        prep_time: "recipeEditPrepTime",
        inactive_time: "recipeEditInactiveTime",
        cook_time: "recipeEditCookTime",
    };
    if (parts.length === 1 && topLevelIds[parts[0]]) {
        return document.getElementById(topLevelIds[parts[0]]);
    }

    const collectionSelectors = {
        ingredients: ["#recipeEditIngredients .recipe-edit-ingredient-row", {
            amount: "quantity",
            name: "ingredient",
        }],
        instructions: ["#recipeEditInstructions .recipe-edit-instruction-row", {
            instruction: "text",
        }],
        equipment: ["#recipeEditEquipment .recipe-edit-equipment-row", {
            equipment: "text",
        }],
        nutrition: ["#recipeEditNutrition .recipe-edit-nutrition-row", {}],
    };
    const config = collectionSelectors[parts[0]];
    const index = Number.parseInt(parts[1], 10);
    if (!config || !Number.isInteger(index)) {
        return null;
    }
    const row = document.querySelectorAll(config[0])[index];
    const field = config[1][parts[2]] || parts[2] || "";
    return row ? row.querySelector(`[data-field="${field}"]`) : null;
}

function showRecipeEditorValidationErrors(errors, options = {}) {
    const summary = document.getElementById("recipeEditValidationSummary");
    const list = summary ? summary.querySelector("[data-recipe-edit-validation-errors]") : null;
    const safeErrors = Array.isArray(errors) ? errors.filter(error => error && error.message) : [];
    if (!summary || !list || !safeErrors.length) {
        return;
    }

    list.replaceChildren(...safeErrors.map(error => {
        const item = document.createElement("li");
        item.textContent = error.message;
        return item;
    }));
    summary.hidden = false;

    const firstErrorControl = safeErrors.map(error => error.control).find(Boolean);
    const optionRow = firstErrorControl && firstErrorControl.closest
        ? firstErrorControl.closest("[data-substitution-option-row]")
        : null;
    if (optionRow) {
        const ingredientRow = recipeIngredientParentRowFromControl(optionRow);
        setRecipeIngredientSubstitutionsExpanded(ingredientRow, null, true, { restoreOtherEdits: false });
        const card = optionRow.closest(".recipe-edit-alternative-card");
        if (card) setRecipeIngredientAlternativeEditMode(card, true, { restoreOtherEdits: false });
    } else if (firstErrorControl && firstErrorControl.closest) {
        const instructionRow = firstErrorControl.closest(".recipe-edit-read-first-instruction");
        const ingredientRow = firstErrorControl.closest(".recipe-edit-read-first-row");
        if (instructionRow) {
            setRecipeInstructionEditMode(instructionRow, true, { restoreOtherEdits: false });
        } else if (ingredientRow) {
            setRecipeIngredientEditMode(ingredientRow, true, { restoreOtherEdits: false });
        }
    }

    const firstControl = safeErrors.map(error => error.control).find(control => {
        return control && !control.hidden && !control.disabled && typeof control.focus === "function";
    });
    if (options.focus !== false) {
        if (firstControl) {
            firstControl.scrollIntoView({ behavior: "smooth", block: "center" });
            firstControl.focus({ preventScroll: true });
        } else {
            summary.scrollIntoView({ behavior: "smooth", block: "start" });
            summary.focus({ preventScroll: true });
        }
    }
}

function validateRecipeEditor(form, payload) {
    clearRecipeEditorValidation(form);
    const errors = [];
    const recipe = payload && payload.recipe && typeof payload.recipe === "object" ? payload.recipe : {};
    const title = document.getElementById("recipeEditTitleInput");
    if (!String(recipe.recipe_title || "").trim()) {
        addRecipeEditorValidationError(errors, "Enter a recipe title.", title, "recipe_title");
    }

    if (!String(payload && payload.original_url || "").trim()) {
        addRecipeEditorValidationError(
            errors,
            "The recipe identifier is missing. Reopen the recipe before saving.",
            document.getElementById("recipeEditSourceUrl"),
            "original_url",
        );
    }

    const ingredientRows = recipeEditIngredientRows();
    let ingredientCount = 0;
    ingredientRows.forEach((row, index) => {
        const name = recipeIngredientDirectField(row, "ingredient");
        const originalText = recipeIngredientDirectField(row, "original_text");
        const quantity = recipeIngredientDirectField(row, "quantity");
        const unit = recipeIngredientDirectField(row, "unit");
        const meaningful = [name, originalText, quantity, unit].some(control => String(control ? control.value : "").trim());
        const hasName = Boolean(String(name ? name.value : "").trim() || String(originalText ? originalText.value : "").trim());
        if (hasName) {
            ingredientCount += 1;
        } else if (meaningful) {
            addRecipeEditorValidationError(errors, `Ingredient ${index + 1} needs a name.`, name, `ingredients.${index}.ingredient`);
        }
        if (recipeEditorNumericExpressionIsMalformed(quantity ? quantity.value : "")) {
            addRecipeEditorValidationError(errors, `Ingredient ${index + 1} has an invalid amount.`, quantity, `ingredients.${index}.quantity`);
        }
        if (unit && unit.validationMessage) {
            addRecipeEditorValidationError(errors, `Ingredient ${index + 1}: ${unit.validationMessage}`, unit, `ingredients.${index}.unit`);
        }

        const scope = recipeIngredientSubstitutionContainer(row) || row;
        scope.querySelectorAll("[data-substitution-option-row]").forEach((optionRow, optionIndex) => {
            const optionName = recipeIngredientDirectField(optionRow, "ingredient");
            const optionQuantity = recipeIngredientDirectField(optionRow, "quantity");
            const optionUnit = recipeIngredientDirectField(optionRow, "unit");
            const hasOptionValues = [optionName, optionQuantity, optionUnit].some(control => String(control ? control.value : "").trim());
            if (hasOptionValues && !String(optionName ? optionName.value : "").trim()) {
                addRecipeEditorValidationError(errors, `Alternative ${optionIndex + 1} for ingredient ${index + 1} needs a name.`, optionName);
            }
            if (recipeEditorNumericExpressionIsMalformed(optionQuantity ? optionQuantity.value : "")) {
                addRecipeEditorValidationError(errors, `Alternative ${optionIndex + 1} for ingredient ${index + 1} has an invalid amount.`, optionQuantity);
            }
            if (optionUnit && optionUnit.validationMessage) {
                addRecipeEditorValidationError(errors, `Alternative ${optionIndex + 1} for ingredient ${index + 1}: ${optionUnit.validationMessage}`, optionUnit);
            }
        });
    });
    if (!ingredientCount) {
        const firstIngredient = ingredientRows[0] && recipeIngredientDirectField(ingredientRows[0], "ingredient");
        addRecipeEditorValidationError(errors, "Add at least one ingredient.", firstIngredient, "ingredients");
    }

    const instructionRows = [...document.querySelectorAll("#recipeEditInstructions .recipe-edit-instruction-row")];
    let populatedInstructionCount = 0;
    let partialInstructionCount = 0;
    instructionRows.forEach((row, index) => {
        const textControl = row.querySelector('[data-field="text"]');
        const step = row.querySelector('[data-field="step_number"]');
        const text = String(textControl ? textControl.value : "").trim();
        const stepText = String(step ? step.value : "").trim();
        const hasRowMetadata = [
            "id",
            "instruction_id",
            "step_id",
            "row_id",
            "step_image_url",
            "step_image_generated_at",
            "step_image_prompt",
        ].some(field => {
            const control = row.querySelector(`[data-field="${field}"]`);
            return Boolean(String(control ? control.value : "").trim());
        });
        const meaningful = Boolean(stepText || hasRowMetadata);

        if (!text) {
            if (meaningful) {
                partialInstructionCount += 1;
                addRecipeEditorValidationError(
                    errors,
                    `Instruction ${index + 1} needs instruction text.`,
                    textControl,
                    `instructions.${index}.instruction`,
                );
            }
            return;
        }

        populatedInstructionCount += 1;
        const stepNumber = Number(stepText);
        if (!/^\d+$/.test(stepText) || !Number.isInteger(stepNumber) || stepNumber <= 0) {
            addRecipeEditorValidationError(
                errors,
                `Instruction ${index + 1} has an invalid step number.`,
                step,
                `instructions.${index}.step_number`,
            );
        }
    });
    if (!populatedInstructionCount && !partialInstructionCount) {
        addRecipeEditorValidationError(
            errors,
            "Add at least one instruction step.",
            instructionRows[0] ? instructionRows[0].querySelector('[data-field="text"]') : null,
            "instructions",
        );
    }

    document.querySelectorAll("#recipeEditEquipment .recipe-edit-equipment-row").forEach((row, index) => {
        const textControl = row.querySelector('[data-field="text"]');
        const text = String(textControl ? textControl.value : "").trim();
        const hasRowMetadata = [
            "id",
            "equipment_id",
            "equipment_row_id",
            "row_id",
            "equipment_image_url",
            "equipment_image_generated_at",
            "equipment_image_prompt",
        ].some(field => {
            const control = row.querySelector(`[data-field="${field}"]`);
            return Boolean(String(control ? control.value : "").trim());
        });
        if (!text && hasRowMetadata) {
            addRecipeEditorValidationError(
                errors,
                `Equipment row ${index + 1} needs an equipment name.`,
                textControl,
                `equipment.${index}.equipment`,
            );
        }
    });

    document.querySelectorAll("#recipeEditNutrition .recipe-edit-nutrition-row").forEach((row, index) => {
        const key = row.querySelector('[data-field="key"]');
        const value = row.querySelector('[data-field="value"]');
        const keyText = String(key ? key.value : "").trim();
        const valueText = String(value ? value.value : "").trim();
        if (keyText && !valueText) {
            addRecipeEditorValidationError(errors, `Nutrition row ${index + 1} needs a value.`, value, `nutrition.${index}.value`);
        } else if (!keyText && valueText) {
            addRecipeEditorValidationError(errors, `Nutrition row ${index + 1} needs a label.`, key, `nutrition.${index}.key`);
        } else if (valueText && recipeEditorNumericExpressionIsMalformed(valueText, { allowUnitSuffix: true })) {
            addRecipeEditorValidationError(errors, `Nutrition row ${index + 1} has an invalid numeric value.`, value, `nutrition.${index}.value`);
        }
    });

    if (errors.length) {
        showRecipeEditorValidationErrors(errors);
    }
    return { valid: errors.length === 0, errors };
}

function applyRecipeEditorServerFieldErrors(fieldErrors = {}) {
    const errors = [];
    Object.entries(fieldErrors && typeof fieldErrors === "object" ? fieldErrors : {}).forEach(([field, message]) => {
        const control = recipeEditorControlForFieldPath(field);
        addRecipeEditorValidationError(errors, String(message || "This field needs attention."), control, field);
    });
    if (errors.length) {
        showRecipeEditorValidationErrors(errors);
    }
    return errors;
}

function setRecipeEditorSavingState(form, saving) {
    if (!form) {
        return;
    }
    form.setAttribute("aria-busy", saving ? "true" : "false");
    form.querySelectorAll("[data-recipe-edit-save]").forEach(button => {
        button.disabled = saving ? true : form.dataset.recipeEditDirty !== "true";
        button.setAttribute("aria-busy", saving ? "true" : "false");
        const label = button.querySelector("[data-recipe-edit-save-label]");
        const spinner = button.querySelector("[data-recipe-edit-save-spinner]");
        if (label) {
            label.textContent = saving ? "Saving…" : "Save Recipe";
        }
        if (spinner) {
            spinner.hidden = !saving;
        }
    });
}

async function recipeEditorJsonResponse(response) {
    const contentType = String(response.headers.get("content-type") || "").toLowerCase();
    const responseText = await response.text();
    if (!responseText) {
        return {};
    }
    if (!contentType.includes("json")) {
        if (!response.ok) {
            return { ok: false, error: `The server returned an unexpected ${response.status} response.` };
        }
        throw new Error("The server returned an invalid response.");
    }
    try {
        return JSON.parse(responseText);
    } catch (err) {
        throw new Error("The server returned an invalid response.");
    }
}

function recipeEditorSaveDebug(eventName, details = {}) {
    const enabled = typeof window !== "undefined"
        && (
            window.RECIPE_EDITOR_SAVE_DEBUG === true
            || document.documentElement.dataset.recipeSaveDebug === "true"
        );
    if (!enabled) {
        return;
    }
    console.debug(`[Recipe save] ${eventName}`, details);
}

function updateRecipeEditorSavedIdentity(identity = {}, submittedPayload = {}, options = {}) {
    const savedSourceUrl = String(identity.source_url || "").trim();
    const savedRecipeId = String(identity.recipe_id || "").trim();
    const updatedAt = String(identity.updated_at || "").trim();
    const form = document.getElementById("recipeEditForm");

    if (savedSourceUrl) {
        setValue("recipeEditOriginalUrl", savedSourceUrl);
        if (options.updateSourceField !== false) {
            setRecipeEditorSourceUrlField({ source_url: savedSourceUrl }, savedSourceUrl, {
                silent: true,
                skipEmpty: true,
            });
        }
        if (recipeEditorStandalonePageIsActive()) {
            document.body.dataset.recipeEditUrl = savedSourceUrl;
            window.history.replaceState(window.history.state, "", recipeEditPageUrl(savedSourceUrl));
        }
    }
    if (savedRecipeId) {
        setValue("recipeEditId", savedRecipeId);
    }
    if (form && updatedAt) {
        form.dataset.recipeUpdatedAt = updatedAt;
    }

    return {
        recipe_id: savedRecipeId || String(submittedPayload.recipe_id || "").trim(),
        source_url: savedSourceUrl || String(submittedPayload.original_url || "").trim(),
        updated_at: updatedAt,
    };
}

function normalizeRecipeEditorCoverImage(value = {}) {
    if (typeof value === "string") {
        const url = value.trim();
        return url ? { url, src: url } : {};
    }

    if (!value || typeof value !== "object") {
        return {};
    }

    const path = String(value.path || "").trim();
    const url = String(value.url || "").trim();
    const src = String(value.src || "").trim();
    const alt = String(value.alt || "").trim();
    const mimeType = String(value.mime_type || value.mimeType || "").trim();
    const source = String(value.source || "").trim();
    const thumbUrl = String(value.thumb_url || value.thumbUrl || "").trim();
    const cardUrl = String(value.card_url || value.cardUrl || "").trim();
    const detailUrl = String(value.detail_url || value.detailUrl || "").trim();
    const srcset = String(value.srcset || "").trim();
    const fullUrl = String(value.full_url || value.fullUrl || "").trim();
    const imagePrompt = String(value.prompt || value.image_prompt || value.cover_image_prompt || "").trim();
    const normalized = {};

    if (path) {
        normalized.path = path;
    }

    if (url) {
        normalized.url = url;
    } else if (!path && src) {
        normalized.url = src;
    }

    if (src) {
        normalized.src = src;
    }

    if (alt) {
        normalized.alt = alt;
    }

    if (mimeType) {
        normalized.mime_type = mimeType;
    }

    if (source) {
        normalized.source = source;
    }

    if (thumbUrl) {
        normalized.thumb_url = thumbUrl;
    }

    if (cardUrl) {
        normalized.card_url = cardUrl;
    }

    if (detailUrl) {
        normalized.detail_url = detailUrl;
    }

    if (srcset) {
        normalized.srcset = srcset;
    }

    if (fullUrl) {
        normalized.full_url = fullUrl;
    }

    if (imagePrompt) {
        normalized.prompt = imagePrompt;
        normalized.image_prompt = imagePrompt;
    }

    return normalized.path || normalized.url || normalized.src ? normalized : {};
}

function setRecipeEditorCoverPrompt(imagePrompt, hasImage = false) {
    const promptPanel = document.getElementById("recipeEditCoverPrompt");
    const promptText = document.getElementById("recipeEditCoverPromptText");
    const promptValue = String(imagePrompt || "").trim();
    const shouldShow = Boolean(hasImage && promptValue);

    if (!promptPanel || !promptText) {
        return;
    }

    promptText.textContent = promptValue;
    promptPanel.hidden = !shouldShow;
    setRecipeImagePromptCollapsed(promptPanel, true);
}

function setRecipeEditorCoverImageViewLoaded(image, loaded) {
    const view = image ? image.closest("[data-recipe-edit-cover-view]") : null;
    const empty = view ? view.querySelector("[data-recipe-edit-cover-empty]") : null;
    if (!image || !view) {
        return false;
    }

    image.hidden = !loaded;
    if (empty) empty.hidden = loaded;
    view.classList.toggle("has-cover", loaded);
    return false;
}

function handleRecipeEditorCoverImageLoad(image) {
    return setRecipeEditorCoverImageViewLoaded(image, true);
}

function handleRecipeEditorCoverImageError(image) {
    if (image) image.removeAttribute("srcset");
    return setRecipeEditorCoverImageViewLoaded(image, false);
}

function setRecipeEditorCoverImage(coverImage = {}, fallbackAlt = "") {
    const normalized = normalizeRecipeEditorCoverImage(coverImage);
    const fields = [...document.querySelectorAll("[data-recipe-edit-cover-view]")];
    const images = [...document.querySelectorAll("[data-recipe-edit-cover-image]")];
    const emptyStates = [...document.querySelectorAll("[data-recipe-edit-cover-empty]")];
    const status = document.getElementById("recipeEditCoverStatus");
    const uploadLabel = document.getElementById("recipeEditCoverUploadLabel");
    const generateLabel = document.getElementById("recipeEditCoverGenerateLabel");
    const generateButton = document.getElementById("recipeEditCoverGenerate");
    const removeButtons = [...document.querySelectorAll("[data-recipe-edit-cover-remove]")];
    const alt = normalized.alt || fallbackAlt || "Recipe title image";
    const src = normalized.src || normalized.url || "";
    const displaySrc = normalized.card_url || normalized.thumb_url || src;
    const fullSrc = normalized.full_url || src;
    const hasImage = Boolean(src || normalized.path || normalized.url);

    fields.forEach(field => {
        field.classList.toggle("has-cover", hasImage);
    });

    images.forEach(image => {
        const nextSrc = src || (
            normalized.path && recipeEditorCurrentUrl()
                ? `/recipe_cover_image?url=${encodeURIComponent(recipeEditorCurrentUrl())}`
                : ""
        );
        image.alt = alt;
        if (displaySrc || nextSrc) {
            image.src = displaySrc || nextSrc;
            image.dataset.fullSrc = fullSrc || nextSrc;
            image.loading = "lazy";
            image.decoding = "async";
            if (normalized.srcset) {
                image.srcset = normalized.srcset;
                image.sizes = "(max-width: 900px) 92vw, 720px";
            } else {
                image.removeAttribute("srcset");
            }
            image.hidden = false;
        } else {
            image.removeAttribute("src");
            image.removeAttribute("srcset");
            image.removeAttribute("data-full-src");
            image.hidden = true;
        }
    });

    emptyStates.forEach(empty => {
        empty.hidden = hasImage;
    });

    if (status) {
        status.textContent = hasImage
            ? "This image is shown on recipe cards."
            : "Upload or replace the image shown on recipe cards.";
    }

    if (uploadLabel) {
        uploadLabel.textContent = recipeEditorStandalonePageIsActive()
            ? "Replace Image"
            : (hasImage ? "Replace title image" : "Upload title image");
    }

    if (generateLabel) {
        generateLabel.textContent = recipeEditorStandalonePageIsActive()
            ? (hasImage ? "AI Regenerate" : "AI Generate")
            : (hasImage ? "Regenerate title image" : "Generate title image");
    }

    if (generateButton) {
        generateButton.dataset.hasCoverImage = hasImage ? "true" : "false";
    }

    removeButtons.forEach(removeButton => {
        removeButton.hidden = !hasImage;
        removeButton.disabled = !hasImage;
    });

    document.querySelectorAll("[data-recipe-edit-cover-generate-label]").forEach(label => {
        label.textContent = label.hasAttribute("data-recipe-edit-mobile-generate-label")
            ? "AI Generate"
            : (hasImage ? "AI Regenerate" : "AI Generate");
    });

    closeRecipeImageChangeActions();

    setValue("recipeEditCoverPath", normalized.path || "");
    setValue("recipeEditCoverUrl", normalized.url || "");
    setValue("recipeEditCoverAlt", alt);
    setValue("recipeEditCoverMimeType", normalized.mime_type || "");
    setValue("recipeEditCoverSource", normalized.source || "");
    setRecipeEditorCoverPrompt(normalized.prompt || normalized.image_prompt || "", hasImage);
    updateRecipeEditContextPanels();
}

function collectRecipeEditorCoverImage() {
    const pathInput = document.getElementById("recipeEditCoverPath");
    const urlInput = document.getElementById("recipeEditCoverUrl");
    const altInput = document.getElementById("recipeEditCoverAlt");
    const mimeTypeInput = document.getElementById("recipeEditCoverMimeType");
    const sourceInput = document.getElementById("recipeEditCoverSource");
    const promptText = document.getElementById("recipeEditCoverPromptText");
    const path = String(pathInput ? pathInput.value : "").trim();
    const url = String(urlInput ? urlInput.value : "").trim();
    const alt = String(altInput ? altInput.value : "").trim();
    const mimeType = String(mimeTypeInput ? mimeTypeInput.value : "").trim();
    const source = String(sourceInput ? sourceInput.value : "").trim();
    const prompt = recipeEditorPersistableText(promptText ? promptText.textContent : "");
    const coverImage = {};

    if (path) {
        coverImage.path = path;
    }

    if (url) {
        coverImage.url = url;
    }

    if (alt) {
        coverImage.alt = alt;
    }

    if (mimeType) {
        coverImage.mime_type = mimeType;
    }

    if (source) {
        coverImage.source = source;
    }

    if (prompt) {
        coverImage.prompt = prompt;
        coverImage.image_prompt = prompt;
    }

    return coverImage.path || coverImage.url || coverImage.prompt ? coverImage : {};
}

function normalizeRecipeCoverImageSnapshot(value = {}) {
    const coverImage = normalizeRecipeEditorCoverImage(value);

    return {
        path: String(coverImage.path || "").trim(),
        url: String(coverImage.url || "").trim(),
        alt: String(coverImage.alt || "").trim(),
        mime_type: String(coverImage.mime_type || "").trim(),
        source: String(coverImage.source || "").trim(),
    };
}

function cacheBustRecipeCoverSrc(src) {
    if (!src || !src.startsWith("/recipe_cover_image")) {
        return src || "";
    }

    const separator = src.includes("?") ? "&" : "?";
    return `${src}${separator}_cover=${Date.now()}`;
}

const RECIPE_IMAGE_PROVIDER_STORAGE_KEY = "recipe-image-provider";
const RECIPE_IMAGE_THUMBNAIL_SIZE_STORAGE_KEY = "recipe-image-thumbnail-size";
const RECIPE_IMAGE_THUMBNAIL_DEFAULT_SIZE = 64;
const RECIPE_IMAGE_THUMBNAIL_MIN_SIZE = 32;
const RECIPE_IMAGE_THUMBNAIL_MAX_SIZE = 80;
const RECIPE_IMAGE_THUMBNAIL_STEP_SIZE = 8;
let recipeImageProviderSelectorEventsBound = false;
let recipeImageThumbnailSize = RECIPE_IMAGE_THUMBNAIL_DEFAULT_SIZE;

function normalizeRecipeImageProvider(value) {
    const provider = String(value || "").trim().toLowerCase().replace(/-/g, "_");

    if (provider === "chatgpt" || provider === "chat_gpt" || provider === "gpt") {
        return "openai";
    }

    return provider === "openai" || provider === "comfyui" ? provider : "";
}

function selectedRecipeImageProvider() {
    if (recipeEditorStandalonePageIsActive()) {
        return "openai";
    }
    const select = document.querySelector("[data-recipe-image-provider-select]")
        || document.getElementById("recipeEditImageProvider");

    return rememberedRecipeImageProvider()
        || normalizeRecipeImageProvider(select ? select.value : "");
}

function recipeImageProviderPayload() {
    const provider = selectedRecipeImageProvider();

    return provider ? { image_provider: provider } : {};
}

function rememberedRecipeImageProvider() {
    try {
        return normalizeRecipeImageProvider(
            window.localStorage
                ? window.localStorage.getItem(RECIPE_IMAGE_PROVIDER_STORAGE_KEY)
                : ""
        );
    } catch (err) {
        console.warn("Unable to restore recipe image provider selection.", err);
        return "";
    }
}

function setAllRecipeImageProviderSelectors(provider) {
    const normalizedProvider = normalizeRecipeImageProvider(provider);

    if (!normalizedProvider) {
        return;
    }

    document.querySelectorAll("[data-recipe-image-provider-select]").forEach(select => {
        if (select && normalizeRecipeImageProvider(select.value) !== normalizedProvider) {
            select.value = normalizedProvider;
        }
    });
}

function rememberRecipeImageProvider(provider) {
    const normalizedProvider = normalizeRecipeImageProvider(provider);

    if (!normalizedProvider) {
        return;
    }

    setAllRecipeImageProviderSelectors(normalizedProvider);
    try {
        if (window.localStorage) {
            window.localStorage.setItem(RECIPE_IMAGE_PROVIDER_STORAGE_KEY, normalizedProvider);
        }
    } catch (err) {
        console.warn("Unable to remember recipe image provider selection.", err);
    }
}

function refreshRecipeImageProviderSelectors(root = document) {
    const provider = rememberedRecipeImageProvider() || selectedRecipeImageProvider() || "openai";
    const scope = root && typeof root.querySelectorAll === "function" ? root : document;

    scope.querySelectorAll("[data-recipe-image-provider-select]").forEach(select => {
        select.value = provider;
    });
}

function initRecipeImageProviderSelector() {
    refreshRecipeImageProviderSelectors(document);

    if (recipeImageProviderSelectorEventsBound) {
        return;
    }

    recipeImageProviderSelectorEventsBound = true;
    document.addEventListener("change", event => {
        const select = event.target && event.target.closest
            ? event.target.closest("[data-recipe-image-provider-select]")
            : null;
        if (select) {
            rememberRecipeImageProvider(select.value);
        }
    });
}

function normalizeRecipeImageThumbnailSize(value) {
    const parsed = Number.parseInt(value, 10);

    if (!Number.isFinite(parsed)) {
        return RECIPE_IMAGE_THUMBNAIL_DEFAULT_SIZE;
    }

    const stepped = Math.round(parsed / RECIPE_IMAGE_THUMBNAIL_STEP_SIZE) * RECIPE_IMAGE_THUMBNAIL_STEP_SIZE;
    return Math.max(
        RECIPE_IMAGE_THUMBNAIL_MIN_SIZE,
        Math.min(RECIPE_IMAGE_THUMBNAIL_MAX_SIZE, stepped)
    );
}

function rememberedRecipeImageThumbnailSize() {
    try {
        return normalizeRecipeImageThumbnailSize(
            window.localStorage
                ? window.localStorage.getItem(RECIPE_IMAGE_THUMBNAIL_SIZE_STORAGE_KEY)
                : ""
        );
    } catch (err) {
        console.warn("Unable to restore recipe image thumbnail size.", err);
        return RECIPE_IMAGE_THUMBNAIL_DEFAULT_SIZE;
    }
}

function updateRecipeImageThumbnailSizeControls(size = recipeImageThumbnailSize) {
    document.querySelectorAll("[data-recipe-thumbnail-size-value]").forEach(label => {
        label.textContent = `${size}px`;
    });
    document.querySelectorAll("[data-recipe-thumbnail-size-decrease]").forEach(button => {
        button.disabled = size <= RECIPE_IMAGE_THUMBNAIL_MIN_SIZE;
    });
    document.querySelectorAll("[data-recipe-thumbnail-size-increase]").forEach(button => {
        button.disabled = size >= RECIPE_IMAGE_THUMBNAIL_MAX_SIZE;
    });
}

function applyRecipeImageThumbnailSize(size, options = {}) {
    const normalizedSize = normalizeRecipeImageThumbnailSize(size);
    recipeImageThumbnailSize = normalizedSize;
    document.documentElement.style.setProperty("--recipe-edit-thumbnail-size", `${normalizedSize}px`);
    document.documentElement.style.setProperty("--recipe-edit-thumbnail-slot", `${normalizedSize + 2}px`);

    if (options.persist) {
        try {
            if (window.localStorage) {
                window.localStorage.setItem(RECIPE_IMAGE_THUMBNAIL_SIZE_STORAGE_KEY, String(normalizedSize));
            }
        } catch (err) {
            console.warn("Unable to remember recipe image thumbnail size.", err);
        }
    }

    updateRecipeImageThumbnailSizeControls(normalizedSize);
    return normalizedSize;
}

function initRecipeImageThumbnailSizeControls() {
    applyRecipeImageThumbnailSize(rememberedRecipeImageThumbnailSize());
}

function changeRecipeImageThumbnailSize(button, direction) {
    const stepDirection = Number(direction) < 0 ? -1 : 1;
    applyRecipeImageThumbnailSize(
        recipeImageThumbnailSize + (stepDirection * RECIPE_IMAGE_THUMBNAIL_STEP_SIZE),
        { persist: true }
    );
    return false;
}

function resetRecipeImageThumbnailSize(button) {
    applyRecipeImageThumbnailSize(RECIPE_IMAGE_THUMBNAIL_DEFAULT_SIZE, { persist: true });
    return false;
}

function recipeImageProviderFieldHtml(selectId = "") {
    if (recipeEditorStandalonePageIsActive()) {
        return "";
    }
    const idAttribute = selectId ? ` id="${escapeAttribute(selectId)}"` : "";
    const forAttribute = selectId ? ` for="${escapeAttribute(selectId)}"` : "";

    return `
        <label class="recipe-edit-image-provider-field recipe-image-provider-inline-field"${forAttribute}>
            <span>Image Generator</span>
            <select${idAttribute} data-recipe-image-provider-select>
                <option value="openai" selected>ChatGPT / OpenAI</option>
                <option value="comfyui">ComfyUI local</option>
            </select>
        </label>
    `;
}

function toggleRecipeImageChangeActions(button) {
    const wrapper = button?.closest(".recipe-edit-cover-details");
    const openMenu = wrapper?.querySelector("[data-recipe-image-change-actions]");
    if (openMenu) {
        closeRecipeImageChangeActions({ restoreFocus: true });
        return false;
    }
    closeRecipeImageChangeActions();
    const template = wrapper?.querySelector("[data-recipe-image-change-menu-template]");
    const actions = template?.content.firstElementChild?.cloneNode(true);
    if (actions) {
        wrapper.appendChild(actions);
        const generateButton = actions.querySelector("#recipeEditCoverGenerate");
        if (generateButton && recipeCoverImageGenerationPending) {
            generateButton.disabled = true;
            generateButton.querySelector("span").textContent = "Generating...";
        }
        button.setAttribute("aria-expanded", "true");
        actions.querySelector("button")?.focus();
    }
    return false;
}

function closeRecipeImageChangeActions(options = {}) {
    const actions = document.querySelector("[data-recipe-image-change-actions]");
    const button = document.querySelector(".recipe-edit-image-card .recipe-edit-cover-primary-actions [aria-expanded]");
    if (actions) actions.remove();
    if (button) button.setAttribute("aria-expanded", "false");
    if (options.restoreFocus) button?.focus({ preventScroll: true });
}

document.addEventListener("pointerdown", event => {
    const actions = document.querySelector("[data-recipe-image-change-actions]");
    const toggle = document.querySelector(".recipe-edit-image-card .recipe-edit-cover-primary-actions [aria-expanded]");
    if (!actions || actions.contains(event.target) || toggle?.contains(event.target)) return;
    closeRecipeImageChangeActions();
});

document.addEventListener("keydown", event => {
    const actions = document.querySelector("[data-recipe-image-change-actions]");
    if (event.key === "Escape" && actions) {
        event.preventDefault();
        closeRecipeImageChangeActions({ restoreFocus: true });
    }
});

function openRecipeCoverUpload() {
    const input = document.getElementById("recipeEditCoverUpload");

    closeRecipeImageChangeActions();

    if (input) {
        input.click();
    }

    return false;
}

async function uploadRecipeCoverImage(input) {
    const file = input && input.files ? input.files[0] : null;

    if (!file) {
        return false;
    }

    const originalUrl = recipeEditorCurrentUrl();
    const sourceUrl = recipeEditorSourceUrlForSave() || originalUrl;
    const titleInput = document.getElementById("recipeEditTitleInput");
    const displayInput = document.getElementById("recipeEditDisplayName");
    const fallbackAlt = (titleInput ? titleInput.value.trim() : "")
        || (displayInput ? displayInput.value.trim() : "")
        || "Recipe title image";

    if (!originalUrl) {
        setRecipeEditStatus("Unable to upload title image: missing recipe URL.", true);
        input.value = "";
        return false;
    }

    const formData = new FormData();
    formData.append("url", originalUrl);
    formData.append("source_url", sourceUrl);
    formData.append("alt", fallbackAlt);
    formData.append("cover_image", file);

    try {
        setRecipeEditStatus("Uploading title image...");
        const response = await fetch("/api/recipe_cover_image", {
            method: "POST",
            body: formData,
        });
        const data = await response.json();

        if (!response.ok || !data.ok) {
            throw new Error((data && data.error) || "Unable to upload title image.");
        }

        const coverImage = normalizeRecipeEditorCoverImage(data.cover_image || {});
        if (coverImage.src) {
            coverImage.src = cacheBustRecipeCoverSrc(coverImage.src);
        }

        setRecipeEditorCoverImage(coverImage, fallbackAlt);
        rememberRecipeEditorCoverImageAsSaved();
        setRecipeEditStatus("Title image updated. Save Recipe to keep any other edits.");
        showRecipeQuantityUpdatedMessage("", "", "", "Recipe title image updated.");
    } catch (err) {
        console.warn("Unable to upload recipe title image.", err);
        setRecipeEditStatus(err.message || "Unable to upload title image.", true);
    } finally {
        if (input) {
            input.value = "";
        }
    }

    return false;
}

function recipeCoverImageGenerationErrorMessage(data, fallbackMessage = "Unable to generate title image.") {
    const localUnavailable = Boolean(
        data && (
            data.local_generation_unavailable
            || data.error_code === "COMFYUI_UNAVAILABLE"
            || data.error_code === "COMFYUI_TIMEOUT"
            || data.error_code === "COMFYUI_GENERATION_FAILED"
            || data.error_code === "COMFYUI_CHECKPOINT_NOT_FOUND"
            || data.error_code === "LOCAL_IMAGE_GENERATION_UNAVAILABLE"
        )
    );

    return localUnavailable
        ? "Local image generation is unavailable. Start ComfyUI and try again."
        : ((data && data.error) || fallbackMessage);
}

async function requestRecipeCoverImageGeneration(payload = {}, signal = null) {
    const response = await fetch("/api/recipe_cover_image/generate", {
        method: "POST",
        headers: {
            "Content-Type": "application/json",
        },
        body: JSON.stringify({
            ...payload,
            ...recipeImageProviderPayload(),
        }),
        signal,
    });
    let data = {};
    try {
        data = await response.json();
    } catch (err) {
        data = {};
    }
    syncOpenAiUsageDashboardFromResponse(data);

    if (!response.ok || !data.ok) {
        throw new Error(recipeCoverImageGenerationErrorMessage(data));
    }

    return data;
}

async function generateRecipeCoverImage(button) {
    if (recipeCoverImageGenerationPending) return false;
    closeRecipeImageChangeActions();
    const originalUrl = recipeEditorCurrentUrl();
    const titleInput = document.getElementById("recipeEditTitleInput");
    const displayInput = document.getElementById("recipeEditDisplayName");
    const fallbackAlt = (titleInput ? titleInput.value.trim() : "")
        || (displayInput ? displayInput.value.trim() : "")
        || "Recipe title image";
    const currentCoverImage = collectRecipeEditorCoverImage();
    const hasCoverImage = Boolean(currentCoverImage.path || currentCoverImage.url);

    if (!originalUrl) {
        setRecipeEditStatus("Unable to generate title image: missing recipe URL.", true);
        return false;
    }
    recipeCoverImageGenerationPending = true;

    const buttonLabel = button
        ? button.querySelector("[data-recipe-edit-cover-generate-label], span:last-child")
        : document.getElementById("recipeEditCoverGenerateLabel");
    const originalText = buttonLabel
        ? buttonLabel.textContent
        : (button ? button.textContent : "");
    const controller = new AbortController();
    const timeout = window.setTimeout(() => controller.abort(), 150000);

    try {
        if (button) {
            button.disabled = true;
            if (buttonLabel) {
                buttonLabel.textContent = hasCoverImage ? "Regenerating..." : "Generating...";
            } else {
                button.textContent = hasCoverImage ? "Regenerating..." : "Generating...";
            }
        }
        setRecipeEditStatus(hasCoverImage ? "Regenerating title image..." : "Generating title image...");

        const data = await requestRecipeCoverImageGeneration({
            url: originalUrl,
            alt: fallbackAlt,
            overwrite: hasCoverImage,
        }, controller.signal);

        const coverImage = normalizeRecipeEditorCoverImage(data.cover_image || {});
        const imagePrompt = String(
            data.cover_image_prompt
            || data.image_prompt
            || (data.recipe && data.recipe.cover_image_prompt)
            || ""
        ).trim();
        if (imagePrompt) {
            coverImage.prompt = imagePrompt;
            coverImage.image_prompt = imagePrompt;
        }
        if (coverImage.src) {
            coverImage.src = cacheBustRecipeCoverSrc(coverImage.src);
        }

        setRecipeEditorCoverImage(coverImage, fallbackAlt);
        rememberRecipeEditorCoverImageAsSaved();
        setRecipeEditStatus("Title image generated. Save Recipe to keep any other edits.");
        showRecipeQuantityUpdatedMessage("", "", "", "Recipe title image generated.");
    } catch (err) {
        const timedOut = err && err.name === "AbortError";
        const message = timedOut
            ? "Title image generation timed out. Please try again."
            : (err.message || "Unable to generate title image.");
        console.warn("Unable to generate recipe title image.", err);
        setRecipeEditStatus(message, true);
    } finally {
        recipeCoverImageGenerationPending = false;
        window.clearTimeout(timeout);
        if (button) {
            button.disabled = false;
            if (buttonLabel) {
                buttonLabel.textContent = originalText || (hasCoverImage ? "Regenerate title image" : "Generate title image");
            } else {
                button.textContent = originalText || (hasCoverImage ? "Regenerate title image" : "Generate title image");
            }
        }
    }

    return false;
}

async function removeRecipeCoverImage(button) {
    const originalUrl = recipeEditorCurrentUrl();
    const currentCoverImage = collectRecipeEditorCoverImage();
    const hasCoverImage = Boolean(currentCoverImage.path || currentCoverImage.url);

    if (!originalUrl) {
        setRecipeEditStatus("Unable to remove title image: missing recipe URL.", true);
        return false;
    }

    if (!hasCoverImage) {
        setRecipeEditorCoverImage({});
        return false;
    }

    if (!window.confirm("Remove this recipe title image?")) {
        return false;
    }

    if (button) {
        button.disabled = true;
    }

    try {
        setRecipeEditStatus("Removing title image...");
        const response = await fetch("/api/recipe_cover_image/remove", {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
            },
            body: JSON.stringify({
                url: originalUrl,
            }),
        });
        let data = {};
        try {
            data = await response.json();
        } catch (err) {
            data = {};
        }

        if (!response.ok || !data.ok) {
            throw new Error((data && data.error) || "Unable to remove title image.");
        }

        setRecipeEditorCoverImage({});
        rememberRecipeEditorCoverImageAsSaved();
        if (data.recipe && typeof data.recipe === "object") {
            recipeEditOriginalSnapshot = normalizeRecipeEditorSnapshot(data.recipe);
        } else if (recipeEditOriginalSnapshot) {
            recipeEditOriginalSnapshot.cover_image = normalizeRecipeCoverImageSnapshot({});
        }
        setRecipeEditStatus("Title image removed.");
        showRecipeQuantityUpdatedMessage("", "", "", "Recipe title image removed.");
    } catch (err) {
        console.warn("Unable to remove recipe title image.", err);
        setRecipeEditStatus(err.message || "Unable to remove title image.", true);
    } finally {
        if (button && !button.hidden) {
            button.disabled = false;
        }
    }

    return false;
}

function populateRecipeScalingControls(scaling = {}, servings = "") {
    const select = document.getElementById("recipeEditScaleMultiplier");

    if (!select) {
        return;
    }

    const options = normalizeRecipeScalingOptions(
        scaling.available_multipliers
            || scaling.multipliers
            || scaling.scaling_multipliers
            || []
    );
    const selectedMultiplier = parseRecipeScaleMultiplier(
        scaling.selected_multiplier !== undefined
            ? scaling.selected_multiplier
            : scaling.scaling_multiplier
    ) || 1;
    const baseServings = String(scaling.base_servings || servings || "").trim();

    recipeEditScalingOptions = options;
    select.innerHTML = options
        .map(option => {
            const value = String(option.value);
            const selected = Math.abs(option.value - selectedMultiplier) < 0.000001 ? " selected" : "";
            return `<option value="${escapeAttribute(value)}"${selected}>${escapeHtml(option.label)}</option>`;
        })
        .join("");
    select.dataset.baseServings = baseServings;

    const servingsInput = document.getElementById("recipeEditServings");
    if (servingsInput) {
        servingsInput.dataset.baseServings = baseServings;
    }
}

function normalizeRecipeScalingOptions(options) {
    const normalized = new Map();

    (Array.isArray(options) ? options : []).forEach(option => {
        const rawValue = typeof option === "object" && option !== null
            ? (option.value !== undefined ? option.value : option.multiplier)
            : option;
        const label = typeof option === "object" && option !== null
            ? (option.label || option.text || option.name || "")
            : "";
        const multiplier = parseRecipeScaleMultiplier(rawValue) || parseRecipeScaleMultiplier(label);

        if (!multiplier) {
            return;
        }

        normalized.set(String(multiplier), {
            label: formatRecipeScaleMultiplierLabel(multiplier),
            value: multiplier,
        });
    });

    if (!normalized.size) {
        [
            { label: "1/2x", value: 0.5 },
            { label: "1x", value: 1 },
            { label: "2x", value: 2 },
            { label: "3x", value: 3 },
        ].forEach(option => normalized.set(String(option.value), option));
    }

    if (!normalized.has("1")) {
        normalized.set("1", { label: "1x", value: 1 });
    }

    return [...normalized.values()].sort((a, b) => a.value - b.value);
}

function parseRecipeScaleMultiplier(value) {
    if (value === null || value === undefined) {
        return null;
    }

    if (typeof value === "number") {
        return value > 0 ? value : null;
    }

    let text = String(value || "").trim().toLowerCase().replace("×", "x");
    const xMatch = text.match(/(\d+(?:\.\d+)?|\d+\s*\/\s*\d+)\s*x\b/);

    if (xMatch) {
        text = xMatch[1];
    } else {
        text = text.replace(/x$/, "").trim();
    }

    text = text.replace(/\s+/g, "");
    const fractionMatch = text.match(/^(\d+)\/(\d+)$/);

    if (fractionMatch) {
        const denominator = Number(fractionMatch[2]);
        return denominator ? Number(fractionMatch[1]) / denominator : null;
    }

    const multiplier = Number(text);
    return Number.isFinite(multiplier) && multiplier > 0 ? multiplier : null;
}

function formatRecipeScaleMultiplierLabel(value) {
    const multiplier = parseRecipeScaleMultiplier(value) || 1;

    if (Math.abs(multiplier - 0.5) < 0.000001) {
        return "1/2x";
    }

    if (Number.isInteger(multiplier)) {
        return `${multiplier}x`;
    }

    return `${multiplier}x`;
}

function applyRecipeScaleMultiplier(select) {
    const multiplier = parseRecipeScaleMultiplier(select ? select.value : null) || 1;
    const servingsInput = document.getElementById("recipeEditServings");

    if (servingsInput) {
        const baseServings = (
            select && select.dataset.baseServings
                ? select.dataset.baseServings
                : servingsInput.dataset.baseServings || servingsInput.value
        );

        if (!servingsInput.dataset.baseServings) {
            servingsInput.dataset.baseServings = String(baseServings || "").trim();
        }

        servingsInput.value = scaleServingsForDisplay(baseServings, multiplier);
    }

    recipeEditIngredientRows().forEach(row => {
        applyRecipeScaleToIngredientRow(row, multiplier);
        row.querySelectorAll("[data-substitution-option-row]").forEach(optionRow => {
            applyRecipeScaleToIngredientRow(optionRow, multiplier);
        });
    });
}

function applyRecipeScaleToIngredientRow(row, multiplier) {
    const quantityInput = row.querySelector('[data-field="quantity"]');
    const unitInput = row.querySelector('[data-field="unit"]');
    const baseQuantityInput = row.querySelector('[data-field="base_quantity"]');
    const baseUnitInput = row.querySelector('[data-field="base_unit"]');

    if (quantityInput && baseQuantityInput) {
        const baseQuantity = baseQuantityInput.value || quantityInput.value.trim();

        if (!baseQuantityInput.value) {
            baseQuantityInput.value = baseQuantity;
        }

        quantityInput.value = scaleQuantityForDisplay(baseQuantity, multiplier);
    }

    if (unitInput && baseUnitInput) {
        const baseUnit = baseUnitInput.value || unitInput.value.trim();

        if (!baseUnitInput.value) {
            baseUnitInput.value = baseUnit;
        }

        unitInput.value = baseUnit;
    }
}

function collectRecipeScalingPayload() {
    const select = document.getElementById("recipeEditScaleMultiplier");
    const servingsInput = document.getElementById("recipeEditServings");
    const selectedMultiplier = parseRecipeScaleMultiplier(select ? select.value : null) || 1;
    const baseServings = (
        select && select.dataset.baseServings
            ? select.dataset.baseServings
            : servingsInput && servingsInput.dataset.baseServings
                ? servingsInput.dataset.baseServings
                : servingsInput
                    ? servingsInput.value.trim()
                    : ""
    );

    return {
        selected_multiplier: selectedMultiplier,
        base_multiplier: 1,
        base_servings: baseServings,
        available_multipliers: recipeEditScalingOptions.length
            ? recipeEditScalingOptions
            : normalizeRecipeScalingOptions([]),
    };
}

function firstRecipeEditorFoodReviewMarker() {
    return document.querySelector("#recipeEditIngredients .recipe-edit-food-warning:not([hidden])");
}

function recipeEditorFoodReviewMarkerForRow(row) {
    return row ? row.querySelector(".recipe-edit-food-warning:not([hidden])") : null;
}

async function activateRecipeEditorFoodReviewMarker(marker) {
    if (!marker || !marker.isConnected || marker.hidden) {
        return false;
    }

    await waitForNextPaint();
    return openFoodReviewAlternatives(marker);
}

function scrollRecipeEditorToFoodReview(options = {}) {
    const marker = firstRecipeEditorFoodReviewMarker();

    if (!marker) {
        return null;
    }

    const row = marker.closest(".recipe-edit-ingredient-row") || marker;
    document.querySelectorAll(".recipe-edit-review-target").forEach(element => {
        element.classList.remove("recipe-edit-review-target");
    });
    row.classList.add("recipe-edit-review-target");
    row.scrollIntoView({
        behavior: "smooth",
        block: "center",
        inline: "nearest",
    });

    const ingredientInput = row.querySelector('[data-field="ingredient"]');
    if (ingredientInput && options.focus !== false) {
        setTimeout(() => {
            try {
                ingredientInput.focus({ preventScroll: true });
            } catch (err) {
                ingredientInput.focus();
            }
        }, 250);
    }

    setTimeout(() => row.classList.remove("recipe-edit-review-target"), 2400);
    return marker;
}

function recipeEditorIngredientRowForName(ingredientName) {
    const targetKey = normalizeIngredientJumpKey(ingredientName);

    if (!targetKey) {
        return null;
    }

    const rows = recipeEditIngredientRows();
    const match = rows.reduce((best, candidate) => {
        const ingredientInput = candidate.querySelector('[data-field="ingredient"]');
        const originalTextInput = candidate.querySelector('[data-field="original_text"]');
        const ingredientKey = normalizeIngredientJumpKey(ingredientInput ? ingredientInput.value : "");
        const originalTextKey = normalizeIngredientJumpKey(originalTextInput ? originalTextInput.value : "");
        const score = ingredientJumpMatchScore(targetKey, ingredientKey, originalTextKey);

        return score > best.score ? { row: candidate, score } : best;
    }, { row: null, score: 0 });

    return match.row;
}

function scrollRecipeEditorToIngredient(ingredientName, options = {}) {
    const row = recipeEditorIngredientRowForName(ingredientName);

    if (!row) {
        setRecipeEditStatus(`Ingredient not found: ${ingredientName}`, true);
        return null;
    }

    document.querySelectorAll(".recipe-edit-review-target").forEach(element => {
        element.classList.remove("recipe-edit-review-target");
    });
    row.classList.add("recipe-edit-review-target");
    row.scrollIntoView({
        behavior: "smooth",
        block: "center",
        inline: "nearest",
    });

    const ingredientInput = row.querySelector('[data-field="ingredient"]');
    if (ingredientInput && options.focus !== false) {
        setTimeout(() => {
            try {
                ingredientInput.focus({ preventScroll: true });
                ingredientInput.select();
            } catch (err) {
                ingredientInput.focus();
            }
        }, 250);
    }

    setTimeout(() => row.classList.remove("recipe-edit-review-target"), 3000);
    return row;
}

function ingredientJumpMatchScore(targetKey, ingredientKey, originalTextKey) {
    if (!targetKey) {
        return 0;
    }

    if (ingredientKey && ingredientKey === targetKey) {
        return 1000;
    }
    if (originalTextKey && originalTextKey === targetKey) {
        return 950;
    }
    if (ingredientKey && ingredientKey.includes(targetKey)) {
        return 700 + targetKey.length;
    }
    if (originalTextKey && originalTextKey.includes(targetKey)) {
        return 650 + targetKey.length;
    }
    if (ingredientKey && ingredientKey.length >= 12 && targetKey.includes(ingredientKey)) {
        return 500 + ingredientKey.length;
    }
    if (originalTextKey && originalTextKey.length >= 12 && targetKey.includes(originalTextKey)) {
        return 450 + originalTextKey.length;
    }

    return 0;
}

function scrollRecipeEditorToSection(sectionKey) {
    const normalized = String(sectionKey || "").trim().toLowerCase().replace(/[^a-z]+/g, "");
    setRecipeEditActiveTab(normalized);
    const selector = {
        ingredients: ".recipe-edit-ingredients-section",
        equipment: ".recipe-edit-equipment-section",
        instructions: ".recipe-edit-instructions-section",
        nutrition: ".recipe-edit-nutrition-section",
        notes: ".recipe-edit-reflection-section",
        reflection: ".recipe-edit-reflection-section",
    }[normalized];
    const section = selector ? document.querySelector(selector) : null;

    if (!section) {
        setRecipeEditStatus("Recipe section not found.", true);
        return false;
    }

    document.querySelectorAll(".recipe-edit-review-target").forEach(element => {
        element.classList.remove("recipe-edit-review-target");
    });
    section.classList.add("recipe-edit-review-target");
    section.scrollIntoView({
        behavior: "smooth",
        block: "start",
        inline: "nearest",
    });

    const focusTarget = section.querySelector(
        ".recipe-edit-ingredient-row input, " +
        ".recipe-edit-equipment-row input, " +
        ".recipe-edit-instruction-row textarea, " +
        ".recipe-edit-nutrition-row input, " +
        ".recipe-edit-reflection-note-row textarea, " +
        "input, textarea, select"
    );

    const instructionRow = focusTarget && focusTarget.closest
        ? focusTarget.closest(".recipe-edit-read-first-instruction")
        : null;
    if (instructionRow) {
        setRecipeInstructionEditMode(instructionRow, true);
    }

    if (focusTarget) {
        setTimeout(() => {
            try {
                focusTarget.focus({ preventScroll: true });
                if (typeof focusTarget.select === "function") {
                    focusTarget.select();
                }
            } catch (err) {
                focusTarget.focus();
            }
        }, 250);
    }

    setTimeout(() => section.classList.remove("recipe-edit-review-target"), 3000);
    return true;
}

function normalizeIngredientJumpKey(value) {
    return String(value || "")
        .trim()
        .toLowerCase()
        .replace(/&/g, " and ")
        .replace(/[^a-z0-9]+/g, " ")
        .replace(/\s+/g, " ")
        .trim();
}

async function openFoodReviewAlternatives(marker) {
    const row = marker ? marker.closest(".recipe-edit-ingredient-row") : null;

    if (!row) {
        return false;
    }

    expandRecipeIngredientRow(row);

    if (marker.dataset.reviewKind === "ingredient_choice" || marker.dataset.reviewKind === "ingredient_text_choice") {
        await waitForNextPaint();
        focusIngredientChoiceReview(row);
        return false;
    }

    activeFoodReviewRow = row;
    activeFoodReviewAlternatives = [];
    showFoodReviewAlternativesModal();
    renderFoodReviewAlternativesLoading(row);

    try {
        const response = await fetch("/api/food_review_alternatives", {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
            },
            body: JSON.stringify(foodReviewPayloadFromRow(row)),
        });
        const data = await response.json();
        syncOpenAiUsageDashboardFromResponse(data);

        if (!response.ok || !data.ok) {
            throw new Error((data && data.error) || "Unable to load alternatives.");
        }

        activeFoodReviewAlternatives = data.alternatives || [];
        renderFoodReviewAlternatives(data);
    } catch (err) {
        console.warn("Unable to load food review alternatives.", err);
        renderFoodReviewAlternativesError(err.message || "Unable to load alternatives.");
    }

    return false;
}

function openFoodReviewAlternativesFromKey(event, marker) {
    if (!event || (event.key !== "Enter" && event.key !== " ")) {
        return;
    }

    event.preventDefault();
    openFoodReviewAlternatives(marker);
}

function foodReviewPayloadFromRow(row) {
    const payload = fieldValuesFromRow(row);
    const marker = row.querySelector(".recipe-edit-food-warning");
    const review = recipeIngredientFoodReviewPayload(row);

    if (marker && marker.dataset.blockedBy) {
        try {
            payload.blocked_by = JSON.parse(marker.dataset.blockedBy);
        } catch (err) {
            payload.blocked_by = [];
        }
    }

    if (review) {
        payload.food_review = review;
        payload.review_kind = review.kind || "";
        payload.review_reason = review.reason || "";
    }

    payload.recipe_title = document.getElementById("recipeEditTitleInput")
        ? document.getElementById("recipeEditTitleInput").value.trim()
        : "";
    payload.display_name = document.getElementById("recipeEditDisplayName")
        ? document.getElementById("recipeEditDisplayName").value.trim()
        : "";

    return payload;
}

function parseRecipeIngredientFoodReview(row) {
    if (!row || !row.dataset.ingredientTextReview) {
        return null;
    }

    try {
        const parsed = JSON.parse(row.dataset.ingredientTextReview);
        return parsed && typeof parsed === "object" ? parsed : null;
    } catch (err) {
        return null;
    }
}

function recipeIngredientFoodReviewPayload(row) {
    const review = parseRecipeIngredientFoodReview(row);

    if (!review) {
        return null;
    }

    const status = String(row.dataset.foodReviewState || review.status || "").trim().toLowerCase();
    const expectedKey = row.dataset.ingredientTextReviewKey || review.text_key || "";
    const currentKey = ingredientTextReviewKeyFromRow(row);
    const statusAllowsChangedText = ["accepted", "ignored", "reviewed", "manual_edit"].includes(status);

    if (!statusAllowsChangedText && expectedKey && currentKey && expectedKey !== currentKey) {
        return null;
    }

    const normalized = normalizeRecipeIngredientFoodReviewState({
        ...review,
        status: status || review.status || "",
        text_key: statusAllowsChangedText ? (currentKey || expectedKey) : (expectedKey || currentKey),
    });

    return normalized;
}

function setRecipeIngredientFoodReviewPayload(row, review) {
    if (!row || !review || typeof review !== "object") {
        return;
    }

    const normalized = normalizeRecipeIngredientFoodReviewState(review);

    if (!normalized) {
        return;
    }

    row.dataset.ingredientTextReview = JSON.stringify(normalized);
    row.dataset.ingredientTextReviewKey = normalized.text_key || ingredientTextReviewKeyFromRow(row);
    row.dataset.foodReviewState = normalized.status || "";
}

function showFoodReviewAlternativesModal() {
    let modal = document.getElementById("foodReviewAlternativesModal");

    if (!modal) {
        modal = document.createElement("div");
        modal.id = "foodReviewAlternativesModal";
        modal.className = "food-review-alt-backdrop";
        modal.setAttribute("aria-hidden", "true");
        modal.innerHTML = `
            <div class="food-review-alt-dialog" role="dialog" aria-modal="true" aria-labelledby="foodReviewAltTitle">
                <div class="food-review-alt-header">
                    <div>
                        <h2 id="foodReviewAltTitle">Food Review Alternatives</h2>
                        <div id="foodReviewAltSubtitle" class="food-review-alt-subtitle"></div>
                    </div>
                    <button type="button" class="food-review-alt-close" onclick="closeFoodReviewAlternatives()">Close</button>
                </div>
                <div id="foodReviewAltContent" class="food-review-alt-content"></div>
            </div>
        `;
        document.body.appendChild(modal);
    }

    modal.classList.add("open");
    modal.setAttribute("aria-hidden", "false");
}

function closeFoodReviewAlternatives() {
    const modal = document.getElementById("foodReviewAlternativesModal");

    if (modal) {
        modal.classList.remove("open");
        modal.setAttribute("aria-hidden", "true");
    }
}

function renderFoodReviewAlternativesLoading(row) {
    const subtitle = document.getElementById("foodReviewAltSubtitle");
    const content = document.getElementById("foodReviewAltContent");
    const payload = foodReviewPayloadFromRow(row);

    if (subtitle) {
        subtitle.textContent = payload.ingredient || payload.original_text || "Ingredient";
    }

    if (content) {
        content.innerHTML = `
            <div class="food-review-alt-state">
                Asking ChatGPT for practical swaps...
            </div>
        `;
    }
}

function renderFoodReviewAlternatives(data) {
    const subtitle = document.getElementById("foodReviewAltSubtitle");
    const content = document.getElementById("foodReviewAltContent");
    const review = data.review || {};
    const alternatives = data.alternatives || [];
    const suspiciousReview = foodReviewIsSuspicious(review);

    if (subtitle) {
        const issues = (review.blocked_by || []).join("; ");
        subtitle.textContent = issues
            ? `${review.ingredient || review.original_text || "Ingredient"} - ${issues}`
            : (review.ingredient || review.original_text || "Ingredient");
    }

    if (!content) {
        return;
    }

    if (!alternatives.length) {
        content.innerHTML = `
            ${suspiciousReview ? renderSuspiciousFoodReviewIssue(review) : ""}
            <div class="food-review-alt-state">
                No alternatives came back for this ingredient.
            </div>
            ${suspiciousReview ? renderSuspiciousFoodReviewActions() : ""}
        `;
        return;
    }

    content.innerHTML = `
        ${suspiciousReview ? renderSuspiciousFoodReviewIssue(review) : ""}
        ${alternatives.map((item, index) => `
        <div class="food-review-alt-card">
            <div class="food-review-alt-card-main">
                <div class="food-review-alt-name">${escapeHtml(item.ingredient)}</div>
                <div class="food-review-alt-meta">${escapeHtml(formatFoodReviewAmount(item))}</div>
                <div class="food-review-alt-reason">${escapeHtml(item.reason || "Suggested as a recipe-compatible replacement.")}</div>
                ${item.adjustment ? `<div class="food-review-alt-adjustment">${escapeHtml(item.adjustment)}</div>` : ""}
            </div>
            <div class="food-review-alt-card-actions">
                <span class="food-review-alt-confidence ${escapeAttribute(item.confidence || "medium")}">${escapeHtml(item.confidence || "medium")}</span>
                <button type="button" onclick="applyFoodReviewAlternative(${index})">${suspiciousReview ? "Accept Fix" : "Use"}</button>
            </div>
        </div>
        `).join("")}
        ${suspiciousReview ? renderSuspiciousFoodReviewActions() : ""}
    `;
}

function foodReviewIsSuspicious(review = {}) {
    return String(review.kind || review.review_kind || "").trim() === "suspicious_ingredient";
}

function renderSuspiciousFoodReviewIssue(review = {}) {
    const original = review.original_ingredient || review.original_text || review.ingredient || "Ingredient";
    const reason = review.reason || review.review_reason || "This ingredient may have been generated incorrectly.";
    const warning = review.warning || "";

    return `
        <div class="food-review-alt-card food-review-alt-issue">
            <div class="food-review-alt-card-main">
                <div class="food-review-alt-name">Original: ${escapeHtml(original)}</div>
                <div class="food-review-alt-reason">${escapeHtml(reason)}</div>
                ${warning ? `<div class="food-review-alt-adjustment">${escapeHtml(warning)}</div>` : ""}
            </div>
        </div>
    `;
}

function renderSuspiciousFoodReviewActions() {
    return `
        <div class="food-review-alt-actions">
            <button type="button" onclick="ignoreFoodReviewIssue()">Ignore</button>
            <button type="button" onclick="editFoodReviewManually()">Edit Manually</button>
        </div>
    `;
}

function renderFoodReviewAlternativesError(message) {
    const subtitle = document.getElementById("foodReviewAltSubtitle");
    const content = document.getElementById("foodReviewAltContent");

    if (subtitle) {
        subtitle.textContent = "Could not load alternatives";
    }

    if (content) {
        content.innerHTML = `
            <div class="food-review-alt-state error">
                ${escapeHtml(message)}
            </div>
        `;
    }
}

function formatFoodReviewAmount(item) {
    const amount = `${item.quantity || ""} ${item.unit || ""}`.trim();
    return amount || "Amount depends on recipe taste and texture.";
}

function applyFoodReviewAlternative(index) {
    const alternative = activeFoodReviewAlternatives[index];
    const row = activeFoodReviewRow;

    if (!alternative || !row) {
        return;
    }

    setRowFieldValue(row, "ingredient", alternative.ingredient || "");
    setRowFieldValue(row, "quantity", alternative.quantity || "");
    setRowFieldValue(row, "unit", alternative.unit || "");
    setRowFieldValue(row, "purchasable_item", alternative.purchasable_item || alternative.ingredient || "");
    setRowFieldValue(row, "parsed_name", alternative.ingredient || "");
    setRowFieldValue(row, "normalized_name", alternative.ingredient || "");
    setRowFieldValue(row, "confidence", alternative.confidence || "medium");
    setRowFieldValue(row, "warning", "");
    setRowFieldValue(
        row,
        "original_text",
        alternative.original_text
            || `${alternative.quantity || ""} ${alternative.unit || ""} ${alternative.ingredient || ""}`.trim()
    );
    const purchaseGroupInput = row.querySelector('[data-field="purchase_group"]');
    if (purchaseGroupInput) {
        purchaseGroupInput.value = "";
    }
    const warningMessage = row.querySelector("[data-ingredient-warning-message]");
    if (warningMessage) {
        warningMessage.hidden = true;
        warningMessage.textContent = "";
    }
    markRecipeIngredientReviewStatus(row, "accepted", "Reviewed with an accepted AI fix.");
    closeFoodReviewAlternatives();
    showRecipeQuantityUpdatedMessage("", "", "", "Fix accepted. Save Recipe to keep it.");
}

function markRecipeIngredientReviewed(row) {
    markRecipeIngredientReviewStatus(row, "reviewed", "Reviewed with a ChatGPT alternative.");
}

function markRecipeIngredientReviewStatus(row, status, title) {
    const marker = row ? row.querySelector(".recipe-edit-food-warning") : null;

    if (!row || !marker) {
        return;
    }

    const review = recipeIngredientFoodReviewPayload(row) || parseRecipeIngredientFoodReview(row) || {};
    const normalizedStatus = String(status || "reviewed").trim().toLowerCase();
    const resolved = ["accepted", "ignored", "reviewed"].includes(normalizedStatus);
    setRecipeIngredientFoodReviewPayload(row, {
        ...review,
        status: normalizedStatus,
        needs_review: !resolved,
        text_key: ingredientTextReviewKeyFromRow(row),
    });
    if (resolved) {
        setRowFieldValue(row, "warning", "");
        const warningMessage = row.querySelector("[data-ingredient-warning-message]");
        if (warningMessage) {
            warningMessage.hidden = true;
            warningMessage.textContent = "";
        }
    }

    row.dataset.foodReviewState = normalizedStatus;
    marker.hidden = false;
    marker.textContent = normalizedStatus === "ignored" ? "Ignored" : "Reviewed";
    marker.title = title || "Reviewed.";
    marker.dataset.blockedBy = "[]";
    marker.tabIndex = 0;
    marker.classList.add("reviewed");
    updateRecipeIngredientFoodRuleWarning(row);
}

function ignoreFoodReviewIssue() {
    const row = activeFoodReviewRow;

    if (!row) {
        return false;
    }

    markRecipeIngredientReviewStatus(row, "ignored", "Ignored after ingredient review.");
    closeFoodReviewAlternatives();
    showRecipeQuantityUpdatedMessage("", "", "", "Food Review ignored. Save Recipe to keep it.");
    return false;
}

function editFoodReviewManually() {
    const row = activeFoodReviewRow;

    if (!row) {
        return false;
    }

    closeFoodReviewAlternatives();
    expandRecipeIngredientRow(row);
    const ingredientInput = row.querySelector('[data-field="ingredient"]');
    if (ingredientInput) {
        ingredientInput.focus();
        if (typeof ingredientInput.select === "function") {
            ingredientInput.select();
        }
    }

    updateRecipeIngredientFoodRuleWarning(row);
    return false;
}

function setRowFieldValue(row, field, value) {
    const input = row.querySelector(`[data-field="${field}"]`);

    if (input) {
        input.value = value;
        const eventName = input.tagName === "SELECT" || input.type === "checkbox" ? "change" : "input";
        input.dispatchEvent(new Event(eventName, { bubbles: true }));
        if (field === "store_section") {
            syncRecipeIngredientStoreSectionControl(input);
        }
    }
}

