    const row = recipeEditActionRowFromButton(button);

    if (!row) {
        return false;
    }

    const sibling = recipeEditAdjacentMovableRow(row, direction);

    if (direction < 0 && sibling) {
        sibling.before(row);
    } else if (direction > 0 && sibling) {
        sibling.after(row);
    }

    updateRecipeEditRowOrder(row);
    return false;
