function collectRecipeNoteSections() {
    return [...document.querySelectorAll("#recipeEditRecipeNotes .recipe-edit-note-section-row")]
        .map(row => {
            const headingField = row.querySelector('[data-field="heading"]');
            const itemsField = row.querySelector('[data-field="items"]');
            const heading = String(headingField ? headingField.value : "").trim();
            const items = normalizeRecipeNoteItemsForEditor(itemsField ? itemsField.value : "");

            const values = fieldValuesFromRow(row);
            return {
                id: values.id || "",
                note_section_id: values.note_section_id || "",
                heading,
                items,
            };
        })
        .filter(section => section.heading || section.items.length);
}

async function estimateRecipeNutrition(button, options = {}) {
    const originalText = button ? button.textContent : "";
    const payload = collectRecipeEditorPayload();
    const returnResult = Boolean(options.returnResult);
    const setStatusMessages = options.setStatus !== false;
    let forceEstimate = Boolean(options.forceEstimate || options.force);

    if (!forceEstimate && payload && payload.recipe && recipeHasNutritionData(payload.recipe)) {
        const hasPerServingEstimate = recipeHasPerServingEstimate(payload.recipe);
        const shouldPromptOverwrite = options.promptOverwrite !== false && Boolean(button);
        const overwriteExisting = shouldPromptOverwrite
            ? window.confirm("Nutrition data already exists. Overwrite it with a new per-serving estimate?")
            : false;

        if (overwriteExisting) {
            forceEstimate = true;
        } else {
            updateRecipeEditorPdfControls(payload.recipe, {
                updateInputValues: false,
                useCurrentForMissing: true,
            });
            if (setStatusMessages) {
                setRecipeEditStatus(
                    shouldPromptOverwrite
                        ? "Existing nutrition data was kept."
                        : (hasPerServingEstimate ? "Per-serving nutrition is already available." : "Nutrition data is already available.")
                );
            }
            return returnResult ? { ok: true, already_available: hasPerServingEstimate, canceled: shouldPromptOverwrite } : false;
        }
    }

    if (button) {
        button.disabled = true;
        button.textContent = "Estimating...";
    }

    try {
        if (setStatusMessages) {
            setRecipeEditStatus("Estimating nutrition with ChatGPT...");
        }
        const response = await fetch("/api/recipe_nutrition_estimate", {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
            },
            body: JSON.stringify({
                ...payload,
                force_estimate: forceEstimate,
            }),
        });
        const data = await response.json();
        syncOpenAiUsageDashboardFromResponse(data);

        if (!response.ok || !data.ok) {
            throw new Error((data && data.error) || "Unable to estimate nutrition.");
        }

        applyEstimatedNutritionRows(data.nutrition || []);
        const currentRecipePayload = collectRecipeEditorPayload();
        if (currentRecipePayload && currentRecipePayload.recipe) {
            updateRecipeEditorPdfControls(currentRecipePayload.recipe, {
                updateInputValues: false,
                useCurrentForMissing: true,
            });
        }
        if (setStatusMessages) {
            setRecipeEditStatus("Nutrition estimate added. Review values, then Save Recipe.");
        }
        return returnResult ? { ok: true, data, nutrition: data.nutrition || [] } : false;
    } catch (err) {
        console.warn("Unable to estimate nutrition.", err);
        if (setStatusMessages) {
            setRecipeEditStatus(err.message || "Unable to estimate nutrition.", true);
        }
        if (options.throwOnError) {
            throw err;
        }
        return returnResult ? { ok: false, error: err } : false;
    } finally {
        if (button) {
            button.disabled = false;
            button.textContent = originalText || "Estimate per serving basis";
        }
    }
}

function applyEstimatedNutritionRows(rows) {
    (Array.isArray(rows) ? rows : []).forEach(item => {
        if (!item || !item.key) {
            return;
        }

        setRecipeNutritionRowValue(item.key, item.value || "");
    });
}

function setRecipeNutritionRowValue(key, value) {
    const normalizedKey = normalizeNutritionKey(key);
    let row = [...document.querySelectorAll("#recipeEditNutrition .recipe-edit-nutrition-row")]
        .find(candidate => {
            const input = candidate.querySelector('[data-field="key"]');
            return input && normalizeNutritionKey(input.value) === normalizedKey;
        });

    if (!row) {
        row = addRecipeNutritionRow({ key, value: "" });
    }

    const keyInput = row.querySelector('[data-field="key"]');
    const valueInput = row.querySelector('[data-field="value"]');

    if (keyInput) {
        keyInput.value = key;
    }

    if (valueInput) {
        valueInput.value = value;
        valueInput.dispatchEvent(new Event("input", { bubbles: true }));
    }
}

function normalizeNutritionKey(value) {
    return String(value || "").trim().toLowerCase().replace(/[\s-]+/g, "_");
}

function recipeReflectionTimestamp(value = "") {
    const parsed = value ? new Date(value) : new Date();

    if (Number.isNaN(parsed.getTime())) {
        return new Date().toISOString();
    }

    return parsed.toISOString();
}

function formatRecipeReflectionTimestamp(value) {
    const parsed = value ? new Date(value) : null;

    if (!parsed || Number.isNaN(parsed.getTime())) {
        return "";
    }

    return parsed.toLocaleString(undefined, {
        year: "numeric",
        month: "short",
        day: "numeric",
        hour: "numeric",
        minute: "2-digit",
    });
}

function recipeReflectionNoteId(value = "") {
    const existing = String(value || "").trim();

    if (existing) {
        return existing;
    }

    return `note-${Date.now()}-${Math.random().toString(16).slice(2)}`;
}

function addRecipeReflectionNoteRow(note = {}) {
    const wrap = document.getElementById("recipeEditReflectionNotes");

    if (!wrap) {
        return null;
    }

    const createdAt = String(note.created_at || "").trim() || recipeReflectionTimestamp();
    const feedbackCreatedAt = String(note.chatgpt_feedback_created_at || "").trim();
    const feedback = String(note.chatgpt_feedback || "").trim();
    const row = document.createElement("div");

    row.className = "recipe-edit-reflection-note-row";
    row.innerHTML = `
        <span class="recipe-edit-row-handle" aria-hidden="true">${recipeEditSvgIcon("drag")}</span>
        <div class="recipe-edit-reflection-note-main">
            <div class="recipe-edit-reflection-note-meta">
                <span>Added ${escapeHtml(formatRecipeReflectionTimestamp(createdAt) || createdAt)}</span>
                ${feedbackCreatedAt ? `<span data-note-feedback-time>Feedback ${escapeHtml(formatRecipeReflectionTimestamp(feedbackCreatedAt) || feedbackCreatedAt)}</span>` : `<span data-note-feedback-time hidden></span>`}
            </div>
            <textarea data-field="text" rows="3" placeholder="What worked, what changed, or what should be tried next time?">${escapeHtml(note.text || "")}</textarea>
            <input type="hidden" data-field="note_id" value="${escapeAttribute(recipeReflectionNoteId(note.note_id))}">
            <input type="hidden" data-field="created_at" value="${escapeAttribute(createdAt)}">
            <input type="hidden" data-field="chatgpt_feedback_created_at" value="${escapeAttribute(feedbackCreatedAt)}">
            <textarea data-field="chatgpt_feedback" hidden>${escapeHtml(feedback)}</textarea>
            <div class="recipe-edit-note-feedback" data-note-feedback${feedback ? "" : " hidden"}>${escapeHtml(feedback)}</div>
        </div>
        <div class="recipe-edit-reflection-note-actions">
            <button type="button"
                    class="recipe-edit-note-feedback-btn"
                    onclick="return askRecipeNoteFeedback(this)">
                Ask ChatGPT
            </button>
        <div class="recipe-edit-row-menu-wrap">
                <button type="button"
                        class="recipe-edit-row-menu-btn"
                        aria-label="Note actions"
                        title="Note actions"
                        aria-haspopup="true"
                        aria-expanded="false"
                        onclick="return toggleRecipeEditRowMenu(this, event)">
                    <span aria-hidden="true"></span>
                </button>
                <div class="recipe-edit-row-menu" hidden>
                    <button type="button" onclick="moveRecipeEditRow(this, -1)">Move note up</button>
                    <button type="button" onclick="moveRecipeEditRow(this, 1)">Move note down</button>
                    <button type="button" class="delete" onclick="removeRecipeEditRow(this)">Delete note</button>
                </div>
            </div>
        </div>
        <input type="hidden" data-field="id" value="${escapeAttribute(note.id || "")}">
    `;
    wrap.appendChild(row);
    bindRecipeEditDragAndDrop(row);
    updateRecipeEditorDirtyState();
    return row;
}

function collectRecipeReflectionNotes() {
    return [...document.querySelectorAll("#recipeEditReflectionNotes .recipe-edit-reflection-note-row")]
        .map(row => {
            const item = fieldValuesFromRow(row);
            const text = String(item.text || "").trim();

            return {
                id: String(item.id || "").trim(),
                note_id: recipeReflectionNoteId(item.note_id),
                text,
                created_at: String(item.created_at || "").trim() || recipeReflectionTimestamp(),
                chatgpt_feedback: String(item.chatgpt_feedback || "").trim(),
                chatgpt_feedback_created_at: String(item.chatgpt_feedback_created_at || "").trim(),
            };
        })
        .filter(item => item.text);
}

function applyRecipeNoteFeedbackToRow(row, feedback, createdAt) {
    const feedbackText = String(feedback || "").trim();
    const timestamp = String(createdAt || "").trim() || recipeReflectionTimestamp();
    const feedbackDisplay = row ? row.querySelector("[data-note-feedback]") : null;
    const feedbackInput = row ? row.querySelector('[data-field="chatgpt_feedback"]') : null;
    const feedbackTimeInput = row ? row.querySelector('[data-field="chatgpt_feedback_created_at"]') : null;
    const feedbackTime = row ? row.querySelector("[data-note-feedback-time]") : null;

    if (feedbackInput) {
        feedbackInput.value = feedbackText;
    }

    if (feedbackTimeInput) {
        feedbackTimeInput.value = timestamp;
    }

    if (feedbackDisplay) {
        feedbackDisplay.textContent = feedbackText;
        feedbackDisplay.hidden = !feedbackText;
    }

    if (feedbackTime) {
        feedbackTime.textContent = `Feedback ${formatRecipeReflectionTimestamp(timestamp) || timestamp}`;
        feedbackTime.hidden = !feedbackText;
    }
}

async function askRecipeNoteFeedback(button) {
    const row = button ? button.closest(".recipe-edit-reflection-note-row") : null;
    const noteInput = row ? row.querySelector('[data-field="text"]') : null;
    const note = noteInput ? noteInput.value.trim() : "";

    if (!row || !note) {
        setRecipeEditStatus("Add a recipe note before asking ChatGPT for feedback.", true);
        return false;
    }

    const originalText = button ? button.textContent : "";

    if (button) {
        button.disabled = true;
        button.textContent = "Asking...";
    }

    try {
        setRecipeEditStatus("Asking ChatGPT for note feedback...");
        const payload = collectRecipeEditorPayload();
        const response = await fetch("/api/recipe_note_feedback", {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
            },
            body: JSON.stringify({
                note,
                recipe: payload.recipe,
            }),
        });
        const data = await response.json();
        syncOpenAiUsageDashboardFromResponse(data);

        if (!response.ok || !data.ok) {
            throw new Error((data && data.error) || "Unable to get note feedback.");
        }

        applyRecipeNoteFeedbackToRow(row, data.feedback || "", data.created_at || "");
        setRecipeEditStatus("ChatGPT feedback added. Save Recipe to keep it.");
    } catch (err) {
        console.warn("Unable to get recipe note feedback.", err);
        setRecipeEditStatus(err.message || "Unable to get note feedback.", true);
    } finally {
        if (button) {
            button.disabled = false;
            button.textContent = originalText || "Ask ChatGPT";
        }
    }

    return false;
}

function removeRecipeEditRow(button) {
    const row = recipeEditActionRowFromButton(button);

    if (row) {
        const wasIngredient = row.classList.contains("recipe-edit-ingredient-row");
        const wasEquipment = row.classList.contains("recipe-edit-equipment-row");
        const wasInstruction = row.classList.contains("recipe-edit-instruction-row");
        const wasRecipeNote = row.classList.contains("recipe-edit-note-section-row");
        closeRecipeEditRowMenus();
        row.remove();

        if (wasIngredient) {
            updateRecipeIngredientRowIndexes();
        }
        if (wasEquipment) {
            updateRecipeEquipmentRowNumbers();
        }
        if (wasInstruction) {
            updateRecipeInstructionStepNumbers();
        }
        if (wasRecipeNote) {
            updateRecipeNotesEmptyState();
        }
        updateRecipeEditContextPanels();
        updateRecipeEditorDirtyState();
    }

    return false;
}

function recipeHasGeneratedCloudflarePdf(recipe = {}) {
    const values = normalizeRecipeEditorPdfValues(recipe, recipeEditorCurrentUrl(), {
        useCurrentForMissing: true,
    });

    return Boolean(String(values.generated_cloudflare_pdf_url || "").trim());
}

async function recipePdfSaveChoiceForPayload(recipe = {}) {
    if (recipeHasGeneratedCloudflarePdf(recipe)) {
        return "save_without_pdf";
    }

    return promptRecipeMissingPdfOnSave();
}

function promptRecipeMissingPdfOnSave() {
    return new Promise(resolve => {
        let overlay = document.getElementById("recipePdfSavePromptOverlay");

        if (overlay) {
            overlay.remove();
        }

        overlay = document.createElement("div");
        overlay.id = "recipePdfSavePromptOverlay";
        overlay.className = "recipe-qty-progress-backdrop recipe-pdf-save-prompt-backdrop open";
        overlay.setAttribute("aria-hidden", "false");
        overlay.innerHTML = `
            <div class="recipe-qty-progress-card recipe-pdf-save-prompt-card" role="dialog" aria-modal="true" aria-labelledby="recipePdfSavePromptTitle" aria-describedby="recipePdfSavePromptMessage">
                <div class="recipe-qty-progress-header">
                    <h2 id="recipePdfSavePromptTitle">Recipe PDF</h2>
                </div>
                <p id="recipePdfSavePromptMessage" class="recipe-pdf-save-prompt-message">
                    This recipe does not have a generated Recipe PDF yet. Do you want to create one now?
                </p>
                <div class="recipe-save-progress-actions recipe-pdf-save-prompt-actions">
                    <button type="button" class="recipe-save-progress-action primary" data-recipe-pdf-save-choice="create">Save and Create PDF</button>
                    <button type="button" class="recipe-save-progress-action secondary" data-recipe-pdf-save-choice="save_without_pdf">Save Without PDF</button>
                    <button type="button" class="recipe-save-progress-action secondary" data-recipe-pdf-save-choice="cancel">Cancel</button>
                </div>
            </div>
        `;
        document.body.appendChild(overlay);

        const settle = choice => {
            overlay.removeEventListener("keydown", handleKeydown);
            overlay.remove();
            resolve(choice);
        };
        const handleKeydown = event => {
            if (event.key === "Escape") {
                event.preventDefault();
                settle("cancel");
            }
        };

        overlay.addEventListener("keydown", handleKeydown);
        overlay.querySelectorAll("[data-recipe-pdf-save-choice]").forEach(button => {
            button.addEventListener("click", () => {
                settle(button.dataset.recipePdfSaveChoice || "cancel");
            });
        });

        const primaryButton = overlay.querySelector('[data-recipe-pdf-save-choice="create"]');
        if (primaryButton) {
            primaryButton.focus({ preventScroll: true });
        }
    });
}

async function saveRecipeEditor(event) {
    if (event) {
        event.preventDefault();
    }

    const form = document.getElementById("recipeEditForm");
    if (!form) {
        return false;
    }

    recipeEditorSaveDebug("submit", {
        recipe_id: document.getElementById("recipeEditId")?.value || "",
        route: "/api/recipe",
    });

    if (form.dataset.saving === "true") {
        recipeEditorSaveDebug("duplicate prevented");
        setRecipeEditStatus("A recipe save is already in progress.");
        return false;
    }

    form.dataset.saving = "true";
    setRecipeEditorSavingState(form, true);
    setRecipeEditStatus("Validating recipe...");

    let payload = null;
    let submittedSnapshot = "";
    let coreSaveSucceeded = false;
    let followUpStage = "saving the recipe";
    let savedIdentity = null;
    let savedIdentityApplied = false;
    let savedBaselineSnapshot = "";
    const previousSavedSnapshot = recipeEditSavedFormSnapshots.get(form) || "";

    try {
        payload = collectRecipeEditorPayload();
        const validation = validateRecipeEditor(form, payload);
        recipeEditorSaveDebug("validation", {
            valid: validation.valid,
            error_count: validation.errors.length,
        });
        if (!validation.valid) {
            setRecipeEditStatus("Some fields need attention. Review the highlighted fields and try again.", true);
            return false;
        }

        submittedSnapshot = recipeEditorCurrentSaveSnapshot(form);
        const shouldSaveCategories = recipeEditCategoryValuesChanged();
        const pdfSaveChoice = await recipePdfSaveChoiceForPayload(payload.recipe);
        if (pdfSaveChoice === "cancel") {
            setRecipeEditStatus("Save canceled. Your changes are still on this page.");
            return false;
        }

        const shouldCreatePdf = pdfSaveChoice === "create";
        const pdfCreationReason = shouldCreatePdf ? "missing_pdf" : "";
        const progressItems = buildRecipeSaveProgressItems(payload.recipe);
        let refreshProgressIndex = progressItems.length - 1;
        let categoryProgressIndex = null;
        let pdfProgressIndex = null;
        if (shouldSaveCategories) {
            categoryProgressIndex = refreshProgressIndex;
            progressItems.splice(refreshProgressIndex, 0, {
                label: "Cookbook categories",
                detail: "Saving the recipe menu categories.",
            });
            refreshProgressIndex += 1;
        }
        if (shouldCreatePdf) {
            pdfProgressIndex = refreshProgressIndex;
            progressItems.splice(refreshProgressIndex, 0, {
                label: "Recipe PDF",
                detail: pdfCreationReason === "manual_edits"
                    ? "Regenerating the manual recipe PDF from the saved edits."
                    : "Creating the PDF archive because this recipe does not have one yet.",
            });
            refreshProgressIndex += 1;
        }
        showRecipeSaveProgressOverlay(progressItems);
        updateRecipeSaveProgressItem(0, "running", "Saving...");
        setRecipeEditStatus("Saving recipe...");

        followUpStage = "saving the recipe";
        recipeEditorSaveDebug("request", {
            route: "/api/recipe",
            method: "POST",
            recipe_id: payload.recipe_id || "",
            ingredient_count: payload.recipe.ingredients.length,
            instruction_count: payload.recipe.instructions.length,
            equipment_count: payload.recipe.equipment.length,
            nutrition_count: payload.recipe.nutrition.length,
        });
        const response = await fetch("/api/recipe", {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
            },
            credentials: "same-origin",
            body: JSON.stringify(payload),
        });
        const data = await recipeEditorJsonResponse(response);
        recipeEditorSaveDebug("response", {
            status: response.status,
            ok: response.ok,
            body: data,
        });

        if (!response.ok || !(data.ok || data.success)) {
            const fieldErrors = data && data.field_errors && typeof data.field_errors === "object"
                ? data.field_errors
                : {};
            if (Object.keys(fieldErrors).length) {
                applyRecipeEditorServerFieldErrors(fieldErrors);
            }
            const error = new Error(
                (data && (data.message || data.error))
                || `The recipe could not be saved (${response.status}).`
            );
            error.fieldErrors = fieldErrors;
            throw error;
        }
        coreSaveSucceeded = true;
        markRecipeIngredientRowsPersisted();
        const responseRecipe = data.recipe && typeof data.recipe === "object" ? data.recipe : {};
        const savedRecipeId = String(data.recipe_id || responseRecipe.recipe_id || payload.recipe_id || "").trim();
        const savedSourceUrl = String(
            responseRecipe.source_url
            || payload.recipe.source_url
            || payload.original_url
        ).trim();
        savedIdentity = {
            recipe_id: savedRecipeId,
            source_url: savedSourceUrl,
            updated_at: data.updated_at || responseRecipe.updated_at || "",
        };
        savedBaselineSnapshot = rememberRecipeEditorSubmittedState(form, submittedSnapshot, savedIdentity, {
            preserveCategoriesFrom: previousSavedSnapshot,
        });
        updateRecipeEditorSavedIdentity(savedIdentity, payload, { updateSourceField: false });
        savedIdentityApplied = true;
        invalidateRecipeEditorCache(payload.original_url);
        if (savedSourceUrl && savedSourceUrl !== payload.original_url) {
            invalidateRecipeEditorCache(savedSourceUrl);
        }
        if (data.recipe) {
            rememberRecipeEditorData(savedSourceUrl, {
                recipe: responseRecipe,
                store_sections: recipeEditStoreSections,
                food_rules: recipeEditFoodRules,
            });
        }

        updateRecipeSaveProgressItem(0, "done", "Saved");
        updateRecipeSaveProgressItem(1, "done", "Updated");

        let recipeForEditor = data.recipe || {
            ...payload.recipe,
            recipe_id: savedRecipeId,
            source_url: savedSourceUrl,
            updated_at: data.updated_at || "",
        };
        const sourceUrl = savedSourceUrl;
        let createdPdfPublicUrl = "";
        let createdPdfUploadError = "";

        if (shouldCreatePdf && isUploadedRecipeSourceUrl(sourceUrl || "") && !recipeHasPerServingEstimate(payload.recipe || {})) {
            throw new Error("Estimate per serving basis is required before creating the recipe PDF.");
        }

        if (shouldSaveCategories) {
            followUpStage = "saving cookbook categories";
            updateRecipeSaveProgressItem(categoryProgressIndex, "running", "Saving...");
            setRecipeEditStatus("Saving recipe categories...");
            const categoryResult = await saveRecipeEditorCategories(sourceUrl, payload.original_url);
            if (categoryResult.canceled) {
                updateRecipeSaveProgressItem(categoryProgressIndex, "done", "Skipped");
            } else if (categoryResult.skipped) {
                updateRecipeSaveProgressItem(categoryProgressIndex, "done", "No cookbook");
            } else {
                updateRecipeSaveProgressItem(categoryProgressIndex, "done", "Saved");
                savedBaselineSnapshot = rememberRecipeEditorSubmittedState(form, submittedSnapshot, savedIdentity);
                rememberRecipeEditorSubmittedCategories(form, submittedSnapshot);
            }
        }

        if (shouldCreatePdf) {
            followUpStage = "creating the recipe PDF";
            updateRecipeSaveProgressItem(pdfProgressIndex, "running", "Generating...");
            setRecipeEditStatus("Generating PDF...");
            const pdfData = await createRecipePdfAndUploadForSource(sourceUrl);
            createdPdfPublicUrl = recipePdfDataCloudflareUrl(pdfData);
            createdPdfUploadError = pdfData.upload_error || "";
            recipeForEditor = {
                ...(recipeForEditor || {}),
                source_url: pdfData.url || sourceUrl,
                generated_pdf_path: pdfData.generated_pdf_path || pdfData.generated_recipe_pdf_path || pdfData.pdf_path || "",
                pdf_available: true,
                pdf_local_available: Boolean(pdfData.pdf_local_available),
                generated_cloudflare_pdf_url: createdPdfPublicUrl,
                pdf_public_url: createdPdfPublicUrl,
                pdf_object_key: pdfData.pdf_object_key || "",
                pdf_uploaded_at: pdfData.pdf_uploaded_at || "",
            };
            updateRecipeSaveProgressItem(pdfProgressIndex, "done", createdPdfPublicUrl ? "Cloud ready" : "Created");
        }

        const changedDuringSave = recipeEditorCurrentSaveSnapshot(form) !== savedBaselineSnapshot;
        if (changedDuringSave) {
            updateRecipeSaveProgressItem(refreshProgressIndex, "done", "New edits kept");
        } else {
            followUpStage = "refreshing the saved page values";
            updateRecipeSaveProgressItem(refreshProgressIndex, "running", "Refreshing...");
            await refreshStoreMarkup();
            if (shouldSaveCategories && sourceUrl) {
                try {
                    recipeForEditor = await fetchRecipeEditorData(sourceUrl);
                } catch (err) {
                    console.warn("Unable to refresh recipe categories after save.", err);
                }
            }
            if (recipeForEditor) {
                populateRecipeEditor(recipeForEditor, recipeForEditor.source_url || sourceUrl);
            }
            updateRecipeSaveProgressItem(refreshProgressIndex, "done", "Refreshed");
        }

        const warnings = Array.isArray(data.warnings) ? data.warnings.filter(Boolean) : [];
        const successMessage = changedDuringSave
            ? "Recipe saved successfully. Newer edits remain unsaved."
            : "Recipe saved successfully.";
        setRecipeSaveProgressSummary(
            warnings.length
                ? `${successMessage} ${warnings.join(" ")}`
                : (shouldCreatePdf
                ? (
                    createdPdfPublicUrl
                        ? `${successMessage} PDF created.`
                        : (createdPdfUploadError || `${successMessage} PDF created, but Cloudflare upload is not ready.`)
                )
                : successMessage)
        );
        setRecipeSaveProgressActionsState("done");
        setRecipeEditStatus(successMessage);
        showRecipeQuantityUpdatedMessage(
            "",
            "",
            "",
            shouldCreatePdf && createdPdfPublicUrl
                ? "Recipe saved successfully. PDF created."
                : "Recipe saved successfully."
        );
    } catch (err) {
        console.warn("Unable to save recipe.", err);
        recipeEditorSaveDebug("caught exception", { error: err });
        const safeMessage = String(err && err.message || "").trim();
        const message = coreSaveSucceeded
            ? `Recipe saved, but ${followUpStage} could not finish. ${safeMessage || "Try that step again."}`
            : `Recipe could not be saved. Your changes are still on this page. ${safeMessage || "Review the highlighted fields or try again."}`;
        setRecipeEditStatus(message, true);
        setRecipeSaveProgressSummary(message);
        updateRecipeSaveProgressFailed();
        setRecipeSaveProgressActionsState("failed");
    } finally {
        if (coreSaveSucceeded && savedIdentity && !savedIdentityApplied) {
            savedBaselineSnapshot = rememberRecipeEditorSubmittedState(form, submittedSnapshot, savedIdentity, {
                preserveCategoriesFrom: previousSavedSnapshot,
            });
            updateRecipeEditorSavedIdentity(savedIdentity, payload || {}, { updateSourceField: false });
        }
        const currentForm = document.getElementById("recipeEditForm") || form;
        delete form.dataset.saving;
        delete currentForm.dataset.saving;
        updateRecipeEditorDirtyState(currentForm);
        setRecipeEditorSavingState(currentForm, false);
    }

    return false;
}

function recipeInferOverwriteEnabled() {
    const checkbox = document.getElementById("recipeEditInferOverwriteAiFields");
    return Boolean(checkbox && checkbox.checked);
}

function recipeInferPreviewEnabled() {
    const checkbox = document.getElementById("recipeEditInferPreviewOnly");
    return Boolean(checkbox && checkbox.checked);
}

function recipeInferenceOptionEnabled(options, key, fallback) {
    const optionObject = options && typeof options === "object" ? options : {};
    return Object.prototype.hasOwnProperty.call(optionObject, key)
        ? Boolean(optionObject[key])
        : Boolean(fallback);
}

function applyRecipeEditorInferenceOptions(options = {}) {
    const optionObject = options && typeof options === "object" ? options : {};
    const overwriteCheckbox = document.getElementById("recipeEditInferOverwriteAiFields");
    const previewCheckbox = document.getElementById("recipeEditInferPreviewOnly");

    recipeEditInferenceContext = {
        cookbook_id: String(optionObject.cookbookId || optionObject.cookbook_id || "").trim(),
        cookbook_name: String(optionObject.cookbookName || optionObject.cookbook_name || "").trim(),
    };

    if (overwriteCheckbox && Object.prototype.hasOwnProperty.call(optionObject, "overwriteAiFields")) {
        overwriteCheckbox.checked = Boolean(optionObject.overwriteAiFields);
    }

    if (previewCheckbox && Object.prototype.hasOwnProperty.call(optionObject, "previewOnly")) {
        previewCheckbox.checked = Boolean(optionObject.previewOnly);
    }
}

function recipeInferenceSummary(data = {}) {
    if (data.skipped) {
        return "No missing recipe details were found.";
    }
    const fields = Array.isArray(data.preview_only ? data.would_update_fields : data.updated_fields)
        ? (data.preview_only ? data.would_update_fields : data.updated_fields)
        : [];
    if (!fields.length) {
        return "Recipe details checked.";
    }
    const action = data.preview_only ? "Would infer" : "Inferred";
    return `${action} ${fields.length} field${fields.length === 1 ? "" : "s"}: ${fields.join(", ")}.`;
}

function recipeIngredientsRegenerationSummary(data = {}) {
    const ingredients = Array.isArray(data.ingredients)
        ? data.ingredients
        : (data.recipe && Array.isArray(data.recipe.ingredients) ? data.recipe.ingredients : []);
    const count = ingredients.length;
    const action = data.preview_only ? "Previewed" : "Regenerated";

    return `${action} ${count} ingredient${count === 1 ? "" : "s"}.`;
}

function recipeNotesRegenerationSummary(data = {}) {
    const notes = Array.isArray(data.recipe_notes)
        ? data.recipe_notes
        : (data.recipe && Array.isArray(data.recipe.recipe_notes) ? data.recipe.recipe_notes : []);
    const itemCount = notes.reduce((total, section) => {
        const items = section && Array.isArray(section.items) ? section.items : [];
        return total + items.length;
    }, 0);
    const sectionCount = notes.length;
    const action = data.preview_only ? "Previewed" : "Regenerated";

    return `${action} ${sectionCount} note section${sectionCount === 1 ? "" : "s"} with ${itemCount} note${itemCount === 1 ? "" : "s"}.`;
}

function updateRecipeDescriptionAiActionLabel() {
    const description = document.getElementById("recipeEditDescription");
    const hasDescription = Boolean(String(description ? description.value : "").trim());
    document.querySelectorAll("[data-recipe-description-ai-label]").forEach(label => {
        label.textContent = recipeEditDescriptionRequestPending
            ? "Generating..."
            : (hasDescription ? "Regenerate Description" : "Generate Description");
    });
}

function recipeDescriptionReviewModal() {
    return document.querySelector("[data-recipe-description-review]");
}

function setRecipeDescriptionReviewError(message = "") {
    const error = recipeDescriptionReviewModal()?.querySelector("[data-recipe-description-review-error]");
    if (!error) return;
    error.textContent = String(message || "").trim();
    error.hidden = !error.textContent;
}

function setRecipeDescriptionActionsBusy(isBusy) {
    recipeEditDescriptionRequestPending = Boolean(isBusy);
    document.querySelectorAll("[data-recipe-description-ai-action]").forEach(action => {
        action.disabled = recipeEditDescriptionRequestPending;
        if (!action.querySelector("[data-recipe-description-ai-label]")) {
            action.textContent = recipeEditDescriptionRequestPending ? "Generating..." : "Regenerate";
        }
    });
    const apply = recipeDescriptionReviewModal()?.querySelector("[data-recipe-description-review-apply]");
    if (apply) apply.disabled = recipeEditDescriptionRequestPending || !recipeEditDescriptionProposal;
    updateRecipeDescriptionAiActionLabel();
}

function recipeDescriptionReviewFocusableElements(modal) {
    return Array.from(modal?.querySelectorAll('button:not([disabled]), [href], input:not([disabled]), textarea:not([disabled]), [tabindex]:not([tabindex="-1"])') || [])
        .filter(element => !element.hidden && element.getAttribute("aria-hidden") !== "true");
}

function handleRecipeDescriptionReviewKeydown(event) {
    const modal = recipeDescriptionReviewModal();
    if (!modal || modal.hidden) return;
    if (event.key === "Escape") {
        event.preventDefault();
        closeRecipeDescriptionReview();
        return;
    }
    if (event.key !== "Tab") return;
    const focusable = recipeDescriptionReviewFocusableElements(modal);
    if (!focusable.length) return;
    const first = focusable[0];
    const last = focusable[focusable.length - 1];
    if (event.shiftKey && document.activeElement === first) {
        event.preventDefault();
        last.focus();
    } else if (!event.shiftKey && document.activeElement === last) {
        event.preventDefault();
        first.focus();
    }
}

function openRecipeDescriptionReview(currentDescription, proposedDescription, trigger = null) {
    const modal = recipeDescriptionReviewModal();
    if (!modal) return false;
    recipeEditDescriptionProposal = String(proposedDescription || "").trim();
    if (trigger && !modal.contains(trigger)) recipeEditDescriptionReviewTrigger = trigger;
    const current = modal.querySelector("[data-recipe-description-current]");
    const proposed = modal.querySelector("[data-recipe-description-proposed]");
    if (current) current.textContent = String(currentDescription || "").trim() || "No description yet.";
    if (proposed) proposed.textContent = recipeEditDescriptionProposal;
    setRecipeDescriptionReviewError();
    modal.hidden = false;
    document.addEventListener("keydown", handleRecipeDescriptionReviewKeydown);
    const apply = modal.querySelector("[data-recipe-description-review-apply]");
    if (apply) {
        apply.disabled = !recipeEditDescriptionProposal;
        window.requestAnimationFrame(() => apply.focus());
    }
    return false;
}

function closeRecipeDescriptionReview(options = {}) {
    const modal = recipeDescriptionReviewModal();
    const restoreFocus = options.restoreFocus !== false;
    if (!modal || modal.hidden) return false;
    modal.hidden = true;
    setRecipeDescriptionReviewError();
    document.removeEventListener("keydown", handleRecipeDescriptionReviewKeydown);
    recipeEditDescriptionProposal = "";
    if (restoreFocus && recipeEditDescriptionReviewTrigger && recipeEditDescriptionReviewTrigger.isConnected) {
        recipeEditDescriptionReviewTrigger.focus();
    }
    recipeEditDescriptionReviewTrigger = null;
    return false;
}

function closeRecipeDescriptionReviewFromBackdrop(event) {
    if (event && event.target === event.currentTarget) return closeRecipeDescriptionReview();
    return false;
}

async function regenerateRecipeDescription(button) {
    if (recipeEditDescriptionRequestPending) return false;
    const recipeUrl = recipeEditorCurrentUrl();
    const description = document.getElementById("recipeEditDescription");
    const currentDescription = String(description ? description.value : "").trim();
    const modal = recipeDescriptionReviewModal();

    closeRecipeEditRowMenus();
    if (!recipeUrl) {
        setRecipeEditStatus("Recipe URL is required before generating a description.", true);
        return false;
    }

    if (!modal || modal.hidden) recipeEditDescriptionReviewTrigger = button;
    setRecipeDescriptionReviewError();
    setRecipeDescriptionActionsBusy(true);
    setRecipeEditStatus(currentDescription ? "Regenerating recipe description..." : "Generating recipe description...");

    try {
        const payload = collectRecipeEditorPayload();
        const response = await fetch("/api/recipe/regenerate_description", {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
                "X-Requested-With": "fetch",
            },
            body: JSON.stringify({
                url: recipeUrl,
                original_url: payload.original_url,
                recipe: {
                    ...payload.recipe,
                    ...collectRecipeEditorCategoryValues(),
                },
                cookbook_id: recipeEditInferenceContext.cookbook_id || "",
                cookbook_name: recipeEditInferenceContext.cookbook_name || "",
            }),
        });
        const data = await response.json();
        syncOpenAiUsageDashboardFromResponse(data);
        if (!response.ok || !data.ok) {
            throw new Error((data && data.error) || "Unable to generate a recipe description.");
        }
        const proposed = String(data.description || "").trim();
        if (!proposed || proposed.length > 1200) {
            throw new Error("Description generation returned an invalid proposal.");
        }
        openRecipeDescriptionReview(currentDescription, proposed, recipeEditDescriptionReviewTrigger || button);
        setRecipeEditStatus("Description proposal ready for review.");
    } catch (err) {
        console.warn("Unable to generate recipe description.", err);
        const message = err.message || "Unable to generate a recipe description.";
        if (modal && !modal.hidden) setRecipeDescriptionReviewError(message);
        setRecipeEditStatus(message, true);
    } finally {
        setRecipeDescriptionActionsBusy(false);
    }
    return false;
}

function replaceRecipeDescriptionProposal(button) {
    const description = document.getElementById("recipeEditDescription");
    if (!description || !recipeEditDescriptionProposal || recipeEditDescriptionRequestPending) return false;
    description.value = recipeEditDescriptionProposal;
    description.dispatchEvent(new Event("input", { bubbles: true }));
    description.dispatchEvent(new Event("change", { bubbles: true }));
    const form = document.getElementById("recipeEditForm");
    if (form) form.dataset.recipeEditDirty = "true";
    updateRecipeEditDescriptionCount();
    updateRecipeDescriptionAiActionLabel();
    closeRecipeDescriptionReview({ restoreFocus: false });
    setRecipeEditStatus("Description replaced in the editor. Save Recipe to keep this change.");
    description.focus();
    return false;
}

async function regenerateRecipeIngredientsSection(button) {
    const recipeUrl = recipeEditorCurrentUrl();
    const originalText = button ? button.textContent : "";
    const previewOnly = recipeInferPreviewEnabled();

    closeRecipeEditRowMenus();

    if (!recipeUrl) {
        setRecipeEditStatus("Recipe URL is required before regenerating ingredients.", true);
        return false;
    }

    if (!previewOnly) {
        const shouldContinue = window.confirm(
            "Regenerate and save the Ingredients section? Current ingredient rows will be replaced."
        );
        if (!shouldContinue) {
            return false;
        }
    }

    try {
        if (button) {
            button.disabled = true;
            button.textContent = previewOnly ? "Previewing..." : "Regenerating...";
        }
        setRecipeEditStatus(`${previewOnly ? "Previewing" : "Regenerating"} ingredients...`);

        const payload = collectRecipeEditorPayload();
        const response = await fetch("/api/recipe/regenerate_ingredients", {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
                "X-Requested-With": "fetch",
            },
            body: JSON.stringify({
                url: recipeUrl,
                original_url: payload.original_url,
                recipe: payload.recipe,
                cookbook_id: recipeEditInferenceContext.cookbook_id || "",
                cookbook_name: recipeEditInferenceContext.cookbook_name || "",
                preview_only: previewOnly,
            }),
        });
        const data = await response.json();
        syncOpenAiUsageDashboardFromResponse(data);

        if (!response.ok || !data.ok) {
            throw new Error((data && data.error) || "Unable to regenerate ingredients.");
        }

        if (previewOnly) {
            replaceRecipeEditorIngredients(data.ingredients || (data.recipe ? data.recipe.ingredients : []));
        } else {
            invalidateRecipeEditorCache(recipeUrl);
            if (data.recipe) {
                rememberRecipeEditorData(data.recipe.source_url || data.recipe_url || recipeUrl, {
                    recipe: data.recipe,
                    store_sections: recipeEditStoreSections,
                    food_rules: recipeEditFoodRules,
                });
                populateRecipeEditor(data.recipe, data.recipe.source_url || data.recipe_url || recipeUrl);
            } else {
                const refreshed = await fetchRecipeEditorData(data.recipe_url || recipeUrl, { useCache: false });
                populateRecipeEditor(refreshed, refreshed.source_url || data.recipe_url || recipeUrl);
            }
            await refreshStoreMarkup({ cacheBust: true });
        }

        const message = `${recipeIngredientsRegenerationSummary(data)} ${previewOnly ? "Review and Save Recipe to keep changes." : "Ingredients saved."}`;
        setRecipeEditStatus(message);
        showRecipeQuantityUpdatedMessage("", "", "", message);
    } catch (err) {
        console.warn("Unable to regenerate recipe ingredients.", err);
        setRecipeEditStatus(err.message || "Unable to regenerate ingredients.", true);
    } finally {
        if (button && button.isConnected) {
            button.disabled = false;
            button.textContent = originalText || "Regenerate Ingredients";
        }
    }

    return false;
}

